def _ensure_real_grosscode_package() -> None:
    grosscode_module = sys.modules.get("grosscode")
    grosscode_init = REPO_ROOT / "grosscode" / "__init__.py"
    if grosscode_module is not None:
        module_file = getattr(grosscode_module, "__file__", None)
        module_path = tuple(str(value) for value in getattr(grosscode_module, "__path__", ()))
        if module_file == str(grosscode_init) and module_path == (str(grosscode_init.parent),):
            return
        if module_file is None or not module_path:
            for key in tuple(sys.modules.keys()):
                if str(key) == "grosscode" or str(key).startswith("grosscode."):
                    del sys.modules[str(key)]
    __import__("grosscode")

