@dataclass(slots=True)
class FutureParityScorer:
    frontier: ProgressiveFrontierLayout
    target_syndrome_int: int
    mode: str = "cached"
    stats: FutureParityScorerStats = field(default_factory=FutureParityScorerStats)
    payload_cache: dict[int, FutureParityBoundaryPayload] = field(default_factory=dict)

    def __post_init__(self) -> None:
        self.mode = _normalize_future_parity_scorer(str(self.mode))

    def boundary_payload(self, *, boundary_column_index: int, active_mask: int) -> FutureParityBoundaryPayload:
        payload = self.payload_cache.get(int(boundary_column_index))
        if payload is None or int(payload.active_mask) != int(active_mask):
            payload = _build_future_parity_boundary_payload(
                frontier=self.frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            self.payload_cache[int(boundary_column_index)] = payload
            self.stats.payload_build_count += 1
        return payload

    def features_from_detector_mask(
        self,
        *,
        det_mask: int,
        active_mask: int,
        boundary_column_index: int,
    ) -> FrontierMismatchFeatures:
        started = time.perf_counter()
        if str(self.mode) == "cached":
            payload = self.boundary_payload(
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            features = _future_mismatch_features_from_payload(
                det_mask=int(det_mask),
                target_syndrome_int=int(self.target_syndrome_int),
                payload=payload,
            )
        else:
            features = _future_mismatch_features(
                det_mask=int(det_mask),
                active_mask=int(active_mask),
                target_syndrome_int=int(self.target_syndrome_int),
                column_index=int(boundary_column_index),
                frontier=self.frontier,
            )
            self.stats.from_scratch_score_calls += 1
        self.stats.fallback_score_calls += 1
        self.stats.score_calls += 1
        self.stats.scorer_time_s += float(time.perf_counter() - started)
        return features

    def score_from_detector_mask(
        self,
        *,
        det_mask: int,
        active_mask: int,
        boundary_column_index: int,
    ) -> float:
        return float(
            self.features_from_detector_mask(
                det_mask=int(det_mask),
                active_mask=int(active_mask),
                boundary_column_index=int(boundary_column_index),
            ).parity_logodds
        )

    def transition_features(
        self,
        *,
        parent_det_mask: int,
        detector_response_mask: int,
        parent_features: FrontierMismatchFeatures,
        row_updates: tuple[FrontierRowUpdate, ...],
    ) -> FrontierMismatchFeatures:
        started = time.perf_counter()
        features = _incremental_child_mismatch_features(
            parent_det_mask=int(parent_det_mask),
            detector_response_mask=int(detector_response_mask),
            target_syndrome_int=int(self.target_syndrome_int),
            parent_features=parent_features,
            row_updates=tuple(row_updates),
        )
        self.stats.incremental_update_count += 1
        self.stats.scorer_time_s += float(time.perf_counter() - started)
        return features


