class PrunedPrefixRescueFrontier:
    remaining_columns: int
    state_log_mass: dict[int, float]


def _trim_pruned_prefix_rescue_ttl_reservoir_topk(
    *,
    ttl_state_log_mass: dict[tuple[int, int], float],
    topk: int,
) -> dict[tuple[int, int], float]:
    if int(topk) <= 0 or len(ttl_state_log_mass) <= int(topk):
        return {
            (int(key), int(ttl)): float(log_mass)
            for (key, ttl), log_mass in ttl_state_log_mass.items()
        }
    kept_items = sorted(
        ttl_state_log_mass.items(),
        key=lambda item: (
            float(item[1]),
            int(item[0][1]),
            -int(item[0][0]),
        ),
        reverse=True,
    )[: int(topk)]
    return {
        (int(key), int(ttl)): float(log_mass)
        for (key, ttl), log_mass in kept_items
    }


