def summarize_progressive_beam_diagnostics(result: ProgressiveDecodeResult) -> ProgressiveBeamDiagnosticsSummary:
    posteriors = np.asarray(tuple(result.logical_posteriors), dtype=np.float64).reshape(-1)
    if str(result.status) != "ok" or posteriors.size == 0:
        top1 = float("nan")
        top2 = float("nan")
        posterior_gap = float("nan")
        log_posterior_gap = float("nan")
    else:
        sorted_values = np.sort(posteriors)
        top1 = float(sorted_values[-1])
        top2 = float(sorted_values[-2]) if sorted_values.size >= 2 else 0.0
        posterior_gap = float(top1 - top2)
        if float(top1) <= 0.0:
            log_posterior_gap = float("-inf")
        elif float(top2) <= 0.0:
            log_posterior_gap = float("inf")
        else:
            log_posterior_gap = float(math.log(float(top1)) - math.log(float(top2)))

    beam_size = result.beam_size
    candidate_counts = np.asarray(tuple(result.beam_candidate_state_count_by_column), dtype=np.float64).reshape(-1)
    prune_step_count = int(np.count_nonzero(candidate_counts > 0.0))
    overflow_step_count = 0
    max_candidate_to_beam_ratio = 0.0
    mean_candidate_to_beam_ratio = 0.0
    mean_overflow_candidate_to_beam_ratio = 0.0
    if beam_size is not None and int(beam_size) > 0 and candidate_counts.size > 0:
        valid_mask = candidate_counts > 0.0
        if np.any(valid_mask):
            ratios = candidate_counts[valid_mask] / float(int(beam_size))
            overflow_mask = ratios > 1.0
            prune_step_count = int(ratios.size)
            overflow_step_count = int(np.count_nonzero(overflow_mask))
            max_candidate_to_beam_ratio = float(np.max(ratios))
            mean_candidate_to_beam_ratio = float(np.mean(ratios))
            if np.any(overflow_mask):
                mean_overflow_candidate_to_beam_ratio = float(np.mean(ratios[overflow_mask]))

    discarded_prefix_mass = np.asarray(tuple(result.discarded_prefix_mass_by_column), dtype=np.float64).reshape(-1)
    discarded_prefix_fraction = np.asarray(
        tuple(result.discarded_prefix_mass_fraction_by_column), dtype=np.float64
    ).reshape(-1)
    truth_logical_discarded_prefix_mass = np.asarray(
        tuple(result.truth_logical_discarded_prefix_mass_by_column), dtype=np.float64
    ).reshape(-1)
    truth_logical_discarded_prefix_fraction = np.asarray(
        tuple(result.truth_logical_discarded_prefix_mass_fraction_by_column), dtype=np.float64
    ).reshape(-1)
    if candidate_counts.size > 0:
        prune_mask = candidate_counts > 0.0
    else:
        prune_mask = np.zeros(discarded_prefix_mass.shape, dtype=bool)
    finite_prune_mass_mask = prune_mask[: discarded_prefix_mass.size] & np.isfinite(discarded_prefix_mass)
    finite_prune_fraction_mask = prune_mask[: discarded_prefix_fraction.size] & np.isfinite(discarded_prefix_fraction)
    finite_truth_prune_mass_mask = (
        prune_mask[: truth_logical_discarded_prefix_mass.size] & np.isfinite(truth_logical_discarded_prefix_mass)
    )
    finite_truth_prune_fraction_mask = (
        prune_mask[: truth_logical_discarded_prefix_fraction.size]
        & np.isfinite(truth_logical_discarded_prefix_fraction)
    )
    discard_step_count = 0
    max_discarded_prefix_mass = 0.0
    mean_discarded_prefix_mass = 0.0
    max_discarded_prefix_fraction = 0.0
    mean_discarded_prefix_fraction = 0.0
    truth_logical_discard_step_count = 0
    max_truth_logical_discarded_prefix_mass = 0.0
    mean_truth_logical_discarded_prefix_mass = 0.0
    max_truth_logical_discarded_prefix_fraction = 0.0
    mean_truth_logical_discarded_prefix_fraction = 0.0
    if discarded_prefix_mass.size > 0 and np.any(finite_prune_mass_mask):
        discarded_on_prune = discarded_prefix_mass[finite_prune_mass_mask]
        discard_step_count = int(np.count_nonzero(discarded_on_prune > 0.0))
        max_discarded_prefix_mass = float(np.max(discarded_on_prune))
        mean_discarded_prefix_mass = float(np.mean(discarded_on_prune))
    if discarded_prefix_fraction.size > 0 and np.any(finite_prune_fraction_mask):
        discarded_fraction_on_prune = discarded_prefix_fraction[finite_prune_fraction_mask]
        max_discarded_prefix_fraction = float(np.max(discarded_fraction_on_prune))
        mean_discarded_prefix_fraction = float(np.mean(discarded_fraction_on_prune))
    if truth_logical_discarded_prefix_mass.size > 0 and np.any(finite_truth_prune_mass_mask):
        truth_discarded_on_prune = truth_logical_discarded_prefix_mass[finite_truth_prune_mass_mask]
        truth_logical_discard_step_count = int(np.count_nonzero(truth_discarded_on_prune > 0.0))
        max_truth_logical_discarded_prefix_mass = float(np.max(truth_discarded_on_prune))
        mean_truth_logical_discarded_prefix_mass = float(np.mean(truth_discarded_on_prune))
    if truth_logical_discarded_prefix_fraction.size > 0 and np.any(finite_truth_prune_fraction_mask):
        truth_discarded_fraction_on_prune = truth_logical_discarded_prefix_fraction[finite_truth_prune_fraction_mask]
        max_truth_logical_discarded_prefix_fraction = float(np.max(truth_discarded_fraction_on_prune))
        mean_truth_logical_discarded_prefix_fraction = float(np.mean(truth_discarded_fraction_on_prune))

    return ProgressiveBeamDiagnosticsSummary(
        top1_posterior=float(top1),
        top2_posterior=float(top2),
        posterior_gap=float(posterior_gap),
        log_posterior_gap=float(log_posterior_gap),
        prune_step_count=int(prune_step_count),
        overflow_step_count=int(overflow_step_count),
        max_candidate_to_beam_ratio=float(max_candidate_to_beam_ratio),
        mean_candidate_to_beam_ratio=float(mean_candidate_to_beam_ratio),
        mean_overflow_candidate_to_beam_ratio=float(mean_overflow_candidate_to_beam_ratio),
        discard_step_count=int(discard_step_count),
        max_discarded_prefix_mass=float(max_discarded_prefix_mass),
        mean_discarded_prefix_mass=float(mean_discarded_prefix_mass),
        max_discarded_prefix_fraction=float(max_discarded_prefix_fraction),
        mean_discarded_prefix_fraction=float(mean_discarded_prefix_fraction),
        truth_logical_discard_step_count=int(truth_logical_discard_step_count),
        max_truth_logical_discarded_prefix_mass=float(max_truth_logical_discarded_prefix_mass),
        mean_truth_logical_discarded_prefix_mass=float(mean_truth_logical_discarded_prefix_mass),
        max_truth_logical_discarded_prefix_fraction=float(max_truth_logical_discarded_prefix_fraction),
        mean_truth_logical_discarded_prefix_fraction=float(mean_truth_logical_discarded_prefix_fraction),
    )


def summarize_progressive_certificate(result: ProgressiveDecodeResult) -> ProgressiveCertificateSummary:
    diagnostics = summarize_progressive_beam_diagnostics(result)
    return ProgressiveCertificateSummary(
        winner_retained_mass=float(diagnostics.top1_posterior),
        runner_up_retained_mass=float(diagnostics.top2_posterior),
        retained_mass_gap=float(diagnostics.posterior_gap),
        log_retained_mass_gap=float(diagnostics.log_posterior_gap),
        cumulative_discarded_prefix_mass=float(result.cumulative_discarded_prefix_mass),
        cumulative_truth_logical_discarded_prefix_mass=float(result.cumulative_truth_logical_discarded_prefix_mass),
        max_discarded_prefix_fraction=float(diagnostics.max_discarded_prefix_fraction),
        mean_discarded_prefix_fraction=float(diagnostics.mean_discarded_prefix_fraction),
        max_truth_logical_discarded_prefix_fraction=float(
            diagnostics.max_truth_logical_discarded_prefix_fraction
        ),
        mean_truth_logical_discarded_prefix_fraction=float(
            diagnostics.mean_truth_logical_discarded_prefix_fraction
        ),
    )


def diagnose_progressive_truth_logical(
    *,
    result: ProgressiveDecodeResult,
    truth_logical_mask: int,
) -> ProgressiveTruthLogicalDiagnosis:
    summaries = tuple(result.terminal_logical_class_summaries)
    truth_mask = int(truth_logical_mask)
    summary_by_logical = {
        int(summary.logical_mask): summary
        for summary in summaries
    }
    truth_summary = summary_by_logical.get(int(truth_mask))
    mass_rank_by_logical = {
        int(summary.logical_mask): index + 1
        for index, summary in enumerate(
            sorted(summaries, key=lambda item: (-float(item.log_mass), int(item.logical_mask)))
        )
    }
    viterbi_rank_by_logical = {
        int(summary.logical_mask): index + 1
        for index, summary in enumerate(
            sorted(summaries, key=lambda item: (-float(item.best_viterbi), int(item.logical_mask)))
        )
    }
    status = str(result.status)
    if str(status) == "exception":
        failure_mode = "exception_fail"
    elif str(status) != "ok":
        failure_mode = "syndrome_fail"
    elif int(result.logical_hat) == int(truth_mask):
        failure_mode = "selected"
    elif truth_summary is None:
        failure_mode = "truth_missing_terminal"
    else:
        failure_mode = "truth_present_but_not_selected"
    return ProgressiveTruthLogicalDiagnosis(
        truth_logical_mask=int(truth_mask),
        failure_mode=str(failure_mode),
        truth_present_terminal=bool(truth_summary is not None),
        terminal_class_count=int(len(summaries)),
        truth_terminal_log_mass=(
            float(truth_summary.log_mass)
            if truth_summary is not None
            else float("nan")
        ),
        truth_terminal_best_viterbi=(
            float(truth_summary.best_viterbi)
            if truth_summary is not None
            else float("nan")
        ),
        truth_terminal_representative_cost=(
            float(truth_summary.representative_cost)
            if truth_summary is not None
            else float("nan")
        ),
        truth_terminal_log_mass_rank=(
            int(mass_rank_by_logical[int(truth_mask)])
            if truth_summary is not None
            else 0
        ),
        truth_terminal_best_viterbi_rank=(
            int(viterbi_rank_by_logical[int(truth_mask)])
            if truth_summary is not None
            else 0
        ),
    )


