def terminal_candidate_feature_rows(
    *,
    result: ProgressiveDecodeResult,
    truth_logical_mask: int | None = None,
    metadata: Mapping[str, object] | None = None,
) -> list[dict[str, object]]:
    """Return decoder-visible terminal-class features plus optional diagnostic labels."""

    summaries = tuple(result.terminal_logical_class_summaries)
    if not summaries:
        return []
    meta = dict(metadata or {})
    contributor_count_by_logical = {
        int(logical): int(count)
        for logical, count in tuple(result.terminal_contributor_count_by_logical_items)
    }
    state_entry_count_by_logical = {
        int(logical): len(tuple(entries))
        for logical, entries in tuple(result.terminal_state_log_mass_rep_cost_by_logical_items)
    }
    committee_members = tuple(getattr(result, "committee_members", tuple()))
    committee_member_count = int(len(committee_members))

    def _rank_map(
        ordered: Sequence[TerminalLogicalClassSummary],
    ) -> dict[int, int]:
        return {
            int(summary.logical_mask): int(index)
            for index, summary in enumerate(tuple(ordered), start=1)
        }

    log_mass_order = sorted(
        summaries,
        key=lambda item: (-float(item.log_mass), int(item.logical_mask)),
    )
    viterbi_order = sorted(
        summaries,
        key=lambda item: (-float(item.best_viterbi), int(item.logical_mask)),
    )
    rep_cost_order = sorted(
        summaries,
        key=lambda item: (float(item.representative_cost), -float(item.log_mass), int(item.logical_mask)),
    )
    top_log_mass = float(log_mass_order[0].log_mass)
    top_best_viterbi = float(viterbi_order[0].best_viterbi)
    min_rep_cost = float(rep_cost_order[0].representative_cost)
    log_evidence = float(result.log_evidence)
    linear_best_viterbi_weight = float(result.final_logical_select_linear_best_viterbi_weight)
    linear_rep_cost_weight = float(result.final_logical_select_linear_rep_cost_weight)
    linear_log_contributor_weight = float(result.final_logical_select_linear_log_contributor_weight)
    rank2_viterbi_tolerance = float(result.final_logical_select_rank2_viterbi_tolerance)

    def _contributor_count(logical: int) -> int:
        return max(1, int(contributor_count_by_logical.get(int(logical), 0)))

    def _linear_score(summary: TerminalLogicalClassSummary) -> float:
        contributor_count = int(_contributor_count(int(summary.logical_mask)))
        return float(
            float(summary.log_mass)
            + float(linear_best_viterbi_weight) * (float(summary.best_viterbi) - float(summary.log_mass))
            - float(linear_rep_cost_weight) * float(summary.representative_cost)
            + float(linear_log_contributor_weight) * math.log(float(max(1, int(contributor_count))))
        )

    linear_order = sorted(
        summaries,
        key=lambda item: (
            -float(_linear_score(item)),
            -float(item.log_mass),
            int(item.logical_mask),
        ),
    )
    mass_rank = _rank_map(log_mass_order)
    viterbi_rank = _rank_map(viterbi_order)
    rep_cost_rank = _rank_map(rep_cost_order)
    linear_rank = _rank_map(linear_order)

    rows: list[dict[str, object]] = []
    for summary in log_mass_order:
        logical = int(summary.logical_mask)
        class_log_posterior = (
            float(summary.log_mass) - float(log_evidence)
            if math.isfinite(float(log_evidence))
            else float("-inf")
        )
        class_posterior = (
            float(math.exp(float(class_log_posterior)))
            if math.isfinite(float(class_log_posterior))
            else 0.0
        )
        selected_member_count = sum(
            1
            for member in committee_members
            if int(getattr(member, "logical_hat", -1)) == int(logical)
        )
        forward_support = any(
            str(getattr(member, "direction", "")).strip().lower() == "forward"
            and int(getattr(member, "logical_hat", -1)) == int(logical)
            for member in committee_members
        )
        backward_support = any(
            str(getattr(member, "direction", "")).strip().lower() == "backward"
            and int(getattr(member, "logical_hat", -1)) == int(logical)
            for member in committee_members
        )
        row = {
            "scope": str(meta.get("scope", meta.get("side", ""))),
            "side": str(meta.get("side", meta.get("scope", ""))),
            "shot": meta.get("shot", ""),
            "order": str(meta.get("order", "")),
            "policy": str(meta.get("policy", "")),
            "score_mode": str(meta.get("score_mode", result.score_mode)),
            "final_logical_select_mode": str(result.final_logical_select_mode),
            "selected_logical": int(result.logical_hat),
            "truth_logical": "" if truth_logical_mask is None else int(truth_logical_mask),
            "terminal_logical": int(logical),
            "terminal_rank_by_log_mass": int(mass_rank[int(logical)]),
            "terminal_rank_by_best_viterbi": int(viterbi_rank[int(logical)]),
            "terminal_rank_by_representative_cost": int(rep_cost_rank[int(logical)]),
            "terminal_rank_by_linear_score": int(linear_rank[int(logical)]),
            "class_log_mass": float(summary.log_mass),
            "class_log_posterior": float(class_log_posterior),
            "class_posterior": float(class_posterior),
            "log_mass_gap_to_best": float(top_log_mass - float(summary.log_mass)),
            "best_viterbi": float(summary.best_viterbi),
            "best_viterbi_gap_to_best": float(top_best_viterbi - float(summary.best_viterbi)),
            "representative_cost": float(summary.representative_cost),
            "representative_cost_gap_to_best": float(float(summary.representative_cost) - float(min_rep_cost)),
            "terminal_contributor_count": int(_contributor_count(int(logical))),
            "terminal_state_entry_count": int(state_entry_count_by_logical.get(int(logical), 0)),
            "committee_selected_member_count": int(selected_member_count),
            "committee_forward_support": bool(forward_support),
            "committee_backward_support": bool(backward_support),
            "committee_member_count": int(committee_member_count),
            "linear_score": float(_linear_score(summary)),
            "linear_best_viterbi_weight": float(linear_best_viterbi_weight),
            "linear_rep_cost_weight": float(linear_rep_cost_weight),
            "linear_log_contributor_weight": float(linear_log_contributor_weight),
            "rank2_viterbi_tolerance": float(rank2_viterbi_tolerance),
            "terminal_class_count": int(len(summaries)),
            "terminal_top_log_mass_gap": float(result.terminal_top_log_mass_gap),
            "diagnostic_is_selected": bool(int(logical) == int(result.logical_hat)),
            "diagnostic_is_truth": (
                bool(int(logical) == int(truth_logical_mask))
                if truth_logical_mask is not None
                else False
            ),
        }
        rows.append({name: row.get(name, "") for name in TERMINAL_CANDIDATE_FEATURE_COLUMNS})
    return rows


def annotate_progressive_result_with_truth_logical_diagnosis(
    *,
    result: ProgressiveDecodeResult,
    truth_logical_mask: int,
) -> ProgressiveDecodeResult:
    return replace(
        result,
        truth_logical_diagnosis=diagnose_progressive_truth_logical(
            result=result,
            truth_logical_mask=int(truth_logical_mask),
        ),
    )


def _summarize_shadow_rank_steps(
    steps: dict[str, list[ProgressiveShadowRankStep]],
) -> tuple[ProgressiveShadowRankSummary, ...]:
    out: list[ProgressiveShadowRankSummary] = []
    for compared_score_mode in sorted(steps):
        mode_steps = steps[str(compared_score_mode)]
        if not mode_steps:
            continue
        out.append(
            ProgressiveShadowRankSummary(
                compared_score_mode=str(compared_score_mode),
                compared_step_count=int(len(mode_steps)),
                disagreement_step_count=int(sum(1 for step in mode_steps if bool(step.disagreement))),
                winner_disagreement_step_count=int(sum(1 for step in mode_steps if bool(step.winner_disagreement))),
                max_symmetric_difference_count=int(
                    max(int(step.symmetric_difference_count) for step in mode_steps)
                ),
            )
        )
    return tuple(out)


def should_trigger_progressive_selective_fallback(
    *,
    result: ProgressiveDecodeResult,
    diagnostics: ProgressiveBeamDiagnosticsSummary,
    min_log_posterior_gap: float = 0.0,
    min_overflow_step_count: int = 0,
    min_max_candidate_to_beam_ratio: float = 0.0,
    min_mean_candidate_to_beam_ratio: float = 0.0,
    trigger_mode: str = "either",
) -> tuple[bool, str]:
    trigger_mode_key = str(trigger_mode).strip().lower()
    allowed_trigger_modes = {"log_gap", "overflow", "either"}
    if trigger_mode_key not in allowed_trigger_modes:
        raise ValueError(f"trigger_mode must be one of {sorted(allowed_trigger_modes)}")

    if str(result.status) != "ok":
        return True, f"status_{str(result.status)}"

    gap_trigger = False
    overflow_trigger = False
    reasons: list[str] = []

    if float(min_log_posterior_gap) > 0.0:
        gap_value = float(diagnostics.log_posterior_gap)
        if math.isnan(float(gap_value)) or float(gap_value) < float(min_log_posterior_gap):
            gap_trigger = True
            reasons.append("low_log_gap")

    overflow_count_threshold = max(0, int(min_overflow_step_count))
    if int(overflow_count_threshold) > 0 and int(diagnostics.overflow_step_count) >= int(overflow_count_threshold):
        overflow_trigger = True
        reasons.append("high_overflow_count")
    if float(min_max_candidate_to_beam_ratio) > 0.0 and float(diagnostics.max_candidate_to_beam_ratio) >= float(
        min_max_candidate_to_beam_ratio
    ):
        overflow_trigger = True
        reasons.append("high_overflow_ratio")
    if float(min_mean_candidate_to_beam_ratio) > 0.0 and float(diagnostics.mean_candidate_to_beam_ratio) >= float(
        min_mean_candidate_to_beam_ratio
    ):
        overflow_trigger = True
        reasons.append("high_mean_overflow_ratio")

    if trigger_mode_key == "log_gap":
        triggered = bool(gap_trigger)
    elif trigger_mode_key == "overflow":
        triggered = bool(overflow_trigger)
    else:
        triggered = bool(gap_trigger or overflow_trigger)

    if not bool(triggered):
        return False, "confident"
    if reasons:
        return True, "+".join(dict.fromkeys(str(reason) for reason in reasons))
    return True, str(trigger_mode_key)


