def _pairlogodds_width_adaptive_weights_for_beam_size(beam_size: int | None) -> tuple[float, float]:
    if beam_size is None or int(beam_size) <= 0:
        return (1.0, 0.0)
    if int(beam_size) <= 8:
        return (0.75, 0.25)
    if int(beam_size) <= 64:
        return (0.85, 0.15)
    return (1.0, 0.0)


def _normalize_pairlogodds_pair_selection(pair_selection: str | None) -> str:
    normalized = str(pair_selection or PAIRLOGODDS_PAIR_SELECTION_DEFAULT).strip().lower()
    return str(PAIRLOGODDS_PAIR_SELECTION_ALIASES.get(normalized, normalized))


def _pairlogodds_base_pair_selection(pair_selection: str) -> str:
    key = _normalize_pairlogodds_pair_selection(str(pair_selection))
    if str(key).endswith("_2opt"):
        return str(key[: -len("_2opt")])
    return str(key)


def _pairlogodds_uses_2opt(pair_selection: str) -> bool:
    return _normalize_pairlogodds_pair_selection(str(pair_selection)).endswith("_2opt")


PAIRLOGODDS_ATLAS_CSV_ENV = "FRONTIERK_PAIRLOGODDS_ATLAS_CSV"
PAIRLOGODDS_ATLAS_BOUNDARY_MODE_ENV = "FRONTIERK_PAIRLOGODDS_ATLAS_BOUNDARY_MODE"
PAIRLOGODDS_ATLAS_SCOPE_ENV = "FRONTIERK_PAIRLOGODDS_ATLAS_SCOPE"
PAIRLOGODDS_ATLAS_DIRECTION_ENV = "FRONTIERK_PAIRLOGODDS_ATLAS_DIRECTION"


def _pairlogodds_normalized_pair(row_i: int, row_j: int) -> tuple[int, int]:
    left = int(row_i)
    right = int(row_j)
    if int(left) <= int(right):
        return (int(left), int(right))
    return (int(right), int(left))


def _append_unique_pair(
    target: dict[tuple[str, str, int] | tuple[str, str], list[tuple[int, int]]],
    key: tuple[str, str, int] | tuple[str, str],
    pair: tuple[int, int],
) -> None:
    values = target.setdefault(key, [])
    if tuple(pair) not in values:
        values.append(tuple(pair))


@lru_cache(maxsize=16)
def _load_pairlogodds_atlas_table(path: str) -> FuturePairlogoddsAtlasTable:
    atlas_path = Path(str(path)).expanduser()
    if not atlas_path.exists():
        raise FileNotFoundError(f"pairlogodds atlas CSV does not exist: {atlas_path}")

    boundary_bin_size = 32
    metadata_path = atlas_path.parent / "metadata.json"
    if metadata_path.exists():
        try:
            metadata = json.loads(metadata_path.read_text(encoding="utf-8"))
            boundary_bin_size = max(1, int(metadata.get("boundary_bin_size", boundary_bin_size)))
        except Exception:
            boundary_bin_size = 32

    by_exact: dict[tuple[str, str, int], list[tuple[int, int]]] = {}
    by_bin: dict[tuple[str, str, int], list[tuple[int, int]]] = {}
    by_scope_direction: dict[tuple[str, str], list[tuple[int, int]]] = {}
    with atlas_path.open("r", newline="", encoding="utf-8") as handle:
        reader = csv.DictReader(handle)
        required = {"row_i", "row_j"}
        if not required.issubset(set(reader.fieldnames or ())):
            raise ValueError(f"pairlogodds atlas CSV is missing required columns {sorted(required)}: {atlas_path}")
        for row in reader:
            try:
                pair = _pairlogodds_normalized_pair(int(row["row_i"]), int(row["row_j"]))
            except Exception:
                continue
            scope = str(row.get("scope", "")).strip()
            direction = str(row.get("direction", "")).strip()
            try:
                boundary_index = int(row.get("boundary_index", -1))
            except Exception:
                boundary_index = -1
            try:
                boundary_bin = int(row.get("boundary_bin", int(boundary_index) // max(1, int(boundary_bin_size))))
            except Exception:
                boundary_bin = int(boundary_index) // max(1, int(boundary_bin_size)) if int(boundary_index) >= 0 else -1
            _append_unique_pair(by_scope_direction, (str(scope), str(direction)), tuple(pair))
            if int(boundary_index) >= 0:
                _append_unique_pair(by_exact, (str(scope), str(direction), int(boundary_index)), tuple(pair))
            if int(boundary_bin) >= 0:
                _append_unique_pair(by_bin, (str(scope), str(direction), int(boundary_bin)), tuple(pair))

    return FuturePairlogoddsAtlasTable(
        path=str(atlas_path),
        boundary_bin_size=int(boundary_bin_size),
        pairs_by_exact_boundary={key: tuple(values) for key, values in by_exact.items()},
        pairs_by_boundary_bin={key: tuple(values) for key, values in by_bin.items()},
        pairs_by_scope_direction={key: tuple(values) for key, values in by_scope_direction.items()},
    )


def _pairlogodds_atlas_scope_for_columns(columns: Sequence[ProgressiveColumn]) -> str:
    override = str(os.environ.get(PAIRLOGODDS_ATLAS_SCOPE_ENV, "")).strip()
    if override:
        return str(override)
    if not columns:
        return ""
    family = str(getattr(columns[0], "family", "")).lower()
    if family.endswith("_x") or "_x_" in family or "memory_x" in family:
        return "memory_X"
    if family.endswith("_z") or "_z_" in family or "memory_z" in family:
        return "memory_Z"
    return ""


def _pairlogodds_atlas_direction_for_columns(columns: Sequence[ProgressiveColumn]) -> str:
    override = str(os.environ.get(PAIRLOGODDS_ATLAS_DIRECTION_ENV, "")).strip()
    if override:
        return str(override)
    if len(columns) < 2:
        return "decode"
    sample_width = min(16, max(1, len(columns) // 4))
    first_offsets = [int(getattr(column, "instruction_offset", int(index))) for index, column in enumerate(columns[:sample_width])]
    last_offsets = [
        int(getattr(column, "instruction_offset", len(columns) - sample_width + int(index)))
        for index, column in enumerate(columns[-sample_width:])
    ]
    first_mean = sum(int(value) for value in first_offsets) / float(len(first_offsets))
    last_mean = sum(int(value) for value in last_offsets) / float(len(last_offsets))
    return "backward" if float(first_mean) > float(last_mean) else "decode"


def _pairlogodds_atlas_lookup_keys(scope: str, direction: str) -> tuple[tuple[str, str], ...]:
    return (
        (str(scope), str(direction)),
        (str(scope), ""),
        ("", str(direction)),
        ("", ""),
    )


def _pairlogodds_atlas_path_from_env() -> str:
    path = str(os.environ.get(PAIRLOGODDS_ATLAS_CSV_ENV, "")).strip()
    if not path:
        raise RuntimeError(
            f"pair_selection='atlas' requires {PAIRLOGODDS_ATLAS_CSV_ENV} to point to row_correlation_atlas.csv"
        )
    return str(path)


def _pairlogodds_atlas_pair_union_for_columns(columns: Sequence[ProgressiveColumn]) -> frozenset[tuple[int, int]]:
    table = _load_pairlogodds_atlas_table(_pairlogodds_atlas_path_from_env())
    scope = _pairlogodds_atlas_scope_for_columns(columns)
    direction = _pairlogodds_atlas_direction_for_columns(columns)
    pairs: list[tuple[int, int]] = []
    seen: set[tuple[int, int]] = set()
    for key in _pairlogodds_atlas_lookup_keys(str(scope), str(direction)):
        for pair in tuple(table.pairs_by_scope_direction.get(tuple(key), tuple())):
            if tuple(pair) in seen:
                continue
            seen.add(tuple(pair))
            pairs.append(tuple(pair))
    return frozenset(tuple(pair) for pair in pairs)


def _pairlogodds_atlas_pairs_for_boundary(
    *,
    columns: Sequence[ProgressiveColumn],
    boundary_column_index: int,
) -> tuple[tuple[int, int], ...]:
    table = _load_pairlogodds_atlas_table(_pairlogodds_atlas_path_from_env())
    scope = _pairlogodds_atlas_scope_for_columns(columns)
    direction = _pairlogodds_atlas_direction_for_columns(columns)
    mode = str(os.environ.get(PAIRLOGODDS_ATLAS_BOUNDARY_MODE_ENV, "bin")).strip().lower()
    boundary_index = int(boundary_column_index)
    boundary_bin = int(boundary_index) // max(1, int(table.boundary_bin_size))
    out: list[tuple[int, int]] = []
    seen: set[tuple[int, int]] = set()
    for scope_direction in _pairlogodds_atlas_lookup_keys(str(scope), str(direction)):
        exact_key = (str(scope_direction[0]), str(scope_direction[1]), int(boundary_index))
        bin_key = (str(scope_direction[0]), str(scope_direction[1]), int(boundary_bin))
        sources: tuple[tuple[tuple[int, int], ...], ...]
        if mode == "exact":
            sources = (tuple(table.pairs_by_exact_boundary.get(exact_key, tuple())),)
        elif mode == "exact_or_bin":
            exact_pairs = tuple(table.pairs_by_exact_boundary.get(exact_key, tuple()))
            sources = (exact_pairs,) if exact_pairs else (tuple(table.pairs_by_boundary_bin.get(bin_key, tuple())),)
        else:
            sources = (tuple(table.pairs_by_boundary_bin.get(bin_key, tuple())),)
        for source_pairs in sources:
            for pair in source_pairs:
                if tuple(pair) in seen:
                    continue
                seen.add(tuple(pair))
                out.append(tuple(pair))
    return tuple(out)


NO_PREFIX_SCORE_MODE_PREFIX = "no_prefix_"


@lru_cache(maxsize=4096)
def _no_prefix_inner_score_mode(score_mode_key: str) -> str | None:
    normalized = str(score_mode_key).strip().lower()
    prefix = str(NO_PREFIX_SCORE_MODE_PREFIX)
    if not normalized.startswith(prefix):
        return None
    inner = str(normalized[len(prefix):]).strip()
    if not inner or inner == "prefix" or inner.startswith(prefix):
        return None
    return str(inner)


@lru_cache(maxsize=4096)
def _score_mode_uses_future_parity_features(score_mode_key: str) -> bool:
    normalized = str(score_mode_key).strip().lower()
    no_prefix_inner = _no_prefix_inner_score_mode(str(normalized))
    if no_prefix_inner is not None:
        return _score_mode_uses_future_parity_features(str(no_prefix_inner))
    pairlogodds_weights = _pairlogodds_weights_from_score_mode(normalized)
    pair_frustration_config = _future_pair_frustration_config_from_score_mode(normalized)
    exact_singleton_alpha = _mixed_factor_exact_singleton_alpha_from_score_mode(normalized)
    return normalized in {
        "future_touch_count",
        "future_parity_logmass",
        "future_parity_logmass_only",
        "future_parity_logodds_only",
        "future_parity_logodds",
        "deadline_weighted_future_parity_tau16",
        "z_deadline_weighted_future_parity_tau16",
        STAGE1_RELIABILITY_SCORE_MODE,
        "future_parity_quotient_probe",
        "future_parity_logodds_singlefix_bonus",
        "future_parity_logodds_singlefix_best",
        "future_parity_logodds_singlefix_bonus_with_spill_penalty",
        "future_parity_logodds_local_cone_delta0",
        "forward_cut_state_lookahead",
        "forward_terminal_lookahead",
        "future_parity_lookahead",
        "future_parity_overflow_lookahead",
        "future_parity_adaptive_lookahead",
        "future_parity_logical_lookahead",
        "future_parity_logical_adaptive_lookahead",
        "residual_lex",
        "future_urgency_lex",
    } or _is_learned_linear_score_mode(normalized) or (
        _score_mode_is_forward_cut_state_lookahead_family(normalized)
        or _future_parity_logodds_alpha_from_score_mode(normalized) is not None
        or _future_parity_logodds_prefix_beta_from_score_mode(normalized) is not None
        or _future_parity_logodds_prefix_taper_config_from_score_mode(normalized) is not None
        or _future_parity_logodds_logsupport_config_from_score_mode(normalized) is not None
        or _future_parity_logodds_compact_feature_config_from_score_mode(normalized) is not None
        or pair_frustration_config is not None
        or exact_singleton_alpha is not None
        or _mixed_factor_pairlogodds_plus_closing_config_from_score_mode(normalized) is not None
        or _future_parity_deadline_logodds_config_from_score_mode(normalized) is not None
        or _mixed_pairlogodds_support_gate_config_from_score_mode(normalized) is not None
        or _mixed_closing_logmass_config_from_score_mode(normalized) is not None
        or (
            pairlogodds_weights is not None
            and float(pairlogodds_weights[1]) == 0.0
        )
    )


@lru_cache(maxsize=4096)
def _score_mode_is_no_prefix_survivor_lane(score_mode_key: str) -> bool:
    normalized = str(score_mode_key).strip().lower()
    no_prefix_inner = _no_prefix_inner_score_mode(str(normalized))
    if no_prefix_inner is not None:
        return _score_mode_supports_boundary_secondary_rerank(str(no_prefix_inner))
    return normalized in {
        "future_parity_logmass_only",
        "future_parity_logodds_only",
        "deadline_weighted_future_parity_tau16",
        "z_deadline_weighted_future_parity_tau16",
    }


@lru_cache(maxsize=4096)
def _score_mode_uses_prefix_nonzero_steps(score_mode_key: str) -> bool:
    return str(score_mode_key) in {
        "future_repair_steps_lex",
    }


@lru_cache(maxsize=4096)
def _low_error_event_cap_from_score_mode(score_mode_key: str) -> int | None:
    normalized = str(score_mode_key).strip().lower()
    if normalized == LOW_ERROR_LOGMASS_SCORE_MODE_PREFIX:
        return int(DEFAULT_LOW_ERROR_EVENT_CAP)
    prefix = f"{LOW_ERROR_LOGMASS_SCORE_MODE_PREFIX}_e"
    if not normalized.startswith(prefix):
        return None
    suffix = str(normalized[len(prefix):]).strip()
    if not suffix or not suffix.isdigit():
        return None
    return int(suffix)


@lru_cache(maxsize=4096)
def _active_frontierk_beam_from_score_mode(score_mode_key: str) -> int | None:
    normalized = str(score_mode_key).strip().lower()
    if normalized == ACTIVE_FRONTIERK_SCORE_MODE_PREFIX:
        return int(DEFAULT_ACTIVE_FRONTIERK_BEAM)
    prefix = f"{ACTIVE_FRONTIERK_SCORE_MODE_PREFIX}_k"
    if not normalized.startswith(prefix):
        return None
    suffix = str(normalized[len(prefix):]).strip()
    if not suffix or not suffix.isdigit():
        return None
    beam_size = int(suffix)
    return int(beam_size) if int(beam_size) > 0 else None


@lru_cache(maxsize=4096)
def _parse_pairlogodds_weight_token(token: str) -> float | None:
    normalized = str(token).strip().lower()
    if not normalized:
        return None
    if "p" in normalized and "." not in normalized:
        normalized = normalized.replace("p", ".")
    if normalized.startswith("m") and "-" not in normalized:
        normalized = "-" + normalized[1:]
    try:
        value = float(normalized)
    except ValueError:
        return None
    if not math.isfinite(float(value)) or float(value) < 0.0:
        return None
    return float(value)


_LEARNED_LINEAR_SCHEMA_VERSIONS = frozenset(
    {
        "frontierk_future_parity_learned_linear_v1",
        "frontierk_learned_linear_score_v1",
    }
)
_LEARNED_LINEAR_BASE_FEATURES = frozenset(
    {
        "bias",
        "intercept",
        "parity_logodds",
        "future_parity_logodds",
        "future_parity_logodds_a0p8",
        "future_total_logodds",
        "horizon_logodds_inf",
        "mismatch_count",
        "mismatch_fraction",
        "touch_bonus",
        "urgency_penalty",
        "negative_urgency_penalty",
        "active_row_count",
        "active_fraction",
        "closing_row_count",
        "touched_row_count",
        "closure_block_touched_row_count",
        "boundary_column_index",
        "processed_fraction",
        "remaining_columns",
        "remaining_fraction",
    }
)


def _is_learned_linear_score_mode(score_mode_key: str) -> bool:
    return str(score_mode_key).strip().lower() in LEARNED_LINEAR_SCORE_MODES


def _learned_linear_feature_is_allowed(feature_name: str) -> bool:
    name = str(feature_name).strip().lower()
    if name in _LEARNED_LINEAR_BASE_FEATURES:
        return True
    if _future_parity_logodds_alpha_from_score_mode(str(name)) is not None:
        return True
    if name.startswith("horizon_logodds_h"):
        suffix = str(name[len("horizon_logodds_h"):]).strip()
        return bool(suffix.isdigit() and int(suffix) >= 0)
    if name.startswith("deadline_boost_tau"):
        token = str(name[len("deadline_boost_tau"):]).strip()
        value = _parse_pairlogodds_weight_token(token)
        return bool(value is not None and float(value) > 0.0)
    return False


def validate_future_parity_learned_linear_config(
    config: FutureParityLearnedLinearConfig,
) -> FutureParityLearnedLinearConfig:
    schema_version = str(config.schema_version).strip()
    if schema_version not in _LEARNED_LINEAR_SCHEMA_VERSIONS:
        raise ValueError(
            "learned score config schema_version must be one of "
            f"{sorted(_LEARNED_LINEAR_SCHEMA_VERSIONS)}"
        )
    score_mode = str(config.score_mode).strip().lower()
    if score_mode not in LEARNED_LINEAR_SCORE_MODES:
        raise ValueError(f"learned score config score_mode must be one of {sorted(LEARNED_LINEAR_SCORE_MODES)}")
    intercept = float(config.intercept)
    if math.isnan(intercept) or not math.isfinite(intercept):
        raise ValueError("learned score config intercept must be finite")
    score_clip = float(config.score_clip)
    if math.isnan(score_clip) or float(score_clip) <= 0.0:
        raise ValueError("learned score config score_clip must be positive or inf")
    coefficients: list[tuple[str, float]] = []
    seen: set[str] = set()
    for raw_name, raw_value in tuple(config.coefficients):
        name = str(raw_name).strip().lower()
        if not name:
            raise ValueError("learned score coefficient feature names must not be empty")
        if name in {"bias", "intercept"}:
            raise ValueError("use top-level intercept instead of a bias/intercept coefficient")
        if name in seen:
            raise ValueError(f"duplicate learned score coefficient feature {name!r}")
        if not _learned_linear_feature_is_allowed(str(name)):
            raise ValueError(f"unsupported learned score feature {name!r}")
        value = float(raw_value)
        if math.isnan(value) or not math.isfinite(value):
            raise ValueError(f"learned score coefficient for {name!r} must be finite")
        seen.add(str(name))
        coefficients.append((str(name), float(value)))
    if not coefficients:
        raise ValueError("learned score config must contain at least one nonzero coefficient")
    return FutureParityLearnedLinearConfig(
        schema_version=str(schema_version),
        score_mode=str(score_mode),
        intercept=float(intercept),
        coefficients=tuple(coefficients),
        score_clip=float(score_clip),
        description=str(config.description),
        source=str(config.source),
    )


def load_future_parity_learned_linear_config(path: Path | str) -> FutureParityLearnedLinearConfig:
    config_path = Path(path)
    with config_path.open(encoding="utf-8") as handle:
        raw = json.load(handle)
    if not isinstance(raw, dict):
        raise ValueError("learned score coefficient JSON must be an object")
    schema_version = str(raw.get("schema_version", "")).strip()
    score_mode = str(raw.get("score_mode", "future_parity_learned_linear_v1")).strip().lower()
    intercept = float(raw.get("intercept", 0.0))
    score_clip_raw = raw.get("score_clip", raw.get("clip", float("inf")))
    score_clip = float("inf") if score_clip_raw is None else float(score_clip_raw)
    raw_coefficients = raw.get("coefficients")
    coefficient_items: list[tuple[str, float]] = []
    if isinstance(raw_coefficients, dict):
        coefficient_items = [(str(key), float(value)) for key, value in raw_coefficients.items()]
    else:
        feature_names = raw.get("feature_names")
        coefficients = raw.get("coefficient_values", raw.get("coef", raw.get("coefficients")))
        if not isinstance(feature_names, list) or not isinstance(coefficients, list):
            raise ValueError(
                "learned score JSON must contain either object field `coefficients` "
                "or parallel `feature_names` and `coefficient_values` arrays"
            )
        if len(feature_names) != len(coefficients):
            raise ValueError("learned score feature_names and coefficient_values lengths differ")
        coefficient_items = [(str(name), float(value)) for name, value in zip(feature_names, coefficients)]
    return validate_future_parity_learned_linear_config(
        FutureParityLearnedLinearConfig(
            schema_version=str(schema_version),
            score_mode=str(score_mode),
            intercept=float(intercept),
            coefficients=tuple(coefficient_items),
            score_clip=float(score_clip),
            description=str(raw.get("description", "")),
            source=str(raw.get("source", "")),
        )
    )


def future_parity_learned_linear_config_digest(config: FutureParityLearnedLinearConfig) -> str:
    payload = {
        "schema_version": str(config.schema_version),
        "score_mode": str(config.score_mode),
        "intercept": float(config.intercept),
        "coefficients": [[str(name), float(value)] for name, value in tuple(config.coefficients)],
        "score_clip": float(config.score_clip),
    }
    return hashlib.sha256(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()


def _normalize_nearcut_mode(raw: str | None) -> str:
    text = str(raw or "disabled").strip().lower()
    if text in {"", "none", "false", "0", "off", "disabled"}:
        return "disabled"
    if text in {"shadow", NEARCUT_SHADOW_SCORE_MODE}:
        return "shadow"
    if text in {"union", "guarded", "guarded_union", NEARCUT_UNION_SCORE_MODE}:
        return "guarded_union"
    raise ValueError(f"nearcut_mode must be one of {NEARCUT_RUNTIME_MODES}")


def _nearcut_feature_has_leakage(name: str) -> bool:
    lowered = str(name).strip().lower()
    return any(str(token) in lowered for token in NEARCUT_LEAKAGE_FEATURE_SUBSTRINGS)


def _nearcut_feature_is_allowed(name: str) -> bool:
    lowered = str(name).strip().lower()
    return bool(lowered in NEARCUT_ALLOWED_FEATURES and not _nearcut_feature_has_leakage(str(lowered)))


def _validate_nearcut_policy(policy: NearCutPolicy) -> NearCutPolicy:
    candidate_gap = float(policy.candidate_gap)
    candidate_positive_slack = float(policy.candidate_positive_slack)
    prefix_gap_from_best = float(policy.prefix_gap_from_best)
    if math.isnan(candidate_gap) or not math.isfinite(candidate_gap) or candidate_gap < 0.0:
        raise ValueError("nearcut candidate_gap must be finite and >= 0")
    if math.isnan(candidate_positive_slack) or not math.isfinite(candidate_positive_slack) or candidate_positive_slack < 0.0:
        raise ValueError("nearcut candidate_positive_slack must be finite and >= 0")
    if math.isnan(prefix_gap_from_best) or not math.isfinite(prefix_gap_from_best) or prefix_gap_from_best < 0.0:
        raise ValueError("nearcut prefix_gap_from_best must be finite and >= 0")
    min_learned_score = None if policy.min_learned_score is None else float(policy.min_learned_score)
    if min_learned_score is not None and (math.isnan(min_learned_score) or not math.isfinite(min_learned_score)):
        raise ValueError("nearcut min_learned_score must be finite when provided")
    if int(policy.max_extra_states) < 0:
        raise ValueError("nearcut max_extra_states must be >= 0")
    if int(policy.max_extra_states_per_boundary) < 0:
        raise ValueError("nearcut max_extra_states_per_boundary must be >= 0")
    return NearCutPolicy(
        candidate_gap=float(candidate_gap),
        candidate_positive_slack=float(candidate_positive_slack),
        max_extra_states=int(policy.max_extra_states),
        max_extra_states_per_boundary=int(policy.max_extra_states_per_boundary),
        prefix_gap_from_best=float(prefix_gap_from_best),
        min_learned_score=min_learned_score,
        protect_baseline_retained_set=bool(policy.protect_baseline_retained_set),
        admit_only_pruned_nearcut_states=bool(policy.admit_only_pruned_nearcut_states),
    )


def _nearcut_policy_from_mapping(raw: Mapping[str, object] | None) -> NearCutPolicy:
    payload = dict(raw or {})
    return _validate_nearcut_policy(
        NearCutPolicy(
            candidate_gap=float(payload.get("candidate_gap", payload.get("nearcut_gap", 2.0))),
            candidate_positive_slack=float(payload.get("candidate_positive_slack", 0.0)),
            max_extra_states=int(payload.get("max_extra_states", 1)),
            max_extra_states_per_boundary=int(payload.get("max_extra_states_per_boundary", 1)),
            prefix_gap_from_best=float(payload.get("prefix_gap_from_best", 10.0)),
            min_learned_score=(
                None
                if payload.get("min_learned_score", None) is None
                else float(payload.get("min_learned_score"))
            ),
            protect_baseline_retained_set=bool(payload.get("protect_baseline_retained_set", True)),
            admit_only_pruned_nearcut_states=bool(payload.get("admit_only_pruned_nearcut_states", True)),
        )
    )


def validate_nearcut_linear_model(model: NearCutLinearModel) -> NearCutLinearModel:
    if int(model.schema_version) != 1:
        raise ValueError("nearcut model schema_version must be 1")
    model_type = str(model.model_type).strip()
    if model_type != "nearcut_linear_logistic":
        raise ValueError("nearcut model_type must be 'nearcut_linear_logistic'")
    score_mode = str(model.score_mode).strip().lower()
    if score_mode != NEARCUT_MODEL_SCORE_MODE:
        raise ValueError(f"nearcut score_mode must be {NEARCUT_MODEL_SCORE_MODE!r}")
    intercept = float(model.intercept)
    if math.isnan(intercept) or not math.isfinite(intercept):
        raise ValueError("nearcut intercept must be finite")
    normalization_mode = str(model.normalization_mode).strip().lower()
    if normalization_mode not in {"runtime_boundary"}:
        raise ValueError("nearcut normalization mode must be 'runtime_boundary'")
    normalization_epsilon = float(model.normalization_epsilon)
    if math.isnan(normalization_epsilon) or not math.isfinite(normalization_epsilon) or normalization_epsilon <= 0.0:
        raise ValueError("nearcut normalization epsilon must be finite and > 0")
    seen: set[str] = set()
    coefficients_by_name = {str(name).strip().lower(): float(value) for name, value in tuple(model.coefficients)}
    feature_names: list[str] = []
    coefficients: list[tuple[str, float]] = []
    for raw_name in tuple(model.feature_names):
        name = str(raw_name).strip().lower()
        if not name:
            raise ValueError("nearcut feature names must not be empty")
        if name in seen:
            raise ValueError(f"duplicate nearcut feature {name!r}")
        if not _nearcut_feature_is_allowed(str(name)):
            raise ValueError(f"unsupported or leakage-prone nearcut feature {name!r}")
        if name not in coefficients_by_name:
            raise ValueError(f"nearcut coefficient missing for feature {name!r}")
        value = float(coefficients_by_name[str(name)])
        if math.isnan(value) or not math.isfinite(value):
            raise ValueError(f"nearcut coefficient for {name!r} must be finite")
        seen.add(str(name))
        feature_names.append(str(name))
        coefficients.append((str(name), float(value)))
    for name in coefficients_by_name:
        if name not in seen:
            raise ValueError(f"nearcut coefficient has unknown feature {name!r}")
    if not feature_names:
        raise ValueError("nearcut model must contain at least one runtime feature")
    policy = _validate_nearcut_policy(model.policy)
    validated = NearCutLinearModel(
        schema_version=1,
        model_type=str(model_type),
        score_mode=str(score_mode),
        created_utc=str(model.created_utc),
        feature_names=tuple(feature_names),
        intercept=float(intercept),
        coefficients=tuple(coefficients),
        normalization_mode=str(normalization_mode),
        normalization_epsilon=float(normalization_epsilon),
        policy=policy,
        training_summary=dict(model.training_summary),
        source_path=str(model.source_path),
        raw_sha256=str(model.raw_sha256),
        canonical_sha256="",
    )
    return replace(validated, canonical_sha256=nearcut_linear_model_digest(validated))


def nearcut_linear_model_digest(model: NearCutLinearModel) -> str:
    payload = {
        "schema_version": int(model.schema_version),
        "model_type": str(model.model_type),
        "score_mode": str(model.score_mode),
        "feature_names": [str(name) for name in tuple(model.feature_names)],
        "intercept": float(model.intercept),
        "coefficients": {str(name): float(value) for name, value in tuple(model.coefficients)},
        "normalization": {
            "mode": str(model.normalization_mode),
            "epsilon": float(model.normalization_epsilon),
        },
        "nearcut_policy": {
            "candidate_gap": float(model.policy.candidate_gap),
            "candidate_positive_slack": float(model.policy.candidate_positive_slack),
            "max_extra_states": int(model.policy.max_extra_states),
            "max_extra_states_per_boundary": int(model.policy.max_extra_states_per_boundary),
            "prefix_gap_from_best": float(model.policy.prefix_gap_from_best),
            "min_learned_score": model.policy.min_learned_score,
            "protect_baseline_retained_set": bool(model.policy.protect_baseline_retained_set),
            "admit_only_pruned_nearcut_states": bool(model.policy.admit_only_pruned_nearcut_states),
        },
    }
    return hashlib.sha256(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()


def nearcut_model_json_payload(model: NearCutLinearModel) -> dict[str, object]:
    return {
        "schema_version": int(model.schema_version),
        "model_type": str(model.model_type),
        "score_mode": str(model.score_mode),
        "created_utc": str(model.created_utc),
        "feature_names": [str(name) for name in tuple(model.feature_names)],
        "intercept": float(model.intercept),
        "coefficients": {str(name): float(value) for name, value in tuple(model.coefficients)},
        "normalization": {
            "mode": str(model.normalization_mode),
            "epsilon": float(model.normalization_epsilon),
        },
        "nearcut_policy": {
            "candidate_gap": float(model.policy.candidate_gap),
            "candidate_positive_slack": float(model.policy.candidate_positive_slack),
            "max_extra_states": int(model.policy.max_extra_states),
            "max_extra_states_per_boundary": int(model.policy.max_extra_states_per_boundary),
            "prefix_gap_from_best": float(model.policy.prefix_gap_from_best),
            "min_learned_score": model.policy.min_learned_score,
            "protect_baseline_retained_set": bool(model.policy.protect_baseline_retained_set),
            "admit_only_pruned_nearcut_states": bool(model.policy.admit_only_pruned_nearcut_states),
        },
        "training_summary": dict(model.training_summary),
    }


def load_nearcut_model_json(path: Path | str) -> NearCutLinearModel:
    model_path = Path(path)
    raw_bytes = model_path.read_bytes()
    raw = json.loads(raw_bytes.decode("utf-8"))
    if not isinstance(raw, dict):
        raise ValueError("nearcut model JSON must be an object")
    normalization = raw.get("normalization", {})
    if not isinstance(normalization, Mapping):
        raise ValueError("nearcut normalization must be an object")
    raw_coefficients = raw.get("coefficients")
    if not isinstance(raw_coefficients, Mapping):
        raise ValueError("nearcut coefficients must be an object")
    raw_feature_names = raw.get("feature_names")
    if not isinstance(raw_feature_names, list):
        raise ValueError("nearcut feature_names must be a list")
    policy_raw = raw.get("nearcut_policy", {})
    if not isinstance(policy_raw, Mapping):
        raise ValueError("nearcut_policy must be an object")
    model = NearCutLinearModel(
        schema_version=int(raw.get("schema_version", 0)),
        model_type=str(raw.get("model_type", "")),
        score_mode=str(raw.get("score_mode", "")),
        created_utc=str(raw.get("created_utc", "")),
        feature_names=tuple(str(name) for name in raw_feature_names),
        intercept=float(raw.get("intercept", 0.0)),
        coefficients=tuple((str(name), float(value)) for name, value in raw_coefficients.items()),
        normalization_mode=str(normalization.get("mode", "runtime_boundary")),
        normalization_epsilon=float(normalization.get("epsilon", 1.0e-9)),
        policy=_nearcut_policy_from_mapping(policy_raw),
        training_summary=dict(raw.get("training_summary", {}) if isinstance(raw.get("training_summary", {}), Mapping) else {}),
        source_path=str(model_path.resolve()),
        raw_sha256=hashlib.sha256(raw_bytes).hexdigest(),
    )
    return validate_nearcut_linear_model(model)


def override_nearcut_model_policy(
    model: NearCutLinearModel,
    *,
    candidate_gap: float | None = None,
    max_extra_states: int | None = None,
    max_extra_states_per_boundary: int | None = None,
    prefix_gap_from_best: float | None = None,
    candidate_positive_slack: float | None = None,
    min_learned_score: float | None = None,
) -> NearCutLinearModel:
    policy = model.policy
    next_policy = _validate_nearcut_policy(
        NearCutPolicy(
            candidate_gap=float(policy.candidate_gap if candidate_gap is None else candidate_gap),
            candidate_positive_slack=float(
                policy.candidate_positive_slack
                if candidate_positive_slack is None
                else candidate_positive_slack
            ),
            max_extra_states=int(policy.max_extra_states if max_extra_states is None else max_extra_states),
            max_extra_states_per_boundary=int(
                policy.max_extra_states_per_boundary
                if max_extra_states_per_boundary is None
                else max_extra_states_per_boundary
            ),
            prefix_gap_from_best=float(
                policy.prefix_gap_from_best if prefix_gap_from_best is None else prefix_gap_from_best
            ),
            min_learned_score=(
                policy.min_learned_score
                if min_learned_score is None
                else float(min_learned_score)
            ),
            protect_baseline_retained_set=bool(policy.protect_baseline_retained_set),
            admit_only_pruned_nearcut_states=bool(policy.admit_only_pruned_nearcut_states),
        )
    )
    return validate_nearcut_linear_model(replace(model, policy=next_policy))


def _nearcut_model_uses_future_parity_features(model: NearCutLinearModel | None) -> bool:
    if model is None:
        return False
    return any("future_parity" in str(name) for name in tuple(model.feature_names))


