@dataclass(frozen=True, slots=True)
class ForwardCutStateLookaheadModeConfig:
    combination_mode: str
    mix_weight: float
    signal_kind: str = "prefix"


@dataclass(frozen=True, slots=True)
class FutureParityDeadlineLogoddsConfig:
    tau: float
    beta: float
    alpha: float = 1.0


@dataclass(frozen=True, slots=True)
class FutureParityPrefixTaperConfig:
    early_beta: float
    late_beta: float
    gamma: float = 1.0


@dataclass(frozen=True, slots=True)
class FutureParityLearnedLinearConfig:
    schema_version: str
    score_mode: str
    intercept: float
    coefficients: tuple[tuple[str, float], ...]
    score_clip: float = float("inf")
    description: str = ""
    source: str = ""


@dataclass(frozen=True, slots=True)
class NearCutPolicy:
    candidate_gap: float = 2.0
    candidate_positive_slack: float = 0.0
    max_extra_states: int = 1
    max_extra_states_per_boundary: int = 1
