@lru_cache(maxsize=4096)
def _weighted_score_mode_suffix_value(*, score_mode_key: str, prefix: str) -> float | None:
    normalized = str(score_mode_key).strip().lower()
    if normalized == prefix:
        return 1.0
    tagged_prefix = f"{prefix}_l"
    if not normalized.startswith(tagged_prefix):
        return None
    suffix = str(normalized[len(tagged_prefix):]).strip()
    if not suffix:
        return None
    value = _parse_pairlogodds_weight_token(suffix)
    if value is None or float(value) > 1.0:
        return None
    return float(value)


@lru_cache(maxsize=4096)
def _forward_cut_state_lookahead_mode_config_from_score_mode(
    score_mode_key: str,
) -> ForwardCutStateLookaheadModeConfig | None:
    blend_weight = _weighted_score_mode_suffix_value(
        score_mode_key=str(score_mode_key),
        prefix=str(FORWARD_CUT_STATE_LOOKAHEAD_SCORE_MODE_PREFIX),
    )
    if blend_weight is not None:
        return ForwardCutStateLookaheadModeConfig(
            combination_mode="blend",
            mix_weight=float(blend_weight),
            signal_kind="prefix",
        )
    dual_source_blend_weight = _weighted_score_mode_suffix_value(
        score_mode_key=str(score_mode_key),
        prefix=str(FORWARD_CUT_STATE_DUAL_SOURCE_LOOKAHEAD_SCORE_MODE_PREFIX),
    )
    if dual_source_blend_weight is not None:
        return ForwardCutStateLookaheadModeConfig(
            combination_mode="blend",
            mix_weight=float(dual_source_blend_weight),
            signal_kind="prefix_dual_source",
        )
    resnorm_weight = _weighted_score_mode_suffix_value(
        score_mode_key=str(score_mode_key),
        prefix=str(FORWARD_CUT_STATE_LOOKAHEAD_RESNORM_SCORE_MODE_PREFIX),
    )
    if resnorm_weight is not None:
        return ForwardCutStateLookaheadModeConfig(
            combination_mode="resnorm",
            mix_weight=float(resnorm_weight),
            signal_kind="prefix",
        )
    continuation_resnorm_weight = _weighted_score_mode_suffix_value(
        score_mode_key=str(score_mode_key),
        prefix=str(FORWARD_CUT_STATE_CONTINUATION_RESNORM_SCORE_MODE_PREFIX),
    )
    if continuation_resnorm_weight is not None:
        return ForwardCutStateLookaheadModeConfig(
            combination_mode="resnorm",
            mix_weight=float(continuation_resnorm_weight),
            signal_kind="continuation",
        )
    pairwise_extrinsic_weight = _weighted_score_mode_suffix_value(
        score_mode_key=str(score_mode_key),
        prefix=str(FORWARD_CUT_STATE_PAIRWISE_EXTRINSIC_SCORE_MODE_PREFIX),
    )
    if pairwise_extrinsic_weight is not None:
        return ForwardCutStateLookaheadModeConfig(
            combination_mode="extrinsic",
            mix_weight=float(pairwise_extrinsic_weight),
            signal_kind="pairwise_extrinsic",
        )
    pairwise_extrinsic_widen_weight = _weighted_score_mode_suffix_value(
        score_mode_key=str(score_mode_key),
        prefix=str(FORWARD_CUT_STATE_PAIRWISE_EXTRINSIC_WIDEN_SCORE_MODE_PREFIX),
    )
    if pairwise_extrinsic_widen_weight is not None:
        return ForwardCutStateLookaheadModeConfig(
            combination_mode="widen",
            mix_weight=float(pairwise_extrinsic_widen_weight),
            signal_kind="pairwise_extrinsic",
        )
    return None


@lru_cache(maxsize=4096)
def _score_mode_is_forward_cut_state_lookahead_family(score_mode_key: str) -> bool:
    return _forward_cut_state_lookahead_mode_config_from_score_mode(str(score_mode_key)) is not None


@lru_cache(maxsize=4096)
def _committee_score_modes_from_score_mode(score_mode_key: str) -> tuple[str, ...] | None:
    normalized = str(score_mode_key).strip().lower()
    prefix = "committee_score_modes__"
    if not normalized.startswith(prefix):
        return None
    suffix = str(normalized[len(prefix):]).strip("_")
    if not suffix:
        return None
    modes = tuple(part.strip() for part in suffix.split("__") if str(part).strip())
    if len(modes) < 2:
        return None
    deduped: list[str] = []
    seen: set[str] = set()
    for mode in modes:
        normalized_mode = str(mode).strip().lower()
        if not normalized_mode or normalized_mode in seen:
            continue
        seen.add(normalized_mode)
        deduped.append(str(normalized_mode))
    return tuple(deduped) if len(deduped) >= 2 else None


@lru_cache(maxsize=4096)
def _future_parity_logodds_alpha_from_score_mode(score_mode_key: str) -> float | None:
    normalized = str(score_mode_key).strip().lower()
