@lru_cache(maxsize=4096)
def _future_parity_logodds_prefix_taper_config_from_score_mode(
    score_mode_key: str,
) -> FutureParityPrefixTaperConfig | None:
    normalized = str(score_mode_key).strip().lower()
    prefix = "future_parity_logodds_prefix_taper_"
    if not normalized.startswith(prefix):
        return None
    suffix = str(normalized[len(prefix):]).strip()
    if not suffix:
        return None
    early_beta: float | None = None
    late_beta: float | None = None
    gamma: float | None = None
    seen_parts: set[str] = set()
    for part in suffix.split("_"):
        if not part:
            return None
        if part.startswith("early"):
            key = "early"
            token = str(part[len("early"):])
        elif part.startswith("late"):
            key = "late"
            token = str(part[len("late"):])
        elif part.startswith("gamma"):
            key = "gamma"
            token = str(part[len("gamma"):])
        else:
            return None
        if not token or key in seen_parts:
            return None
        seen_parts.add(str(key))
        value = _parse_pairlogodds_weight_token(token)
        if value is None:
            return None
        if str(key) == "early":
            early_beta = float(value)
        elif str(key) == "late":
            late_beta = float(value)
        else:
            if float(value) <= 0.0:
                return None
            gamma = float(value)
    if early_beta is None or late_beta is None:
        return None
    return FutureParityPrefixTaperConfig(
        early_beta=float(early_beta),
        late_beta=float(late_beta),
        gamma=float(1.0 if gamma is None else gamma),
    )


def _future_parity_logodds_prefix_taper_beta(
    config: FutureParityPrefixTaperConfig,
    *,
    boundary_column_index: int,
    total_columns: int,
) -> float:
    total = max(1, int(total_columns))
    processed = min(max(0, int(boundary_column_index) + 1), int(total))
    processed_fraction = float(processed) / float(total)
    weight = float(processed_fraction) ** float(config.gamma)
    return float(config.early_beta) + (float(config.late_beta) - float(config.early_beta)) * float(weight)


@lru_cache(maxsize=4096)
def _future_parity_logodds_logsupport_config_from_score_mode(
    score_mode_key: str,
) -> tuple[float, float] | None:
    normalized = str(score_mode_key).strip().lower()
    direct_prefix = "future_parity_logodds_logsupport_c"
    if normalized.startswith(direct_prefix):
        alpha = 1.0
        coefficient_token = str(normalized[len(direct_prefix):]).strip()
    else:
        alpha_prefix = "future_parity_logodds_a"
        marker = "_logsupport_c"
        if not normalized.startswith(alpha_prefix) or marker not in normalized:
            return None
        alpha_token, coefficient_token = normalized[len(alpha_prefix):].split(marker, 1)
        alpha_value = _parse_pairlogodds_weight_token(str(alpha_token))
        if alpha_value is None:
            return None
        alpha = float(alpha_value)
        coefficient_token = str(coefficient_token).strip()
    if not coefficient_token:
        return None
    coefficient = _parse_pairlogodds_weight_token(str(coefficient_token))
    if coefficient is None:
        return None
    return (float(alpha), float(coefficient))


@dataclass(frozen=True, slots=True)
class CompactFeatureScoreConfig:
    alpha: float
    feature: str
    coefficient: float
    gamma: float = 1.0


@lru_cache(maxsize=4096)
def _future_parity_logodds_compact_feature_config_from_score_mode(
    score_mode_key: str,
) -> CompactFeatureScoreConfig | None:
    normalized = str(score_mode_key).strip().lower()
    direct_prefix = "future_parity_logodds_"
    alpha_prefix = "future_parity_logodds_a"
    markers = (
        ("detweight", "_detweight_d", "d"),
        ("lowsupport", "_lowsupport_c", "c"),
        ("compactsupport", "_compactsupport_c", "c"),
    )
    alpha = 1.0
    tail = ""
    if normalized.startswith(alpha_prefix):
        suffix = str(normalized[len(alpha_prefix):])
        matched = False
        for _feature, marker, _coefficient_name in markers:
            if marker not in suffix:
                continue
            alpha_token, tail = suffix.split(marker, 1)
            alpha_value = _parse_pairlogodds_weight_token(str(alpha_token))
            if alpha_value is None:
                return None
            alpha = float(alpha_value)
            tail = f"{marker[1:]}{tail}"
            matched = True
            break
        if not matched:
            return None
    elif normalized.startswith(direct_prefix):
        tail = str(normalized[len(direct_prefix):])
    else:
        return None

    for feature, marker, coefficient_name in markers:
        direct_marker = f"{feature}_{coefficient_name}"
        if not tail.startswith(direct_marker):
            continue
        rest = str(tail[len(direct_marker):]).strip()
        gamma = 1.0
        if feature == "compactsupport" and "_g" in rest:
            coefficient_token, gamma_token = rest.split("_g", 1)
            gamma_value = _parse_pairlogodds_weight_token(str(gamma_token))
            if gamma_value is None:
                return None
            gamma = float(gamma_value)
        else:
            coefficient_token = str(rest)
        if not coefficient_token:
            return None
        coefficient = _parse_pairlogodds_weight_token(str(coefficient_token))
        if coefficient is None:
            return None
        return CompactFeatureScoreConfig(
            alpha=float(alpha),
            feature=str(feature),
            coefficient=float(coefficient),
            gamma=float(gamma),
        )
    return None


@lru_cache(maxsize=4096)
def _compiled_singleton_future_parity_rank_plan(score_mode_key: str) -> tuple[float, bool, str] | None:
    """Return (alpha, future_only, heuristic_cache_key) for simple parity-logodds rank modes."""
    normalized = str(score_mode_key).strip().lower()
    no_prefix_inner = _no_prefix_inner_score_mode(str(normalized))
    if no_prefix_inner is not None:
        inner_plan = _compiled_singleton_future_parity_rank_plan(str(no_prefix_inner))
        if inner_plan is None:
            return None
        return (float(inner_plan[0]), True, str(inner_plan[2]))
    if normalized in {"future_parity_logodds", STAGE1_RELIABILITY_SCORE_MODE}:
        return (1.0, False, str(normalized))
    if normalized == "future_parity_logodds_only":
        return (1.0, True, str(normalized))
    alpha = _future_parity_logodds_alpha_from_score_mode(str(normalized))
    if alpha is not None:
        return (float(alpha), False, str(normalized))
    return None


@lru_cache(maxsize=4096)
def _mixed_factor_exact_singleton_alpha_from_score_mode(score_mode_key: str) -> float | None:
    normalized = str(score_mode_key).strip().lower()
