@lru_cache(maxsize=4096)
def _mixed_binarized_outcomes_config_from_score_mode(
    score_mode_key: str,
) -> FutureBinarizedOutcomesModeConfig | None:
    normalized = str(score_mode_key).strip().lower()
    prefix = f"{MIXED_BINARIZED_OUTCOMES_SCORE_MODE_PREFIX}_"
    if not normalized.startswith(prefix):
        return None
    suffix = str(normalized[len(prefix):]).strip()
    variants = (
        "merged_detector_signature",
        "unmerged",
    )
    for variant in variants:
        variant_prefix = f"{variant}_a"
        if not suffix.startswith(variant_prefix):
            continue
        alpha_token = str(suffix[len(variant_prefix):]).strip()
        alpha = _parse_pairlogodds_weight_token(alpha_token)
        if alpha is None:
            return None
        return FutureBinarizedOutcomesModeConfig(
            variant=str(variant),
            alpha=float(alpha),
        )
    return None


@lru_cache(maxsize=4096)
def _future_parity_deadline_logodds_config_from_score_mode(
    score_mode_key: str,
) -> FutureParityDeadlineLogoddsConfig | None:
    normalized = str(score_mode_key).strip().lower()
    prefix = "future_parity_logodds_deadline_"
    alpha = 1.0
    if normalized.startswith(prefix):
        suffix = str(normalized[len(prefix):]).strip()
    else:
        alpha_prefix = "future_parity_logodds_a"
        deadline_marker = "_deadline_"
        if not normalized.startswith(alpha_prefix):
            return None
        tagged_suffix = str(normalized[len(alpha_prefix):]).strip()
        if str(deadline_marker) not in tagged_suffix:
            return None
        alpha_token, suffix = tagged_suffix.split(str(deadline_marker), 1)
        alpha_value = _parse_pairlogodds_weight_token(str(alpha_token))
        if alpha_value is None:
            return None
        alpha = float(alpha_value)
    if not suffix:
        return None
    tau: float | None = None
    beta: float | None = None
    seen_parts: set[str] = set()
    for part in suffix.split("_"):
        if not part:
            return None
        if part.startswith("tau"):
            key = "tau"
            token = str(part[len("tau"):])
        elif part.startswith("beta"):
            key = "beta"
            token = str(part[len("beta"):])
        else:
            return None
        if not token or key in seen_parts:
            return None
        seen_parts.add(str(key))
        value = _parse_pairlogodds_weight_token(token)
        if value is None:
            return None
        if str(key) == "tau":
            if float(value) <= 0.0:
                return None
            tau = float(value)
        else:
            beta = float(value)
    if tau is None or beta is None:
        return None
    return FutureParityDeadlineLogoddsConfig(tau=float(tau), beta=float(beta), alpha=float(alpha))


@lru_cache(maxsize=4096)
def _pairlogodds_mode_config_from_score_mode(
    score_mode_key: str,
    beam_size: int | None = None,
) -> FuturePairlogoddsModeConfig | None:
    normalized = str(score_mode_key).strip().lower()
    prefix = "future_parity_pairlogodds"
    exact_factor_prefix = str(MIXED_FACTOR_EXACT_PAIRLOGODDS_SCORE_MODE_PREFIX)
    if normalized == exact_factor_prefix:
        return FuturePairlogoddsModeConfig(
            singleton_scale=1.0,
            pair_correction_scale=1.0,
            pair_selection="shared_mi",
            max_pairs=0,
        )
    exact_factor_tagged_prefix = f"{exact_factor_prefix}_"
    if normalized.startswith(exact_factor_tagged_prefix):
        return _pairlogodds_mode_config_from_suffix(
            str(normalized[len(exact_factor_tagged_prefix):]).strip(),
            default_pair_selection="shared_mi",
        )
    if normalized == PAIRLOGODDS_WIDTH_ADAPTIVE_SCORE_MODE:
        alpha, beta = _pairlogodds_width_adaptive_weights_for_beam_size(beam_size)
        return FuturePairlogoddsModeConfig(
            singleton_scale=float(alpha),
            pair_correction_scale=float(beta),
            pair_selection=str(PAIRLOGODDS_PAIR_SELECTION_DEFAULT),
            max_pairs=0,
        )
    for accepted_prefix in (prefix, MIXED_PAIRLOGODDS_SCORE_MODE_PREFIX):
        if normalized == str(accepted_prefix):
            return FuturePairlogoddsModeConfig(
                singleton_scale=1.0,
                pair_correction_scale=1.0,
                pair_selection=str(PAIRLOGODDS_PAIR_SELECTION_DEFAULT),
                max_pairs=0,
            )
        tagged_prefix = f"{accepted_prefix}_"
        if normalized.startswith(tagged_prefix):
            return _pairlogodds_mode_config_from_suffix(
                str(normalized[len(tagged_prefix):]).strip()
            )
    return None


