@lru_cache(maxsize=4096)
def _mixed_closing_logmass_config_from_score_mode(
    score_mode_key: str,
) -> FutureClosingLogmassModeConfig | None:
    normalized = str(score_mode_key).strip().lower()
    suffix: str | None = None
    for prefix in (str(MIXED_CLOSING_LOGMASS_SCORE_MODE_PREFIX), str(MIXED_FACTOR_CLOSING_LOGMASS_SCORE_MODE_PREFIX)):
        if normalized == prefix:
            return FutureClosingLogmassModeConfig(window_ticks=1, max_exact_component_rows=12, alpha=1.0)
        tagged_prefix = f"{prefix}_"
        if normalized.startswith(tagged_prefix):
            suffix = str(normalized[len(tagged_prefix):]).strip()
            break
    if suffix is None:
        return None
    if not suffix:
        return None
    window_ticks: int | None = None
    max_exact_component_rows: int | None = None
    alpha = 1.0
    seen_parts: set[str] = set()
    for part in suffix.split("_"):
        if not part:
            return None
        if part.startswith("wtick"):
            key = "wtick"
            token = str(part[len("wtick"):])
            if not token.isdigit():
                return None
            value = int(token)
            if int(value) < 0:
                return None
            window_ticks = int(value)
        elif part.startswith("cap"):
            key = "cap"
            token = str(part[len("cap"):])
            if not token.isdigit():
                return None
            value = int(token)
            if int(value) <= 0:
                return None
            max_exact_component_rows = int(value)
        elif part.startswith("a"):
            key = "a"
            token = str(part[1:])
            value_float = _parse_pairlogodds_weight_token(token)
            if value_float is None:
                return None
            alpha = float(value_float)
        else:
            return None
        if key in seen_parts:
            return None
        seen_parts.add(str(key))
    if window_ticks is None or max_exact_component_rows is None:
        return None
    return FutureClosingLogmassModeConfig(
        window_ticks=int(window_ticks),
        max_exact_component_rows=int(max_exact_component_rows),
        alpha=float(alpha),
        fallback="rowwise",
    )


@lru_cache(maxsize=4096)
def _mixed_factor_pairlogodds_plus_closing_config_from_score_mode(
    score_mode_key: str,
) -> FuturePairlogoddsPlusClosingModeConfig | None:
    normalized = str(score_mode_key).strip().lower()
    split_token = "_plus_closing_"
    prefixes = (
        str(MIXED_FACTOR_PAIRLOGODDS_PLUS_CLOSING_SCORE_MODE_PREFIX),
        str(MIXED_FACTOR_EXACT_PAIRLOGODDS_SCORE_MODE_PREFIX),
    )
    for prefix in prefixes:
        tagged_prefix = f"{prefix}_"
        if not normalized.startswith(tagged_prefix):
            continue
        suffix = str(normalized[len(tagged_prefix):]).strip()
        if str(split_token) not in suffix:
            continue
        pair_suffix, closing_suffix = suffix.split(str(split_token), 1)
        pair_config = _pairlogodds_mode_config_from_suffix(
            str(pair_suffix).strip(),
            default_pair_selection="shared_mi",
        )
        closing_config = _mixed_closing_logmass_config_from_score_mode(
            f"{MIXED_FACTOR_CLOSING_LOGMASS_SCORE_MODE_PREFIX}_{str(closing_suffix).strip()}"
        )
        if pair_config is None or closing_config is None:
            return None
        return FuturePairlogoddsPlusClosingModeConfig(
            pairlogodds=pair_config,
            closing=closing_config,
        )
    return None


@lru_cache(maxsize=4096)
def _pairlogodds_weights_from_score_mode(
    score_mode_key: str,
    beam_size: int | None = None,
) -> tuple[float, float] | None:
    config = _pairlogodds_mode_config_from_score_mode(
        str(score_mode_key),
        beam_size=beam_size,
    )
    if config is None:
        return None
    return (float(config.singleton_scale), float(config.pair_correction_scale))


@lru_cache(maxsize=4096)
def _pairlogodds_pair_selection_from_score_mode(
    score_mode_key: str,
    beam_size: int | None = None,
) -> str | None:
    config = _pairlogodds_mode_config_from_score_mode(
        str(score_mode_key),
        beam_size=beam_size,
    )
    if config is None:
        return None
    return str(config.pair_selection)


