def _score_mode_is_recognized(score_mode_key: str) -> bool:
    normalized = str(score_mode_key).strip().lower()
    no_prefix_inner = _no_prefix_inner_score_mode(str(normalized))
    if no_prefix_inner is not None:
        return (
            _score_mode_is_recognized(str(no_prefix_inner))
            and _score_mode_supports_boundary_secondary_rerank(str(no_prefix_inner))
        )
    return (
        normalized in _BASE_PROGRESSIVE_SCORE_MODES
        or _score_mode_is_forward_cut_state_lookahead_family(normalized)
        or _low_error_event_cap_from_score_mode(normalized) is not None
        or _active_frontierk_beam_from_score_mode(normalized) is not None
        or _pairlogodds_weights_from_score_mode(normalized) is not None
        or _future_pair_frustration_config_from_score_mode(normalized) is not None
        or _mixed_pairlogodds_support_gate_config_from_score_mode(normalized) is not None
        or _mixed_closing_logmass_config_from_score_mode(normalized) is not None
        or _mixed_factor_pairlogodds_plus_closing_config_from_score_mode(normalized) is not None
        or _mixed_factor_exact_singleton_alpha_from_score_mode(normalized) is not None
        or _mixed_binarized_outcomes_config_from_score_mode(normalized) is not None
        or _future_parity_logodds_alpha_from_score_mode(normalized) is not None
        or _future_parity_logodds_prefix_beta_from_score_mode(normalized) is not None
        or _future_parity_logodds_prefix_taper_config_from_score_mode(normalized) is not None
        or _future_parity_logodds_logsupport_config_from_score_mode(normalized) is not None
        or _future_parity_logodds_compact_feature_config_from_score_mode(normalized) is not None
        or _future_parity_deadline_logodds_config_from_score_mode(normalized) is not None
        or _is_learned_linear_score_mode(normalized)
    )


def _score_mode_supports_boundary_secondary_rerank(score_mode_key: str) -> bool:
    normalized = str(score_mode_key).strip().lower()
    return (
        _score_mode_is_recognized(normalized)
        and not _score_mode_is_forward_cut_state_lookahead_family(normalized)
        and normalized not in _BOUNDARY_SECONDARY_UNSUPPORTED_SCORE_MODES
    )


def _parse_multi_score_survivor_lane_spec(raw: str) -> MultiScoreSurvivorLaneSpec:
    text = str(raw).strip()
    if not text or ":" not in text:
        raise ValueError("multi-score survivor lane entries must have form score_mode:fraction[:delta]")
    parts = text.rsplit(":", 2)
    if len(parts) == 2:
        score_mode, fraction_text = parts
        delta_text = None
    elif len(parts) == 3:
        score_mode, fraction_text, delta_text = parts
    else:
        raise ValueError("multi-score survivor lane entries must have form score_mode:fraction[:delta]")
    score_mode_key = str(score_mode).strip().lower()
    if not score_mode_key:
        raise ValueError("multi-score survivor lane score_mode must not be empty")
    try:
        fraction = float(str(fraction_text).strip())
    except ValueError as exc:
        raise ValueError(f"invalid multi-score survivor lane fraction in {raw!r}") from exc
    delta = None
    if delta_text is not None and str(delta_text).strip():
        try:
            delta = float(str(delta_text).strip())
        except ValueError as exc:
            raise ValueError(f"invalid multi-score survivor lane delta in {raw!r}") from exc
    return MultiScoreSurvivorLaneSpec(
        score_mode=str(score_mode_key),
        fraction=float(fraction),
        score_gap_threshold=delta,
    )


def _normalize_multi_score_survivor_lanes(
    lanes: Sequence[object] | None,
) -> tuple[MultiScoreSurvivorLaneSpec, ...]:
    if lanes is None:
        return tuple()
    out: list[MultiScoreSurvivorLaneSpec] = []
    for raw_lane in tuple(lanes):
        if isinstance(raw_lane, MultiScoreSurvivorLaneSpec):
            lane = raw_lane
        elif isinstance(raw_lane, str):
            lane = _parse_multi_score_survivor_lane_spec(raw_lane)
        else:
            try:
                values = tuple(raw_lane)  # type: ignore[arg-type]
            except (TypeError, ValueError) as exc:
                raise ValueError(
                    "multi_score_survivor_lanes entries must be score:fraction[:delta] strings or (score, fraction[, delta]) tuples"
                ) from exc
            if len(values) == 2:
                score_mode, fraction = values
                delta = None
            elif len(values) == 3:
                score_mode, fraction, delta = values
            else:
                raise ValueError(
                    "multi_score_survivor_lanes entries must be score:fraction[:delta] strings or (score, fraction[, delta]) tuples"
                )
            lane = MultiScoreSurvivorLaneSpec(
                score_mode=str(score_mode).strip().lower(),
                fraction=float(fraction),
                score_gap_threshold=None if delta is None else float(delta),
            )
        score_mode_key = str(lane.score_mode).strip().lower()
        fraction = float(lane.fraction)
        score_gap_threshold = lane.score_gap_threshold
        if not score_mode_key:
            raise ValueError("multi-score survivor lane score_mode must not be empty")
        if math.isnan(float(fraction)) or not math.isfinite(float(fraction)):
            raise ValueError("multi-score survivor lane fractions must be finite")
        if float(fraction) < 0.0 or float(fraction) > 1.0:
            raise ValueError("multi-score survivor lane fractions must be in [0, 1]")
        if score_gap_threshold is not None and (
            math.isnan(float(score_gap_threshold))
            or not math.isfinite(float(score_gap_threshold))
            or float(score_gap_threshold) < 0.0
        ):
            raise ValueError("multi-score survivor lane delta values must be finite and nonnegative")
        if not _score_mode_supports_boundary_secondary_rerank(str(score_mode_key)):
            raise ValueError(
                f"multi-score survivor lane score mode {score_mode_key!r} is not supported for no-probe survivor selection"
            )
        out.append(
            MultiScoreSurvivorLaneSpec(
                score_mode=str(score_mode_key),
                fraction=float(fraction),
                score_gap_threshold=(
                    None
                    if score_gap_threshold is None
                    else float(score_gap_threshold)
                ),
            )
        )
    total_fraction = float(sum(float(lane.fraction) for lane in out))
    if float(total_fraction) > 1.0 + 1.0e-12:
        raise ValueError("multi-score survivor lane fractions must sum to <= 1")
    if float(total_fraction) <= 0.0:
        return tuple()
    return tuple(out)


def _multi_score_survivor_lanes_to_string(
    lanes: Sequence[MultiScoreSurvivorLaneSpec],
) -> str:
    return "|".join(
        (
            f"{str(lane.score_mode)}:{float(lane.fraction):.12g}"
            if lane.score_gap_threshold is None
            else f"{str(lane.score_mode)}:{float(lane.fraction):.12g}:{float(lane.score_gap_threshold):.12g}"
        )
        for lane in tuple(lanes)
    )


def _multi_score_survivor_lane_budgets(
    *,
    beam_size: int,
    lanes: Sequence[MultiScoreSurvivorLaneSpec],
) -> tuple[int, ...]:
    if int(beam_size) <= 0:
        return tuple(0 for _lane in tuple(lanes))
    raw_budgets = [float(beam_size) * float(lane.fraction) for lane in tuple(lanes)]
    budgets = [int(math.floor(float(value))) for value in raw_budgets]
    target_total = int(round(float(sum(raw_budgets))))
    target_total = max(0, min(int(beam_size), int(target_total)))
    remaining = max(0, int(target_total) - int(sum(budgets)))
    if int(remaining) > 0:
        remainder_order = sorted(
            range(len(budgets)),
            key=lambda idx: (
                float(raw_budgets[int(idx)]) - float(math.floor(float(raw_budgets[int(idx)]))),
                -int(idx),
            ),
            reverse=True,
        )
        for idx in remainder_order:
            if int(remaining) <= 0:
                break
            if float(lanes[int(idx)].fraction) <= 0.0:
                continue
            budgets[int(idx)] += 1
            remaining -= 1
    return tuple(int(value) for value in budgets)


def _phase_lane_label(
    *,
    processed_column_count: int,
    total_column_count: int,
    early_end: float = 0.33,
    late_start: float = 0.80,
) -> str:
    total = int(total_column_count)
    if int(total) <= 0:
        raise ValueError("total_column_count must be positive for phase lanes")
    early = float(early_end)
    late = float(late_start)
    if (
        math.isnan(float(early))
        or not math.isfinite(float(early))
        or math.isnan(float(late))
        or not math.isfinite(float(late))
        or float(early) < 0.0
        or float(late) > 1.0
        or float(early) > float(late)
    ):
        raise ValueError("phase thresholds must satisfy 0 <= early_end <= late_start <= 1")
    fraction = float(processed_column_count) / float(total)
    if float(fraction) < float(early):
        return "early"
    if float(fraction) < float(late):
        return "middle"
    return "late"


def _phase_lane_mixture_for_schedule(
    schedule: str,
    phase_label: str,
) -> PhaseConditionedLaneMixture:
    schedule_key = str(schedule).strip()
    phase_key = str(phase_label).strip().lower()
    if schedule_key not in PHASE_LANE_SCHEDULES:
        raise ValueError(f"phase_lane_schedule must be one of {sorted(PHASE_LANE_SCHEDULES)}")
    if phase_key not in {"early", "middle", "late"}:
        raise ValueError("phase_label must be one of early, middle, late")
    if schedule_key == "base_75_25_D8":
        return PhaseConditionedLaneMixture(0.75, 0.25, 0.0)
    if schedule_key in {"phase_future_to_prefix_A_D8", "phase_future_to_prefix_A_D9"}:
        if phase_key == "early":
            return PhaseConditionedLaneMixture(0.70, 0.30, 0.0)
        if phase_key == "middle":
            return PhaseConditionedLaneMixture(0.75, 0.25, 0.0)
        return PhaseConditionedLaneMixture(0.80, 0.10, 0.10)
    if phase_key == "late":
        return PhaseConditionedLaneMixture(0.85, 0.10, 0.05)
    return PhaseConditionedLaneMixture(0.75, 0.25, 0.0)


def _phase_lane_budgets(
    *,
    beam_size: int,
    mixture: PhaseConditionedLaneMixture,
) -> tuple[int, int, int]:
    raw = (
        float(beam_size) * float(mixture.primary_fraction),
        float(beam_size) * float(mixture.future_fraction),
        float(beam_size) * float(mixture.prefix_fraction),
    )
    budgets = [max(0, int(round(float(value)))) for value in raw]
    while sum(budgets) > int(beam_size):
        idx = max(range(len(budgets)), key=lambda item: (budgets[int(item)], -int(item)))
        budgets[int(idx)] -= 1
    return tuple(int(value) for value in budgets)  # type: ignore[return-value]


def _default_shadow_score_modes(primary_score_mode: str) -> tuple[str, ...]:
    candidates = (
        "prefix",
        "future_parity_logodds",
        "future_parity_pairlogodds",
        "future_parity_pairtree_support_gate",
    )
    seen: set[str] = set()
    out: list[str] = []
    for score_mode in candidates:
        key = str(score_mode).strip().lower()
        if key == str(primary_score_mode).strip().lower() or key in seen:
            continue
        seen.add(key)
        out.append(key)
    return tuple(out)


def _score_mode_is_pairlogodds_family(score_mode_key: str) -> bool:
    return (
        _pairlogodds_weights_from_score_mode(str(score_mode_key)) is not None
        or _mixed_pairlogodds_support_gate_config_from_score_mode(str(score_mode_key)) is not None
    )


def _normalize_future_parity_scorer(value: str | None) -> str:
    raw = (
        str(value).strip().lower()
        if value is not None and str(value).strip()
        else str(os.environ.get("FRONTIERK_FUTURE_PARITY_SCORER", "cached")).strip().lower()
    )
    aliases = {
        "optimized": "cached",
        "incremental": "cached",
        "cache": "cached",
        "new": "cached",
        "legacy": "old",
        "from_scratch": "old",
        "from-scratch": "old",
    }
    key = str(aliases.get(raw, raw))
    if key not in {"cached", "old"}:
        raise ValueError("future_parity_scorer must be one of ['cached', 'old']")
    return str(key)


def _normalize_log_mass_primary_production_path(value: str | None) -> str:
    raw = (
        str(value).strip().lower()
        if value is not None and str(value).strip()
        else str(os.environ.get("FRONTIERK_LOG_MASS_PRIMARY_PRODUCTION_PATH", "off")).strip().lower()
    )
    aliases = {
        "0": "off",
        "false": "off",
        "no": "off",
        "none": "off",
        "disabled": "off",
        "1": "guarded",
        "true": "guarded",
        "yes": "guarded",
        "on": "guarded",
        "enabled": "guarded",
        "auto": "guarded",
    }
    key = str(aliases.get(raw, raw))
    if key not in {"off", "guarded"}:
        raise ValueError("log_mass_primary_production_path must be one of ['off', 'guarded']")
    return str(key)


def _future_parity_modes_need_features(score_modes: Sequence[str]) -> bool:
    return any(_score_mode_uses_future_parity_features(str(mode)) for mode in tuple(score_modes))


def _debug_boundary_scores(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    active_mask: int,
    target_syndrome_int: int,
    detector_masks: tuple[int, ...],
    score_modes: tuple[str, ...],
    beam_size: int | None = None,
    clamp_assignments: dict[int, int] | None = None,
) -> dict[str, dict[int, float]]:
    normalized_clamps = {} if clamp_assignments is None else {int(key): int(value) for key, value in clamp_assignments.items()}
    score_mode_keys = tuple(str(mode).strip().lower() for mode in score_modes)
    needs_features = any(
        _score_mode_uses_future_parity_features(mode)
        for mode in score_mode_keys
    )
    parity_payload = (
        _build_future_parity_boundary_payload(
            frontier=frontier,
            boundary_column_index=int(boundary_column_index),
            active_mask=int(active_mask),
        )
        if bool(needs_features)
        else None
    )
    features_by_detector = (
        _collect_detector_features_for_masks(
            detector_masks={int(det_mask) for det_mask in detector_masks},
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            column_index=int(boundary_column_index),
            frontier=frontier,
            parity_payload=parity_payload,
        )
        if bool(needs_features)
        else {}
    )
    component_payload_cache: dict[int, FutureComponentHeuristicPayload] = {}
    pairtree_payload_cache: dict[int, FuturePairtreeHeuristicPayload | FuturePairlogoddsHeuristicPayload] = {}
    low_error_payload_cache: dict[tuple[int, int, int], FutureLowErrorHeuristicPayload] = {}
    active_frontier_payload_cache: dict[tuple[int, int], FutureActiveFrontierHeuristicPayload] = {}
    active_frontier_score_cache: dict[tuple[int, int, int], dict[int, float]] = {}
    parity_payload_cache: dict[int, FutureParityBoundaryPayload] = {}
    single_fix_payload_cache: dict[int, FutureSingleFixHeuristicPayload] = {}
    quotient_payload_cache: dict[int, FutureQuotientHeuristicPayload] = {}
    pseudo_payload_cache: dict[tuple[int, int, str], FutureBinarizedOutcomesBoundaryPayload] = {}
    out: dict[str, dict[int, float]] = {}
    for score_mode_key in score_mode_keys:
        mode_scores: dict[int, float] = {}
        for det_mask in detector_masks:
            mode_scores[int(det_mask)] = _boundary_heuristic_mass(
                det_key=int(det_mask),
                score_mode_key=str(score_mode_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                boundary_column_index=int(boundary_column_index),
                beam_size=beam_size,
                columns=columns,
                frontier=frontier,
                clamp_assignments=normalized_clamps,
                features_by_detector=features_by_detector,
                parity_payload_cache=parity_payload_cache,
                component_payload_cache=component_payload_cache,
                pairtree_payload_cache=pairtree_payload_cache,
                low_error_payload_cache=low_error_payload_cache,
                active_frontier_payload_cache=active_frontier_payload_cache,
                active_frontier_score_cache=active_frontier_score_cache,
                single_fix_payload_cache=single_fix_payload_cache,
                quotient_payload_cache=quotient_payload_cache,
                pseudo_payload_cache=pseudo_payload_cache,
            )
        out[str(score_mode_key)] = mode_scores
    return out


def print_toy_pairtree_diagnostic() -> str:
    columns = [
        ProgressiveColumn(
            family="toy",
            index=0,
            label="prefix",
            instruction_offset=0,
            prior_probs=(0.03, 0.40, 0.57),
            detector_response_masks=(0, 1, 3),
            logical_response_masks=(0, 0, 0),
            detector_support_mask=3,
            prior_log_probs=tuple(float(math.log(value)) for value in (0.03, 0.40, 0.57)),
            detector_support_rows=(0, 1),
        ),
        ProgressiveColumn(
            family="toy",
            index=1,
            label="shared_tail",
            instruction_offset=1,
            prior_probs=(0.9, 0.1),
            detector_response_masks=(0, 3),
            logical_response_masks=(0, 0),
            detector_support_mask=3,
            prior_log_probs=(float(math.log(0.9)), float(math.log(0.1))),
            detector_support_rows=(0, 1),
        ),
    ]
    frontier = build_frontier_layout(columns, num_detectors=2)
    boundary_column_index = 0
    active_mask = int(frontier.active_masks_after_column[int(boundary_column_index)])
    scores = _debug_boundary_scores(
        columns=columns,
        frontier=frontier,
        boundary_column_index=int(boundary_column_index),
        active_mask=int(active_mask),
        target_syndrome_int=0,
        detector_masks=(0, 1, 2, 3),
        score_modes=(
            "future_parity_logodds",
            "future_parity_pairlogodds",
            "future_parity_pairtree",
            "future_parity_pairtree_support_gate",
        ),
    )
    lines = [
        "Toy pairtree diagnostic at the boundary after the prefix column.",
        "Scores are boundary-local heuristic masses added to prefix log mass.",
        "det_mask  future_parity_logodds  future_parity_pairlogodds  future_parity_pairtree  future_parity_pairtree_support_gate",
    ]
    for det_mask in (0, 1, 2, 3):
        lines.append(
            f"{int(det_mask):02b}  "
            f"{scores['future_parity_logodds'][int(det_mask)]: .6f}  "
            f"{scores['future_parity_pairlogodds'][int(det_mask)]: .6f}  "
            f"{scores['future_parity_pairtree'][int(det_mask)]: .6f}  "
            f"{scores['future_parity_pairtree_support_gate'][int(det_mask)]: .6f}"
        )
    text = "\n".join(lines)
    print(text, flush=True)
    return text


def _build_toy_pairtree_benchmark_case() -> dict[str, object]:
    columns = [
        ProgressiveColumn(
            family="toy",
            index=0,
            label="prefix",
            instruction_offset=0,
            prior_probs=(0.03, 0.40, 0.57),
            detector_response_masks=(0, 1, 3),
            logical_response_masks=(0, 0, 0),
            detector_support_mask=3,
            prior_log_probs=tuple(float(math.log(value)) for value in (0.03, 0.40, 0.57)),
            detector_support_rows=(0, 1),
        ),
        ProgressiveColumn(
            family="toy",
            index=1,
            label="shared_tail",
            instruction_offset=1,
            prior_probs=(0.9, 0.1),
            detector_response_masks=(0, 3),
            logical_response_masks=(0, 0),
            detector_support_mask=3,
            prior_log_probs=(float(math.log(0.9)), float(math.log(0.1))),
            detector_support_rows=(0, 1),
        ),
    ]
    layout = build_frontier_layout(columns, num_detectors=2)
    return {
        "case_name": "toy_pairtree_shared_suffix",
        "columns": columns,
        "layout": layout,
        "target_syndrome": 0,
        "num_detectors": 2,
        "num_observables": 1,
        "beam_size": 1,
    }


def _build_toy_overflow_benchmark_case() -> dict[str, object]:
    columns = [
        ProgressiveColumn(
            family="toy",
            index=0,
            label="prefix",
            instruction_offset=0,
            prior_probs=(0.1, 0.9),
            detector_response_masks=(0, 1),
            logical_response_masks=(0, 1),
            detector_support_mask=1,
            prior_log_probs=(float(math.log(0.1)), float(math.log(0.9))),
            detector_support_rows=(0,),
        ),
        ProgressiveColumn(
            family="toy",
            index=1,
            label="tail",
            instruction_offset=1,
            prior_probs=(0.99, 0.01),
            detector_response_masks=(0, 1),
            logical_response_masks=(0, 0),
            detector_support_mask=1,
            prior_log_probs=(float(math.log(0.99)), float(math.log(0.01))),
            detector_support_rows=(0,),
        ),
    ]
    layout = build_frontier_layout(columns, num_detectors=1)
    return {
        "case_name": "toy_overflow_single_row",
        "benchmark_kind": "decode",
        "columns": columns,
        "layout": layout,
        "target_syndrome": 0,
        "num_detectors": 1,
        "num_observables": 1,
        "beam_size": 1,
    }


def _build_toy_dense_prune_benchmark_case() -> dict[str, object]:
    base_case = _build_toy_pairtree_benchmark_case()
    num_detectors = int(base_case["num_detectors"])
    next_log_mass: dict[int, float] = {}
    next_viterbi: dict[int, float] = {}
    for logical_mask in range(2048):
        det_mask = (0, 1, 3, 1)[int(logical_mask) % 4]
        prefix_prob = float(1.0 / float(logical_mask + 4))
        key = _pack_state_key(
            det_mask=int(det_mask),
            logical_mask=int(logical_mask),
            num_detectors=int(num_detectors),
            num_observables=11,
        )
        next_log_mass[int(key)] = float(math.log(prefix_prob))
        next_viterbi[int(key)] = float(math.log(prefix_prob))
    return {
        "case_name": "toy_dense_prune_table",
        "benchmark_kind": "prune",
        "columns": base_case["columns"],
        "layout": base_case["layout"],
        "target_syndrome": 0,
        "num_detectors": int(num_detectors),
        "num_observables": 8,
        "beam_size": 16,
        "next_log_mass": next_log_mass,
        "next_viterbi": next_viterbi,
        "boundary_column_index": 0,
        "active_mask": int(base_case["layout"].active_masks_after_column[0]),
    }


def run_progressive_smoke_benchmark(
    *,
    toy_repetitions: int = 1000,
    steane_repetitions: int = 20,
    dense_prune_repetitions: int = 100,
) -> dict[str, object]:
    cases = (
        (_build_toy_pairtree_benchmark_case(), int(toy_repetitions)),
        (_build_toy_overflow_benchmark_case(), int(steane_repetitions)),
        (_build_toy_dense_prune_benchmark_case(), int(dense_prune_repetitions)),
    )
    variants = (
        ("baseline_default", "future_parity_logodds", "legacy"),
        ("optimized_default", "future_parity_logodds", "optimized"),
        ("pairtree_support_gate", "future_parity_pairtree_support_gate", "optimized"),
    )

    rows: list[dict[str, object]] = []
    by_case_and_variant: dict[tuple[str, str], ProgressiveDecodeResult] = {}
    for case, repetitions in cases:
        repetitions = max(1, int(repetitions))
        for variant_label, score_mode, pruning_engine in variants:
            start = time.perf_counter()
            result_status = ""
            logical_hat = 0
            max_state_count = 0
            cumulative_discarded_prefix_mass = 0.0
            kept_keys: tuple[int, ...] = tuple()
            for _ in range(int(repetitions)):
                if str(case.get("benchmark_kind", "decode")) == "prune":
                    prune_result = _prune_beam_frontier(
                        next_log_mass=dict(case["next_log_mass"]),
                        next_viterbi=dict(case["next_viterbi"]),
                        next_parent={},
                        beam_size=int(case["beam_size"]),
                        beam_score_gap_threshold=None,
                        score_mode_key=str(score_mode),
                        lookahead_depth=0,
                        lookahead_shortlist_size=0,
                        detector_bucket_pruning=False,
                        detector_bucket_max_logicals=4,
                        logical_class_reserve_min_classes=0,
                        logical_class_reserve_max_replacements=0,
                        logical_class_reserve_min_remaining_columns=0,
                        logical_class_quota_top_classes=0,
                        logical_class_quota_reserved_slots=0,
                        logical_class_quota_min_remaining_columns=0,
                        lineage_reserve_reserved_slots=0,
                        logical_rerank_columns=0,
                        logical_rerank_shortlist_size=0,
                        logical_rerank_min_classes=0,
                        logical_rerank_state_budget=0,
                        logical_rerank_transition_budget=0,
                        logical_rerank_checkpoint_stride=0,
                        logical_rerank_max_passes=1,
                        logical_rerank_mode="exact_tail",
                        logical_rerank_pass_count=0,
                        logical_rerank_last_remaining_columns=len(case["columns"]) + 1,
                        boundary_column_index=int(case["boundary_column_index"]),
                        columns=case["columns"],
                        frontier=case["layout"],
                        active_mask=int(case["active_mask"]),
                        target_syndrome_int=int(case["target_syndrome"]),
                        num_detectors=int(case["num_detectors"]),
                        num_observables=int(case["num_observables"]),
                        clamp_assignments={},
                        track_best_path=False,
                        detector_features_by_detector=None,
                        parity_payload_cache={},
                        component_payload_cache={},
                        pairtree_payload_cache={},
                        low_error_payload_cache={},
                        single_fix_payload_cache={},
                        quotient_payload_cache={},
                        lineage_origin_masks_by_key=None,
                        debug_pruning_engine=str(pruning_engine),
                        collect_debug_metrics=False,
                        debug_shadow_score_modes=tuple(),
                    )
                    result_status = "pruned"
                    logical_hat = -1
                    max_state_count = int(len(prune_result[0]))
                    cumulative_discarded_prefix_mass = float(prune_result[13])
                    kept_keys = tuple(int(key) for key in prune_result[0].keys())
                else:
                    result = decode_progressive(
                        case["columns"],
                        target_syndrome=int(case["target_syndrome"]),
                        num_detectors=int(case["num_detectors"]),
                        num_observables=int(case["num_observables"]),
                        beam_size=int(case["beam_size"]),
                        score_mode=str(score_mode),
                        layout=case["layout"],
                        track_best_path=False,
                        debug_pruning_engine=str(pruning_engine),
                    )
                    result_status = str(result.status)
                    logical_hat = int(result.logical_hat)
                    max_state_count = int(result.max_state_count)
                    cumulative_discarded_prefix_mass = float(result.cumulative_discarded_prefix_mass)
                    kept_keys = tuple()
            elapsed_s = float(time.perf_counter() - start)
            by_case_and_variant[(str(case["case_name"]), str(variant_label))] = {
                "status": str(result_status),
                "logical_hat": int(logical_hat),
                "max_state_count": int(max_state_count),
                "cumulative_discarded_prefix_mass": float(cumulative_discarded_prefix_mass),
                "kept_keys": kept_keys,
            }
            rows.append(
                {
                    "case_name": str(case["case_name"]),
                    "benchmark_kind": str(case.get("benchmark_kind", "decode")),
                    "variant_label": str(variant_label),
                    "score_mode": str(score_mode),
                    "debug_pruning_engine": str(pruning_engine),
                    "repetitions": int(repetitions),
                    "elapsed_s": float(elapsed_s),
                    "mean_decode_ms": float(1000.0 * float(elapsed_s) / float(repetitions)),
                    "status": str(result_status),
                    "logical_hat": int(logical_hat),
                    "max_state_count": int(max_state_count),
                    "cumulative_discarded_prefix_mass": float(cumulative_discarded_prefix_mass),
                }
            )

    for case_name in sorted({str(row["case_name"]) for row in rows}):
        baseline = by_case_and_variant[(str(case_name), "baseline_default")]
        optimized = by_case_and_variant[(str(case_name), "optimized_default")]
        behavior_match = bool(
            str(baseline["status"]) == str(optimized["status"])
            and int(baseline["logical_hat"]) == int(optimized["logical_hat"])
            and tuple(int(key) for key in baseline.get("kept_keys", tuple()))
            == tuple(int(key) for key in optimized.get("kept_keys", tuple()))
            and np.isclose(
                float(baseline["cumulative_discarded_prefix_mass"]),
                float(optimized["cumulative_discarded_prefix_mass"]),
                atol=1e-12,
                rtol=0.0,
            )
        )
        for row in rows:
            if str(row["case_name"]) == str(case_name) and str(row["variant_label"]) in {"baseline_default", "optimized_default"}:
                row["default_behavior_match"] = bool(behavior_match)

    return {
        "rows": rows,
        "cases": [str(case["case_name"]) for case, _repetitions in cases],
    }


def format_progressive_smoke_benchmark_report(report: dict[str, object]) -> str:
    rows = list(report.get("rows", []))
    lines = [
        "case | kind | variant | engine | mean_decode_ms | status | logical_hat | default_behavior_match",
        "--- | --- | --- | --- | ---: | --- | ---: | ---",
    ]
    for row in rows:
        lines.append(
            f"{row['case_name']} | {row['benchmark_kind']} | {row['variant_label']} | {row['debug_pruning_engine']} | "
            f"{float(row['mean_decode_ms']):.3f} | {row['status']} | {int(row['logical_hat'])} | "
            f"{row.get('default_behavior_match', '')}"
        )
    return "\n".join(lines)


def _column_log_priors(column: ProgressiveColumn) -> tuple[float, ...]:
    if column.prior_log_probs is not None:
        return tuple(float(value) for value in column.prior_log_probs)
    return tuple(
        float("-inf") if float(prob) <= 0.0 else float(math.log(float(prob)))
        for prob in column.prior_probs
    )


def _normalize_clamp_assignments(
    columns: list[ProgressiveColumn],
    clamp_assignments: dict[int, int] | None,
) -> dict[int, int]:
    if clamp_assignments is None:
        return {}
    normalized: dict[int, int] = {}
    for raw_column_index, raw_local_state in dict(clamp_assignments).items():
        column_index = int(raw_column_index)
        local_state = int(raw_local_state)
        if int(column_index) < 0 or int(column_index) >= len(columns):
            raise ValueError(f"clamp column index out of range: {column_index}")
        state_count = int(len(columns[int(column_index)].prior_probs))
        if int(local_state) < 0 or int(local_state) >= int(state_count):
            raise ValueError(
                f"clamp local state out of range for column {column_index}: {local_state} not in [0, {state_count})"
            )
        log_priors = _column_log_priors(columns[int(column_index)])
        if not math.isfinite(float(log_priors[int(local_state)])):
            raise ValueError(f"clamp assignment has zero prior mass at column {column_index}, state {local_state}")
        normalized[int(column_index)] = int(local_state)
    return normalized


def _logaddexp_many(values: dict[int, float] | list[float] | tuple[float, ...]) -> float:
    if isinstance(values, dict):
        arr = np.asarray(list(values.values()), dtype=np.float64)
    else:
        arr = np.asarray(list(values), dtype=np.float64)
    if arr.size == 0:
        return float("-inf")
    return float(np.logaddexp.reduce(arr))


def _log_mass_map_total_prob(values: dict[int, float]) -> float:
    total_log_mass = float(_logaddexp_many(values))
    if not math.isfinite(float(total_log_mass)):
        return 0.0
    return float(math.exp(float(total_log_mass)))


def _forward_terminal_lookahead_bonus(
    *,
    det_mask: int,
    target_syndrome_int: int,
    payload: ForwardTerminalLookaheadPayload | None,
) -> float:
    if payload is None:
        return 0.0
    if (
        int(payload.projection_mask) == 0
        or int(payload.aligned_row_count) <= 0
        or not bool(payload.detector_log_mass)
        or not math.isfinite(float(payload.total_log_mass))
        or float(payload.bonus_weight) <= 0.0
        or float(payload.bonus_clip) <= 0.0
    ):
        return 0.0
    compatible_forward_det = (
        int(target_syndrome_int) ^ int(det_mask)
    ) & int(payload.projection_mask)
    log_mass = payload.detector_log_mass.get(int(compatible_forward_det))
    if log_mass is None or not math.isfinite(float(log_mass)):
        return 0.0
    conditional_logprob = float(log_mass) - float(payload.total_log_mass)
    raw_info = float(conditional_logprob) - float(payload.uniform_logprob)
    if not math.isfinite(float(raw_info)) or float(raw_info) <= 0.0:
        return 0.0
    return float(payload.bonus_weight) * min(float(payload.bonus_clip), float(raw_info))


def _blend_heuristic_summary_metric(old_value: float, new_value: float, mix_weight: float) -> float:
    mix = float(mix_weight)
    if float(mix) <= 0.0:
        return float(old_value)
    if float(mix) >= 1.0:
        return float(new_value)
    if not math.isfinite(float(old_value)):
        return float(new_value)
    if not math.isfinite(float(new_value)):
        return float(old_value)
    return (1.0 - float(mix)) * float(old_value) + float(mix) * float(new_value)


def _robust_location_scale(values: Sequence[float]) -> tuple[float, float]:
    finite_values = [float(value) for value in values if math.isfinite(float(value))]
    if not finite_values:
        return 0.0, float("inf")
    arr = np.asarray(finite_values, dtype=np.float64)
    center = float(np.quantile(arr, 0.50, method="linear"))
    lower = float(np.quantile(arr, 0.10, method="linear"))
    upper = float(np.quantile(arr, 0.90, method="linear"))
    spread = float(upper - lower)
    if not math.isfinite(float(spread)) or float(spread) <= 1e-9:
        return float(center), float("inf")
    return float(center), float(spread)


def _robust_normalized_value(value: float, *, center: float, scale: float) -> float:
    if not math.isfinite(float(value)):
        return float("nan")
    if not math.isfinite(float(scale)) or float(scale) <= 0.0:
        return 0.0
    return (float(value) - float(center)) / float(scale)


def _raw_forward_pairwise_extrinsic_delta(
    *,
    forward_pairwise_extrinsic_payload: ForwardPairwiseExtrinsicPayload | None,
    forward_det_mask: int,
    logical_mask: int,
) -> float:
    if (
        forward_pairwise_extrinsic_payload is None
        or not bool(forward_pairwise_extrinsic_payload.pair_logratio_by_logical)
    ):
        return 0.0
    pair_tables = forward_pairwise_extrinsic_payload.pair_logratio_by_logical.get(int(logical_mask))
    if not pair_tables:
        return 0.0
    delta = 0.0
    for (row_a, row_b), logratio_values in pair_tables.items():
        bit_a = 1 if ((int(forward_det_mask) >> int(row_a)) & 1) else 0
        bit_b = 1 if ((int(forward_det_mask) >> int(row_b)) & 1) else 0
        assignment_index = (int(bit_a) << 1) | int(bit_b)
        delta += float(logratio_values[int(assignment_index)])
    return float(
        max(
            -float(forward_pairwise_extrinsic_payload.correction_clip),
            min(float(forward_pairwise_extrinsic_payload.correction_clip), float(delta)),
        )
    )


def _forward_cut_state_pairwise_widen_extra_budget(mix_weight: float) -> int:
    if not math.isfinite(float(mix_weight)) or float(mix_weight) <= 0.0:
        return 0
    return max(1, int(math.ceil(float(FORWARD_CUT_STATE_PAIRWISE_WIDEN_MAX_EXTRA) * float(mix_weight))))


def _short_lookahead_log_mass(
    *,
    initial_det_mask: int,
    start_column_index: int,
    lookahead_depth: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    tail_parity_payload: FutureParityBoundaryPayload | None = None,
    forward_terminal_payload: ForwardTerminalLookaheadPayload | None = None,
) -> tuple[float, int]:
    if int(lookahead_depth) <= 0 or int(start_column_index) >= len(columns):
        return 0.0, 0

    stop_column_index = min(len(columns), int(start_column_index) + int(lookahead_depth))
    state_log_mass: dict[int, float] = {int(initial_det_mask): 0.0}
    transition_count = 0

    for column_index in range(int(start_column_index), int(stop_column_index)):
        column = columns[int(column_index)]
        close_mask = int(frontier.closing_masks[int(column_index)])
        active_mask = int(frontier.active_masks_after_column[int(column_index)])
        next_log_mass: dict[int, float] = {}
        for det_mask, log_mass in state_log_mass.items():
            for local_state, log_prior in enumerate(_column_log_priors(column)):
                if not math.isfinite(float(log_prior)):
                    continue
                transition_count += 1
                candidate_det = int(det_mask) ^ int(column.detector_response_masks[int(local_state)])
                if (((int(candidate_det) ^ int(target_syndrome_int)) & int(close_mask)) != 0):
                    continue
                next_det = int(candidate_det & int(active_mask))
                next_log_mass[int(next_det)] = _logaddexp_pair(
                    float(next_log_mass.get(int(next_det), float("-inf"))),
                    float(log_mass) + float(log_prior),
                )
        if not next_log_mass:
            return float("-inf"), int(transition_count)
        state_log_mass = next_log_mass
    if tail_parity_payload is None and forward_terminal_payload is None:
        return _logaddexp_many(state_log_mass), int(transition_count)

    scored_suffix_masses: list[float] = []
    for det_mask, log_mass in state_log_mass.items():
        terminal_bonus = float(
            _forward_terminal_lookahead_bonus(
                det_mask=int(det_mask),
                target_syndrome_int=int(target_syndrome_int),
                payload=forward_terminal_payload,
            )
        )
        tail_features = _future_mismatch_features_from_payload(
            det_mask=int(det_mask),
            target_syndrome_int=int(target_syndrome_int),
            payload=tail_parity_payload,
        ) if tail_parity_payload is not None else None
        tail_mass = 0.0
        if tail_features is not None:
            tail_mass = float(tail_features.parity_logodds)
            if not math.isfinite(float(tail_mass)):
                continue
        scored_suffix_masses.append(float(log_mass) + float(tail_mass) + float(terminal_bonus))
    if not scored_suffix_masses:
        return float("-inf"), int(transition_count)
    return _logaddexp_many(scored_suffix_masses), int(transition_count)


def _short_lookahead_logical_summary(
    *,
    initial_det_mask: int,
    start_column_index: int,
    lookahead_depth: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_observables: int = 1,
    tail_parity_payload: FutureParityBoundaryPayload | None = None,
    forward_cut_state_payload: ForwardCutStateLookaheadPayload | None = None,
    forward_pairwise_extrinsic_payload: ForwardPairwiseExtrinsicPayload | None = None,
) -> ShortLookaheadLogicalSummary:
    if int(num_observables) < 1:
        raise ValueError("num_observables must be >= 1")

    def _summarize_logical_log_mass(
        logical_log_mass: dict[int, float],
        *,
        transition_count: int,
        tail_summary: ShortLookaheadLogicalSummary | None = None,
        forward_summary: ShortLookaheadLogicalSummary | None = None,
    ) -> ShortLookaheadLogicalSummary:
        if not logical_log_mass:
            return ShortLookaheadLogicalSummary(
                best_logical_log_mass=float("-inf"),
                total_logical_log_mass=float("-inf"),
                top_logical_log_mass_gap=float("-inf"),
                transition_count=int(transition_count),
                tail_best_logical_log_mass=(
                    float(tail_summary.best_logical_log_mass)
                    if tail_summary is not None
                    else float("nan")
                ),
                tail_total_logical_log_mass=(
                    float(tail_summary.total_logical_log_mass)
                    if tail_summary is not None
                    else float("nan")
                ),
                tail_top_logical_log_mass_gap=(
                    float(tail_summary.top_logical_log_mass_gap)
                    if tail_summary is not None
                    else float("nan")
                ),
                forward_best_logical_log_mass=(
                    float(forward_summary.best_logical_log_mass)
                    if forward_summary is not None
                    else float("nan")
                ),
                forward_total_logical_log_mass=(
                    float(forward_summary.total_logical_log_mass)
                    if forward_summary is not None
                    else float("nan")
                ),
                forward_top_logical_log_mass_gap=(
                    float(forward_summary.top_logical_log_mass_gap)
                    if forward_summary is not None
                    else float("nan")
                ),
            )
        ranked_log_masses = sorted((float(value) for value in logical_log_mass.values()), reverse=True)
        best_logical_log_mass = float(ranked_log_masses[0])
        total_logical_log_mass = float(_logaddexp_many(ranked_log_masses))
        top_logical_log_mass_gap = (
            float("inf")
            if len(ranked_log_masses) <= 1
            else float(ranked_log_masses[0] - ranked_log_masses[1])
        )
        return ShortLookaheadLogicalSummary(
            best_logical_log_mass=float(best_logical_log_mass),
            total_logical_log_mass=float(total_logical_log_mass),
            top_logical_log_mass_gap=float(top_logical_log_mass_gap),
            transition_count=int(transition_count),
            tail_best_logical_log_mass=(
                float(tail_summary.best_logical_log_mass)
                if tail_summary is not None
                else float(best_logical_log_mass)
            ),
            tail_total_logical_log_mass=(
                float(tail_summary.total_logical_log_mass)
                if tail_summary is not None
                else float(total_logical_log_mass)
            ),
            tail_top_logical_log_mass_gap=(
                float(tail_summary.top_logical_log_mass_gap)
                if tail_summary is not None
                else float(top_logical_log_mass_gap)
            ),
            forward_best_logical_log_mass=(
                float(forward_summary.best_logical_log_mass)
                if forward_summary is not None
                else float("nan")
            ),
            forward_total_logical_log_mass=(
                float(forward_summary.total_logical_log_mass)
                if forward_summary is not None
                else float("nan")
            ),
            forward_top_logical_log_mass_gap=(
                float(forward_summary.top_logical_log_mass_gap)
                if forward_summary is not None
                else float("nan")
            ),
        )

    state_log_mass: dict[tuple[int, int], float] = {(int(initial_det_mask), 0): 0.0}
    transition_count = 0

    if int(start_column_index) < len(columns) and int(lookahead_depth) > 0:
        stop_column_index = min(len(columns), int(start_column_index) + int(lookahead_depth))
        for column_index in range(int(start_column_index), int(stop_column_index)):
            column = columns[int(column_index)]
            close_mask = int(frontier.closing_masks[int(column_index)])
            active_mask = int(frontier.active_masks_after_column[int(column_index)])
            next_log_mass: dict[tuple[int, int], float] = {}
            for (det_mask, logical_mask), log_mass in state_log_mass.items():
                for local_state, log_prior in enumerate(_column_log_priors(column)):
                    if not math.isfinite(float(log_prior)):
                        continue
                    transition_count += 1
                    candidate_det = int(det_mask) ^ int(column.detector_response_masks[int(local_state)])
                    if (((int(candidate_det) ^ int(target_syndrome_int)) & int(close_mask)) != 0):
                        continue
                    next_det = int(candidate_det & int(active_mask))
                    next_logical = int(logical_mask) ^ int(column.logical_response_masks[int(local_state)])
                    next_key = (int(next_det), int(next_logical))
                    next_log_mass[next_key] = _logaddexp_pair(
                        float(next_log_mass.get(next_key, float("-inf"))),
                        float(log_mass) + float(log_prior),
                    )
            if not next_log_mass:
                return ShortLookaheadLogicalSummary(
                    best_logical_log_mass=float("-inf"),
                    total_logical_log_mass=float("-inf"),
                    top_logical_log_mass_gap=float("-inf"),
                    transition_count=int(transition_count),
                )
            state_log_mass = next_log_mass

    def _tail_mass_for_leaf(det_mask: int) -> float | None:
        if tail_parity_payload is None:
            return 0.0
        tail_features = _future_mismatch_features_from_payload(
            det_mask=int(det_mask),
            target_syndrome_int=int(target_syndrome_int),
            payload=tail_parity_payload,
        )
        tail_mass = float(tail_features.parity_logodds)
        if not math.isfinite(float(tail_mass)):
            return None
        return float(tail_mass)

    def _build_tail_logical_log_mass() -> dict[int, float]:
        logical_log_mass: dict[int, float] = {}
        for (det_mask, logical_mask), log_mass in state_log_mass.items():
            tail_mass = _tail_mass_for_leaf(int(det_mask))
            if tail_mass is None:
                continue
            logical_log_mass[int(logical_mask)] = _logaddexp_pair(
                float(logical_log_mass.get(int(logical_mask), float("-inf"))),
                float(log_mass) + float(tail_mass),
            )
        return logical_log_mass

    def _build_forward_prefixed_logical_log_mass() -> dict[int, float]:
        logical_log_mass: dict[int, float] = {}
        for (det_mask, logical_mask), log_mass in state_log_mass.items():
            used_forward_prefix = False
            if forward_cut_state_payload is not None and (
                bool(forward_cut_state_payload.logical_entries_by_detector)
                or bool(forward_cut_state_payload.fallback_logical_entries_by_detector)
            ):
                compatible_forward_det = (
                    int(target_syndrome_int) ^ int(det_mask)
                ) & int(forward_cut_state_payload.projection_mask)
                forward_entries = forward_cut_state_payload.logical_entries_by_detector.get(int(compatible_forward_det))
                if not forward_entries and bool(forward_cut_state_payload.fallback_logical_entries_by_detector):
                    forward_entries = forward_cut_state_payload.fallback_logical_entries_by_detector.get(
                        int(compatible_forward_det)
                    )
                if forward_entries:
                    used_forward_prefix = True
                    for forward_logical_mask, forward_log_mass in forward_entries:
                        total_logical_mask = int(forward_logical_mask) ^ int(logical_mask)
                        logical_log_mass[int(total_logical_mask)] = _logaddexp_pair(
                            float(logical_log_mass.get(int(total_logical_mask), float("-inf"))),
                            float(log_mass) + float(forward_log_mass),
                        )
            if bool(used_forward_prefix):
                continue
            tail_mass = _tail_mass_for_leaf(int(det_mask))
            if tail_mass is None:
                continue
            logical_log_mass[int(logical_mask)] = _logaddexp_pair(
                float(logical_log_mass.get(int(logical_mask), float("-inf"))),
                float(log_mass) + float(tail_mass),
            )
        return logical_log_mass

    def _build_pairwise_extrinsic_logical_log_mass() -> dict[int, float]:
        logical_log_mass: dict[int, float] = {}
        for (det_mask, logical_mask), log_mass in state_log_mass.items():
            tail_mass = _tail_mass_for_leaf(int(det_mask))
            if tail_mass is None:
                continue
            compatible_forward_det = (
                int(target_syndrome_int) ^ int(det_mask)
            ) & int(forward_pairwise_extrinsic_payload.projection_mask)
            extrinsic_delta = float(forward_pairwise_extrinsic_payload.mix_weight) * float(
                _raw_forward_pairwise_extrinsic_delta(
                    forward_pairwise_extrinsic_payload=forward_pairwise_extrinsic_payload,
                    forward_det_mask=int(compatible_forward_det),
                    logical_mask=int(logical_mask),
                )
            )
            logical_log_mass[int(logical_mask)] = _logaddexp_pair(
                float(logical_log_mass.get(int(logical_mask), float("-inf"))),
                float(log_mass) + float(tail_mass) + float(extrinsic_delta),
            )
        return logical_log_mass

    tail_logical_log_mass = _build_tail_logical_log_mass()
    if (
        forward_pairwise_extrinsic_payload is not None
        and bool(forward_pairwise_extrinsic_payload.pair_logratio_by_logical)
        and float(forward_pairwise_extrinsic_payload.mix_weight) > 0.0
    ):
        pairwise_logical_log_mass = _build_pairwise_extrinsic_logical_log_mass()
        tail_summary = _summarize_logical_log_mass(
            tail_logical_log_mass,
            transition_count=int(transition_count),
        )
        pairwise_summary = _summarize_logical_log_mass(
            pairwise_logical_log_mass,
            transition_count=int(transition_count),
        )
        if str(forward_pairwise_extrinsic_payload.combination_mode) == "widen":
            return _summarize_logical_log_mass(
                tail_logical_log_mass,
                transition_count=int(transition_count),
                tail_summary=tail_summary,
                forward_summary=pairwise_summary,
            )
        return _summarize_logical_log_mass(
            pairwise_logical_log_mass,
            transition_count=int(transition_count),
            tail_summary=tail_summary,
            forward_summary=pairwise_summary,
        )
    if (
        forward_cut_state_payload is None
        or (
            not bool(forward_cut_state_payload.logical_entries_by_detector)
            and not bool(forward_cut_state_payload.fallback_logical_entries_by_detector)
        )
        or float(forward_cut_state_payload.mix_weight) <= 0.0
    ):
        return _summarize_logical_log_mass(
            tail_logical_log_mass,
            transition_count=int(transition_count),
        )
    forward_logical_log_mass = _build_forward_prefixed_logical_log_mass()
    tail_summary = _summarize_logical_log_mass(
        tail_logical_log_mass,
        transition_count=int(transition_count),
    )
    forward_summary = _summarize_logical_log_mass(
        forward_logical_log_mass,
        transition_count=int(transition_count),
    )
    if str(forward_cut_state_payload.combination_mode) == "resnorm":
        return ShortLookaheadLogicalSummary(
            best_logical_log_mass=float(tail_summary.best_logical_log_mass),
            total_logical_log_mass=float(tail_summary.total_logical_log_mass),
            top_logical_log_mass_gap=float(tail_summary.top_logical_log_mass_gap),
            transition_count=int(transition_count),
            tail_best_logical_log_mass=float(tail_summary.best_logical_log_mass),
            tail_total_logical_log_mass=float(tail_summary.total_logical_log_mass),
            tail_top_logical_log_mass_gap=float(tail_summary.top_logical_log_mass_gap),
            forward_best_logical_log_mass=float(forward_summary.best_logical_log_mass),
            forward_total_logical_log_mass=float(forward_summary.total_logical_log_mass),
            forward_top_logical_log_mass_gap=float(forward_summary.top_logical_log_mass_gap),
        )
    if float(forward_cut_state_payload.mix_weight) >= 1.0:
        return _summarize_logical_log_mass(
            forward_logical_log_mass,
            transition_count=int(transition_count),
            tail_summary=tail_summary,
            forward_summary=forward_summary,
        )
    mix_weight = float(forward_cut_state_payload.mix_weight)
    return ShortLookaheadLogicalSummary(
        best_logical_log_mass=float(
            _blend_heuristic_summary_metric(
                float(tail_summary.best_logical_log_mass),
                float(forward_summary.best_logical_log_mass),
                float(mix_weight),
            )
        ),
        total_logical_log_mass=float(
            _blend_heuristic_summary_metric(
                float(tail_summary.total_logical_log_mass),
                float(forward_summary.total_logical_log_mass),
                float(mix_weight),
            )
        ),
        top_logical_log_mass_gap=float(
            _blend_heuristic_summary_metric(
                float(tail_summary.top_logical_log_mass_gap),
                float(forward_summary.top_logical_log_mass_gap),
                float(mix_weight),
            )
        ),
        transition_count=int(transition_count),
        tail_best_logical_log_mass=float(tail_summary.best_logical_log_mass),
        tail_total_logical_log_mass=float(tail_summary.total_logical_log_mass),
        tail_top_logical_log_mass_gap=float(tail_summary.top_logical_log_mass_gap),
        forward_best_logical_log_mass=float(forward_summary.best_logical_log_mass),
        forward_total_logical_log_mass=float(forward_summary.total_logical_log_mass),
        forward_top_logical_log_mass_gap=float(forward_summary.top_logical_log_mass_gap),
    )


def _probe_short_lookahead_detectors(
    *,
    detector_keys: set[int],
    start_column_index: int,
    lookahead_depth: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    logical_lookahead_enabled: bool,
    num_observables: int = 1,
    forward_terminal_payload: ForwardTerminalLookaheadPayload | None = None,
    forward_cut_state_payload: ForwardCutStateLookaheadPayload | None = None,
    forward_pairwise_extrinsic_payload: ForwardPairwiseExtrinsicPayload | None = None,
) -> tuple[dict[int, float], dict[int, ShortLookaheadLogicalSummary], int]:
    if not detector_keys or int(lookahead_depth) <= 0 or int(start_column_index) >= len(columns):
        return {}, {}, 0

    lookahead_score_by_detector: dict[int, float] = {}
    logical_lookahead_summary_by_detector: dict[int, ShortLookaheadLogicalSummary] = {}
    transition_count = 0

    lookahead_tail_payload: FutureParityBoundaryPayload | None = None
    lookahead_stop_column_index = min(
        len(columns),
        int(start_column_index) + int(lookahead_depth),
    )
    if int(lookahead_stop_column_index) < len(columns):
        tail_boundary_column_index = int(lookahead_stop_column_index) - 1
        tail_active_mask = int(frontier.active_masks_after_column[int(tail_boundary_column_index)])
        lookahead_tail_payload = _build_future_parity_boundary_payload(
            frontier=frontier,
            boundary_column_index=int(tail_boundary_column_index),
            active_mask=int(tail_active_mask),
        )

    for det_key in sorted(int(det_key) for det_key in detector_keys):
        if bool(logical_lookahead_enabled):
            logical_summary = _short_lookahead_logical_summary(
                initial_det_mask=int(det_key),
                start_column_index=int(start_column_index),
                lookahead_depth=int(lookahead_depth),
                columns=columns,
                frontier=frontier,
                target_syndrome_int=int(target_syndrome_int),
                num_observables=int(num_observables),
                tail_parity_payload=lookahead_tail_payload,
                forward_cut_state_payload=forward_cut_state_payload,
                forward_pairwise_extrinsic_payload=forward_pairwise_extrinsic_payload,
            )
            logical_lookahead_summary_by_detector[int(det_key)] = logical_summary
            transition_count += int(logical_summary.transition_count)
        else:
            lookahead_log_mass, lookahead_transition_cost = _short_lookahead_log_mass(
                initial_det_mask=int(det_key),
                start_column_index=int(start_column_index),
                lookahead_depth=int(lookahead_depth),
                columns=columns,
                frontier=frontier,
                target_syndrome_int=int(target_syndrome_int),
                tail_parity_payload=lookahead_tail_payload,
                forward_terminal_payload=forward_terminal_payload,
            )
            lookahead_score_by_detector[int(det_key)] = float(lookahead_log_mass)
            transition_count += int(lookahead_transition_cost)
    return lookahead_score_by_detector, logical_lookahead_summary_by_detector, int(transition_count)


def _propagate_exact_columns(
    *,
    state_log_mass: dict[int, float],
    state_viterbi: dict[int, float],
    state_viterbi_rep_cost: dict[int, int] | None = None,
    state_min_nonzero_steps: dict[int, int] | None = None,
    start_column_index: int,
    stop_column_index: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int = 1,
    track_best_path: bool,
    clamp_assignments: dict[int, int],
    state_budget: int | None = None,
    transition_budget: int | None = None,
) -> tuple[
    str,
    dict[int, float],
    dict[int, float],
    dict[int, int],
    dict[int, int] | None,
    list[dict[int, tuple[int, int]]],
    list[int],
    list[int],
    int,
]:
    if int(start_column_index) >= int(stop_column_index):
        return (
            "ok",
            dict(state_log_mass),
            dict(state_viterbi),
            dict(state_viterbi_rep_cost),
            (None if state_min_nonzero_steps is None else dict(state_min_nonzero_steps)),
            [],
            [],
            [],
            int(start_column_index) - 1,
        )

    detector_mask_mask = (1 << int(num_detectors)) - 1
    tail_state_log_mass = {int(key): float(value) for key, value in state_log_mass.items()}
    tail_state_viterbi = {int(key): float(value) for key, value in state_viterbi.items()}
    tail_state_viterbi_rep_cost = (
        {int(key): int(value) for key, value in state_viterbi_rep_cost.items()}
        if state_viterbi_rep_cost is not None
        else {int(key): 0 for key in tail_state_viterbi.keys()}
    )
    tail_state_min_nonzero_steps = (
        None
        if state_min_nonzero_steps is None
        else {int(key): int(value) for key, value in state_min_nonzero_steps.items()}
    )
    tail_parent_chain: list[dict[int, tuple[int, int]]] = []
    tail_state_count_by_column: list[int] = []
    tail_transition_count_by_column: list[int] = []
    processed_stop_column_index = int(start_column_index) - 1
    cumulative_transition_count = 0

    for column_index in range(int(start_column_index), int(stop_column_index)):
        column = columns[int(column_index)]
        close_mask = int(frontier.closing_masks[int(column_index)])
        active_mask = int(frontier.active_masks_after_column[int(column_index)])
        log_priors = _column_log_priors(column)
        correction_masks = _column_correction_masks(column)
        next_log_mass: dict[int, float] = {}
        next_viterbi: dict[int, float] = {}
        next_viterbi_rep_cost: dict[int, int] = {}
        next_min_nonzero_steps: dict[int, int] | None = (
            {} if tail_state_min_nonzero_steps is not None else None
        )
        next_parent: dict[int, tuple[int, int]] = {}
        transition_count = 0

        for key, log_mass in tail_state_log_mass.items():
            det_mask = _unpack_detector_mask(state_key=int(key), detector_mask_mask=int(detector_mask_mask))
            logical_mask = _unpack_logical_mask(
                state_key=int(key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            correction_mask = _unpack_correction_mask(
                state_key=int(key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            prefix_nonzero_steps = (
                0
                if tail_state_min_nonzero_steps is None
                else int(tail_state_min_nonzero_steps[int(key)])
            )
            viterbi_mass = float(tail_state_viterbi[int(key)])
            viterbi_rep_cost = int(tail_state_viterbi_rep_cost.get(int(key), 0))
            forced_local_state = clamp_assignments.get(int(column_index))
            if forced_local_state is None:
                state_iter = enumerate(log_priors)
            else:
                state_iter = ((int(forced_local_state), float(log_priors[int(forced_local_state)])),)
            for local_state, log_prior in state_iter:
                if not math.isfinite(float(log_prior)):
                    continue
                transition_count += 1
                candidate_det = int(det_mask) ^ int(column.detector_response_masks[int(local_state)])
                if (((int(candidate_det) ^ int(target_syndrome_int)) & int(close_mask)) != 0):
                    continue
                next_det = int(candidate_det & int(active_mask))
                next_logical = int(logical_mask) ^ int(column.logical_response_masks[int(local_state)])
                next_correction = int(correction_mask) ^ int(correction_masks[int(local_state)])
                next_key = _pack_state_key(
                    det_mask=int(next_det),
                    logical_mask=int(next_logical),
                    num_detectors=int(num_detectors),
                    num_observables=int(num_observables),
                    correction_mask=int(next_correction),
                )
                new_log_mass = float(log_mass) + float(log_prior)
                next_log_mass[int(next_key)] = _logaddexp_pair(
                    float(next_log_mass.get(int(next_key), float("-inf"))),
                    float(new_log_mass),
                )
                if next_min_nonzero_steps is not None:
                    new_prefix_nonzero_steps = int(prefix_nonzero_steps) + int(
                        _local_state_nonzero_step_cost(int(local_state))
                    )
                    best_so_far = next_min_nonzero_steps.get(int(next_key))
                    if best_so_far is None or int(new_prefix_nonzero_steps) < int(best_so_far):
                        next_min_nonzero_steps[int(next_key)] = int(new_prefix_nonzero_steps)
                new_viterbi = float(viterbi_mass) + float(log_prior)
                new_viterbi_rep_cost = int(viterbi_rep_cost) + int(
                    _local_state_nonzero_step_cost(int(local_state))
                )
                best_viterbi_so_far = float(next_viterbi.get(int(next_key), float("-inf")))
                best_rep_cost_so_far = int(next_viterbi_rep_cost.get(int(next_key), sys.maxsize))
                if float(new_viterbi) > float(best_viterbi_so_far) or (
                    math.isclose(float(new_viterbi), float(best_viterbi_so_far), rel_tol=0.0, abs_tol=1e-15)
                    and int(new_viterbi_rep_cost) < int(best_rep_cost_so_far)
                ):
                    next_viterbi[int(next_key)] = float(new_viterbi)
                    next_viterbi_rep_cost[int(next_key)] = int(new_viterbi_rep_cost)
                    if bool(track_best_path):
                        next_parent[int(next_key)] = (int(key), int(local_state))

        if not next_log_mass:
            tail_state_count_by_column.append(0)
            tail_transition_count_by_column.append(int(transition_count))
            return (
                "no_path",
                {},
                {},
                {},
                (None if next_min_nonzero_steps is None else {}),
                tail_parent_chain,
                tail_state_count_by_column,
                tail_transition_count_by_column,
                int(column_index),
            )

        projected_state_count = int(len(next_log_mass))
        projected_transition_count = int(cumulative_transition_count) + int(transition_count)
        if (
            (state_budget is not None and int(state_budget) > 0 and int(projected_state_count) > int(state_budget))
            or (
                transition_budget is not None
                and int(transition_budget) > 0
                and int(projected_transition_count) > int(transition_budget)
            )
        ):
            return (
                "budget_exceeded",
                tail_state_log_mass,
                tail_state_viterbi,
                tail_state_viterbi_rep_cost,
                (
                    None
                    if tail_state_min_nonzero_steps is None
                    else dict(tail_state_min_nonzero_steps)
                ),
                tail_parent_chain,
                tail_state_count_by_column,
                tail_transition_count_by_column,
                int(processed_stop_column_index),
            )

        tail_state_log_mass = next_log_mass
        tail_state_viterbi = next_viterbi
        tail_state_viterbi_rep_cost = next_viterbi_rep_cost
        tail_state_min_nonzero_steps = next_min_nonzero_steps
        if bool(track_best_path):
            tail_parent_chain.append(next_parent)
        tail_state_count_by_column.append(int(len(tail_state_log_mass)))
        tail_transition_count_by_column.append(int(transition_count))
        processed_stop_column_index = int(column_index)
        cumulative_transition_count = int(projected_transition_count)

    return (
        "ok",
        tail_state_log_mass,
        tail_state_viterbi,
        tail_state_viterbi_rep_cost,
        (
            None
            if tail_state_min_nonzero_steps is None
            else dict(tail_state_min_nonzero_steps)
        ),
        tail_parent_chain,
        tail_state_count_by_column,
        tail_transition_count_by_column,
        int(processed_stop_column_index),
    )


def _exact_tail_solve(
    *,
    state_log_mass: dict[int, float],
    state_viterbi: dict[int, float],
    state_viterbi_rep_cost: dict[int, int] | None = None,
    state_min_nonzero_steps: dict[int, int] | None = None,
    start_column_index: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int = 1,
    track_best_path: bool,
    clamp_assignments: dict[int, int],
    state_budget: int | None = None,
    transition_budget: int | None = None,
) -> tuple[
    str,
    dict[int, float],
    dict[int, float],
    dict[int, int],
    dict[int, int] | None,
    list[dict[int, tuple[int, int]]],
    list[int],
    list[int],
    int,
]:
    return _propagate_exact_columns(
        state_log_mass=state_log_mass,
        state_viterbi=state_viterbi,
        state_viterbi_rep_cost=state_viterbi_rep_cost,
        state_min_nonzero_steps=state_min_nonzero_steps,
        start_column_index=int(start_column_index),
        stop_column_index=len(columns),
        columns=columns,
        frontier=frontier,
        target_syndrome_int=int(target_syndrome_int),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
        track_best_path=bool(track_best_path),
        clamp_assignments=clamp_assignments,
        state_budget=state_budget,
        transition_budget=transition_budget,
    )


def _syndrome_to_int(syndrome: int | np.ndarray | list[int] | tuple[int, ...]) -> int:
    if isinstance(syndrome, (int, np.integer)):
        return int(syndrome)
    out = 0
    for index, value in enumerate(np.asarray(syndrome, dtype=np.uint8).reshape(-1).tolist()):
        if int(value) != 0:
            out |= 1 << int(index)
    return int(out)


def _support_mask_from_detector_responses(detector_response_masks: tuple[int, ...]) -> int:
    out = 0
    for mask in detector_response_masks:
        out |= int(mask)
    return int(out)


def _support_rows_from_mask(mask: int) -> tuple[int, ...]:
    out: list[int] = []
    value = int(mask)
    while value != 0:
        lsb = int(value & -value)
        out.append(int(lsb.bit_length() - 1))
        value ^= int(lsb)
    return tuple(out)


def _column_support_rows(column: ProgressiveColumn) -> tuple[int, ...]:
    support_rows = tuple(int(row) for row in column.detector_support_rows)
    if support_rows:
        return support_rows
    return _support_rows_from_mask(int(column.detector_support_mask))


def _columns_from_factor_transitions(
    factor_transitions: Sequence[FactorTransition],
) -> list[ProgressiveColumn]:
    columns: list[ProgressiveColumn] = []
    for order_index, factor in enumerate(tuple(factor_transitions)):
        outcomes = tuple(factor.outcomes)
        if not outcomes:
            raise ValueError(f"factor {int(factor.factor_id)} has no outcomes")
        probabilities = tuple(float(outcome.probability) for outcome in outcomes)
        total = float(sum(probabilities))
        if abs(total - 1.0) > 1e-10:
            raise ValueError(
                f"factor {int(factor.factor_id)} outcome probabilities sum to {total:.18g}, not 1"
            )
        if any((not math.isfinite(p) or p < 0.0 or p > 1.0) for p in probabilities):
            raise ValueError(f"factor {int(factor.factor_id)} has invalid outcome probabilities")
        detector_masks = tuple(int(outcome.detector_mask) for outcome in outcomes)
        logical_masks = tuple(int(outcome.logical_mask) for outcome in outcomes)
        detector_support_mask = _support_mask_from_detector_responses(detector_masks)
        instruction_offset = (
            int(factor.instruction_offset)
            if factor.instruction_offset is not None
            else int(order_index)
        )
        label = str(factor.label) if str(factor.label) else f"factor_{int(factor.factor_id)}"
        columns.append(
            ProgressiveColumn(
                family="factorized_transition",
                index=int(order_index),
                label=label,
                instruction_offset=int(instruction_offset),
                prior_probs=tuple(float(p) for p in probabilities),
                detector_response_masks=tuple(int(mask) for mask in detector_masks),
                logical_response_masks=tuple(int(mask) for mask in logical_masks),
                detector_support_mask=int(detector_support_mask),
                prior_log_probs=tuple(
                    float("-inf") if float(p) <= 0.0 else float(math.log(float(p)))
                    for p in probabilities
                ),
                detector_support_rows=_support_rows_from_mask(int(detector_support_mask)),
                physical_time_index=(
                    int(factor.tick)
                    if factor.tick is not None
                    else int(order_index)
                ),
                original_column_index=int(factor.factor_id),
            )
        )
    return columns


def _allowed_detector_distribution(
    *,
    column: ProgressiveColumn,
    forced_local_state: int | None,
) -> tuple[tuple[float, int], ...]:
    if forced_local_state is not None:
        return ((1.0, int(column.detector_response_masks[int(forced_local_state)])),)
    out: list[tuple[float, int]] = []
    for local_state, prob in enumerate(column.prior_probs):
        if float(prob) <= 0.0:
            continue
        out.append((float(prob), int(column.detector_response_masks[int(local_state)])))
    return tuple(out)


def _clip_probabilities(values: tuple[float, ...], *, eps: float = PAIRTREE_EPS) -> tuple[float, ...]:
    clipped = [float(min(max(float(value), float(eps)), 1.0)) for value in values]
    total = float(sum(clipped))
    if not math.isfinite(float(total)) or float(total) <= 0.0:
        uniform = float(1.0 / float(max(1, len(clipped))))
        return tuple(float(uniform) for _ in clipped)
    return tuple(float(value) / float(total) for value in clipped)


def _clip_probability_matrix(values: np.ndarray, *, eps: float = PAIRTREE_EPS) -> np.ndarray:
    probabilities = np.asarray(values, dtype=np.float64)
    squeeze = False
    if int(probabilities.ndim) == 1:
        probabilities = probabilities.reshape(1, -1)
        squeeze = True
    clipped = np.clip(probabilities, float(eps), 1.0)
    totals = np.sum(clipped, axis=1, keepdims=True)
    invalid_rows = (~np.isfinite(totals[:, 0])) | (totals[:, 0] <= 0.0)
    if np.any(invalid_rows):
        clipped[invalid_rows, :] = float(1.0 / float(max(1, clipped.shape[1])))
        totals = np.sum(clipped, axis=1, keepdims=True)
    normalized = clipped / totals
    if bool(squeeze):
        return normalized[0]
    return normalized


def _column_pair_moment_factor(
    *,
    distribution: tuple[tuple[float, int], ...],
    row_u_mask: int,
    row_v_mask: int,
) -> float:
    factor = 0.0
    for prob, response_mask in distribution:
        parity = 1 if bool(int(response_mask) & int(row_u_mask)) ^ bool(int(response_mask) & int(row_v_mask)) else 0
        factor += float(prob) * (-1.0 if int(parity) != 0 else 1.0)
    return float(factor)


def _pairwise_mutual_information(
    *,
    pair_probs: tuple[float, float, float, float],
    single_u: tuple[float, float],
    single_v: tuple[float, float],
) -> float:
    total = 0.0
    for u in (0, 1):
        for v in (0, 1):
            pair_prob = float(pair_probs[(int(u) << 1) | int(v)])
            if float(pair_prob) <= 0.0:
                continue
            total += float(pair_prob) * (
                float(math.log(float(pair_prob)))
                - float(math.log(float(single_u[int(u)])))
                - float(math.log(float(single_v[int(v)])))
            )
    return float(total)


def _maximum_spanning_forest(
    *,
    rows: tuple[int, ...],
    edges: list[tuple[float, int, int, int, tuple[float, float, float, float]]],
) -> tuple[FuturePairtreeEdge, ...]:
    if not rows or not edges:
        return tuple()

    parent: dict[int, int] = {int(row): int(row) for row in rows}

    def _find(row: int) -> int:
        cursor = int(row)
        while int(parent[int(cursor)]) != int(cursor):
            parent[int(cursor)] = int(parent[int(parent[int(cursor)])])
            cursor = int(parent[int(cursor)])
        return int(cursor)

    def _union(row_u: int, row_v: int) -> bool:
        root_u = int(_find(int(row_u)))
        root_v = int(_find(int(row_v)))
        if int(root_u) == int(root_v):
            return False
        parent[int(root_v)] = int(root_u)
        return True

    selected: list[FuturePairtreeEdge] = []
    ranked_edges = sorted(
        edges,
        key=lambda item: (float(item[0]), int(item[1]), -int(item[2]), -int(item[3])),
        reverse=True,
    )
    for weight, _shared_count, row_u, row_v, corrections in ranked_edges:
        if not math.isfinite(float(weight)):
            continue
        if not _union(int(row_u), int(row_v)):
            continue
        selected.append(
            FuturePairtreeEdge(
                row_u=int(row_u),
                row_v=int(row_v),
                row_u_mask=1 << int(row_u),
                row_v_mask=1 << int(row_v),
                log_correction_by_pattern=tuple(float(value) for value in corrections),
            )
        )
    return tuple(selected)


def _maximum_weight_greedy_matching(
    *,
    rows: tuple[int, ...],
    edges: list[tuple[float, int, int, int, tuple[float, float, float, float]]],
) -> tuple[FuturePairtreeEdge, ...]:
    if not rows or not edges:
        return tuple()

    matched_rows: set[int] = set()
    selected: list[FuturePairtreeEdge] = []
    ranked_edges = sorted(
        edges,
        key=lambda item: (float(item[0]), int(item[1]), -int(item[2]), -int(item[3])),
        reverse=True,
    )
    for weight, _shared_count, row_u, row_v, corrections in ranked_edges:
        if not math.isfinite(float(weight)):
            continue
        if int(row_u) in matched_rows or int(row_v) in matched_rows:
            continue
        matched_rows.add(int(row_u))
        matched_rows.add(int(row_v))
        selected.append(
            FuturePairtreeEdge(
                row_u=int(row_u),
                row_v=int(row_v),
                row_u_mask=1 << int(row_u),
                row_v_mask=1 << int(row_v),
                log_correction_by_pattern=tuple(float(value) for value in corrections),
            )
        )
    return tuple(selected)


def _improve_pairlogodds_matching_2opt(
    *,
    selected_candidate_indices: tuple[int, ...],
    local_u: np.ndarray,
    local_v: np.ndarray,
    objective_weights: np.ndarray,
    num_local_rows: int,
    candidate_index_by_pair: dict[tuple[int, int], int],
    rank_by_candidate_index: dict[int, int],
) -> list[int]:
    selected = [int(index) for index in selected_candidate_indices]
    if not selected:
        return []

    objective = np.asarray(objective_weights, dtype=np.float64)

    def _pair_key(a: int, b: int) -> tuple[int, int]:
        return (int(a), int(b)) if int(a) < int(b) else (int(b), int(a))

    def _candidate_for(a: int, b: int) -> int | None:
        candidate_index = candidate_index_by_pair.get(_pair_key(int(a), int(b)))
        if candidate_index is None:
            return None
        if not math.isfinite(float(objective[int(candidate_index)])):
            return None
        return int(candidate_index)

    max_iterations = max(1, int(4 * len(selected) + int(num_local_rows)))
    tolerance = 1.0e-12
    for _iteration in range(int(max_iterations)):
        selected_set = {int(index) for index in selected}
        matched_rows: set[int] = set()
        for candidate_index in selected:
            matched_rows.add(int(local_u[int(candidate_index)]))
            matched_rows.add(int(local_v[int(candidate_index)]))
        unmatched_rows = tuple(
            int(row) for row in range(int(num_local_rows)) if int(row) not in matched_rows
        )

        best_delta = float(tolerance)
        best_one_swap: tuple[int, int] | None = None
        best_two_swap: tuple[int, int, int, int] | None = None

        if unmatched_rows:
            for pos, old_candidate in enumerate(selected):
                old_weight = float(objective[int(old_candidate)])
                a = int(local_u[int(old_candidate)])
                b = int(local_v[int(old_candidate)])
                for free_row in unmatched_rows:
                    for kept_row in (a, b):
                        new_candidate = _candidate_for(int(kept_row), int(free_row))
                        if new_candidate is None or int(new_candidate) in selected_set:
                            continue
                        delta = float(objective[int(new_candidate)]) - float(old_weight)
                        if float(delta) > float(best_delta):
                            best_delta = float(delta)
                            best_one_swap = (int(pos), int(new_candidate))
                            best_two_swap = None

        for pos_a in range(len(selected)):
            candidate_a = int(selected[int(pos_a)])
            row_a0 = int(local_u[int(candidate_a)])
            row_a1 = int(local_v[int(candidate_a)])
            weight_a = float(objective[int(candidate_a)])
            for pos_b in range(int(pos_a) + 1, len(selected)):
                candidate_b = int(selected[int(pos_b)])
                row_b0 = int(local_u[int(candidate_b)])
                row_b1 = int(local_v[int(candidate_b)])
                weight_b = float(objective[int(candidate_b)])
                for new_pair_a, new_pair_b in (
                    ((row_a0, row_b0), (row_a1, row_b1)),
                    ((row_a0, row_b1), (row_a1, row_b0)),
                ):
                    new_candidate_a = _candidate_for(int(new_pair_a[0]), int(new_pair_a[1]))
                    new_candidate_b = _candidate_for(int(new_pair_b[0]), int(new_pair_b[1]))
                    if new_candidate_a is None or new_candidate_b is None:
                        continue
                    if int(new_candidate_a) == int(new_candidate_b):
                        continue
                    blocked = selected_set - {int(candidate_a), int(candidate_b)}
                    if int(new_candidate_a) in blocked or int(new_candidate_b) in blocked:
                        continue
                    delta = (
                        float(objective[int(new_candidate_a)])
                        + float(objective[int(new_candidate_b)])
                        - float(weight_a)
                        - float(weight_b)
                    )
                    if float(delta) > float(best_delta):
                        best_delta = float(delta)
                        best_one_swap = None
                        best_two_swap = (
                            int(pos_a),
                            int(pos_b),
                            int(new_candidate_a),
                            int(new_candidate_b),
                        )

        if best_two_swap is not None:
            pos_a, pos_b, new_candidate_a, new_candidate_b = best_two_swap
            selected[int(pos_a)] = int(new_candidate_a)
            selected[int(pos_b)] = int(new_candidate_b)
            continue
        if best_one_swap is not None:
            pos, new_candidate = best_one_swap
            selected[int(pos)] = int(new_candidate)
            continue
        break

    return sorted(
        (int(index) for index in selected),
        key=lambda index: (int(rank_by_candidate_index.get(int(index), 10**9)), int(index)),
    )


def _support_gate_allowed_patterns(
    *,
    projected_rows: tuple[int, ...],
    active_rows: tuple[int, ...],
    component_columns: tuple[int, ...],
    columns: list[ProgressiveColumn],
    target_syndrome_int: int,
    clamp_assignments: dict[int, int],
) -> tuple[bool, ...]:
    min_nonzero_steps = _support_gate_min_nonzero_steps_by_active_pattern(
        projected_rows=projected_rows,
        active_rows=active_rows,
        component_columns=component_columns,
        columns=columns,
        target_syndrome_int=target_syndrome_int,
        clamp_assignments=clamp_assignments,
    )
    return tuple(int(value) >= 0 for value in min_nonzero_steps)


def _support_gate_min_nonzero_steps_by_active_pattern(
    *,
    projected_rows: tuple[int, ...],
    active_rows: tuple[int, ...],
    component_columns: tuple[int, ...],
    columns: list[ProgressiveColumn],
    target_syndrome_int: int,
    clamp_assignments: dict[int, int],
) -> tuple[int, ...]:
    if not projected_rows:
        return (0,)

    row_to_local = {int(row): int(local_index) for local_index, row in enumerate(projected_rows)}
    active_row_set = {int(row) for row in active_rows}
    projected_size = 1 << int(len(projected_rows))
    active_pattern_count = 1 << int(len(active_rows))
    unreachable_cost = int(len(component_columns)) + 1
    min_nonzero_steps = np.full(int(projected_size), int(unreachable_cost), dtype=np.int32)
    min_nonzero_steps[0] = 0
    for future_column_index in component_columns:
        column = columns[int(future_column_index)]
        log_priors = _column_log_priors(column)
        forced_local_state = clamp_assignments.get(int(future_column_index))
        if forced_local_state is None:
            state_iter = enumerate(log_priors)
        else:
            state_iter = ((int(forced_local_state), float(log_priors[int(forced_local_state)])),)
        min_step_cost_by_local_mask: dict[int, int] = {}
        for local_state, log_prior in state_iter:
            if not math.isfinite(float(log_prior)):
                continue
            local_mask = _project_mask_to_rows(
                int(column.detector_response_masks[int(local_state)]),
                row_to_local,
            )
            step_cost = 0 if int(local_state) == 0 else 1
            best_so_far = min_step_cost_by_local_mask.get(int(local_mask))
            if best_so_far is None or int(step_cost) < int(best_so_far):
                min_step_cost_by_local_mask[int(local_mask)] = int(step_cost)
        if not min_step_cost_by_local_mask:
            return tuple(-1 for _ in range(int(active_pattern_count)))
        current_indices = np.flatnonzero(min_nonzero_steps < int(unreachable_cost)).astype(np.int64, copy=False)
        next_min_nonzero_steps = np.full(int(projected_size), int(unreachable_cost), dtype=np.int32)
        for local_mask, step_cost in min_step_cost_by_local_mask.items():
            candidate_indices = np.bitwise_xor(current_indices, int(local_mask))
            candidate_costs = min_nonzero_steps[current_indices] + int(step_cost)
            np.minimum.at(next_min_nonzero_steps, candidate_indices, candidate_costs)
        min_nonzero_steps = next_min_nonzero_steps

    active_row_to_local = {int(row): int(local_index) for local_index, row in enumerate(active_rows)}
    target_untouched_pattern = 0
    untouched_projected_rows: list[tuple[int, int]] = []
    for projected_local_index, row in enumerate(projected_rows):
        if int(row) in active_row_set:
            continue
        untouched_projected_rows.append((int(projected_local_index), int(row)))
        if (int(target_syndrome_int) & (1 << int(row))) != 0:
            target_untouched_pattern |= 1 << int(projected_local_index)

    min_nonzero_steps_by_active_pattern = [int(unreachable_cost) for _ in range(int(active_pattern_count))]
    for full_pattern in np.flatnonzero(min_nonzero_steps < int(unreachable_cost)).astype(np.int64, copy=False):
        if any(
            (((int(full_pattern) >> int(projected_local_index)) & 1) != ((int(target_untouched_pattern) >> int(projected_local_index)) & 1))
            for projected_local_index, _row in untouched_projected_rows
        ):
            continue
        active_pattern = 0
        for row in active_rows:
            projected_local_index = int(row_to_local[int(row)])
            if ((int(full_pattern) >> int(projected_local_index)) & 1) != 0:
                active_pattern |= 1 << int(active_row_to_local[int(row)])
        min_nonzero_steps_by_active_pattern[int(active_pattern)] = min(
            int(min_nonzero_steps_by_active_pattern[int(active_pattern)]),
            int(min_nonzero_steps[int(full_pattern)]),
        )
    return tuple(
        -1 if int(value) >= int(unreachable_cost) else int(value)
        for value in min_nonzero_steps_by_active_pattern
    )


def _build_future_pairtree_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
    target_syndrome_int: int,
    clamp_assignments: dict[int, int],
    include_support_gate: bool,
    max_support_gate_rows: int = PAIRTREE_SUPPORT_GATE_MAX_ROWS,
) -> FuturePairtreeHeuristicPayload:
    if int(active_mask) == 0 or int(column_index) + 1 >= len(columns):
        return FuturePairtreeHeuristicPayload(
            active_rows=tuple(),
            singleton_logodds_by_row=tuple(),
            tree_edges=tuple(),
            matching_edges=tuple(),
            support_gate_components=tuple(),
            support_gate_precomputed=bool(include_support_gate),
            support_gate_exact=True,
        )

    active_rows = tuple(int(row) for row in _support_rows_from_mask(int(active_mask)))
    active_row_set = {int(row) for row in active_rows}
    active_row_to_local = {int(row): int(local_index) for local_index, row in enumerate(active_rows)}
    row_mu: dict[int, float] = {int(row): 1.0 for row in active_rows}
    active_record_indices_by_row: dict[int, list[int]] = {int(row): [] for row in active_rows}
    future_active_records: list[tuple[tuple[float, int], ...]] = []
    future_column_rows: dict[int, tuple[int, ...]] = {}
    row_to_future_cols: dict[int, list[int]] = {}
    candidate_shared_counts: dict[tuple[int, int], int] = {}

    for future_column_index in range(int(column_index) + 1, len(columns)):
        distribution = _allowed_detector_distribution(
            column=columns[int(future_column_index)],
            forced_local_state=clamp_assignments.get(int(future_column_index)),
        )
        if not distribution:
            continue
        support_mask = 0
        for _prob, response_mask in distribution:
            support_mask |= int(response_mask)
        support_rows = _support_rows_from_mask(int(support_mask))
        if support_rows:
            future_column_rows[int(future_column_index)] = tuple(int(row) for row in support_rows)
            for row in support_rows:
                row_to_future_cols.setdefault(int(row), []).append(int(future_column_index))
        active_distribution: list[tuple[float, int]] = []
        active_touched_rows: set[int] = set()
        for prob, response_mask in distribution:
            active_local_mask = 0
            active_support_mask = int(response_mask) & int(active_mask)
            if int(active_support_mask) != 0:
                for row in _support_rows_from_mask(int(active_support_mask)):
                    active_local_mask |= 1 << int(active_row_to_local[int(row)])
                    active_touched_rows.add(int(row))
            active_distribution.append((float(prob), int(active_local_mask)))
        if not active_touched_rows:
            continue
        record_index = int(len(future_active_records))
        future_active_records.append(tuple((float(prob), int(local_mask)) for prob, local_mask in active_distribution))
        touched_rows_sorted = tuple(sorted(int(row) for row in active_touched_rows))
        for row in touched_rows_sorted:
            row_bit = 1 << int(active_row_to_local[int(row)])
            factor = 0.0
            for prob, local_mask in active_distribution:
                factor += float(prob) * (-1.0 if (int(local_mask) & int(row_bit)) != 0 else 1.0)
            row_mu[int(row)] *= float(factor)
            active_record_indices_by_row[int(row)].append(int(record_index))
        if len(touched_rows_sorted) >= 2:
            for local_u in range(len(touched_rows_sorted)):
                for local_v in range(int(local_u) + 1, len(touched_rows_sorted)):
                    pair = (int(touched_rows_sorted[int(local_u)]), int(touched_rows_sorted[int(local_v)]))
                    candidate_shared_counts[int(pair[0]), int(pair[1])] = int(
                        candidate_shared_counts.get((int(pair[0]), int(pair[1])), 0)
                    ) + 1

    singleton_probs_by_row: dict[int, tuple[float, float]] = {}
    singleton_logodds_by_row: list[float] = []
    for row in active_rows:
        mu = float(min(max(float(row_mu[int(row)]), -1.0), 1.0))
        # For a parity bit with moment mu = E[(-1)^x], the singleton parity masses are
        # P(x=0) = (1 + mu) / 2 and P(x=1) = (1 - mu) / 2.
        even_prob, odd_prob = _clip_probabilities(
            (
                0.5 * (1.0 + float(mu)),
                0.5 * (1.0 - float(mu)),
            ),
            eps=float(PAIRTREE_EPS),
        )
        singleton_probs_by_row[int(row)] = (float(even_prob), float(odd_prob))
        singleton_logodds_by_row.append(float(math.log(float(odd_prob))) - float(math.log(float(even_prob))))

    tree_edges: tuple[FuturePairtreeEdge, ...] = tuple()
    matching_edges: tuple[FuturePairtreeEdge, ...] = tuple()
    if candidate_shared_counts:
        weighted_edges: list[tuple[float, int, int, int, tuple[float, float, float, float]]] = []
        for (row_u, row_v), shared_count in candidate_shared_counts.items():
            relevant_record_indices = sorted(
                {
                    int(record_index)
                    for record_index in active_record_indices_by_row[int(row_u)]
                }.union(
                    int(record_index)
                    for record_index in active_record_indices_by_row[int(row_v)]
                )
            )
            row_u_bit = 1 << int(active_row_to_local[int(row_u)])
            row_v_bit = 1 << int(active_row_to_local[int(row_v)])
            mu_rs = 1.0
            for record_index in relevant_record_indices:
                mu_rs *= _column_pair_moment_factor(
                    distribution=future_active_records[int(record_index)],
                    row_u_mask=int(row_u_bit),
                    row_v_mask=int(row_v_bit),
                )
            mu_u = float(min(max(float(row_mu[int(row_u)]), -1.0), 1.0))
            mu_v = float(min(max(float(row_mu[int(row_v)]), -1.0), 1.0))
            # Pair probabilities follow the standard parity-moment identity
            # P(u,v) = 1/4 * (1 + (-1)^u mu_u + (-1)^v mu_v + (-1)^(u xor v) mu_uv).
            pair_probs = _clip_probabilities(
                (
                    0.25 * (1.0 + float(mu_u) + float(mu_v) + float(mu_rs)),
                    0.25 * (1.0 + float(mu_u) - float(mu_v) - float(mu_rs)),
                    0.25 * (1.0 - float(mu_u) + float(mu_v) - float(mu_rs)),
                    0.25 * (1.0 - float(mu_u) - float(mu_v) + float(mu_rs)),
                ),
                eps=float(PAIRTREE_EPS),
            )
            single_u = singleton_probs_by_row[int(row_u)]
            single_v = singleton_probs_by_row[int(row_v)]
            corrections = tuple(
                float(math.log(float(pair_probs[(int(u) << 1) | int(v)])))
                - float(math.log(float(single_u[int(u)])))
                - float(math.log(float(single_v[int(v)])))
                for u in (0, 1)
                for v in (0, 1)
            )
            mutual_information = _pairwise_mutual_information(
                pair_probs=tuple(float(value) for value in pair_probs),
                single_u=tuple(float(value) for value in single_u),
                single_v=tuple(float(value) for value in single_v),
            )
            weight = float(mutual_information) if math.isfinite(float(mutual_information)) else float(shared_count)
            weighted_edges.append(
                (
                    float(weight),
                    int(shared_count),
                    int(row_u),
                    int(row_v),
                    tuple(float(value) for value in corrections),
                )
            )
        tree_edges = _maximum_spanning_forest(
            rows=tuple(int(row) for row in active_rows),
            edges=weighted_edges,
        )
        matching_edges = _maximum_weight_greedy_matching(
            rows=tuple(int(row) for row in active_rows),
            edges=weighted_edges,
        )

    support_gate_components: list[FutureSupportGateComponent] = []
    support_gate_exact = True
    if bool(include_support_gate):
        visited_rows: set[int] = set()
        for start_row in active_rows:
            if int(start_row) in visited_rows:
                continue
            row_stack = [int(start_row)]
            component_rows: set[int] = set()
            component_cols: set[int] = set()
            while row_stack:
                row = int(row_stack.pop())
                if int(row) in visited_rows:
                    continue
                visited_rows.add(int(row))
                component_rows.add(int(row))
                for future_column_index in row_to_future_cols.get(int(row), []):
                    if int(future_column_index) not in component_cols:
                        component_cols.add(int(future_column_index))
                    for neighbor_row in future_column_rows.get(int(future_column_index), ()):
                        if int(neighbor_row) not in visited_rows:
                            row_stack.append(int(neighbor_row))
            component_rows_tuple = tuple(sorted(int(row) for row in component_rows))
            component_columns_tuple = tuple(sorted(int(col) for col in component_cols))
            component_active_rows = tuple(int(row) for row in component_rows_tuple if int(row) in active_row_set)
            if not component_active_rows:
                continue
            projected_rows = component_rows_tuple
            exact_component = True
            if int(len(projected_rows)) > int(max_support_gate_rows):
                # The preferred gate is exact on the full connected future-row component.
                # When that component is too large, keep an exact projected block around the
                # active rows and their immediate future neighbors instead of paying full cost.
                projected_row_set = {int(row) for row in component_active_rows}
                for future_column_index in component_columns_tuple:
                    column_rows = future_column_rows.get(int(future_column_index), tuple())
                    if not any(int(row) in projected_row_set for row in column_rows):
                        continue
                    projected_row_set.update(int(row) for row in column_rows)
                if int(len(projected_row_set)) > int(max_support_gate_rows):
                    prioritized_rows = sorted(
                        (int(row) for row in projected_row_set if int(row) not in active_row_set),
                        key=lambda row: (
                            int(frontier.detector_first_column[int(row)]),
                            int(frontier.detector_last_column[int(row)]),
                            int(row),
                        ),
                    )
                    projected_row_set = {int(row) for row in component_active_rows}
                    for row in prioritized_rows:
                        if int(len(projected_row_set)) >= int(max_support_gate_rows):
                            break
                        projected_row_set.add(int(row))
                projected_rows = tuple(sorted(int(row) for row in projected_row_set))
                exact_component = int(len(projected_rows)) == int(len(component_rows_tuple))
            if int(len(projected_rows)) < int(len(component_active_rows)) or int(len(projected_rows)) > int(max_support_gate_rows):
                support_gate_exact = False
                continue
            if not exact_component:
                support_gate_exact = False
            min_nonzero_steps_by_active_pattern = _support_gate_min_nonzero_steps_by_active_pattern(
                projected_rows=tuple(int(row) for row in projected_rows),
                active_rows=tuple(int(row) for row in component_active_rows),
                component_columns=tuple(int(col) for col in component_columns_tuple),
                columns=columns,
                target_syndrome_int=int(target_syndrome_int),
                clamp_assignments=clamp_assignments,
            )
            allowed_active_patterns = tuple(
                int(value) >= 0 for value in min_nonzero_steps_by_active_pattern
            )
            support_gate_components.append(
                FutureSupportGateComponent(
                    active_rows=tuple(int(row) for row in component_active_rows),
                    allowed_active_patterns=tuple(bool(value) for value in allowed_active_patterns),
                    projected_row_count=int(len(projected_rows)),
                    exact=bool(exact_component),
                    min_nonzero_steps_by_active_pattern=tuple(
                        int(value) for value in min_nonzero_steps_by_active_pattern
                    ),
                )
            )

    return FuturePairtreeHeuristicPayload(
        active_rows=tuple(int(row) for row in active_rows),
        singleton_logodds_by_row=tuple(float(value) for value in singleton_logodds_by_row),
        tree_edges=tuple(tree_edges),
        matching_edges=tuple(matching_edges),
        support_gate_components=tuple(support_gate_components),
        support_gate_precomputed=bool(include_support_gate),
        support_gate_exact=bool(support_gate_exact),
    )


def _build_future_pairlogodds_payload_from_state(
    *,
    active_rows: tuple[int, ...],
    row_mu: np.ndarray,
    pair_mu: np.ndarray,
    pair_shared_count: np.ndarray,
    pair_overlap_weight: np.ndarray | None = None,
    pair_selection: str = "mi",
    max_pairs: int = 0,
    allowed_pairs: Collection[tuple[int, int]] | None = None,
) -> FuturePairlogoddsHeuristicPayload:
    pair_selection_key = _normalize_pairlogodds_pair_selection(str(pair_selection))
    if str(pair_selection_key) not in PAIRLOGODDS_PAIR_SELECTION_CHOICES:
        raise ValueError(f"unsupported pairlogodds pair selection: {pair_selection!r}")
    base_pair_selection_key = _pairlogodds_base_pair_selection(str(pair_selection_key))
    if not active_rows:
        return FuturePairlogoddsHeuristicPayload(
            active_rows=tuple(),
            matching_edges=tuple(),
            unmatched_row_masks=tuple(),
            unmatched_row_logodds=tuple(),
            pair_selection=str(pair_selection_key),
            max_pairs=int(max(0, int(max_pairs))),
        )

    active_rows_array = np.asarray(active_rows, dtype=np.int32)
    singleton_mu = np.clip(np.asarray(row_mu[active_rows_array], dtype=np.float64), -1.0, 1.0)
    singleton_probs = _clip_probability_matrix(
        np.column_stack(
            (
                0.5 * (1.0 + singleton_mu),
                0.5 * (1.0 - singleton_mu),
            )
        ),
        eps=float(PAIRTREE_EPS),
    )
    singleton_logodds = np.asarray(
        np.log(singleton_probs[:, 1]) - np.log(singleton_probs[:, 0]),
        dtype=np.float64,
    )
    row_masks = tuple(1 << int(row) for row in active_rows_array.tolist())
    allowed_pair_set: frozenset[tuple[int, int]] | None = None
    if allowed_pairs is not None or str(pair_selection_key) == "atlas":
        allowed_pair_set = frozenset(
            _pairlogodds_normalized_pair(int(pair[0]), int(pair[1]))
            for pair in tuple(allowed_pairs or tuple())
        )

    matched_local = np.zeros(int(len(active_rows)), dtype=bool)
    fast_matching_edges: list[FuturePairlogoddsEdge] = []

    if int(len(active_rows)) >= 2:
        shared_counts_sub = np.asarray(
            pair_shared_count[np.ix_(active_rows_array, active_rows_array)],
            dtype=np.int32,
        )
        local_u_all, local_v_all = np.triu_indices(int(len(active_rows)), k=1)
        candidate_mask = np.asarray(shared_counts_sub[local_u_all, local_v_all] > 0, dtype=bool)
        if allowed_pair_set is not None and np.any(candidate_mask):
            allowed_mask = np.asarray(
                [
                    _pairlogodds_normalized_pair(
                        int(active_rows_array[int(local_u_index)]),
                        int(active_rows_array[int(local_v_index)]),
                    )
                    in allowed_pair_set
                    for local_u_index, local_v_index in zip(local_u_all.tolist(), local_v_all.tolist())
                ],
                dtype=bool,
            )
            candidate_mask = np.asarray(candidate_mask & allowed_mask, dtype=bool)
        if np.any(candidate_mask):
            local_u = np.asarray(local_u_all[candidate_mask], dtype=np.int32)
            local_v = np.asarray(local_v_all[candidate_mask], dtype=np.int32)
            shared_counts = np.asarray(shared_counts_sub[local_u, local_v], dtype=np.int32)
            if pair_overlap_weight is None:
                overlap_weights = np.zeros(int(len(local_u)), dtype=np.float64)
            else:
                pair_overlap_weight_sub = np.asarray(
                    pair_overlap_weight[np.ix_(active_rows_array, active_rows_array)],
                    dtype=np.float64,
                )
                overlap_weights = np.asarray(pair_overlap_weight_sub[local_u, local_v], dtype=np.float64)
            pair_mu_sub = np.asarray(
                pair_mu[np.ix_(active_rows_array, active_rows_array)],
                dtype=np.float64,
            )
            mu_u = singleton_mu[local_u]
            mu_v = singleton_mu[local_v]
            mu_uv = np.clip(np.asarray(pair_mu_sub[local_u, local_v], dtype=np.float64), -1.0, 1.0)
            pair_probs = _clip_probability_matrix(
                np.column_stack(
                    (
                        0.25 * (1.0 + mu_u + mu_v + mu_uv),
                        0.25 * (1.0 + mu_u - mu_v - mu_uv),
                        0.25 * (1.0 - mu_u + mu_v - mu_uv),
                        0.25 * (1.0 - mu_u - mu_v + mu_uv),
                    )
                ),
                eps=float(PAIRTREE_EPS),
            )
            log_single_u = np.log(singleton_probs[local_u][:, [0, 0, 1, 1]])
            log_single_v = np.log(singleton_probs[local_v][:, [0, 1, 0, 1]])
            log_pair_probs = np.log(pair_probs)
            corrections = np.asarray(log_pair_probs - log_single_u - log_single_v, dtype=np.float64)
            mutual_information = np.asarray(np.sum(pair_probs * corrections, axis=1), dtype=np.float64)
            weights = np.where(
                np.isfinite(mutual_information),
                mutual_information,
                np.asarray(shared_counts, dtype=np.float64),
            )
            candidate_row_u = np.asarray(active_rows_array[local_u], dtype=np.int32)
            candidate_row_v = np.asarray(active_rows_array[local_v], dtype=np.int32)
            if str(base_pair_selection_key) == "overlap":
                sort_order = np.lexsort(
                    (
                        candidate_row_v,
                        candidate_row_u,
                        -np.asarray(weights, dtype=np.float64),
                        -np.asarray(shared_counts, dtype=np.int64),
                        -np.asarray(overlap_weights, dtype=np.float64),
                    )
                )
                objective_weights = (
                    (np.asarray(overlap_weights, dtype=np.float64) * 1.0e9)
                    + (np.asarray(shared_counts, dtype=np.float64) * 1.0e3)
                    + np.asarray(weights, dtype=np.float64)
                )
            elif str(base_pair_selection_key) == "shared":
                sort_order = np.lexsort(
                    (
                        candidate_row_v,
                        candidate_row_u,
                        -np.asarray(weights, dtype=np.float64),
                        -np.asarray(overlap_weights, dtype=np.float64),
                        -np.asarray(shared_counts, dtype=np.int64),
                    )
                )
                objective_weights = (
                    (np.asarray(shared_counts, dtype=np.float64) * 1.0e9)
                    + (np.asarray(overlap_weights, dtype=np.float64) * 1.0e3)
                    + np.asarray(weights, dtype=np.float64)
                )
            elif str(base_pair_selection_key) == "shared_mi":
                sort_order = np.lexsort(
                    (
                        candidate_row_v,
                        candidate_row_u,
                        -np.asarray(weights, dtype=np.float64),
                        -np.asarray(shared_counts, dtype=np.int64),
                    )
                )
                objective_weights = (
                    (np.asarray(shared_counts, dtype=np.float64) * 1.0e9)
                    + np.asarray(weights, dtype=np.float64)
                )
            else:
                sort_order = np.lexsort(
                    (
                        candidate_row_v,
                        candidate_row_u,
                        -np.asarray(shared_counts, dtype=np.int64),
                        -np.asarray(weights, dtype=np.float64),
                    )
                )
                objective_weights = np.asarray(weights, dtype=np.float64)
            candidate_index_by_pair: dict[tuple[int, int], int] = {
                (
                    min(int(local_u[int(candidate_index)]), int(local_v[int(candidate_index)])),
                    max(int(local_u[int(candidate_index)]), int(local_v[int(candidate_index)])),
                ): int(candidate_index)
                for candidate_index in range(int(len(local_u)))
            }
            rank_by_candidate_index = {
                int(candidate_index): int(rank)
                for rank, candidate_index in enumerate(np.asarray(sort_order, dtype=np.int32).tolist())
            }
            selected_candidate_indices: list[int] = []
            for candidate_index in sort_order.tolist():
                if int(max_pairs) > 0 and len(selected_candidate_indices) >= int(max_pairs):
                    break
                local_index_u = int(local_u[int(candidate_index)])
                local_index_v = int(local_v[int(candidate_index)])
                if bool(matched_local[int(local_index_u)]) or bool(matched_local[int(local_index_v)]):
                    continue
                matched_local[int(local_index_u)] = True
                matched_local[int(local_index_v)] = True
                selected_candidate_indices.append(int(candidate_index))
            if selected_candidate_indices and _pairlogodds_uses_2opt(str(pair_selection_key)):
                selected_candidate_indices = _improve_pairlogodds_matching_2opt(
                    selected_candidate_indices=tuple(int(index) for index in selected_candidate_indices),
                    local_u=np.asarray(local_u, dtype=np.int32),
                    local_v=np.asarray(local_v, dtype=np.int32),
                    objective_weights=np.asarray(objective_weights, dtype=np.float64),
                    num_local_rows=int(len(active_rows)),
                    candidate_index_by_pair=dict(candidate_index_by_pair),
                    rank_by_candidate_index=dict(rank_by_candidate_index),
                )
                matched_local[:] = False
                for candidate_index in selected_candidate_indices:
                    matched_local[int(local_u[int(candidate_index)])] = True
                    matched_local[int(local_v[int(candidate_index)])] = True
            fast_matching_edges = []
            for candidate_index in selected_candidate_indices:
                local_index_u = int(local_u[int(candidate_index)])
                local_index_v = int(local_v[int(candidate_index)])
                correction_by_pattern = np.asarray(corrections[int(candidate_index)], dtype=np.float64)
                corr_00 = float(correction_by_pattern[0])
                fast_matching_edges.append(
                    FuturePairlogoddsEdge(
                        row_u_mask=int(row_masks[int(local_index_u)]),
                        row_v_mask=int(row_masks[int(local_index_v)]),
                        row_u_logodds=float(singleton_logodds[int(local_index_u)]),
                        row_v_logodds=float(singleton_logodds[int(local_index_v)]),
                        boundary_free_correction_by_pattern=tuple(
                            float(correction_by_pattern[int(pattern)]) - float(corr_00)
                            for pattern in range(4)
                        ),
                    )
                )

    unmatched_row_masks = tuple(
        int(row_masks[int(local_index)])
        for local_index in range(int(len(active_rows)))
        if not bool(matched_local[int(local_index)])
    )
    unmatched_row_logodds = tuple(
        float(singleton_logodds[int(local_index)])
        for local_index in range(int(len(active_rows)))
        if not bool(matched_local[int(local_index)])
    )
    return FuturePairlogoddsHeuristicPayload(
        active_rows=tuple(int(row) for row in active_rows),
        matching_edges=tuple(fast_matching_edges),
        unmatched_row_masks=tuple(unmatched_row_masks),
        unmatched_row_logodds=tuple(unmatched_row_logodds),
        pair_selection=str(pair_selection_key),
        max_pairs=int(max(0, int(max_pairs))),
    )


def _populate_future_pairlogodds_payload_cache(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    clamp_assignments: dict[int, int],
    payload_cache: dict[int, FuturePairtreeHeuristicPayload | FuturePairlogoddsHeuristicPayload],
    pair_selection: str = "mi",
    max_pairs: int = 0,
) -> None:
    if not columns:
        return
    columns_tuple = tuple(columns)
    pair_selection_key = _normalize_pairlogodds_pair_selection(str(pair_selection))
    if str(pair_selection_key) not in PAIRLOGODDS_PAIR_SELECTION_CHOICES:
        raise ValueError(f"unsupported pairlogodds pair selection: {pair_selection!r}")
    max_pair_count = max(0, int(max_pairs))
    if all(
        isinstance(payload_cache.get(int(boundary_column_index)), FuturePairlogoddsHeuristicPayload)
        and str(payload_cache[int(boundary_column_index)].pair_selection) == str(pair_selection_key)
        and int(payload_cache[int(boundary_column_index)].max_pairs) == int(max_pair_count)
        for boundary_column_index in range(len(columns))
    ):
        return

    num_detectors = int(len(frontier.detector_first_column))
    active_rows_by_boundary = tuple(
        tuple(int(row) for row in _support_rows_from_mask(int(mask)))
        for mask in frontier.active_masks_after_column
    )
    active_rows = tuple(int(row) for row in active_rows_by_boundary[-1])
    row_mu = np.ones(int(num_detectors), dtype=np.float64)
    pair_mu = np.ones((int(num_detectors), int(num_detectors)), dtype=np.float64)
    pair_shared_count = np.zeros((int(num_detectors), int(num_detectors)), dtype=np.int32)
    pair_overlap_weight = np.zeros((int(num_detectors), int(num_detectors)), dtype=np.float64)
    boundary_payloads: dict[int, FuturePairlogoddsHeuristicPayload] = {}
    use_pair_atlas = str(pair_selection_key) == "atlas"
    atlas_pair_union = (
        _pairlogodds_atlas_pair_union_for_columns(columns_tuple)
        if bool(use_pair_atlas)
        else frozenset()
    )

    for column_index in range(len(columns) - 1, -1, -1):
        allowed_pairs = (
            _pairlogodds_atlas_pairs_for_boundary(
                columns=columns_tuple,
                boundary_column_index=int(column_index),
            )
            if bool(use_pair_atlas)
            else None
        )
        boundary_payloads[int(column_index)] = _build_future_pairlogodds_payload_from_state(
            active_rows=tuple(int(row) for row in active_rows),
            row_mu=row_mu,
            pair_mu=pair_mu,
            pair_shared_count=pair_shared_count,
            pair_overlap_weight=pair_overlap_weight,
            pair_selection=str(pair_selection_key),
            max_pairs=int(max_pair_count),
            allowed_pairs=allowed_pairs,
        )
        if int(column_index) == 0:
            continue

        prev_active_rows = tuple(int(row) for row in active_rows_by_boundary[int(column_index) - 1])

        distribution = _allowed_detector_distribution(
            column=columns[int(column_index)],
            forced_local_state=clamp_assignments.get(int(column_index)),
        )
        if distribution and prev_active_rows:
            active_mask = int(frontier.active_masks_after_column[int(column_index) - 1])
            active_row_to_local = {
                int(row): int(local_index)
                for local_index, row in enumerate(prev_active_rows)
            }
            projected_distribution: list[tuple[float, int]] = []
            touched_rows: set[int] = set()
            for prob, response_mask in distribution:
                active_support_mask = int(response_mask) & int(active_mask)
                local_mask = 0
                while int(active_support_mask) != 0:
                    lsb = int(active_support_mask & -active_support_mask)
                    row = int(lsb.bit_length() - 1)
                    local_mask |= 1 << int(active_row_to_local[int(row)])
                    touched_rows.add(int(row))
                    active_support_mask ^= int(lsb)
                projected_distribution.append((float(prob), int(local_mask)))

            if touched_rows:
                projected_distribution_tuple = tuple((float(prob), int(local_mask)) for prob, local_mask in projected_distribution)
                base_row_mu_by_row = {int(row): float(row_mu[int(row)]) for row in touched_rows}
                row_factor_by_row: dict[int, float] = {}
                touched_rows_sorted = tuple(sorted(int(row) for row in touched_rows))

                for row in touched_rows_sorted:
                    row_bit = 1 << int(active_row_to_local[int(row)])
                    factor = 0.0
                    for prob, local_mask in projected_distribution_tuple:
                        factor += float(prob) * (-1.0 if (int(local_mask) & int(row_bit)) != 0 else 1.0)
                    row_factor_by_row[int(row)] = float(factor)
                    row_mu[int(row)] *= float(factor)

                touched_row_set = {int(row) for row in touched_rows_sorted}
                for row_u in touched_rows_sorted:
                    factor_u = float(row_factor_by_row[int(row_u)])
                    for row_v in prev_active_rows:
                        if int(row_v) == int(row_u):
                            continue
                        pair = (
                            (int(row_u), int(row_v))
                            if int(row_u) < int(row_v)
                            else (int(row_v), int(row_u))
                        )
                        if bool(use_pair_atlas) and tuple(pair) not in atlas_pair_union:
                            continue
                        if int(row_v) in touched_row_set:
                            if int(row_u) > int(row_v):
                                continue
                            row_u_bit = 1 << int(active_row_to_local[int(row_u)])
                            row_v_bit = 1 << int(active_row_to_local[int(row_v)])
                            base_pair_mu = float(
                                pair_mu[int(pair[0]), int(pair[1])]
                                if int(pair_shared_count[int(pair[0]), int(pair[1])]) > 0
                                else float(base_row_mu_by_row[int(pair[0])]) * float(base_row_mu_by_row[int(pair[1])])
                            )
                            pair_factor = _column_pair_moment_factor(
                                distribution=projected_distribution_tuple,
                                row_u_mask=int(row_u_bit),
                                row_v_mask=int(row_v_bit),
                            )
                            updated_pair_mu = float(base_pair_mu) * float(pair_factor)
                            pair_mu[int(pair[0]), int(pair[1])] = float(updated_pair_mu)
                            pair_mu[int(pair[1]), int(pair[0])] = float(updated_pair_mu)
                            pair_shared_count[int(pair[0]), int(pair[1])] = int(
                                pair_shared_count[int(pair[0]), int(pair[1])] + 1
                            )
                            pair_shared_count[int(pair[1]), int(pair[0])] = int(
                                pair_shared_count[int(pair[0]), int(pair[1])]
                            )
                            overlap_weight = 0.0
                            both_rows_mask = int(row_u_bit) | int(row_v_bit)
                            for prob, local_mask in projected_distribution_tuple:
                                if (int(local_mask) & int(both_rows_mask)) == int(both_rows_mask):
                                    overlap_weight += float(prob)
                            pair_overlap_weight[int(pair[0]), int(pair[1])] = float(
                                pair_overlap_weight[int(pair[0]), int(pair[1])] + float(overlap_weight)
                            )
                            pair_overlap_weight[int(pair[1]), int(pair[0])] = float(
                                pair_overlap_weight[int(pair[0]), int(pair[1])]
                            )
                            continue
                        if int(pair_shared_count[int(pair[0]), int(pair[1])]) <= 0:
                            continue
                        updated_pair_mu = float(pair_mu[int(pair[0]), int(pair[1])]) * float(factor_u)
                        pair_mu[int(pair[0]), int(pair[1])] = float(updated_pair_mu)
                        pair_mu[int(pair[1]), int(pair[0])] = float(updated_pair_mu)

        active_rows = tuple(int(row) for row in prev_active_rows)

    for boundary_column_index, payload in boundary_payloads.items():
        payload_cache[int(boundary_column_index)] = payload


def _support_gate_allows_repair_pattern(
    *,
    residual_mask: int,
    payload: FuturePairtreeHeuristicPayload,
) -> bool:
    for component in payload.support_gate_components:
        local_pattern = 0
        for local_index, row in enumerate(component.active_rows):
            if (int(residual_mask) & (1 << int(row))) != 0:
                local_pattern |= 1 << int(local_index)
        if not bool(component.allowed_active_patterns[int(local_pattern)]):
            return False
    return True


def _future_support_gate_min_nonzero_steps(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    payload: FuturePairtreeHeuristicPayload,
) -> int | None:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    total_steps = 0
    for component in payload.support_gate_components:
        local_pattern = 0
        for local_index, row in enumerate(component.active_rows):
            if (int(residual_mask) & (1 << int(row))) != 0:
                local_pattern |= 1 << int(local_index)
        if not component.min_nonzero_steps_by_active_pattern:
            if not bool(component.allowed_active_patterns[int(local_pattern)]):
                return None
            continue
        step_count = int(component.min_nonzero_steps_by_active_pattern[int(local_pattern)])
        if int(step_count) < 0:
            return None
        total_steps += int(step_count)
    return int(total_steps)


def _future_pairtree_log_mass(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    payload: FuturePairtreeHeuristicPayload,
    use_support_gate: bool,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if bool(use_support_gate) and not _support_gate_allows_repair_pattern(
        residual_mask=int(residual_mask),
        payload=payload,
    ):
        return float("-inf")

    # This is the boundary-constant-free version of
    # h_pairtree(b) = sum_r log P_r(b_r) + sum_(r,s) in T log(P_rs(b_r,b_s) / (P_r(b_r) P_s(b_s))).
    total = 0.0
    for local_index, row in enumerate(payload.active_rows):
        if (int(residual_mask) & (1 << int(row))) != 0:
            total += float(payload.singleton_logodds_by_row[int(local_index)])
    for edge in payload.tree_edges:
        bit_u = 1 if (int(residual_mask) & int(edge.row_u_mask)) != 0 else 0
        bit_v = 1 if (int(residual_mask) & int(edge.row_v_mask)) != 0 else 0
        total += float(edge.log_correction_by_pattern[(int(bit_u) << 1) | int(bit_v)])
    return float(total)


def _future_pairlogodds_log_mass(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    payload: FuturePairtreeHeuristicPayload | FuturePairlogoddsHeuristicPayload,
    singleton_scale: float = 1.0,
    pair_correction_scale: float = 1.0,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if isinstance(payload, FuturePairlogoddsHeuristicPayload):
        total = 0.0
        for edge in payload.matching_edges:
            bit_u = 1 if (int(residual_mask) & int(edge.row_u_mask)) != 0 else 0
            bit_v = 1 if (int(residual_mask) & int(edge.row_v_mask)) != 0 else 0
            if int(bit_u) != 0:
                total += float(singleton_scale) * float(edge.row_u_logodds)
            if int(bit_v) != 0:
                total += float(singleton_scale) * float(edge.row_v_logodds)
            total += float(pair_correction_scale) * float(
                edge.boundary_free_correction_by_pattern[(int(bit_u) << 1) | int(bit_v)]
            )
        for row_mask, contribution in zip(payload.unmatched_row_masks, payload.unmatched_row_logodds):
            if (int(residual_mask) & int(row_mask)) != 0:
                total += float(singleton_scale) * float(contribution)
        return float(total)

    active_row_to_local = {int(row): int(local_index) for local_index, row in enumerate(payload.active_rows)}
    paired_row_masks = 0
    total = 0.0

    for edge in payload.matching_edges:
        local_u = int(active_row_to_local[int(edge.row_u)])
        local_v = int(active_row_to_local[int(edge.row_v)])
        bit_u = 1 if (int(residual_mask) & int(edge.row_u_mask)) != 0 else 0
        bit_v = 1 if (int(residual_mask) & int(edge.row_v_mask)) != 0 else 0
        total += float(singleton_scale) * float(bit_u) * float(payload.singleton_logodds_by_row[int(local_u)])
        total += float(singleton_scale) * float(bit_v) * float(payload.singleton_logodds_by_row[int(local_v)])
        total += float(pair_correction_scale) * (
            float(edge.log_correction_by_pattern[(int(bit_u) << 1) | int(bit_v)])
            - float(edge.log_correction_by_pattern[0])
        )
        paired_row_masks |= int(edge.row_u_mask) | int(edge.row_v_mask)

    for local_index, row in enumerate(payload.active_rows):
        row_mask = 1 << int(row)
        if (int(paired_row_masks) & int(row_mask)) != 0:
            continue
        if (int(residual_mask) & int(row_mask)) == 0:
            continue
        total += float(singleton_scale) * float(payload.singleton_logodds_by_row[int(local_index)])
    return float(total)


def _future_pairlogodds_negative_correction_penalty(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    payload: FuturePairlogoddsHeuristicPayload,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    penalty = 0.0
    for edge in payload.matching_edges:
        bit_u = 1 if (int(residual_mask) & int(edge.row_u_mask)) != 0 else 0
        bit_v = 1 if (int(residual_mask) & int(edge.row_v_mask)) != 0 else 0
        correction = float(edge.boundary_free_correction_by_pattern[(int(bit_u) << 1) | int(bit_v)])
        if not math.isfinite(float(correction)):
            if float(correction) < 0.0:
                return float("inf")
            continue
        if float(correction) < 0.0:
            penalty += -float(correction)
    return float(penalty)


def _build_row_future_statistics(
    columns: list[ProgressiveColumn],
    *,
    num_detectors: int,
) -> tuple[tuple[tuple[int, ...], ...], tuple[tuple[float, ...], ...], tuple[tuple[float, ...], ...]]:
    row_touch_columns_lists: list[list[int]] = [[] for _ in range(int(num_detectors))]
    row_touch_flip_prob_lists: list[list[float]] = [[] for _ in range(int(num_detectors))]

    for column_index, column in enumerate(columns):
        support_rows = _column_support_rows(column)
        if not support_rows:
            continue
        prior_probs = tuple(float(value) for value in column.prior_probs)
        for row in support_rows:
            row_mask = 1 << int(row)
            flip_prob = 0.0
            for local_state, response_mask in enumerate(column.detector_response_masks):
                if (int(response_mask) & int(row_mask)) != 0:
                    flip_prob += float(prior_probs[int(local_state)])
            row_touch_columns_lists[int(row)].append(int(column_index))
            row_touch_flip_prob_lists[int(row)].append(float(min(max(flip_prob, 0.0), 1.0)))

    row_touch_columns: list[tuple[int, ...]] = []
    row_suffix_even_probs: list[tuple[float, ...]] = []
    row_suffix_odd_probs: list[tuple[float, ...]] = []
    for row in range(int(num_detectors)):
        touch_columns = tuple(int(value) for value in row_touch_columns_lists[int(row)])
        touch_flip_probs = [float(value) for value in row_touch_flip_prob_lists[int(row)]]
        suffix_even = [0.0 for _ in range(len(touch_flip_probs) + 1)]
        suffix_odd = [0.0 for _ in range(len(touch_flip_probs) + 1)]
        suffix_even[-1] = 1.0
        suffix_odd[-1] = 0.0
        for offset in range(len(touch_flip_probs) - 1, -1, -1):
            flip_prob = float(touch_flip_probs[int(offset)])
            suffix_even[int(offset)] = (
                float(1.0 - flip_prob) * float(suffix_even[int(offset) + 1])
                + float(flip_prob) * float(suffix_odd[int(offset) + 1])
            )
            suffix_odd[int(offset)] = (
                float(1.0 - flip_prob) * float(suffix_odd[int(offset) + 1])
                + float(flip_prob) * float(suffix_even[int(offset) + 1])
            )
        row_touch_columns.append(tuple(int(value) for value in touch_columns))
        row_suffix_even_probs.append(tuple(float(value) for value in suffix_even))
        row_suffix_odd_probs.append(tuple(float(value) for value in suffix_odd))
    return (
        tuple(row_touch_columns),
        tuple(row_suffix_even_probs),
        tuple(row_suffix_odd_probs),
    )


def _future_mismatch_features(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    allow_infinite: bool = True,
) -> FrontierMismatchFeatures:
    mismatch_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if int(mismatch_mask) == 0:
        return FrontierMismatchFeatures(
            mismatch_count=0,
            touch_bonus=0.0,
            urgency_penalty=0.0,
            parity_logodds=0.0,
        )

    mismatch_count = 0
    touch_bonus = 0.0
    urgency_penalty = 0.0
    parity_logodds = 0.0
    tiny = float(np.finfo(np.float64).tiny)
    while int(mismatch_mask) != 0:
        lsb = int(mismatch_mask & -mismatch_mask)
        row = int(lsb.bit_length() - 1)
        touch_columns = frontier.row_touch_columns[int(row)]
        pos = bisect.bisect_right(touch_columns, int(column_index))
        remaining_touches = int(len(touch_columns) - int(pos))
        mismatch_count += 1
        if int(remaining_touches) <= 0:
            impossible = float("-inf") if bool(allow_infinite) else -1.0e300
            return FrontierMismatchFeatures(
                mismatch_count=int(mismatch_count),
                touch_bonus=impossible,
                urgency_penalty=float("inf"),
                parity_logodds=impossible,
            )
        touch_bonus += float(math.log(float(remaining_touches)))
        urgency_penalty += float(1.0 / float(remaining_touches))
        even_prob = float(frontier.row_suffix_even_probs[int(row)][int(pos)])
        odd_prob = float(frontier.row_suffix_odd_probs[int(row)][int(pos)])
        parity_logodds += float(math.log(max(odd_prob, tiny)) - math.log(max(even_prob, tiny)))
        mismatch_mask ^= int(lsb)
    return FrontierMismatchFeatures(
        mismatch_count=int(mismatch_count),
        touch_bonus=float(touch_bonus),
        urgency_penalty=float(urgency_penalty),
        parity_logodds=float(parity_logodds),
    )


def _build_future_parity_boundary_payload(
    *,
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    active_mask: int,
) -> FutureParityBoundaryPayload:
    active_rows = tuple(int(row) for row in _support_rows_from_mask(int(active_mask)))
    closing_rows = tuple(int(row) for row in _support_rows_from_mask(int(frontier.closing_masks[int(boundary_column_index)])))
    touched_rows = tuple(int(update.row) for update in frontier.column_row_updates[int(boundary_column_index)])
    block_start = int(frontier.closure_block_start_by_column[int(boundary_column_index)])
    block_end = int(frontier.closure_block_end_by_column[int(boundary_column_index)])
    closure_block_touched_row_set: set[int] = set()
    for column_index in range(int(block_start), int(block_end) + 1):
        for update in frontier.column_row_updates[int(column_index)]:
            closure_block_touched_row_set.add(int(update.row))

    tiny = float(np.finfo(np.float64).tiny)
    row_metrics: list[FutureParityRowMetric] = []
    row_metric_by_mask: dict[int, FutureParityRowMetric] = {}
    for row in active_rows:
        touch_columns = frontier.row_touch_columns[int(row)]
        pos = bisect.bisect_right(touch_columns, int(boundary_column_index))
        remaining_touches = int(len(touch_columns) - int(pos))
        if int(remaining_touches) <= 0:
            continue
        future_touch_columns = tuple(int(value) for value in touch_columns[int(pos):])
        first_touch_distance = int(future_touch_columns[0]) - int(boundary_column_index)
        last_touch_distance = int(future_touch_columns[-1]) - int(boundary_column_index)
        even_prob = float(frontier.row_suffix_even_probs[int(row)][int(pos)])
        odd_prob = float(frontier.row_suffix_odd_probs[int(row)][int(pos)])
        metric = FutureParityRowMetric(
            row=int(row),
            row_mask=int(1 << int(row)),
            touch_bonus=float(math.log(float(remaining_touches))),
            urgency_penalty=float(1.0 / float(remaining_touches)),
            parity_logodds=float(math.log(max(odd_prob, tiny)) - math.log(max(even_prob, tiny))),
            even_log_mass=float(math.log(max(even_prob, tiny))),
            odd_log_mass=float(math.log(max(odd_prob, tiny))),
            deadline_distance=int(last_touch_distance),
            first_touch_distance=int(first_touch_distance),
            last_touch_distance=int(last_touch_distance),
        )
        row_metrics.append(metric)
        row_metric_by_mask[int(metric.row_mask)] = metric

    return FutureParityBoundaryPayload(
        boundary_column_index=int(boundary_column_index),
        active_mask=int(active_mask),
        active_rows=tuple(int(row) for row in active_rows),
        closing_rows=tuple(int(row) for row in closing_rows),
        touched_rows=tuple(int(row) for row in touched_rows),
        closure_block_touched_rows=tuple(int(row) for row in sorted(closure_block_touched_row_set)),
        row_metrics=tuple(row_metrics),
        row_metric_by_mask=row_metric_by_mask,
    )


def _future_mismatch_features_from_payload(
    *,
    det_mask: int,
    target_syndrome_int: int,
    payload: FutureParityBoundaryPayload,
    allow_infinite: bool = True,
) -> FrontierMismatchFeatures:
    mismatch_mask = int(det_mask ^ target_syndrome_int) & int(payload.active_mask)
    if int(mismatch_mask) == 0:
        return FrontierMismatchFeatures(
            mismatch_count=0,
            touch_bonus=0.0,
            urgency_penalty=0.0,
            parity_logodds=0.0,
        )

    mismatch_count = 0
    touch_bonus = 0.0
    urgency_penalty = 0.0
    parity_logodds = 0.0
    while int(mismatch_mask) != 0:
        lsb = int(mismatch_mask & -mismatch_mask)
        metric = payload.row_metric_by_mask.get(int(lsb))
        if metric is None:
            impossible = float("-inf") if bool(allow_infinite) else -1.0e300
            return FrontierMismatchFeatures(
                mismatch_count=int(mismatch_count) + 1,
                touch_bonus=impossible,
                urgency_penalty=float("inf"),
                parity_logodds=impossible,
            )
        mismatch_count += 1
        touch_bonus += float(metric.touch_bonus)
        urgency_penalty += float(metric.urgency_penalty)
        parity_logodds += float(metric.parity_logodds)
        mismatch_mask ^= int(lsb)
    return FrontierMismatchFeatures(
        mismatch_count=int(mismatch_count),
        touch_bonus=float(touch_bonus),
        urgency_penalty=float(urgency_penalty),
        parity_logodds=float(parity_logodds),
    )


def _build_future_binarized_outcomes_boundary_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    active_mask: int,
    variant: str,
) -> FutureBinarizedOutcomesBoundaryPayload:
    active_rows = tuple(int(row) for row in _support_rows_from_mask(int(active_mask)))
    closing_rows = tuple(int(row) for row in _support_rows_from_mask(int(frontier.closing_masks[int(boundary_column_index)])))
    touched_rows = tuple(int(update.row) for update in frontier.column_row_updates[int(boundary_column_index)])
    block_start = int(frontier.closure_block_start_by_column[int(boundary_column_index)])
    block_end = int(frontier.closure_block_end_by_column[int(boundary_column_index)])
    closure_block_touched_row_set: set[int] = set()
    for column_index in range(int(block_start), int(block_end) + 1):
        for update in frontier.column_row_updates[int(column_index)]:
            closure_block_touched_row_set.add(int(update.row))

    variant_key = str(variant).strip().lower()
    if variant_key not in {"unmerged", "merged_detector_signature"}:
        raise ValueError("binarized-outcomes variant must be unmerged or merged_detector_signature")

    pseudo_events: list[tuple[int, float]] = []
    merged_probability_by_mask: dict[int, float] = {}
    scorer_work = 0
    for future_column_index in range(int(boundary_column_index) + 1, len(columns)):
        column = columns[int(future_column_index)]
        for probability, detector_mask in zip(column.prior_probs, column.detector_response_masks):
            prob = float(probability)
            if prob <= 0.0:
                continue
            projected_mask = int(detector_mask) & int(active_mask)
            if int(projected_mask) == 0:
                continue
            scorer_work += 1
            if variant_key == "merged_detector_signature":
                merged_probability_by_mask[int(projected_mask)] = (
                    float(merged_probability_by_mask.get(int(projected_mask), 0.0)) + float(prob)
                )
            else:
                pseudo_events.append((int(projected_mask), float(prob)))
    if variant_key == "merged_detector_signature":
        pseudo_events = tuple((int(mask), float(prob)) for mask, prob in sorted(merged_probability_by_mask.items()))  # type: ignore[assignment]

    tiny = float(np.finfo(np.float64).tiny)
    eps = float(PAIRTREE_EPS)
    row_metrics: list[FutureParityRowMetric] = []
    row_metric_by_mask: dict[int, FutureParityRowMetric] = {}
    for row in active_rows:
        row_mask = 1 << int(row)
        mu = 1.0
        touch_count = 0
        for event_mask, event_probability in tuple(pseudo_events):
            if (int(event_mask) & int(row_mask)) == 0:
                continue
            probability = float(min(max(float(event_probability), 0.0), 1.0 - float(eps)))
            mu *= float(1.0 - 2.0 * float(probability))
            touch_count += 1
        if int(touch_count) <= 0:
            continue
        mu = float(min(max(float(mu), -1.0), 1.0))
        even_prob, odd_prob = _clip_probabilities(
            (
                0.5 * (1.0 + float(mu)),
                0.5 * (1.0 - float(mu)),
            ),
            eps=float(eps),
        )
        touch_columns = frontier.row_touch_columns[int(row)]
        pos = bisect.bisect_right(touch_columns, int(boundary_column_index))
        future_touch_columns = tuple(int(value) for value in touch_columns[int(pos):])
        first_touch_distance = int(future_touch_columns[0]) - int(boundary_column_index) if future_touch_columns else 0
        last_touch_distance = int(future_touch_columns[-1]) - int(boundary_column_index) if future_touch_columns else 0
        metric = FutureParityRowMetric(
            row=int(row),
            row_mask=int(row_mask),
            touch_bonus=float(math.log(float(touch_count))),
            urgency_penalty=float(1.0 / float(touch_count)),
            parity_logodds=float(math.log(max(float(odd_prob), tiny)) - math.log(max(float(even_prob), tiny))),
            even_log_mass=float(math.log(max(float(even_prob), tiny))),
            odd_log_mass=float(math.log(max(float(odd_prob), tiny))),
            deadline_distance=int(last_touch_distance),
            first_touch_distance=int(first_touch_distance),
            last_touch_distance=int(last_touch_distance),
        )
        row_metrics.append(metric)
        row_metric_by_mask[int(row_mask)] = metric

    return FutureBinarizedOutcomesBoundaryPayload(
        parity_payload=FutureParityBoundaryPayload(
            boundary_column_index=int(boundary_column_index),
            active_mask=int(active_mask),
            active_rows=tuple(int(row) for row in active_rows),
            closing_rows=tuple(int(row) for row in closing_rows),
            touched_rows=tuple(int(row) for row in touched_rows),
            closure_block_touched_rows=tuple(int(row) for row in sorted(closure_block_touched_row_set)),
            row_metrics=tuple(row_metrics),
            row_metric_by_mask=row_metric_by_mask,
        ),
        pseudo_column_count=int(len(tuple(pseudo_events))),
        scorer_work=int(scorer_work),
    )


def _incremental_child_mismatch_features(
    *,
    parent_det_mask: int,
    detector_response_mask: int,
    target_syndrome_int: int,
    parent_features: FrontierMismatchFeatures,
    row_updates: tuple[FrontierRowUpdate, ...],
) -> FrontierMismatchFeatures:
    if not row_updates:
        return parent_features

    mismatch_count = int(parent_features.mismatch_count)
    touch_bonus = float(parent_features.touch_bonus)
    urgency_penalty = float(parent_features.urgency_penalty)
    parity_logodds = float(parent_features.parity_logodds)
    parent_mismatch_mask = int(parent_det_mask) ^ int(target_syndrome_int)
    child_mismatch_mask = int(parent_mismatch_mask) ^ int(detector_response_mask)

    for update in row_updates:
        row_mask = update.row_mask
        if update.active_before and (parent_mismatch_mask & row_mask) != 0:
            mismatch_count -= 1
            touch_bonus -= update.touch_bonus_before
            urgency_penalty -= update.urgency_before
            parity_logodds -= update.parity_logodds_before
        if update.active_after and (child_mismatch_mask & row_mask) != 0:
            mismatch_count += 1
            touch_bonus += update.touch_bonus_after
            urgency_penalty += update.urgency_after
            parity_logodds += update.parity_logodds_after

    return FrontierMismatchFeatures(
        mismatch_count=int(mismatch_count),
        touch_bonus=float(touch_bonus),
        urgency_penalty=float(urgency_penalty),
        parity_logodds=float(parity_logodds),
    )


def _compile_frontier_feature_update_terms(
    row_updates: tuple[FrontierRowUpdate, ...],
) -> tuple[
    tuple[tuple[int, float, float, float], ...],
    tuple[tuple[int, float, float, float], ...],
]:
    before_terms: list[tuple[int, float, float, float]] = []
    after_terms: list[tuple[int, float, float, float]] = []
    for update in row_updates:
        row_mask = int(update.row_mask)
        if bool(update.active_before):
            before_terms.append(
                (
                    int(row_mask),
                    float(update.touch_bonus_before),
                    float(update.urgency_before),
                    float(update.parity_logodds_before),
                )
            )
        if bool(update.active_after):
            after_terms.append(
                (
                    int(row_mask),
                    float(update.touch_bonus_after),
                    float(update.urgency_after),
                    float(update.parity_logodds_after),
                )
            )
    return tuple(before_terms), tuple(after_terms)


_BINARY_MODEL_ORDER_CACHE_STATS = BinaryModelOrderCacheStats()


def _binary_model_order_cache_stats_snapshot() -> BinaryModelOrderCacheStats:
    stats = _BINARY_MODEL_ORDER_CACHE_STATS
    return BinaryModelOrderCacheStats(
        layout_hit_count=int(stats.layout_hit_count),
        layout_miss_count=int(stats.layout_miss_count),
        layout_build_time_s=float(stats.layout_build_time_s),
        feature_terms_hit_count=int(stats.feature_terms_hit_count),
        feature_terms_miss_count=int(stats.feature_terms_miss_count),
        feature_terms_build_time_s=float(stats.feature_terms_build_time_s),
        binary_payload_hit_count=int(stats.binary_payload_hit_count),
        binary_payload_miss_count=int(stats.binary_payload_miss_count),
        binary_payload_build_time_s=float(stats.binary_payload_build_time_s),
    )


def _binary_model_order_cache_stats_delta(
    start: BinaryModelOrderCacheStats,
) -> BinaryModelOrderCacheStats:
    stats = _BINARY_MODEL_ORDER_CACHE_STATS
    return BinaryModelOrderCacheStats(
        layout_hit_count=int(stats.layout_hit_count) - int(start.layout_hit_count),
        layout_miss_count=int(stats.layout_miss_count) - int(start.layout_miss_count),
        layout_build_time_s=float(stats.layout_build_time_s) - float(start.layout_build_time_s),
        feature_terms_hit_count=int(stats.feature_terms_hit_count) - int(start.feature_terms_hit_count),
        feature_terms_miss_count=int(stats.feature_terms_miss_count) - int(start.feature_terms_miss_count),
        feature_terms_build_time_s=float(stats.feature_terms_build_time_s)
        - float(start.feature_terms_build_time_s),
        binary_payload_hit_count=int(stats.binary_payload_hit_count) - int(start.binary_payload_hit_count),
        binary_payload_miss_count=int(stats.binary_payload_miss_count) - int(start.binary_payload_miss_count),
        binary_payload_build_time_s=float(stats.binary_payload_build_time_s)
        - float(start.binary_payload_build_time_s),
    )


_BINARY_FEATURE_UPDATE_TERMS_CACHE: dict[
    tuple[tuple[FrontierRowUpdate, ...], ...],
    tuple[
        tuple[
            tuple[tuple[int, float, float, float], ...],
            tuple[tuple[int, float, float, float], ...],
        ],
        ...,
    ],
] = {}


def _compile_frontier_feature_update_terms_by_column(
    *,
    frontier: ProgressiveFrontierLayout,
    enabled: bool,
) -> tuple[
    tuple[
        tuple[tuple[int, float, float, float], ...],
        tuple[tuple[int, float, float, float], ...],
    ],
    ...,
]:
    if not bool(enabled):
        return tuple()
    row_updates_by_column = tuple(frontier.column_row_updates)
    cached = _BINARY_FEATURE_UPDATE_TERMS_CACHE.get(row_updates_by_column)
    if cached is not None:
        _BINARY_MODEL_ORDER_CACHE_STATS.feature_terms_hit_count += 1
        return cached

    _BINARY_MODEL_ORDER_CACHE_STATS.feature_terms_miss_count += 1
    build_started = time.perf_counter()
    compiled = tuple(
        _compile_frontier_feature_update_terms(tuple(row_updates))
        for row_updates in row_updates_by_column
    )
    _BINARY_MODEL_ORDER_CACHE_STATS.feature_terms_build_time_s += float(
        time.perf_counter() - build_started
    )
    if len(_BINARY_FEATURE_UPDATE_TERMS_CACHE) >= 64:
        _BINARY_FEATURE_UPDATE_TERMS_CACHE.clear()
    _BINARY_FEATURE_UPDATE_TERMS_CACHE[row_updates_by_column] = compiled
    return compiled


def _binary_production_transition_fast_path_disabled() -> bool:
    value = str(os.environ.get("FRONTIERK_BINARY_TRANSITION_FAST_PATH", "1")).strip().lower()
    return value in {"0", "false", "off", "no"}


def _compile_binary_transition_terms(
    column: ProgressiveColumn,
) -> tuple[float, float, int, int, int, int] | None:
    if (
        len(column.prior_probs) != 2
        or len(column.detector_response_masks) != 2
        or len(column.logical_response_masks) != 2
    ):
        return None
    log_priors = _column_log_priors(column)
    if len(log_priors) != 2:
        return None
    return (
        float(log_priors[0]),
        float(log_priors[1]),
        int(column.detector_response_masks[0]),
        int(column.detector_response_masks[1]),
        int(column.logical_response_masks[0]),
        int(column.logical_response_masks[1]),
    )


_BINARY_LOCAL_PATTERN_FEATURE_TABLE_MAX_DEGREE = 12


def _compile_binary_local_pattern_feature_table(
    *,
    row_updates: tuple[FrontierRowUpdate, ...],
) -> BinaryFrontierKLocalPatternFeatureTable | None:
    local_row_masks = tuple(int(update.row_mask) for update in tuple(row_updates))
    degree = int(len(local_row_masks))
    if int(degree) > int(_BINARY_LOCAL_PATTERN_FEATURE_TABLE_MAX_DEGREE):
        return None
    if int(len(set(local_row_masks))) != int(degree):
        return None

    local_row_mask = 0
    for row_mask in local_row_masks:
        row_mask_int = int(row_mask)
        local_row_mask |= int(row_mask_int)

    table_size = 1 << int(degree)
    no_count_one: list[int] = []
    no_touch_one: list[float] = []
    no_urgency_one: list[float] = []
    no_parity_one: list[float] = []
    toggle_count_one: list[int] = []
    toggle_touch_one: list[float] = []
    toggle_urgency_one: list[float] = []
    toggle_parity_one: list[float] = []
    toggle_zero_count = 0
    toggle_zero_touch = 0.0
    toggle_zero_urgency = 0.0
    toggle_zero_parity = 0.0
    for update in tuple(row_updates):
        active_before = bool(update.active_before)
        active_after = bool(update.active_after)
        before_count = 1 if active_before else 0
        after_count = 1 if active_after else 0
        before_touch = float(update.touch_bonus_before) if active_before else 0.0
        before_urgency = float(update.urgency_before) if active_before else 0.0
        before_parity = float(update.parity_logodds_before) if active_before else 0.0
        after_touch = float(update.touch_bonus_after) if active_after else 0.0
        after_urgency = float(update.urgency_after) if active_after else 0.0
        after_parity = float(update.parity_logodds_after) if active_after else 0.0

        no_count_one.append(int(-int(before_count) + int(after_count)))
        no_touch_one.append(float(-before_touch + after_touch))
        no_urgency_one.append(float(-before_urgency + after_urgency))
        no_parity_one.append(float(-before_parity + after_parity))
        toggle_count_one.append(int(-int(before_count) - int(after_count)))
        toggle_touch_one.append(float(-before_touch - after_touch))
        toggle_urgency_one.append(float(-before_urgency - after_urgency))
        toggle_parity_one.append(float(-before_parity - after_parity))
        if active_after:
            toggle_zero_count += 1
            toggle_zero_touch += float(after_touch)
            toggle_zero_urgency += float(after_urgency)
            toggle_zero_parity += float(after_parity)

    sparse_masks = [0] * int(table_size)
    no_count_deltas = [0] * int(table_size)
    no_touch_deltas = [0.0] * int(table_size)
    no_urgency_deltas = [0.0] * int(table_size)
    no_parity_deltas = [0.0] * int(table_size)
    toggle_count_deltas = [0] * int(table_size)
    toggle_touch_deltas = [0.0] * int(table_size)
    toggle_urgency_deltas = [0.0] * int(table_size)
    toggle_parity_deltas = [0.0] * int(table_size)
    toggle_count_deltas[0] = int(toggle_zero_count)
    toggle_touch_deltas[0] = float(toggle_zero_touch)
    toggle_urgency_deltas[0] = float(toggle_zero_urgency)
    toggle_parity_deltas[0] = float(toggle_zero_parity)
    pattern_by_local_mask: dict[int, int] = {0: 0}

    for pattern in range(1, int(table_size)):
        lsb = int(pattern) & -int(pattern)
        local_index = int(lsb.bit_length() - 1)
        previous = int(pattern) ^ int(lsb)
        sparse_mask = int(sparse_masks[int(previous)]) | int(local_row_masks[int(local_index)])
        sparse_masks[int(pattern)] = int(sparse_mask)
        pattern_by_local_mask[int(sparse_mask)] = int(pattern)
        no_count_deltas[int(pattern)] = int(no_count_deltas[int(previous)]) + int(
            no_count_one[int(local_index)]
        )
        no_touch_deltas[int(pattern)] = float(no_touch_deltas[int(previous)]) + float(
            no_touch_one[int(local_index)]
        )
        no_urgency_deltas[int(pattern)] = float(no_urgency_deltas[int(previous)]) + float(
            no_urgency_one[int(local_index)]
        )
        no_parity_deltas[int(pattern)] = float(no_parity_deltas[int(previous)]) + float(
            no_parity_one[int(local_index)]
        )
        toggle_count_deltas[int(pattern)] = int(toggle_count_deltas[int(previous)]) + int(
            toggle_count_one[int(local_index)]
        )
        toggle_touch_deltas[int(pattern)] = float(toggle_touch_deltas[int(previous)]) + float(
            toggle_touch_one[int(local_index)]
        )
        toggle_urgency_deltas[int(pattern)] = float(toggle_urgency_deltas[int(previous)]) + float(
            toggle_urgency_one[int(local_index)]
        )
        toggle_parity_deltas[int(pattern)] = float(toggle_parity_deltas[int(previous)]) + float(
            toggle_parity_one[int(local_index)]
        )

    return BinaryFrontierKLocalPatternFeatureTable(
        local_row_mask=int(local_row_mask),
        pattern_by_local_mask=pattern_by_local_mask,
        no_count_deltas=tuple(int(value) for value in no_count_deltas),
        no_touch_deltas=tuple(float(value) for value in no_touch_deltas),
        no_urgency_deltas=tuple(float(value) for value in no_urgency_deltas),
        no_parity_deltas=tuple(float(value) for value in no_parity_deltas),
        toggle_count_deltas=tuple(int(value) for value in toggle_count_deltas),
        toggle_touch_deltas=tuple(float(value) for value in toggle_touch_deltas),
        toggle_urgency_deltas=tuple(float(value) for value in toggle_urgency_deltas),
        toggle_parity_deltas=tuple(float(value) for value in toggle_parity_deltas),
    )


def _compile_binary_frontierk_column_payload(
    column: ProgressiveColumn,
    row_updates: tuple[FrontierRowUpdate, ...],
) -> BinaryFrontierKColumnPayload | None:
    """Compile the exact binary DEM no-error/toggle case into primitive payload arrays."""
    if (
        len(column.prior_probs) != 2
        or len(column.detector_response_masks) != 2
        or len(column.logical_response_masks) != 2
    ):
        return None
    if int(column.detector_response_masks[0]) != 0 or int(column.logical_response_masks[0]) != 0:
        return None
    if column.correction_response_masks is not None:
        correction_masks = _column_correction_masks(column)
        if len(correction_masks) != 2 or int(correction_masks[0]) != 0:
            return None
    log_priors = _column_log_priors(column)
    if len(log_priors) != 2:
        return None
    no_error_log_const = float(log_priors[0])
    toggle_log_prior = float(log_priors[1])
    if not math.isfinite(float(no_error_log_const)):
        return None
    toggle_logodds = float("-inf")
    if math.isfinite(float(toggle_log_prior)):
        toggle_logodds = float(toggle_log_prior) - float(no_error_log_const)

    row_update_mask = 0
    before_row_bit_masks: list[int] = []
    before_touch_bonus_weights: list[float] = []
    before_urgency_weights: list[float] = []
    before_parity_logodds_weights: list[float] = []
    after_row_bit_masks: list[int] = []
    after_touch_bonus_weights: list[float] = []
    after_urgency_weights: list[float] = []
    after_parity_logodds_weights: list[float] = []
    for update in tuple(row_updates):
        row_mask = int(update.row_mask)
        row_update_mask |= int(row_mask)
        active_before = bool(update.active_before)
        active_after = bool(update.active_after)
        touch_before = float(update.touch_bonus_before)
        touch_after = float(update.touch_bonus_after)
        urgency_before = float(update.urgency_before)
        urgency_after = float(update.urgency_after)
        parity_before = float(update.parity_logodds_before)
        parity_after = float(update.parity_logodds_after)
        if bool(active_before):
            before_row_bit_masks.append(int(row_mask))
            before_touch_bonus_weights.append(float(touch_before))
            before_urgency_weights.append(float(urgency_before))
            before_parity_logodds_weights.append(float(parity_before))
        if bool(active_after):
            after_row_bit_masks.append(int(row_mask))
            after_touch_bonus_weights.append(float(touch_after))
            after_urgency_weights.append(float(urgency_after))
            after_parity_logodds_weights.append(float(parity_after))
    if int(row_update_mask) != int(column.detector_response_masks[1]):
        return None
    before_row_bit_masks_tuple = tuple(int(value) for value in before_row_bit_masks)
    before_touch_bonus_weights_tuple = tuple(float(value) for value in before_touch_bonus_weights)
    before_urgency_weights_tuple = tuple(float(value) for value in before_urgency_weights)
    before_parity_logodds_weights_tuple = tuple(float(value) for value in before_parity_logodds_weights)
    after_row_bit_masks_tuple = tuple(int(value) for value in after_row_bit_masks)
    after_touch_bonus_weights_tuple = tuple(float(value) for value in after_touch_bonus_weights)
    after_urgency_weights_tuple = tuple(float(value) for value in after_urgency_weights)
    after_parity_logodds_weights_tuple = tuple(float(value) for value in after_parity_logodds_weights)
    local_pattern_feature_table = _compile_binary_local_pattern_feature_table(
        row_updates=tuple(row_updates),
    )

    return BinaryFrontierKColumnPayload(
        no_error_log_const=float(no_error_log_const),
        toggle_logodds=float(toggle_logodds),
        toggle_detector_mask=int(column.detector_response_masks[1]),
        toggle_observable_mask=int(column.logical_response_masks[1]),
        before_row_bit_masks=before_row_bit_masks_tuple,
        before_touch_bonus_weights=before_touch_bonus_weights_tuple,
        before_urgency_weights=before_urgency_weights_tuple,
        before_parity_logodds_weights=before_parity_logodds_weights_tuple,
        after_row_bit_masks=after_row_bit_masks_tuple,
        after_touch_bonus_weights=after_touch_bonus_weights_tuple,
        after_urgency_weights=after_urgency_weights_tuple,
        after_parity_logodds_weights=after_parity_logodds_weights_tuple,
        local_pattern_feature_table=local_pattern_feature_table,
    )


_BINARY_FAST_PATH_COLUMN_CACHE: dict[
    tuple[tuple[int, ...], tuple[tuple[FrontierRowUpdate, ...], ...]],
    tuple[
        tuple[ProgressiveColumn, ...],
        tuple[tuple[float, float, int, int, int, int] | None, ...],
        tuple[BinaryFrontierKColumnPayload | None, ...],
    ],
] = {}
_BINARY_FAST_PATH_COLUMN_STRUCTURAL_CACHE: dict[
    tuple[tuple[ProgressiveColumn, ...], tuple[tuple[FrontierRowUpdate, ...], ...]],
    tuple[
        tuple[tuple[float, float, int, int, int, int] | None, ...],
        tuple[BinaryFrontierKColumnPayload | None, ...],
    ],
] = {}


def _compile_binary_fast_path_column_caches(
    *,
    columns: Sequence[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    enabled: bool,
) -> tuple[
    tuple[tuple[float, float, int, int, int, int] | None, ...],
    tuple[BinaryFrontierKColumnPayload | None, ...],
]:
    if not bool(enabled):
        return tuple(), tuple()

    columns_tuple = tuple(columns)
    row_updates_by_column = tuple(frontier.column_row_updates)
    column_identity = tuple(id(column) for column in columns_tuple)
    identity_cache_key = (column_identity, row_updates_by_column)
    cached = _BINARY_FAST_PATH_COLUMN_CACHE.get(identity_cache_key)
    if cached is not None and all(
        cached_column is column for cached_column, column in zip(cached[0], columns_tuple, strict=True)
    ):
        _BINARY_MODEL_ORDER_CACHE_STATS.binary_payload_hit_count += 1
        return cached[1], cached[2]

    structural_cache_key = (columns_tuple, row_updates_by_column)
    structural_cached = _BINARY_FAST_PATH_COLUMN_STRUCTURAL_CACHE.get(structural_cache_key)
    if structural_cached is not None:
        _BINARY_MODEL_ORDER_CACHE_STATS.binary_payload_hit_count += 1
        if len(_BINARY_FAST_PATH_COLUMN_CACHE) >= 64:
            _BINARY_FAST_PATH_COLUMN_CACHE.clear()
        _BINARY_FAST_PATH_COLUMN_CACHE[identity_cache_key] = (
            columns_tuple,
            structural_cached[0],
            structural_cached[1],
        )
        return structural_cached

    _BINARY_MODEL_ORDER_CACHE_STATS.binary_payload_miss_count += 1
    build_started = time.perf_counter()
    payloads: list[BinaryFrontierKColumnPayload | None] = []
    terms: list[tuple[float, float, int, int, int, int] | None] = []
    for column, row_updates in zip(columns_tuple, row_updates_by_column):
        payload = _compile_binary_frontierk_column_payload(column, tuple(row_updates))
        payloads.append(payload)
        terms.append(None if payload is not None else _compile_binary_transition_terms(column))

    compiled_terms = tuple(terms)
    compiled_payloads = tuple(payloads)
    _BINARY_MODEL_ORDER_CACHE_STATS.binary_payload_build_time_s += float(
        time.perf_counter() - build_started
    )
    if len(_BINARY_FAST_PATH_COLUMN_CACHE) >= 64:
        _BINARY_FAST_PATH_COLUMN_CACHE.clear()
    if len(_BINARY_FAST_PATH_COLUMN_STRUCTURAL_CACHE) >= 64:
        _BINARY_FAST_PATH_COLUMN_STRUCTURAL_CACHE.clear()
    _BINARY_FAST_PATH_COLUMN_CACHE[identity_cache_key] = (
        columns_tuple,
        compiled_terms,
        compiled_payloads,
    )
    _BINARY_FAST_PATH_COLUMN_STRUCTURAL_CACHE[structural_cache_key] = (
        compiled_terms,
        compiled_payloads,
    )
    return compiled_terms, compiled_payloads


def _incremental_child_mismatch_features_from_terms(
    *,
    parent_det_mask: int,
    detector_response_mask: int,
    target_syndrome_int: int,
    parent_features: FrontierMismatchFeatures,
    update_terms: tuple[
        tuple[tuple[int, float, float, float], ...],
        tuple[tuple[int, float, float, float], ...],
    ],
) -> FrontierMismatchFeatures:
    before_terms, after_terms = update_terms
    if not before_terms and not after_terms:
        return parent_features

    mismatch_count = int(parent_features.mismatch_count)
    touch_bonus = float(parent_features.touch_bonus)
    urgency_penalty = float(parent_features.urgency_penalty)
    parity_logodds = float(parent_features.parity_logodds)
    parent_mismatch_mask = int(parent_det_mask) ^ int(target_syndrome_int)
    child_mismatch_mask = int(parent_mismatch_mask) ^ int(detector_response_mask)

    for row_mask, row_touch_bonus, row_urgency, row_parity_logodds in before_terms:
        if (parent_mismatch_mask & row_mask) != 0:
            mismatch_count -= 1
            touch_bonus -= row_touch_bonus
            urgency_penalty -= row_urgency
            parity_logodds -= row_parity_logodds
    for row_mask, row_touch_bonus, row_urgency, row_parity_logodds in after_terms:
        if (child_mismatch_mask & row_mask) != 0:
            mismatch_count += 1
            touch_bonus += row_touch_bonus
            urgency_penalty += row_urgency
            parity_logodds += row_parity_logodds

    return FrontierMismatchFeatures(
        mismatch_count=int(mismatch_count),
        touch_bonus=float(touch_bonus),
        urgency_penalty=float(urgency_penalty),
        parity_logodds=float(parity_logodds),
    )


def _advance_binary_frontierk_logodds_fast_path(
    *,
    state_log_mass: dict[int, float],
    state_viterbi: dict[int, float],
    state_viterbi_rep_cost: dict[int, int],
    current_detector_features: dict[int, FrontierMismatchFeatures],
    binary_payload: BinaryFrontierKColumnPayload,
    close_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    detector_mask_mask: int,
    logical_mask_mask: int,
    state_key_logical_shift: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    track_best_path: bool,
    log_mass_primary_only: bool,
    sparse_viterbi_maps_enabled: bool,
    future_parity_scorer_stats: FutureParityScorerStats,
    binary_fast_path_stats: BinaryFrontierKFastPathStats,
) -> tuple[
    dict[int, float],
    dict[int, float],
    dict[int, int],
    dict[int, tuple[int, int]],
    dict[int, FrontierMismatchFeatures],
    dict[int, int],
    int,
    int,
]:
    expansion_started = time.perf_counter()
    no_error_log_const = float(binary_payload.no_error_log_const)
    toggle_logodds = float(binary_payload.toggle_logodds)
    toggle_detector_mask = int(binary_payload.toggle_detector_mask)
    toggle_observable_mask = int(binary_payload.toggle_observable_mask)
    toggle_finite = math.isfinite(float(toggle_logodds))

    close_mask_int = int(close_mask)
    active_mask_int = int(active_mask)
    target_int = int(target_syndrome_int)
    detector_mask_mask_int = int(detector_mask_mask)
    logical_mask_mask_int = int(logical_mask_mask)
    logical_shift = int(state_key_logical_shift)
    prev_column_index = int(column_index) - 1
    prev_active_mask = 0 if int(prev_column_index) < 0 else int(frontier.active_masks_after_column[int(prev_column_index)])

    before_row_bit_masks = binary_payload.before_row_bit_masks
    before_touch = binary_payload.before_touch_bonus_weights
    before_urgency = binary_payload.before_urgency_weights
    before_parity = binary_payload.before_parity_logodds_weights
    after_row_bit_masks = binary_payload.after_row_bit_masks
    after_touch = binary_payload.after_touch_bonus_weights
    after_urgency = binary_payload.after_urgency_weights
    after_parity = binary_payload.after_parity_logodds_weights

    feature_components_by_detector: dict[int, tuple[int, float, float, float]] = {}
    next_log_mass: dict[int, float] = {}
    next_viterbi: dict[int, float] = {}
    next_viterbi_rep_cost: dict[int, int] = {}
    next_parent: dict[int, tuple[int, int]] = {}
    incoming_count_by_key: dict[int, int] = {}

    current_features_get = current_detector_features.get
    next_log_mass_get = next_log_mass.get
    next_viterbi_get = next_viterbi.get
    next_viterbi_rep_cost_get = next_viterbi_rep_cost.get
    incoming_get = incoming_count_by_key.get
    logadd = _logaddexp_pair
    isclose = math.isclose
    sys_maxsize = sys.maxsize
    track_viterbi = not bool(log_mass_primary_only)
    transition_count = 0
    closure_reject_count = 0
    explicit_branch_count = 0
    skipped_no_error_count = 0
    feature_update_count = 0
    feature_update_time_s = 0.0

    for key_raw, log_mass_raw in state_log_mass.items():
        key_int = int(key_raw)
        log_mass = float(log_mass_raw)
        det_mask = int(key_int & detector_mask_mask_int)
        logical_mask = int((key_int >> logical_shift) & logical_mask_mask_int)
        parent_feature = current_features_get(det_mask)
        if parent_feature is None:
            fallback_started = time.perf_counter()
            parent_feature = _future_mismatch_features(
                det_mask=det_mask,
                active_mask=prev_active_mask,
                target_syndrome_int=target_int,
                column_index=prev_column_index,
                frontier=frontier,
            )
            future_parity_scorer_stats.fallback_score_calls += 1
            future_parity_scorer_stats.from_scratch_score_calls += 1
            future_parity_scorer_stats.scorer_time_s += float(time.perf_counter() - fallback_started)
        parent_mismatch_count = int(parent_feature.mismatch_count)
        parent_touch_bonus = float(parent_feature.touch_bonus)
        parent_urgency_penalty = float(parent_feature.urgency_penalty)
        parent_parity_logodds = float(parent_feature.parity_logodds)
        viterbi_mass = float(state_viterbi[int(key_int)]) if bool(track_viterbi) else 0.0
        viterbi_rep_cost = (
            int(state_viterbi_rep_cost.get(int(key_int), 0)) if bool(track_viterbi) else 0
        )

        no_next_det = 0
        toggle_next_det = 0
        no_accepted = False
        toggle_accepted = False

        transition_count += 1
        skipped_no_error_count += 1
        no_candidate_det = det_mask
        if ((no_candidate_det ^ target_int) & close_mask_int) != 0:
            closure_reject_count += 1
        else:
            no_accepted = True
            no_next_det = no_candidate_det & active_mask_int

        if toggle_finite:
            transition_count += 1
            explicit_branch_count += 1
            toggle_candidate_det = det_mask ^ toggle_detector_mask
            if ((toggle_candidate_det ^ target_int) & close_mask_int) != 0:
                closure_reject_count += 1
            else:
                toggle_accepted = True
                toggle_next_det = toggle_candidate_det & active_mask_int

        need_no_feature = no_accepted and no_next_det not in feature_components_by_detector
        need_toggle_feature = toggle_accepted and toggle_next_det not in feature_components_by_detector
        if need_no_feature or need_toggle_feature:
            feature_started = time.perf_counter()
            parent_mismatch_mask = det_mask ^ target_int
            base_count = parent_mismatch_count
            base_touch = parent_touch_bonus
            base_urgency = parent_urgency_penalty
            base_parity = parent_parity_logodds
            for index, row_mask in enumerate(before_row_bit_masks):
                if (parent_mismatch_mask & row_mask) != 0:
                    base_count -= 1
                    base_touch -= before_touch[index]
                    base_urgency -= before_urgency[index]
                    base_parity -= before_parity[index]
            no_count = base_count
            toggle_count = base_count
            no_touch = base_touch
            toggle_touch = base_touch
            no_urgency = base_urgency
            toggle_urgency = base_urgency
            no_parity = base_parity
            toggle_parity = base_parity
            for index, row_mask in enumerate(after_row_bit_masks):
                if (parent_mismatch_mask & row_mask) != 0:
                    no_count += 1
                    no_touch += after_touch[index]
                    no_urgency += after_urgency[index]
                    no_parity += after_parity[index]
                else:
                    toggle_count += 1
                    toggle_touch += after_touch[index]
                    toggle_urgency += after_urgency[index]
                    toggle_parity += after_parity[index]
            feature_update_time_s += float(time.perf_counter() - feature_started)
            if need_no_feature:
                feature_components_by_detector[no_next_det] = (
                    no_count,
                    no_touch,
                    no_urgency,
                    no_parity,
                )
                feature_update_count += 1
            if need_toggle_feature:
                feature_components_by_detector[toggle_next_det] = (
                    toggle_count,
                    toggle_touch,
                    toggle_urgency,
                    toggle_parity,
                )
                feature_update_count += 1

        if no_accepted:
            next_key = no_next_det | (logical_mask << logical_shift)
            existing_log_mass = next_log_mass_get(next_key)
            if existing_log_mass is None:
                incoming_count_by_key[next_key] = 1
                next_log_mass[next_key] = log_mass
                if bool(track_viterbi):
                    next_viterbi[next_key] = viterbi_mass
                    next_viterbi_rep_cost[next_key] = viterbi_rep_cost
                if bool(track_best_path):
                    next_parent[next_key] = (key_int, 0)
            else:
                incoming_count_by_key[next_key] = int(incoming_get(next_key, 0)) + 1
                next_log_mass[next_key] = logadd(float(existing_log_mass), log_mass)
                if bool(track_viterbi):
                    best_viterbi = float(next_viterbi_get(next_key, float("-inf")))
                    best_rep_cost = int(next_viterbi_rep_cost_get(next_key, sys_maxsize))
                    if viterbi_mass > best_viterbi or (
                        isclose(viterbi_mass, best_viterbi, rel_tol=0.0, abs_tol=1e-15)
                        and viterbi_rep_cost < best_rep_cost
                    ):
                        next_viterbi[next_key] = viterbi_mass
                        next_viterbi_rep_cost[next_key] = viterbi_rep_cost
                        if bool(track_best_path):
                            next_parent[next_key] = (key_int, 0)

        if toggle_accepted:
            next_logical = logical_mask ^ toggle_observable_mask
            next_key = toggle_next_det | (next_logical << logical_shift)
            new_log_mass = log_mass + toggle_logodds
            existing_log_mass = next_log_mass_get(next_key)
            new_viterbi = viterbi_mass + toggle_logodds if bool(track_viterbi) else 0.0
            new_rep_cost = int(viterbi_rep_cost) + 1 if bool(track_viterbi) else 0
            if existing_log_mass is None:
                incoming_count_by_key[next_key] = 1
                next_log_mass[next_key] = new_log_mass
                if bool(track_viterbi):
                    next_viterbi[next_key] = new_viterbi
                    next_viterbi_rep_cost[next_key] = new_rep_cost
                if bool(track_best_path):
                    next_parent[next_key] = (key_int, 1)
            else:
                incoming_count_by_key[next_key] = int(incoming_get(next_key, 0)) + 1
                next_log_mass[next_key] = logadd(float(existing_log_mass), new_log_mass)
                if bool(track_viterbi):
                    best_viterbi = float(next_viterbi_get(next_key, float("-inf")))
                    best_rep_cost = int(next_viterbi_rep_cost_get(next_key, sys_maxsize))
                    if new_viterbi > best_viterbi or (
                        isclose(new_viterbi, best_viterbi, rel_tol=0.0, abs_tol=1e-15)
                        and new_rep_cost < best_rep_cost
                    ):
                        next_viterbi[next_key] = new_viterbi
                        next_viterbi_rep_cost[next_key] = new_rep_cost
                        if bool(track_best_path):
                            next_parent[next_key] = (key_int, 1)

    binary_fast_path_stats.transition_expansion_time_s += float(time.perf_counter() - expansion_started)
    binary_fast_path_stats.explicit_branch_count += int(explicit_branch_count)
    binary_fast_path_stats.skipped_no_error_branch_count += int(skipped_no_error_count)
    future_parity_scorer_stats.incremental_update_count += int(feature_update_count)
    future_parity_scorer_stats.scorer_time_s += float(feature_update_time_s)

    merge_started = time.perf_counter()
    if float(no_error_log_const) != 0.0:
        for key_int in tuple(next_log_mass.keys()):
            next_log_mass[int(key_int)] = float(next_log_mass[int(key_int)]) + float(no_error_log_const)
        if bool(track_viterbi):
            for key_int in tuple(next_viterbi.keys()):
                next_viterbi[int(key_int)] = float(next_viterbi[int(key_int)]) + float(no_error_log_const)
    if not bool(track_viterbi):
        if bool(sparse_viterbi_maps_enabled):
            next_viterbi = next_log_mass
            next_viterbi_rep_cost = {}
        else:
            next_viterbi = dict(next_log_mass)
            next_viterbi_rep_cost = {int(key): 0 for key in next_log_mass.keys()}

    next_detector_features = {
        int(det_key): FrontierMismatchFeatures(
            mismatch_count=int(components[0]),
            touch_bonus=float(components[1]),
            urgency_penalty=float(components[2]),
            parity_logodds=float(components[3]),
        )
        for det_key, components in feature_components_by_detector.items()
    }
    binary_fast_path_stats.merge_time_s += float(time.perf_counter() - merge_started)
    return (
        next_log_mass,
        next_viterbi,
        next_viterbi_rep_cost,
        next_parent,
        next_detector_features,
        incoming_count_by_key,
        int(transition_count),
        int(closure_reject_count),
    )


def _advance_binary_frontierk_logodds_primary_topk_fast_path(
    *,
    state_log_mass: dict[int, float],
    current_detector_features: dict[int, FrontierMismatchFeatures],
    binary_payload: BinaryFrontierKColumnPayload,
    close_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    detector_mask_mask: int,
    logical_mask_mask: int,
    state_key_logical_shift: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    beam_size: int,
    beam_score_gap_threshold: float,
    compiled_plan: tuple[float, bool, str],
    num_observables: int,
    diagnostic_truth_logical_mask: int | None,
    no_merge_fast_path_enabled: bool,
    array_candidate_buffer_enabled: bool,
    sparse_viterbi_maps_enabled: bool,
    local_pattern_feature_table_enabled: bool,
    unique_detector_score_fast_path_enabled: bool,
    small_candidate_direct_gap_enabled: bool,
    zero_close_mask_fast_path_enabled: bool,
    streaming_rank_selector_enabled: bool,
    two_pass_rank_selector_enabled: bool,
    deferred_feature_materialization_enabled: bool,
    hotloop_instrumentation_enabled: bool,
    future_parity_scorer_stats: FutureParityScorerStats,
    binary_fast_path_stats: BinaryFrontierKFastPathStats,
) -> tuple[
    dict[int, float],
    dict[int, float],
    dict[int, int],
    dict[int, tuple[int, int]],
    dict[int, FrontierMismatchFeatures],
    dict[int, int],
    int,
    int,
    int,
    int,
    int,
    int,
    int,
    float,
    float,
    float,
    float,
    float,
    float,
    float,
]:
    """Fused production path for binary logodds advance plus primary fixed-Delta top-K."""
    fused_started = time.perf_counter()
    expansion_started = fused_started
    no_error_log_const = float(binary_payload.no_error_log_const)
    toggle_logodds = float(binary_payload.toggle_logodds)
    toggle_detector_mask = int(binary_payload.toggle_detector_mask)
    toggle_observable_mask = int(binary_payload.toggle_observable_mask)
    toggle_finite = math.isfinite(float(toggle_logodds))

    close_mask_int = int(close_mask)
    active_mask_int = int(active_mask)
    target_int = int(target_syndrome_int)
    detector_mask_mask_int = int(detector_mask_mask)
    logical_mask_mask_int = int(logical_mask_mask)
    logical_shift = int(state_key_logical_shift)
    prev_column_index = int(column_index) - 1
    prev_active_mask = 0 if int(prev_column_index) < 0 else int(frontier.active_masks_after_column[int(prev_column_index)])

    before_row_bit_masks = binary_payload.before_row_bit_masks
    before_touch = binary_payload.before_touch_bonus_weights
    before_urgency = binary_payload.before_urgency_weights
    before_parity = binary_payload.before_parity_logodds_weights
    after_row_bit_masks = binary_payload.after_row_bit_masks
    after_touch = binary_payload.after_touch_bonus_weights
    after_urgency = binary_payload.after_urgency_weights
    after_parity = binary_payload.after_parity_logodds_weights
    local_row_mask = int(binary_payload.toggle_detector_mask)

    if bool(no_merge_fast_path_enabled):
        no_merge_feature_components_by_detector: dict[int, tuple[int, float, float, float]] = {}
        no_merge_seen_keys: set[int] = set()
        no_merge_candidate_items: list[tuple[int, int, float]] = []
        no_merge_candidate_items_append = no_merge_candidate_items.append
        no_merge_seen_add = no_merge_seen_keys.add
        no_merge_failed = False
        no_merge_current_features_get = current_detector_features.get
        no_merge_transition_count = 0
        no_merge_closure_reject_count = 0
        no_merge_explicit_branch_count = 0
        no_merge_skipped_no_error_count = 0
        no_merge_feature_update_count = 0
        no_merge_feature_update_time_s = 0.0
        no_merge_fallback_score_calls = 0
        no_merge_from_scratch_score_calls = 0
        no_merge_fallback_score_time_s = 0.0

        for key_raw, log_mass_raw in state_log_mass.items():
            key_int = int(key_raw)
            log_mass = float(log_mass_raw)
            det_mask = int(key_int & detector_mask_mask_int)
            logical_mask = int((key_int >> logical_shift) & logical_mask_mask_int)
            parent_feature = no_merge_current_features_get(det_mask)
            if parent_feature is None:
                fallback_started = time.perf_counter()
                parent_feature = _future_mismatch_features(
                    det_mask=det_mask,
                    active_mask=prev_active_mask,
                    target_syndrome_int=target_int,
                    column_index=prev_column_index,
                    frontier=frontier,
                )
                no_merge_fallback_score_calls += 1
                no_merge_from_scratch_score_calls += 1
                no_merge_fallback_score_time_s += float(time.perf_counter() - fallback_started)
            parent_mismatch_count = int(parent_feature.mismatch_count)
            parent_touch_bonus = float(parent_feature.touch_bonus)
            parent_urgency_penalty = float(parent_feature.urgency_penalty)
            parent_parity_logodds = float(parent_feature.parity_logodds)

            no_next_det = 0
            toggle_next_det = 0
            no_accepted = False
            toggle_accepted = False

            no_merge_transition_count += 1
            no_merge_skipped_no_error_count += 1
            no_candidate_det = det_mask
            if ((no_candidate_det ^ target_int) & close_mask_int) != 0:
                no_merge_closure_reject_count += 1
            else:
                no_accepted = True
                no_next_det = no_candidate_det & active_mask_int

            if toggle_finite:
                no_merge_transition_count += 1
                no_merge_explicit_branch_count += 1
                toggle_candidate_det = det_mask ^ toggle_detector_mask
                if ((toggle_candidate_det ^ target_int) & close_mask_int) != 0:
                    no_merge_closure_reject_count += 1
                else:
                    toggle_accepted = True
                    toggle_next_det = toggle_candidate_det & active_mask_int

            need_no_feature = no_accepted and no_next_det not in no_merge_feature_components_by_detector
            need_toggle_feature = (
                toggle_accepted
                and toggle_next_det not in no_merge_feature_components_by_detector
            )
            if need_no_feature or need_toggle_feature:
                feature_started = time.perf_counter()
                parent_mismatch_mask = det_mask ^ target_int
                base_count = parent_mismatch_count
                base_touch = parent_touch_bonus
                base_urgency = parent_urgency_penalty
                base_parity = parent_parity_logodds
                for index, row_mask in enumerate(before_row_bit_masks):
                    if (parent_mismatch_mask & row_mask) != 0:
                        base_count -= 1
                        base_touch -= before_touch[index]
                        base_urgency -= before_urgency[index]
                        base_parity -= before_parity[index]
                no_count = base_count
                toggle_count = base_count
                no_touch = base_touch
                toggle_touch = base_touch
                no_urgency = base_urgency
                toggle_urgency = base_urgency
                no_parity = base_parity
                toggle_parity = base_parity
                for index, row_mask in enumerate(after_row_bit_masks):
                    if (parent_mismatch_mask & row_mask) != 0:
                        no_count += 1
                        no_touch += after_touch[index]
                        no_urgency += after_urgency[index]
                        no_parity += after_parity[index]
                    else:
                        toggle_count += 1
                        toggle_touch += after_touch[index]
                        toggle_urgency += after_urgency[index]
                        toggle_parity += after_parity[index]
                no_merge_feature_update_time_s += float(time.perf_counter() - feature_started)
                if need_no_feature:
                    no_merge_feature_components_by_detector[no_next_det] = (
                        no_count,
                        no_touch,
                        no_urgency,
                        no_parity,
                    )
                    no_merge_feature_update_count += 1
                if need_toggle_feature:
                    no_merge_feature_components_by_detector[toggle_next_det] = (
                        toggle_count,
                        toggle_touch,
                        toggle_urgency,
                        toggle_parity,
                    )
                    no_merge_feature_update_count += 1

            if no_accepted:
                next_key = no_next_det | (logical_mask << logical_shift)
                if next_key in no_merge_seen_keys:
                    no_merge_failed = True
                    break
                no_merge_seen_add(next_key)
                no_merge_candidate_items_append((next_key, no_next_det, log_mass))

            if toggle_accepted:
                next_logical = logical_mask ^ toggle_observable_mask
                next_key = toggle_next_det | (next_logical << logical_shift)
                if next_key in no_merge_seen_keys:
                    no_merge_failed = True
                    break
                no_merge_seen_add(next_key)
                no_merge_candidate_items_append((next_key, toggle_next_det, log_mass + toggle_logodds))

        if not bool(no_merge_failed):
            binary_fast_path_stats.transition_expansion_time_s += float(
                time.perf_counter() - expansion_started
            )
            binary_fast_path_stats.explicit_branch_count += int(no_merge_explicit_branch_count)
            binary_fast_path_stats.skipped_no_error_branch_count += int(no_merge_skipped_no_error_count)
            future_parity_scorer_stats.incremental_update_count += int(no_merge_feature_update_count)
            future_parity_scorer_stats.fallback_score_calls += int(no_merge_fallback_score_calls)
            future_parity_scorer_stats.from_scratch_score_calls += int(no_merge_from_scratch_score_calls)
            future_parity_scorer_stats.scorer_time_s += float(
                no_merge_feature_update_time_s + no_merge_fallback_score_time_s
            )

            prune_started = time.perf_counter()
            selected_beam_size = int(beam_size)
            candidate_count = int(len(no_merge_candidate_items))
            accepted_transition_count = int(no_merge_transition_count) - int(no_merge_closure_reject_count)
            merge_count = 0
            if bool(hotloop_instrumentation_enabled):
                _record_binary_hotloop_instrumentation(
                    stats=binary_fast_path_stats,
                    state_log_mass=state_log_mass,
                    detector_mask_mask=detector_mask_mask_int,
                    target_syndrome_int=target_int,
                    local_row_mask=local_row_mask,
                    accepted_transition_count=int(accepted_transition_count),
                    candidate_count=int(candidate_count),
                    unique_candidate_detector_count=int(len(no_merge_feature_components_by_detector)),
                )
            alpha, future_only, _heuristic_mode_key = compiled_plan
            alpha_value = float(alpha)
            future_only_value = bool(future_only)
            truth_logical_target_mask = (
                None if diagnostic_truth_logical_mask is None else int(diagnostic_truth_logical_mask)
            )
            truth_logical_accounting_enabled = truth_logical_target_mask is not None
            logical_mask_mask_for_truth = (1 << int(num_observables)) - 1

            compiled_score_by_detector: dict[int, float] = {}
            candidate_prefix_mass = 0.0
            truth_logical_candidate_prefix_mass = 0.0
            best_rank_value: tuple[float, float, float] | None = None
            top_log_mass_key: int | None = None
            top_log_mass_value = float("-inf")
            candidate_rank_items: list[tuple[int, int, float, float, float, bool]] = []
            candidate_rank_items_append = candidate_rank_items.append
            feature_components_get = no_merge_feature_components_by_detector.__getitem__
            compiled_score_get = compiled_score_by_detector.get
            compiled_score_set = compiled_score_by_detector.__setitem__
            exp = math.exp
            score_calls = 0

            for key_int, det_key, raw_prefix_mass in no_merge_candidate_items:
                prefix_mass = float(raw_prefix_mass) + float(no_error_log_const)
                prefix_prob = float(exp(prefix_mass))
                candidate_prefix_mass += float(prefix_prob)
                truth_logical_match = False
                if bool(truth_logical_accounting_enabled) and (
                    (int(key_int) >> int(logical_shift)) & int(logical_mask_mask_for_truth)
                ) == int(truth_logical_target_mask):
                    truth_logical_candidate_prefix_mass += float(prefix_prob)
                    truth_logical_match = True
                if top_log_mass_key is None or float(prefix_mass) > float(top_log_mass_value):
                    top_log_mass_key = int(key_int)
                    top_log_mass_value = float(prefix_mass)
                heuristic_mass = compiled_score_get(int(det_key))
                if heuristic_mass is None:
                    components = feature_components_get(int(det_key))
                    score_calls += 1
                    heuristic_mass = alpha_value * float(components[3])
                    compiled_score_set(int(det_key), float(heuristic_mass))
                rank0 = (
                    float(heuristic_mass)
                    if bool(future_only_value)
                    else float(prefix_mass) + float(heuristic_mass)
                )
                candidate_rank_items_append(
                    (
                        int(key_int),
                        int(det_key),
                        float(prefix_mass),
                        float(prefix_prob),
                        float(rank0),
                        bool(truth_logical_match),
                    )
                )
                rank_value = (float(rank0), float(prefix_mass), 0.0)
                if best_rank_value is None or rank_value > best_rank_value:
                    best_rank_value = rank_value
            future_parity_scorer_stats.score_calls += int(score_calls)

            top_log_mass_incoming_count = 0 if top_log_mass_key is None else 1
            top_log_mass_merge_count = 0

            kept_indices: list[int] = []
            if best_rank_value is None or int(selected_beam_size) <= 0:
                kept_keys: list[int] = []
            else:
                cutoff = float(best_rank_value[0]) - float(beam_score_gap_threshold)
                score_gap_keys: list[int] = []
                score_gap_indices: list[int] = []
                score_gap_rank0_values: list[float] = []
                score_gap_rank1_values: list[float] = []
                score_gap_count = 0
                top_heap: list[tuple[tuple[float, float, float, int], int]] | None = None
                for candidate_index, rank_item in enumerate(candidate_rank_items):
                    key_int = int(rank_item[0])
                    rank0 = float(rank_item[4])
                    rank1 = float(rank_item[2])
                    if not (float(rank0) >= float(cutoff)):
                        continue
                    insertion_index = int(score_gap_count)
                    score_gap_count += 1
                    if int(score_gap_count) <= int(selected_beam_size):
                        score_gap_keys.append(key_int)
                        score_gap_indices.append(int(candidate_index))
                        score_gap_rank0_values.append(float(rank0))
                        score_gap_rank1_values.append(float(rank1))
                        continue
                    comparable = (float(rank0), float(rank1), 0.0, -int(insertion_index))
                    if top_heap is None:
                        top_heap = [
                            (
                                (
                                    float(score_gap_rank0_values[index]),
                                    float(score_gap_rank1_values[index]),
                                    0.0,
                                    -int(index),
                                ),
                                int(score_gap_indices[index]),
                            )
                            for index in range(int(selected_beam_size))
                        ]
                        heapq.heapify(top_heap)
                    if comparable > top_heap[0][0]:
                        heapq.heapreplace(top_heap, (comparable, int(candidate_index)))
                if int(score_gap_count) <= int(selected_beam_size):
                    kept_keys = list(score_gap_keys)
                    kept_indices = list(score_gap_indices)
                elif top_heap is None:
                    kept_keys = list(score_gap_keys[: int(selected_beam_size)])
                    kept_indices = list(score_gap_indices[: int(selected_beam_size)])
                else:
                    kept_indices = [
                        int(candidate_index)
                        for _comparable, candidate_index in sorted(
                            top_heap,
                            key=lambda item: item[0],
                            reverse=True,
                        )
                    ]
                    kept_keys = [
                        int(candidate_rank_items[int(candidate_index)][0])
                        for candidate_index in kept_indices
                    ]

            merge_started = time.perf_counter()
            pruned_count = int(candidate_count - len(kept_keys))
            kept_log_mass: dict[int, float] = {}
            retained_prefix_mass = 0.0
            truth_logical_retained_prefix_mass = 0.0
            kept_detector_features: dict[int, FrontierMismatchFeatures] = {}
            for kept_index in kept_indices:
                candidate_index = int(kept_index)
                rank_item = candidate_rank_items[int(candidate_index)]
                key_int = int(rank_item[0])
                det_key = int(rank_item[1])
                log_mass = float(rank_item[2])
                prefix_prob = float(rank_item[3])
                kept_log_mass[key_int] = log_mass
                retained_prefix_mass += float(prefix_prob)
                if bool(truth_logical_accounting_enabled) and bool(rank_item[5]):
                    truth_logical_retained_prefix_mass += float(prefix_prob)
                if int(det_key) not in kept_detector_features:
                    components = feature_components_get(int(det_key))
                    kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                        mismatch_count=int(components[0]),
                        touch_bonus=float(components[1]),
                        urgency_penalty=float(components[2]),
                        parity_logodds=float(components[3]),
                    )
            if bool(sparse_viterbi_maps_enabled):
                kept_viterbi = kept_log_mass
                kept_viterbi_rep_cost = {}
            else:
                kept_viterbi = dict(kept_log_mass)
                kept_viterbi_rep_cost: dict[int, int] = {
                    int(key): 0 for key in kept_log_mass.keys()
                }
            kept_parent: dict[int, tuple[int, int]] = {}
            kept_incoming_count_by_key: dict[int, int] = {}
            binary_fast_path_stats.merge_time_s += float(time.perf_counter() - merge_started)

            discarded_prefix_mass = (
                max(0.0, float(candidate_prefix_mass) - float(retained_prefix_mass))
                if int(pruned_count) > 0
                else 0.0
            )
            discarded_prefix_mass_fraction = (
                float(discarded_prefix_mass) / float(candidate_prefix_mass)
                if float(candidate_prefix_mass) > 0.0
                else 0.0
            )
            truth_logical_discarded_prefix_mass = 0.0
            truth_logical_discarded_prefix_mass_fraction = 0.0
            if bool(truth_logical_accounting_enabled):
                truth_logical_discarded_prefix_mass = max(
                    0.0,
                    float(truth_logical_candidate_prefix_mass)
                    - float(truth_logical_retained_prefix_mass),
                )
                truth_logical_discarded_prefix_mass_fraction = (
                    float(truth_logical_discarded_prefix_mass)
                    / float(truth_logical_candidate_prefix_mass)
                    if float(truth_logical_candidate_prefix_mass) > 0.0
                    else 0.0
                )
            binary_fast_path_stats.prune_sort_time_s += float(time.perf_counter() - prune_started)
            binary_fast_path_stats.fused_primary_topk_count += 1
            binary_fast_path_stats.fused_primary_topk_time_s += float(
                time.perf_counter() - fused_started
            )

            return (
                kept_log_mass,
                kept_viterbi,
                kept_viterbi_rep_cost,
                kept_parent,
                kept_detector_features,
                kept_incoming_count_by_key,
                int(no_merge_transition_count),
                int(no_merge_closure_reject_count),
                int(candidate_count),
                int(merge_count),
                int(top_log_mass_incoming_count),
                int(top_log_mass_merge_count),
                int(pruned_count),
                float(candidate_prefix_mass),
                float(retained_prefix_mass),
                float(discarded_prefix_mass_fraction),
                float(truth_logical_candidate_prefix_mass),
                float(truth_logical_retained_prefix_mass),
                float(truth_logical_discarded_prefix_mass),
                float(truth_logical_discarded_prefix_mass_fraction),
            )

        expansion_started = time.perf_counter()

    if bool(array_candidate_buffer_enabled):
        feature_components_by_detector: dict[int, tuple[int, float, float, float]] = {}
        candidate_index_by_key: dict[int, int] = {}
        candidate_keys: list[int] = []
        candidate_det_keys: list[int] = []
        candidate_log_masses: list[float] = []
        candidate_extra_counts: list[int] = []
        candidate_keys_append = candidate_keys.append
        candidate_det_keys_append = candidate_det_keys.append
        candidate_log_masses_append = candidate_log_masses.append
        candidate_extra_counts_append = candidate_extra_counts.append
        candidate_index_get = candidate_index_by_key.get
        candidate_index_set = candidate_index_by_key.__setitem__

        current_features_get = current_detector_features.get
        logadd = _logaddexp_pair
        transition_count = 0
        closure_reject_count = 0
        explicit_branch_count = 0
        skipped_no_error_count = 0
        feature_update_count = 0
        feature_update_time_s = 0.0

        for key_raw, log_mass_raw in state_log_mass.items():
            key_int = int(key_raw)
            log_mass = float(log_mass_raw)
            det_mask = int(key_int & detector_mask_mask_int)
            logical_mask = int((key_int >> logical_shift) & logical_mask_mask_int)
            parent_feature = current_features_get(det_mask)
            if parent_feature is None:
                fallback_started = time.perf_counter()
                parent_feature = _future_mismatch_features(
                    det_mask=det_mask,
                    active_mask=prev_active_mask,
                    target_syndrome_int=target_int,
                    column_index=prev_column_index,
                    frontier=frontier,
                )
                future_parity_scorer_stats.fallback_score_calls += 1
                future_parity_scorer_stats.from_scratch_score_calls += 1
                future_parity_scorer_stats.scorer_time_s += float(time.perf_counter() - fallback_started)
            parent_mismatch_count = int(parent_feature.mismatch_count)
            parent_touch_bonus = float(parent_feature.touch_bonus)
            parent_urgency_penalty = float(parent_feature.urgency_penalty)
            parent_parity_logodds = float(parent_feature.parity_logodds)

            no_next_det = 0
            toggle_next_det = 0
            no_accepted = False
            toggle_accepted = False

            transition_count += 1
            skipped_no_error_count += 1
            no_candidate_det = det_mask
            if ((no_candidate_det ^ target_int) & close_mask_int) != 0:
                closure_reject_count += 1
            else:
                no_accepted = True
                no_next_det = no_candidate_det & active_mask_int

            if toggle_finite:
                transition_count += 1
                explicit_branch_count += 1
                toggle_candidate_det = det_mask ^ toggle_detector_mask
                if ((toggle_candidate_det ^ target_int) & close_mask_int) != 0:
                    closure_reject_count += 1
                else:
                    toggle_accepted = True
                    toggle_next_det = toggle_candidate_det & active_mask_int

            need_no_feature = no_accepted and no_next_det not in feature_components_by_detector
            need_toggle_feature = toggle_accepted and toggle_next_det not in feature_components_by_detector
            if need_no_feature or need_toggle_feature:
                feature_started = time.perf_counter()
                parent_mismatch_mask = det_mask ^ target_int
                base_count = parent_mismatch_count
                base_touch = parent_touch_bonus
                base_urgency = parent_urgency_penalty
                base_parity = parent_parity_logodds
                for index, row_mask in enumerate(before_row_bit_masks):
                    if (parent_mismatch_mask & row_mask) != 0:
                        base_count -= 1
                        base_touch -= before_touch[index]
                        base_urgency -= before_urgency[index]
                        base_parity -= before_parity[index]
                no_count = base_count
                toggle_count = base_count
                no_touch = base_touch
                toggle_touch = base_touch
                no_urgency = base_urgency
                toggle_urgency = base_urgency
                no_parity = base_parity
                toggle_parity = base_parity
                for index, row_mask in enumerate(after_row_bit_masks):
                    if (parent_mismatch_mask & row_mask) != 0:
                        no_count += 1
                        no_touch += after_touch[index]
                        no_urgency += after_urgency[index]
                        no_parity += after_parity[index]
                    else:
                        toggle_count += 1
                        toggle_touch += after_touch[index]
                        toggle_urgency += after_urgency[index]
                        toggle_parity += after_parity[index]
                feature_update_time_s += float(time.perf_counter() - feature_started)
                if need_no_feature:
                    feature_components_by_detector[no_next_det] = (
                        no_count,
                        no_touch,
                        no_urgency,
                        no_parity,
                    )
                    feature_update_count += 1
                if need_toggle_feature:
                    feature_components_by_detector[toggle_next_det] = (
                        toggle_count,
                        toggle_touch,
                        toggle_urgency,
                        toggle_parity,
                    )
                    feature_update_count += 1

            if no_accepted:
                next_key = no_next_det | (logical_mask << logical_shift)
                existing_index = candidate_index_get(next_key)
                if existing_index is None:
                    candidate_index = len(candidate_keys)
                    candidate_index_set(next_key, int(candidate_index))
                    candidate_keys_append(int(next_key))
                    candidate_det_keys_append(int(no_next_det))
                    candidate_log_masses_append(float(log_mass))
                    candidate_extra_counts_append(0)
                else:
                    candidate_index = int(existing_index)
                    candidate_extra_counts[candidate_index] = int(candidate_extra_counts[candidate_index]) + 1
                    candidate_log_masses[candidate_index] = logadd(
                        float(candidate_log_masses[candidate_index]),
                        log_mass,
                    )

            if toggle_accepted:
                next_logical = logical_mask ^ toggle_observable_mask
                next_key = toggle_next_det | (next_logical << logical_shift)
                new_log_mass = log_mass + toggle_logodds
                existing_index = candidate_index_get(next_key)
                if existing_index is None:
                    candidate_index = len(candidate_keys)
                    candidate_index_set(next_key, int(candidate_index))
                    candidate_keys_append(int(next_key))
                    candidate_det_keys_append(int(toggle_next_det))
                    candidate_log_masses_append(float(new_log_mass))
                    candidate_extra_counts_append(0)
                else:
                    candidate_index = int(existing_index)
                    candidate_extra_counts[candidate_index] = int(candidate_extra_counts[candidate_index]) + 1
                    candidate_log_masses[candidate_index] = logadd(
                        float(candidate_log_masses[candidate_index]),
                        float(new_log_mass),
                    )

        binary_fast_path_stats.transition_expansion_time_s += float(time.perf_counter() - expansion_started)
        binary_fast_path_stats.explicit_branch_count += int(explicit_branch_count)
        binary_fast_path_stats.skipped_no_error_branch_count += int(skipped_no_error_count)
        future_parity_scorer_stats.incremental_update_count += int(feature_update_count)
        future_parity_scorer_stats.scorer_time_s += float(feature_update_time_s)

        prune_started = time.perf_counter()
        selected_beam_size = int(beam_size)
        candidate_count = int(len(candidate_keys))
        accepted_transition_count = int(transition_count) - int(closure_reject_count)
        merge_count = max(0, int(accepted_transition_count) - int(candidate_count))
        if bool(hotloop_instrumentation_enabled):
            _record_binary_hotloop_instrumentation(
                stats=binary_fast_path_stats,
                state_log_mass=state_log_mass,
                detector_mask_mask=detector_mask_mask_int,
                target_syndrome_int=target_int,
                local_row_mask=local_row_mask,
                accepted_transition_count=int(accepted_transition_count),
                candidate_count=int(candidate_count),
                unique_candidate_detector_count=int(len(feature_components_by_detector)),
            )
        alpha, future_only, _heuristic_mode_key = compiled_plan
        alpha_value = float(alpha)
        future_only_value = bool(future_only)
        truth_logical_target_mask = (
            None if diagnostic_truth_logical_mask is None else int(diagnostic_truth_logical_mask)
        )
        truth_logical_accounting_enabled = truth_logical_target_mask is not None
        logical_mask_mask_for_truth = (1 << int(num_observables)) - 1

        compiled_score_by_detector: dict[int, float] = {}
        candidate_prefix_masses: list[float] = [0.0] * int(candidate_count)
        candidate_prefix_probs: list[float] = [0.0] * int(candidate_count)
        candidate_truth_flags: list[bool] = [False] * int(candidate_count)
        candidate_prefix_mass = 0.0
        truth_logical_candidate_prefix_mass = 0.0
        best_rank_value: tuple[float, float, float] | None = None
        top_log_mass_index = -1
        top_log_mass_value = float("-inf")
        feature_components_get = feature_components_by_detector.__getitem__
        compiled_score_get = compiled_score_by_detector.get
        compiled_score_set = compiled_score_by_detector.__setitem__
        exp = math.exp
        score_calls = 0

        for candidate_index, key_int in enumerate(candidate_keys):
            prefix_mass = float(candidate_log_masses[int(candidate_index)]) + float(no_error_log_const)
            prefix_prob = float(exp(prefix_mass))
            candidate_prefix_masses[int(candidate_index)] = float(prefix_mass)
            candidate_prefix_probs[int(candidate_index)] = float(prefix_prob)
            candidate_prefix_mass += float(prefix_prob)
            truth_logical_match = False
            if bool(truth_logical_accounting_enabled) and (
                (int(key_int) >> int(logical_shift)) & int(logical_mask_mask_for_truth)
            ) == int(truth_logical_target_mask):
                truth_logical_candidate_prefix_mass += float(prefix_prob)
                truth_logical_match = True
            candidate_truth_flags[int(candidate_index)] = bool(truth_logical_match)
            if int(top_log_mass_index) < 0 or float(prefix_mass) > float(top_log_mass_value):
                top_log_mass_index = int(candidate_index)
                top_log_mass_value = float(prefix_mass)
            det_key = int(candidate_det_keys[int(candidate_index)])
            heuristic_mass = compiled_score_get(det_key)
            if heuristic_mass is None:
                components = feature_components_get(det_key)
                score_calls += 1
                heuristic_mass = alpha_value * float(components[3])
                compiled_score_set(det_key, float(heuristic_mass))
            rank0 = (
                float(heuristic_mass)
                if bool(future_only_value)
                else float(prefix_mass) + float(heuristic_mass)
            )
            if (
                best_rank_value is None
                or float(rank0) > float(best_rank_value[0])
                or (
                    float(rank0) == float(best_rank_value[0])
                    and float(prefix_mass) > float(best_rank_value[1])
                )
            ):
                best_rank_value = (float(rank0), float(prefix_mass), 0.0)
        future_parity_scorer_stats.score_calls += int(score_calls)

        top_log_mass_incoming_count = (
            0
            if int(top_log_mass_index) < 0
            else 1 + int(candidate_extra_counts[int(top_log_mass_index)])
        )
        top_log_mass_merge_count = max(0, int(top_log_mass_incoming_count) - 1)

        kept_indices: list[int] = []
        if best_rank_value is None or int(selected_beam_size) <= 0:
            pass
        else:
            cutoff = float(best_rank_value[0]) - float(beam_score_gap_threshold)
            score_gap_indices: list[int] = []
            score_gap_rank0_values: list[float] = []
            score_gap_rank1_values: list[float] = []
            score_gap_count = 0
            top_heap: list[tuple[tuple[float, float, float, int], int]] | None = None
            for candidate_index, prefix_mass in enumerate(candidate_prefix_masses):
                rank1 = float(prefix_mass)
                det_key = int(candidate_det_keys[int(candidate_index)])
                heuristic_mass = compiled_score_by_detector[det_key]
                rank0 = (
                    float(heuristic_mass)
                    if bool(future_only_value)
                    else float(prefix_mass) + float(heuristic_mass)
                )
                if not (float(rank0) >= float(cutoff)):
                    continue
                insertion_index = int(score_gap_count)
                score_gap_count += 1
                if int(score_gap_count) <= int(selected_beam_size):
                    score_gap_indices.append(int(candidate_index))
                    score_gap_rank0_values.append(float(rank0))
                    score_gap_rank1_values.append(float(rank1))
                    continue
                comparable = (float(rank0), float(rank1), 0.0, -int(insertion_index))
                if top_heap is None:
                    top_heap = [
                        (
                            (
                                float(score_gap_rank0_values[index]),
                                float(score_gap_rank1_values[index]),
                                0.0,
                                -int(index),
                            ),
                            int(score_gap_indices[index]),
                        )
                        for index in range(int(selected_beam_size))
                    ]
                    heapq.heapify(top_heap)
                if comparable > top_heap[0][0]:
                    heapq.heapreplace(top_heap, (comparable, int(candidate_index)))
            if int(score_gap_count) <= int(selected_beam_size):
                kept_indices = list(score_gap_indices)
            elif top_heap is None:
                kept_indices = list(score_gap_indices[: int(selected_beam_size)])
            else:
                kept_indices = [
                    int(candidate_index)
                    for _comparable, candidate_index in sorted(
                        top_heap,
                        key=lambda item: item[0],
                        reverse=True,
                    )
                ]

        merge_started = time.perf_counter()
        pruned_count = int(candidate_count - len(kept_indices))
        kept_log_mass: dict[int, float] = {}
        retained_prefix_mass = 0.0
        truth_logical_retained_prefix_mass = 0.0
        kept_detector_features: dict[int, FrontierMismatchFeatures] = {}
        kept_incoming_count_by_key: dict[int, int] = {}
        for kept_index in kept_indices:
            candidate_index = int(kept_index)
            key_int = int(candidate_keys[candidate_index])
            det_key = int(candidate_det_keys[candidate_index])
            kept_log_mass[key_int] = float(candidate_prefix_masses[candidate_index])
            prefix_prob = float(candidate_prefix_probs[candidate_index])
            retained_prefix_mass += float(prefix_prob)
            if bool(truth_logical_accounting_enabled) and bool(candidate_truth_flags[candidate_index]):
                truth_logical_retained_prefix_mass += float(prefix_prob)
            extra_count = int(candidate_extra_counts[candidate_index])
            if int(extra_count) > 0:
                kept_incoming_count_by_key[key_int] = 1 + int(extra_count)
            if int(det_key) not in kept_detector_features:
                components = feature_components_get(det_key)
                kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                    mismatch_count=int(components[0]),
                    touch_bonus=float(components[1]),
                    urgency_penalty=float(components[2]),
                    parity_logodds=float(components[3]),
                )
        if bool(sparse_viterbi_maps_enabled):
            kept_viterbi = kept_log_mass
            kept_viterbi_rep_cost = {}
        else:
            kept_viterbi = dict(kept_log_mass)
            kept_viterbi_rep_cost: dict[int, int] = {int(key): 0 for key in kept_log_mass.keys()}
        kept_parent: dict[int, tuple[int, int]] = {}
        binary_fast_path_stats.merge_time_s += float(time.perf_counter() - merge_started)

        discarded_prefix_mass = (
            max(0.0, float(candidate_prefix_mass) - float(retained_prefix_mass))
            if int(pruned_count) > 0
            else 0.0
        )
        discarded_prefix_mass_fraction = (
            float(discarded_prefix_mass) / float(candidate_prefix_mass)
            if float(candidate_prefix_mass) > 0.0
            else 0.0
        )
        truth_logical_discarded_prefix_mass = 0.0
        truth_logical_discarded_prefix_mass_fraction = 0.0
        if bool(truth_logical_accounting_enabled):
            truth_logical_discarded_prefix_mass = max(
                0.0,
                float(truth_logical_candidate_prefix_mass) - float(truth_logical_retained_prefix_mass),
            )
            truth_logical_discarded_prefix_mass_fraction = (
                float(truth_logical_discarded_prefix_mass) / float(truth_logical_candidate_prefix_mass)
                if float(truth_logical_candidate_prefix_mass) > 0.0
                else 0.0
            )
        binary_fast_path_stats.prune_sort_time_s += float(time.perf_counter() - prune_started)
        binary_fast_path_stats.fused_primary_topk_count += 1
        binary_fast_path_stats.fused_primary_topk_time_s += float(time.perf_counter() - fused_started)

        return (
            kept_log_mass,
            kept_viterbi,
            kept_viterbi_rep_cost,
            kept_parent,
            kept_detector_features,
            kept_incoming_count_by_key,
            int(transition_count),
            int(closure_reject_count),
            int(candidate_count),
            int(merge_count),
            int(top_log_mass_incoming_count),
            int(top_log_mass_merge_count),
            int(pruned_count),
            float(candidate_prefix_mass),
            float(retained_prefix_mass),
            float(discarded_prefix_mass_fraction),
            float(truth_logical_candidate_prefix_mass),
            float(truth_logical_retained_prefix_mass),
            float(truth_logical_discarded_prefix_mass),
            float(truth_logical_discarded_prefix_mass_fraction),
        )

    feature_components_by_detector: dict[int, tuple[int, float, float, float]] = {}
    feature_parity_by_detector: dict[int, float] = {}
    deferred_feature_recipe_by_detector: dict[int, tuple[FrontierMismatchFeatures, int, bool]] = {}
    next_log_mass: dict[int, float] = {}
    merged_extra_count_by_key: dict[int, int] = {}

    current_features_get = current_detector_features.get
    next_log_mass_get = next_log_mass.get
    merged_extra_get = merged_extra_count_by_key.get
    logadd = _logaddexp_pair
    transition_count = 0
    closure_reject_count = 0
    explicit_branch_count = 0
    skipped_no_error_count = 0
    feature_update_count = 0
    feature_update_time_s = 0.0
    feature_table = (
        binary_payload.local_pattern_feature_table
        if bool(local_pattern_feature_table_enabled)
        else None
    )
    if feature_table is not None:
        table_local_row_mask = int(feature_table.local_row_mask)
        table_pattern_by_local_mask = feature_table.pattern_by_local_mask
        table_no_count_deltas = feature_table.no_count_deltas
        table_no_touch_deltas = feature_table.no_touch_deltas
        table_no_urgency_deltas = feature_table.no_urgency_deltas
        table_no_parity_deltas = feature_table.no_parity_deltas
        table_toggle_count_deltas = feature_table.toggle_count_deltas
        table_toggle_touch_deltas = feature_table.toggle_touch_deltas
        table_toggle_urgency_deltas = feature_table.toggle_urgency_deltas
        table_toggle_parity_deltas = feature_table.toggle_parity_deltas
        table_entry_count = int(len(table_no_count_deltas))
        binary_fast_path_stats.local_pattern_feature_table_boundary_count += 1
        binary_fast_path_stats.local_pattern_feature_table_entry_count += int(table_entry_count)
        binary_fast_path_stats.local_pattern_feature_table_max_entries_per_column = max(
            int(binary_fast_path_stats.local_pattern_feature_table_max_entries_per_column),
            int(table_entry_count),
        )
    elif bool(local_pattern_feature_table_enabled):
        table_local_row_mask = 0
        table_pattern_by_local_mask: dict[int, int] = {}
        table_no_count_deltas: tuple[int, ...] = tuple()
        table_no_touch_deltas: tuple[float, ...] = tuple()
        table_no_urgency_deltas: tuple[float, ...] = tuple()
        table_no_parity_deltas: tuple[float, ...] = tuple()
        table_toggle_count_deltas: tuple[int, ...] = tuple()
        table_toggle_touch_deltas: tuple[float, ...] = tuple()
        table_toggle_urgency_deltas: tuple[float, ...] = tuple()
        table_toggle_parity_deltas: tuple[float, ...] = tuple()
        binary_fast_path_stats.local_pattern_feature_table_fallback_count += 1
    else:
        table_local_row_mask = 0
        table_pattern_by_local_mask = {}
        table_no_count_deltas = tuple()
        table_no_touch_deltas = tuple()
        table_no_urgency_deltas = tuple()
        table_no_parity_deltas = tuple()
        table_toggle_count_deltas = tuple()
        table_toggle_touch_deltas = tuple()
        table_toggle_urgency_deltas = tuple()
        table_toggle_parity_deltas = tuple()

    deferred_feature_materialization_used = bool(
        deferred_feature_materialization_enabled and feature_table is not None
    )
    if bool(deferred_feature_materialization_used):
        binary_fast_path_stats.deferred_feature_materialization_boundary_count += 1
    elif bool(deferred_feature_materialization_enabled):
        binary_fast_path_stats.deferred_feature_materialization_fallback_count += 1
    zero_close_mask_fast_path_used = bool(
        zero_close_mask_fast_path_enabled and int(close_mask_int) == 0
    )
    if bool(zero_close_mask_fast_path_used):
        binary_fast_path_stats.zero_close_mask_fast_path_boundary_count += 1
        binary_fast_path_stats.zero_close_mask_fast_path_state_count += int(len(state_log_mass))
    zero_close_toggle_finite_fast_path_used = bool(
        zero_close_mask_fast_path_used and toggle_finite
    )

    for key_raw, log_mass_raw in state_log_mass.items():
        key_int = int(key_raw)
        log_mass = float(log_mass_raw)
        det_mask = int(key_int & detector_mask_mask_int)
        logical_mask = int((key_int >> logical_shift) & logical_mask_mask_int)
        parent_feature = current_features_get(det_mask)
        if parent_feature is None:
            fallback_started = time.perf_counter()
            parent_feature = _future_mismatch_features(
                det_mask=det_mask,
                active_mask=prev_active_mask,
                target_syndrome_int=target_int,
                column_index=prev_column_index,
                frontier=frontier,
            )
            future_parity_scorer_stats.fallback_score_calls += 1
            future_parity_scorer_stats.from_scratch_score_calls += 1
            future_parity_scorer_stats.scorer_time_s += float(time.perf_counter() - fallback_started)
        parent_mismatch_count = int(parent_feature.mismatch_count)
        parent_touch_bonus = float(parent_feature.touch_bonus)
        parent_urgency_penalty = float(parent_feature.urgency_penalty)
        parent_parity_logodds = float(parent_feature.parity_logodds)

        no_next_det = 0
        toggle_next_det = 0
        no_accepted = False
        toggle_accepted = False

        transition_count += 1
        skipped_no_error_count += 1
        if bool(zero_close_toggle_finite_fast_path_used):
            no_accepted = True
            no_next_det = det_mask & active_mask_int
            transition_count += 1
            explicit_branch_count += 1
            toggle_accepted = True
            toggle_candidate_det = det_mask ^ toggle_detector_mask
            toggle_next_det = toggle_candidate_det & active_mask_int
        elif bool(zero_close_mask_fast_path_used):
            no_accepted = True
            no_next_det = det_mask & active_mask_int
        else:
            no_candidate_det = det_mask
            if ((no_candidate_det ^ target_int) & close_mask_int) != 0:
                closure_reject_count += 1
            else:
                no_accepted = True
                no_next_det = no_candidate_det & active_mask_int

            if toggle_finite:
                transition_count += 1
                explicit_branch_count += 1
                toggle_candidate_det = det_mask ^ toggle_detector_mask
                if ((toggle_candidate_det ^ target_int) & close_mask_int) != 0:
                    closure_reject_count += 1
                else:
                    toggle_accepted = True
                    toggle_next_det = toggle_candidate_det & active_mask_int

        if bool(deferred_feature_materialization_used):
            need_no_feature = no_accepted and no_next_det not in feature_parity_by_detector
            need_toggle_feature = toggle_accepted and toggle_next_det not in feature_parity_by_detector
        else:
            need_no_feature = no_accepted and no_next_det not in feature_components_by_detector
            need_toggle_feature = toggle_accepted and toggle_next_det not in feature_components_by_detector
        if need_no_feature or need_toggle_feature:
            feature_started = time.perf_counter()
            parent_mismatch_mask = det_mask ^ target_int
            if bool(deferred_feature_materialization_used):
                local_pattern = table_pattern_by_local_mask[
                    int(parent_mismatch_mask) & int(table_local_row_mask)
                ]
                no_parity = float(parent_parity_logodds) + float(
                    table_no_parity_deltas[int(local_pattern)]
                )
                toggle_parity = float(parent_parity_logodds) + float(
                    table_toggle_parity_deltas[int(local_pattern)]
                )
                binary_fast_path_stats.local_pattern_feature_table_lookup_count += 1
                if need_no_feature:
                    feature_parity_by_detector[no_next_det] = float(no_parity)
                    deferred_feature_recipe_by_detector[no_next_det] = (
                        parent_feature,
                        int(local_pattern),
                        False,
                    )
                    feature_update_count += 1
                if need_toggle_feature:
                    feature_parity_by_detector[toggle_next_det] = float(toggle_parity)
                    deferred_feature_recipe_by_detector[toggle_next_det] = (
                        parent_feature,
                        int(local_pattern),
                        True,
                    )
                    feature_update_count += 1
            elif feature_table is not None:
                parent_mismatch_count = int(parent_feature.mismatch_count)
                parent_touch_bonus = float(parent_feature.touch_bonus)
                parent_urgency_penalty = float(parent_feature.urgency_penalty)
                local_pattern = table_pattern_by_local_mask[
                    int(parent_mismatch_mask) & int(table_local_row_mask)
                ]
                no_count = int(parent_mismatch_count) + int(table_no_count_deltas[int(local_pattern)])
                no_touch = float(parent_touch_bonus) + float(table_no_touch_deltas[int(local_pattern)])
                no_urgency = float(parent_urgency_penalty) + float(
                    table_no_urgency_deltas[int(local_pattern)]
                )
                no_parity = float(parent_parity_logodds) + float(
                    table_no_parity_deltas[int(local_pattern)]
                )
                toggle_count = int(parent_mismatch_count) + int(
                    table_toggle_count_deltas[int(local_pattern)]
                )
                toggle_touch = float(parent_touch_bonus) + float(
                    table_toggle_touch_deltas[int(local_pattern)]
                )
                toggle_urgency = float(parent_urgency_penalty) + float(
                    table_toggle_urgency_deltas[int(local_pattern)]
                )
                toggle_parity = float(parent_parity_logodds) + float(
                    table_toggle_parity_deltas[int(local_pattern)]
                )
                binary_fast_path_stats.local_pattern_feature_table_lookup_count += 1
                if need_no_feature:
                    feature_components_by_detector[no_next_det] = (
                        no_count,
                        no_touch,
                        no_urgency,
                        no_parity,
                    )
                    feature_update_count += 1
                if need_toggle_feature:
                    feature_components_by_detector[toggle_next_det] = (
                        toggle_count,
                        toggle_touch,
                        toggle_urgency,
                        toggle_parity,
                    )
                    feature_update_count += 1
            else:
                parent_mismatch_count = int(parent_feature.mismatch_count)
                parent_touch_bonus = float(parent_feature.touch_bonus)
                parent_urgency_penalty = float(parent_feature.urgency_penalty)
                base_count = parent_mismatch_count
                base_touch = parent_touch_bonus
                base_urgency = parent_urgency_penalty
                base_parity = parent_parity_logodds
                for index, row_mask in enumerate(before_row_bit_masks):
                    if (parent_mismatch_mask & row_mask) != 0:
                        base_count -= 1
                        base_touch -= before_touch[index]
                        base_urgency -= before_urgency[index]
                        base_parity -= before_parity[index]
                no_count = base_count
                toggle_count = base_count
                no_touch = base_touch
                toggle_touch = base_touch
                no_urgency = base_urgency
                toggle_urgency = base_urgency
                no_parity = base_parity
                toggle_parity = base_parity
                for index, row_mask in enumerate(after_row_bit_masks):
                    if (parent_mismatch_mask & row_mask) != 0:
                        no_count += 1
                        no_touch += after_touch[index]
                        no_urgency += after_urgency[index]
                        no_parity += after_parity[index]
                    else:
                        toggle_count += 1
                        toggle_touch += after_touch[index]
                        toggle_urgency += after_urgency[index]
                        toggle_parity += after_parity[index]
                if need_no_feature:
                    feature_components_by_detector[no_next_det] = (
                        no_count,
                        no_touch,
                        no_urgency,
                        no_parity,
                    )
                    feature_update_count += 1
                if need_toggle_feature:
                    feature_components_by_detector[toggle_next_det] = (
                        toggle_count,
                        toggle_touch,
                        toggle_urgency,
                        toggle_parity,
                    )
                    feature_update_count += 1
            feature_update_time_s += float(time.perf_counter() - feature_started)

        if no_accepted:
            next_key = no_next_det | (logical_mask << logical_shift)
            existing_log_mass = next_log_mass_get(next_key)
            if existing_log_mass is None:
                next_log_mass[next_key] = log_mass
            else:
                merged_extra_count_by_key[next_key] = int(merged_extra_get(next_key, 0)) + 1
                next_log_mass[next_key] = logadd(float(existing_log_mass), log_mass)

        if toggle_accepted:
            next_logical = logical_mask ^ toggle_observable_mask
            next_key = toggle_next_det | (next_logical << logical_shift)
            new_log_mass = log_mass + toggle_logodds
            existing_log_mass = next_log_mass_get(next_key)
            if existing_log_mass is None:
                next_log_mass[next_key] = new_log_mass
            else:
                merged_extra_count_by_key[next_key] = int(merged_extra_get(next_key, 0)) + 1
                next_log_mass[next_key] = logadd(float(existing_log_mass), new_log_mass)

    binary_fast_path_stats.transition_expansion_time_s += float(time.perf_counter() - expansion_started)
    binary_fast_path_stats.explicit_branch_count += int(explicit_branch_count)
    binary_fast_path_stats.skipped_no_error_branch_count += int(skipped_no_error_count)
    future_parity_scorer_stats.incremental_update_count += int(feature_update_count)
    future_parity_scorer_stats.scorer_time_s += float(feature_update_time_s)

    prune_started = time.perf_counter()
    selected_beam_size = int(beam_size)
    candidate_count = int(len(next_log_mass))
    accepted_transition_count = int(transition_count) - int(closure_reject_count)
    merge_count = max(0, int(accepted_transition_count) - int(candidate_count))
    feature_detector_count = (
        int(len(feature_parity_by_detector))
        if bool(deferred_feature_materialization_used)
        else int(len(feature_components_by_detector))
    )
    if bool(hotloop_instrumentation_enabled):
        _record_binary_hotloop_instrumentation(
            stats=binary_fast_path_stats,
            state_log_mass=state_log_mass,
            detector_mask_mask=detector_mask_mask_int,
            target_syndrome_int=target_int,
            local_row_mask=local_row_mask,
            accepted_transition_count=int(accepted_transition_count),
            candidate_count=int(candidate_count),
            unique_candidate_detector_count=int(feature_detector_count),
        )
    unique_detector_score_fast_path_used = bool(
        unique_detector_score_fast_path_enabled
        and int(candidate_count) == int(feature_detector_count)
    )
    if bool(unique_detector_score_fast_path_used):
        binary_fast_path_stats.unique_detector_score_fast_path_boundary_count += 1
        binary_fast_path_stats.unique_detector_score_fast_path_candidate_count += int(candidate_count)
    streaming_rank_selector_used = bool(
        streaming_rank_selector_enabled
        and int(selected_beam_size) > 0
        and math.isfinite(float(beam_score_gap_threshold))
    )
    if bool(streaming_rank_selector_used):
        binary_fast_path_stats.streaming_rank_selector_boundary_count += 1
    alpha, future_only, _heuristic_mode_key = compiled_plan
    alpha_value = float(alpha)
    future_only_value = bool(future_only)
    truth_logical_target_mask = (
        None if diagnostic_truth_logical_mask is None else int(diagnostic_truth_logical_mask)
    )
    truth_logical_accounting_enabled = truth_logical_target_mask is not None
    logical_mask_mask_for_truth = (1 << int(num_observables)) - 1

    two_pass_rank_selector_used = bool(
        two_pass_rank_selector_enabled and not bool(streaming_rank_selector_used)
    )
    if bool(two_pass_rank_selector_used):
        binary_fast_path_stats.two_pass_rank_selector_boundary_count += 1
        binary_fast_path_stats.two_pass_rank_selector_candidate_count += int(candidate_count)

        candidate_prefix_mass = 0.0
        truth_logical_candidate_prefix_mass = 0.0
        best_rank_value: tuple[float, float, float] | None = None
        top_log_mass_key: int | None = None
        top_log_mass_value = float("-inf")
        feature_components_get = feature_components_by_detector.__getitem__
        feature_parity_get = feature_parity_by_detector.__getitem__
        exp = math.exp
        score_calls = 0

        if bool(unique_detector_score_fast_path_used):
            score_calls += int(candidate_count)
            compiled_score_by_detector: dict[int, float] = {}
            for key, raw_prefix_mass in next_log_mass.items():
                key_int = int(key)
                prefix_mass = float(raw_prefix_mass) + float(no_error_log_const)
                prefix_prob = float(exp(prefix_mass))
                candidate_prefix_mass += float(prefix_prob)
                if bool(truth_logical_accounting_enabled) and (
                    (key_int >> int(logical_shift)) & int(logical_mask_mask_for_truth)
                ) == int(truth_logical_target_mask):
                    truth_logical_candidate_prefix_mass += float(prefix_prob)
                if top_log_mass_key is None or float(prefix_mass) > float(top_log_mass_value):
                    top_log_mass_key = key_int
                    top_log_mass_value = float(prefix_mass)
                det_key = int(key_int & detector_mask_mask_int)
                parity_logodds = (
                    float(feature_parity_get(det_key))
                    if bool(deferred_feature_materialization_used)
                    else float(feature_components_get(det_key)[3])
                )
                heuristic_mass = alpha_value * float(parity_logodds)
                rank0 = (
                    float(heuristic_mass)
                    if bool(future_only_value)
                    else float(prefix_mass) + float(heuristic_mass)
                )
                if (
                    best_rank_value is None
                    or float(rank0) > float(best_rank_value[0])
                    or (
                        float(rank0) == float(best_rank_value[0])
                        and float(prefix_mass) > float(best_rank_value[1])
                    )
                ):
                    best_rank_value = (float(rank0), float(prefix_mass), 0.0)
        else:
            compiled_score_by_detector = {}
            compiled_score_get = compiled_score_by_detector.get
            compiled_score_set = compiled_score_by_detector.__setitem__
            for key, raw_prefix_mass in next_log_mass.items():
                key_int = int(key)
                prefix_mass = float(raw_prefix_mass) + float(no_error_log_const)
                prefix_prob = float(exp(prefix_mass))
                candidate_prefix_mass += float(prefix_prob)
                if bool(truth_logical_accounting_enabled) and (
                    (key_int >> int(logical_shift)) & int(logical_mask_mask_for_truth)
                ) == int(truth_logical_target_mask):
                    truth_logical_candidate_prefix_mass += float(prefix_prob)
                if top_log_mass_key is None or float(prefix_mass) > float(top_log_mass_value):
                    top_log_mass_key = key_int
                    top_log_mass_value = float(prefix_mass)
                det_key = int(key_int & detector_mask_mask_int)
                heuristic_mass = compiled_score_get(det_key)
                if heuristic_mass is None:
                    score_calls += 1
                    parity_logodds = (
                        float(feature_parity_get(det_key))
                        if bool(deferred_feature_materialization_used)
                        else float(feature_components_get(det_key)[3])
                    )
                    heuristic_mass = alpha_value * float(parity_logodds)
                    compiled_score_set(det_key, float(heuristic_mass))
                rank0 = (
                    float(heuristic_mass)
                    if bool(future_only_value)
                    else float(prefix_mass) + float(heuristic_mass)
                )
                if (
                    best_rank_value is None
                    or float(rank0) > float(best_rank_value[0])
                    or (
                        float(rank0) == float(best_rank_value[0])
                        and float(prefix_mass) > float(best_rank_value[1])
                    )
                ):
                    best_rank_value = (float(rank0), float(prefix_mass), 0.0)
        future_parity_scorer_stats.score_calls += int(score_calls)

        top_log_mass_incoming_count = (
            0
            if top_log_mass_key is None
            else 1 + int(merged_extra_count_by_key.get(int(top_log_mass_key), 0))
        )
        top_log_mass_merge_count = max(0, int(top_log_mass_incoming_count) - 1)

        retained_records: list[tuple[int, int, float, float, bool]] = []
        kept_count = 0
        if best_rank_value is not None and int(selected_beam_size) > 0:
            cutoff = float(best_rank_value[0]) - float(beam_score_gap_threshold)
            score_gap_count = 0
            top_heap: list[
                tuple[
                    tuple[float, float, float, int],
                    tuple[int, int, float, float, bool],
                ]
            ] | None = None
            score_gap_records: list[tuple[int, int, float, float, bool]] = []
            score_gap_rank0_values: list[float] = []
            score_gap_rank1_values: list[float] = []
            for key, raw_prefix_mass in next_log_mass.items():
                key_int = int(key)
                prefix_mass = float(raw_prefix_mass) + float(no_error_log_const)
                det_key = int(key_int & detector_mask_mask_int)
                if bool(unique_detector_score_fast_path_used):
                    parity_logodds = (
                        float(feature_parity_get(det_key))
                        if bool(deferred_feature_materialization_used)
                        else float(feature_components_get(det_key)[3])
                    )
                    heuristic_mass = alpha_value * float(parity_logodds)
                else:
                    heuristic_mass = float(compiled_score_by_detector[int(det_key)])
                rank0 = (
                    float(heuristic_mass)
                    if bool(future_only_value)
                    else float(prefix_mass) + float(heuristic_mass)
                )
                if not (float(rank0) >= float(cutoff)):
                    continue
                prefix_prob = float(exp(prefix_mass))
                truth_logical_match = bool(
                    bool(truth_logical_accounting_enabled)
                    and (
                        (key_int >> int(logical_shift)) & int(logical_mask_mask_for_truth)
                    )
                    == int(truth_logical_target_mask)
                )
                record = (
                    int(key_int),
                    int(det_key),
                    float(prefix_mass),
                    float(prefix_prob),
                    bool(truth_logical_match),
                )
                insertion_index = int(score_gap_count)
                score_gap_count += 1
                if int(score_gap_count) <= int(selected_beam_size):
                    score_gap_records.append(record)
                    score_gap_rank0_values.append(float(rank0))
                    score_gap_rank1_values.append(float(prefix_mass))
                    continue
                comparable = (float(rank0), float(prefix_mass), 0.0, -int(insertion_index))
                if top_heap is None:
                    top_heap = [
                        (
                            (
                                float(score_gap_rank0_values[index]),
                                float(score_gap_rank1_values[index]),
                                0.0,
                                -int(index),
                            ),
                            score_gap_records[index],
                        )
                        for index in range(int(selected_beam_size))
                    ]
                    heapq.heapify(top_heap)
                    binary_fast_path_stats.two_pass_rank_selector_heap_boundary_count += 1
                if comparable > top_heap[0][0]:
                    heapq.heapreplace(top_heap, (comparable, record))
            if int(score_gap_count) <= int(selected_beam_size):
                retained_records = list(score_gap_records)
            elif top_heap is None:
                retained_records = list(score_gap_records[: int(selected_beam_size)])
            else:
                retained_records = [
                    record
                    for _comparable, record in sorted(
                        top_heap,
                        key=lambda item: item[0],
                        reverse=True,
                    )
                ]
            kept_count = int(len(retained_records))
            if (
                bool(small_candidate_direct_gap_enabled)
                and int(candidate_count) <= int(selected_beam_size)
            ):
                binary_fast_path_stats.small_candidate_direct_gap_boundary_count += 1
                binary_fast_path_stats.small_candidate_direct_gap_candidate_count += int(candidate_count)

        merge_started = time.perf_counter()
        pruned_count = int(candidate_count - int(kept_count))
        kept_log_mass: dict[int, float] = {}
        retained_prefix_mass = 0.0
        truth_logical_retained_prefix_mass = 0.0
        kept_detector_features: dict[int, FrontierMismatchFeatures] = {}
        deferred_full_feature_count = 0
        kept_incoming_count_by_key: dict[int, int] = {}
        for key_int, det_key, log_mass, prefix_prob, truth_logical_match in retained_records:
            kept_log_mass[int(key_int)] = float(log_mass)
            retained_prefix_mass += float(prefix_prob)
            if bool(truth_logical_accounting_enabled) and bool(truth_logical_match):
                truth_logical_retained_prefix_mass += float(prefix_prob)
            extra_count = int(merged_extra_count_by_key.get(int(key_int), 0))
            if int(extra_count) > 0:
                kept_incoming_count_by_key[int(key_int)] = 1 + int(extra_count)
            if int(det_key) not in kept_detector_features:
                if bool(deferred_feature_materialization_used):
                    materialize_started = time.perf_counter()
                    parent_feature, local_pattern, toggle_branch = deferred_feature_recipe_by_detector[
                        int(det_key)
                    ]
                    pattern_index = int(local_pattern)
                    if bool(toggle_branch):
                        kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                            mismatch_count=int(parent_feature.mismatch_count)
                            + int(table_toggle_count_deltas[pattern_index]),
                            touch_bonus=float(parent_feature.touch_bonus)
                            + float(table_toggle_touch_deltas[pattern_index]),
                            urgency_penalty=float(parent_feature.urgency_penalty)
                            + float(table_toggle_urgency_deltas[pattern_index]),
                            parity_logodds=float(parent_feature.parity_logodds)
                            + float(table_toggle_parity_deltas[pattern_index]),
                        )
                    else:
                        kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                            mismatch_count=int(parent_feature.mismatch_count)
                            + int(table_no_count_deltas[pattern_index]),
                            touch_bonus=float(parent_feature.touch_bonus)
                            + float(table_no_touch_deltas[pattern_index]),
                            urgency_penalty=float(parent_feature.urgency_penalty)
                            + float(table_no_urgency_deltas[pattern_index]),
                            parity_logodds=float(parent_feature.parity_logodds)
                            + float(table_no_parity_deltas[pattern_index]),
                        )
                    future_parity_scorer_stats.scorer_time_s += float(
                        time.perf_counter() - materialize_started
                    )
                    deferred_full_feature_count += 1
                else:
                    components = feature_components_get(int(det_key))
                    kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                        mismatch_count=int(components[0]),
                        touch_bonus=float(components[1]),
                        urgency_penalty=float(components[2]),
                        parity_logodds=float(components[3]),
                    )
        if bool(deferred_feature_materialization_used):
            binary_fast_path_stats.deferred_feature_materialization_parity_feature_count += int(
                len(feature_parity_by_detector)
            )
            binary_fast_path_stats.deferred_feature_materialization_full_feature_count += int(
                deferred_full_feature_count
            )
        if bool(sparse_viterbi_maps_enabled):
            kept_viterbi = kept_log_mass
            kept_viterbi_rep_cost = {}
        else:
            kept_viterbi = dict(kept_log_mass)
            kept_viterbi_rep_cost: dict[int, int] = {
                int(key): 0 for key in kept_log_mass.keys()
            }
        kept_parent: dict[int, tuple[int, int]] = {}
        binary_fast_path_stats.merge_time_s += float(time.perf_counter() - merge_started)

        discarded_prefix_mass = (
            max(0.0, float(candidate_prefix_mass) - float(retained_prefix_mass))
            if int(pruned_count) > 0
            else 0.0
        )
        discarded_prefix_mass_fraction = (
            float(discarded_prefix_mass) / float(candidate_prefix_mass)
            if float(candidate_prefix_mass) > 0.0
            else 0.0
        )
        truth_logical_discarded_prefix_mass = 0.0
        truth_logical_discarded_prefix_mass_fraction = 0.0
        if bool(truth_logical_accounting_enabled):
            truth_logical_discarded_prefix_mass = max(
                0.0,
                float(truth_logical_candidate_prefix_mass) - float(truth_logical_retained_prefix_mass),
            )
            truth_logical_discarded_prefix_mass_fraction = (
                float(truth_logical_discarded_prefix_mass) / float(truth_logical_candidate_prefix_mass)
                if float(truth_logical_candidate_prefix_mass) > 0.0
                else 0.0
            )
        binary_fast_path_stats.prune_sort_time_s += float(time.perf_counter() - prune_started)
        binary_fast_path_stats.fused_primary_topk_count += 1
        binary_fast_path_stats.fused_primary_topk_time_s += float(time.perf_counter() - fused_started)

        return (
            kept_log_mass,
            kept_viterbi,
            kept_viterbi_rep_cost,
            kept_parent,
            kept_detector_features,
            kept_incoming_count_by_key,
            int(transition_count),
            int(closure_reject_count),
            int(candidate_count),
            int(merge_count),
            int(top_log_mass_incoming_count),
            int(top_log_mass_merge_count),
            int(pruned_count),
            float(candidate_prefix_mass),
            float(retained_prefix_mass),
            float(discarded_prefix_mass_fraction),
            float(truth_logical_candidate_prefix_mass),
            float(truth_logical_retained_prefix_mass),
            float(truth_logical_discarded_prefix_mass),
            float(truth_logical_discarded_prefix_mass_fraction),
        )

    candidate_prefix_mass = 0.0
    truth_logical_candidate_prefix_mass = 0.0
    best_rank_value: tuple[float, float, float] | None = None
    top_log_mass_key: int | None = None
    top_log_mass_value = float("-inf")
    candidate_rank_items: list[tuple[int, int, float, float, float, bool]] = []
    candidate_rank_items_append = candidate_rank_items.append
    feature_components_get = feature_components_by_detector.__getitem__
    feature_parity_get = feature_parity_by_detector.__getitem__
    exp = math.exp
    isfinite = math.isfinite
    score_calls = 0
    rank_window_stored_count = 0
    rank_window_skipped_count = 0

    if bool(unique_detector_score_fast_path_used):
        score_calls += int(candidate_count)
        for key, raw_prefix_mass in next_log_mass.items():
            key_int = int(key)
            prefix_mass = float(raw_prefix_mass) + float(no_error_log_const)
            prefix_prob = float(exp(prefix_mass))
            candidate_prefix_mass += float(prefix_prob)
            truth_logical_match = False
            if bool(truth_logical_accounting_enabled) and (
                (key_int >> int(logical_shift)) & int(logical_mask_mask_for_truth)
            ) == int(truth_logical_target_mask):
                truth_logical_candidate_prefix_mass += float(prefix_prob)
                truth_logical_match = True
            if top_log_mass_key is None or float(prefix_mass) > float(top_log_mass_value):
                top_log_mass_key = key_int
                top_log_mass_value = float(prefix_mass)
            det_key = int(key_int & detector_mask_mask_int)
            parity_logodds = (
                float(feature_parity_get(det_key))
                if bool(deferred_feature_materialization_used)
                else float(feature_components_get(det_key)[3])
            )
            heuristic_mass = alpha_value * float(parity_logodds)
            rank0 = (
                float(heuristic_mass)
                if bool(future_only_value)
                else float(prefix_mass) + float(heuristic_mass)
            )
            if (
                best_rank_value is None
                or float(rank0) > float(best_rank_value[0])
                or (
                    float(rank0) == float(best_rank_value[0])
                    and float(prefix_mass) > float(best_rank_value[1])
                )
            ):
                best_rank_value = (float(rank0), float(prefix_mass), 0.0)
            if bool(streaming_rank_selector_used) and bool(isfinite(float(rank0))):
                cutoff_now = float(best_rank_value[0]) - float(beam_score_gap_threshold)
                if bool(isfinite(float(cutoff_now))) and not (float(rank0) >= float(cutoff_now)):
                    rank_window_skipped_count += 1
                    continue
            candidate_rank_items_append(
                (
                    key_int,
                    det_key,
                    float(prefix_mass),
                    float(prefix_prob),
                    float(rank0),
                    bool(truth_logical_match),
                )
            )
            rank_window_stored_count += 1
    else:
        compiled_score_by_detector: dict[int, float] = {}
        compiled_score_get = compiled_score_by_detector.get
        compiled_score_set = compiled_score_by_detector.__setitem__
        for key, raw_prefix_mass in next_log_mass.items():
            key_int = int(key)
            prefix_mass = float(raw_prefix_mass) + float(no_error_log_const)
            prefix_prob = float(exp(prefix_mass))
            candidate_prefix_mass += float(prefix_prob)
            truth_logical_match = False
            if bool(truth_logical_accounting_enabled) and (
                (key_int >> int(logical_shift)) & int(logical_mask_mask_for_truth)
            ) == int(truth_logical_target_mask):
                truth_logical_candidate_prefix_mass += float(prefix_prob)
                truth_logical_match = True
            if top_log_mass_key is None or float(prefix_mass) > float(top_log_mass_value):
                top_log_mass_key = key_int
                top_log_mass_value = float(prefix_mass)
            det_key = int(key_int & detector_mask_mask_int)
            heuristic_mass = compiled_score_get(det_key)
            if heuristic_mass is None:
                score_calls += 1
                parity_logodds = (
                    float(feature_parity_get(det_key))
                    if bool(deferred_feature_materialization_used)
                    else float(feature_components_get(det_key)[3])
                )
                heuristic_mass = alpha_value * float(parity_logodds)
                compiled_score_set(det_key, float(heuristic_mass))
            rank0 = (
                float(heuristic_mass)
                if bool(future_only_value)
                else float(prefix_mass) + float(heuristic_mass)
            )
            if (
                best_rank_value is None
                or float(rank0) > float(best_rank_value[0])
                or (
                    float(rank0) == float(best_rank_value[0])
                    and float(prefix_mass) > float(best_rank_value[1])
                )
            ):
                best_rank_value = (float(rank0), float(prefix_mass), 0.0)
            if bool(streaming_rank_selector_used) and bool(isfinite(float(rank0))):
                cutoff_now = float(best_rank_value[0]) - float(beam_score_gap_threshold)
                if bool(isfinite(float(cutoff_now))) and not (float(rank0) >= float(cutoff_now)):
                    rank_window_skipped_count += 1
                    continue
            candidate_rank_items_append(
                (
                    key_int,
                    det_key,
                    float(prefix_mass),
                    float(prefix_prob),
                    float(rank0),
                    bool(truth_logical_match),
                )
            )
            rank_window_stored_count += 1
    future_parity_scorer_stats.score_calls += int(score_calls)
    if bool(streaming_rank_selector_used):
        binary_fast_path_stats.streaming_rank_selector_stored_candidate_count += int(
            rank_window_stored_count
        )
        binary_fast_path_stats.streaming_rank_selector_skipped_candidate_count += int(
            rank_window_skipped_count
        )
        if int(rank_window_stored_count) > int(
            binary_fast_path_stats.streaming_rank_selector_max_window_candidate_count
        ):
            binary_fast_path_stats.streaming_rank_selector_max_window_candidate_count = int(
                rank_window_stored_count
            )

    top_log_mass_incoming_count = (
        0
        if top_log_mass_key is None
        else 1 + int(merged_extra_count_by_key.get(int(top_log_mass_key), 0))
    )
    top_log_mass_merge_count = max(0, int(top_log_mass_incoming_count) - 1)

    kept_indices: list[int] = []
    kept_count = 0
    if best_rank_value is None or int(selected_beam_size) <= 0:
        kept_keys: list[int] = []
    else:
        cutoff = float(best_rank_value[0]) - float(beam_score_gap_threshold)
        if bool(small_candidate_direct_gap_enabled) and int(candidate_count) <= int(selected_beam_size):
            binary_fast_path_stats.small_candidate_direct_gap_boundary_count += 1
            binary_fast_path_stats.small_candidate_direct_gap_candidate_count += int(candidate_count)
            kept_keys = []
            kept_indices_append = kept_indices.append
            for candidate_index, rank_item in enumerate(candidate_rank_items):
                if float(rank_item[4]) >= float(cutoff):
                    kept_indices_append(int(candidate_index))
            kept_count = int(len(kept_indices))
        else:
            score_gap_keys: list[int] = []
            score_gap_indices: list[int] = []
            score_gap_rank0_values: list[float] = []
            score_gap_rank1_values: list[float] = []
            score_gap_count = 0
            top_heap: list[tuple[tuple[float, float, float, int], int]] | None = None
            for candidate_index, rank_item in enumerate(candidate_rank_items):
                key_int = int(rank_item[0])
                rank0 = float(rank_item[4])
                rank1 = float(rank_item[2])
                if not (float(rank0) >= float(cutoff)):
                    continue
                insertion_index = int(score_gap_count)
                score_gap_count += 1
                if int(score_gap_count) <= int(selected_beam_size):
                    score_gap_keys.append(key_int)
                    score_gap_indices.append(int(candidate_index))
                    score_gap_rank0_values.append(float(rank0))
                    score_gap_rank1_values.append(float(rank1))
                    continue
                comparable = (float(rank0), float(rank1), 0.0, -int(insertion_index))
                if top_heap is None:
                    top_heap = [
                        (
                            (
                                float(score_gap_rank0_values[index]),
                                float(score_gap_rank1_values[index]),
                                0.0,
                                -int(index),
                            ),
                            int(score_gap_indices[index]),
                        )
                        for index in range(int(selected_beam_size))
                    ]
                    heapq.heapify(top_heap)
                if comparable > top_heap[0][0]:
                    heapq.heapreplace(top_heap, (comparable, int(candidate_index)))
            if int(score_gap_count) <= int(selected_beam_size):
                kept_keys = list(score_gap_keys)
                kept_indices = list(score_gap_indices)
            elif top_heap is None:
                kept_keys = list(score_gap_keys[: int(selected_beam_size)])
                kept_indices = list(score_gap_indices[: int(selected_beam_size)])
            else:
                kept_indices = [
                    int(candidate_index)
                    for _comparable, candidate_index in sorted(
                        top_heap,
                        key=lambda item: item[0],
                        reverse=True,
                    )
                ]
                kept_keys = [
                    int(candidate_rank_items[int(candidate_index)][0])
                    for candidate_index in kept_indices
                ]
            kept_count = int(len(kept_keys))

    merge_started = time.perf_counter()
    pruned_count = int(candidate_count - int(kept_count))
    kept_log_mass: dict[int, float] = {}
    retained_prefix_mass = 0.0
    truth_logical_retained_prefix_mass = 0.0
    kept_detector_features: dict[int, FrontierMismatchFeatures] = {}
    deferred_full_feature_count = 0
    for kept_index in kept_indices:
        candidate_index = int(kept_index)
        rank_item = candidate_rank_items[int(candidate_index)]
        key_int = int(rank_item[0])
        det_key = int(rank_item[1])
        log_mass = float(rank_item[2])
        prefix_prob = float(rank_item[3])
        kept_log_mass[key_int] = log_mass
        retained_prefix_mass += float(prefix_prob)
        if bool(truth_logical_accounting_enabled) and bool(rank_item[5]):
            truth_logical_retained_prefix_mass += float(prefix_prob)
        if int(det_key) not in kept_detector_features:
            if bool(deferred_feature_materialization_used):
                materialize_started = time.perf_counter()
                parent_feature, local_pattern, toggle_branch = deferred_feature_recipe_by_detector[
                    int(det_key)
                ]
                pattern_index = int(local_pattern)
                if bool(toggle_branch):
                    kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                        mismatch_count=int(parent_feature.mismatch_count)
                        + int(table_toggle_count_deltas[pattern_index]),
                        touch_bonus=float(parent_feature.touch_bonus)
                        + float(table_toggle_touch_deltas[pattern_index]),
                        urgency_penalty=float(parent_feature.urgency_penalty)
                        + float(table_toggle_urgency_deltas[pattern_index]),
                        parity_logodds=float(parent_feature.parity_logodds)
                        + float(table_toggle_parity_deltas[pattern_index]),
                    )
                else:
                    kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                        mismatch_count=int(parent_feature.mismatch_count)
                        + int(table_no_count_deltas[pattern_index]),
                        touch_bonus=float(parent_feature.touch_bonus)
                        + float(table_no_touch_deltas[pattern_index]),
                        urgency_penalty=float(parent_feature.urgency_penalty)
                        + float(table_no_urgency_deltas[pattern_index]),
                        parity_logodds=float(parent_feature.parity_logodds)
                        + float(table_no_parity_deltas[pattern_index]),
                    )
                future_parity_scorer_stats.scorer_time_s += float(
                    time.perf_counter() - materialize_started
                )
                deferred_full_feature_count += 1
            else:
                components = feature_components_get(det_key)
                kept_detector_features[int(det_key)] = FrontierMismatchFeatures(
                    mismatch_count=int(components[0]),
                    touch_bonus=float(components[1]),
                    urgency_penalty=float(components[2]),
                    parity_logodds=float(components[3]),
                )
    if bool(deferred_feature_materialization_used):
        binary_fast_path_stats.deferred_feature_materialization_parity_feature_count += int(
            len(feature_parity_by_detector)
        )
        binary_fast_path_stats.deferred_feature_materialization_full_feature_count += int(
            deferred_full_feature_count
        )
    if bool(sparse_viterbi_maps_enabled):
        kept_viterbi = kept_log_mass
        kept_viterbi_rep_cost = {}
    else:
        kept_viterbi = dict(kept_log_mass)
        kept_viterbi_rep_cost: dict[int, int] = {int(key): 0 for key in kept_log_mass.keys()}
    kept_parent: dict[int, tuple[int, int]] = {}
    kept_incoming_count_by_key = {
        int(key): 1 + int(extra_count)
        for key, extra_count in merged_extra_count_by_key.items()
        if int(key) in kept_log_mass
    }
    binary_fast_path_stats.merge_time_s += float(time.perf_counter() - merge_started)

    discarded_prefix_mass = (
        max(0.0, float(candidate_prefix_mass) - float(retained_prefix_mass))
        if int(pruned_count) > 0
        else 0.0
    )
    discarded_prefix_mass_fraction = (
        float(discarded_prefix_mass) / float(candidate_prefix_mass)
        if float(candidate_prefix_mass) > 0.0
        else 0.0
    )
    truth_logical_discarded_prefix_mass = 0.0
    truth_logical_discarded_prefix_mass_fraction = 0.0
    if bool(truth_logical_accounting_enabled):
        truth_logical_discarded_prefix_mass = max(
            0.0,
            float(truth_logical_candidate_prefix_mass) - float(truth_logical_retained_prefix_mass),
        )
        truth_logical_discarded_prefix_mass_fraction = (
            float(truth_logical_discarded_prefix_mass) / float(truth_logical_candidate_prefix_mass)
            if float(truth_logical_candidate_prefix_mass) > 0.0
            else 0.0
        )
    binary_fast_path_stats.prune_sort_time_s += float(time.perf_counter() - prune_started)
    binary_fast_path_stats.fused_primary_topk_count += 1
    binary_fast_path_stats.fused_primary_topk_time_s += float(time.perf_counter() - fused_started)

    return (
        kept_log_mass,
        kept_viterbi,
        kept_viterbi_rep_cost,
        kept_parent,
        kept_detector_features,
        kept_incoming_count_by_key,
        int(transition_count),
        int(closure_reject_count),
        int(candidate_count),
        int(merge_count),
        int(top_log_mass_incoming_count),
        int(top_log_mass_merge_count),
        int(pruned_count),
        float(candidate_prefix_mass),
        float(retained_prefix_mass),
        float(discarded_prefix_mass_fraction),
        float(truth_logical_candidate_prefix_mass),
        float(truth_logical_retained_prefix_mass),
        float(truth_logical_discarded_prefix_mass),
        float(truth_logical_discarded_prefix_mass_fraction),
    )


def _advance_binary_production_transition_fast_path(
    *,
    state_log_mass: dict[int, float],
    state_viterbi: dict[int, float],
    state_viterbi_rep_cost: dict[int, int],
    current_detector_features: dict[int, FrontierMismatchFeatures],
    binary_terms: tuple[float, float, int, int, int, int],
    row_update_terms: tuple[
        tuple[tuple[int, float, float, float], ...],
        tuple[tuple[int, float, float, float], ...],
    ],
    close_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    detector_mask_mask: int,
    logical_mask_mask: int,
    state_key_logical_shift: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    track_best_path: bool,
    log_mass_primary_only: bool,
    sparse_viterbi_maps_enabled: bool,
    future_parity_scorer_stats: FutureParityScorerStats,
) -> tuple[
    dict[int, float],
    dict[int, float],
    dict[int, int],
    dict[int, tuple[int, int]],
    dict[int, FrontierMismatchFeatures],
    dict[int, int],
    int,
    int,
]:
    (
        log_prior0,
        log_prior1,
        detector_response0,
        detector_response1,
        logical_response0,
        logical_response1,
    ) = binary_terms
    prior0_finite = math.isfinite(float(log_prior0))
    prior1_finite = math.isfinite(float(log_prior1))

    next_log_mass: dict[int, float] = {}
    next_viterbi: dict[int, float] = {}
    next_viterbi_rep_cost: dict[int, int] = {}
    next_parent: dict[int, tuple[int, int]] = {}
    next_detector_features: dict[int, FrontierMismatchFeatures] = {}
    incoming_count_by_key: dict[int, int] = {}
    transition_count = 0
    closure_reject_count = 0
    feature_update_count = 0

    next_log_mass_get = next_log_mass.get
    next_viterbi_get = next_viterbi.get
    next_viterbi_rep_cost_get = next_viterbi_rep_cost.get
    incoming_get = incoming_count_by_key.get
    current_features_get = current_detector_features.get
    logadd = _logaddexp_pair
    isclose = math.isclose
    sys_maxsize = sys.maxsize
    track_viterbi = not bool(log_mass_primary_only)
    close_mask_int = int(close_mask)
    active_mask_int = int(active_mask)
    target_int = int(target_syndrome_int)
    detector_mask_mask_int = int(detector_mask_mask)
    logical_mask_mask_int = int(logical_mask_mask)
    logical_shift = int(state_key_logical_shift)
    prev_column_index = int(column_index) - 1
    prev_active_mask = 0 if int(prev_column_index) < 0 else int(frontier.active_masks_after_column[int(prev_column_index)])

    for key_int, log_mass in state_log_mass.items():
        det_mask = key_int & detector_mask_mask_int
        logical_mask = (key_int >> logical_shift) & logical_mask_mask_int
        parent_features = current_features_get(det_mask)
        if parent_features is None:
            fallback_started = time.perf_counter()
            parent_features = _future_mismatch_features(
                det_mask=det_mask,
                active_mask=prev_active_mask,
                target_syndrome_int=target_int,
                column_index=prev_column_index,
                frontier=frontier,
            )
            fallback_elapsed = float(time.perf_counter() - fallback_started)
            future_parity_scorer_stats.fallback_score_calls += 1
            future_parity_scorer_stats.from_scratch_score_calls += 1
            future_parity_scorer_stats.scorer_time_s += float(fallback_elapsed)
        viterbi_mass = state_viterbi[key_int] if bool(track_viterbi) else 0.0
        viterbi_rep_cost = state_viterbi_rep_cost.get(key_int, 0) if bool(track_viterbi) else 0

        if prior0_finite:
            transition_count += 1
            candidate_det = det_mask ^ detector_response0
            if ((candidate_det ^ target_int) & close_mask_int) != 0:
                closure_reject_count += 1
            else:
                next_det = candidate_det & active_mask_int
                next_logical = logical_mask ^ logical_response0
                next_key = next_det | (next_logical << logical_shift)
                incoming_count_by_key[next_key] = incoming_get(next_key, 0) + 1
                new_log_mass = log_mass + log_prior0
                existing_log_mass = next_log_mass_get(next_key)
                if existing_log_mass is None:
                    next_log_mass[next_key] = new_log_mass
                else:
                    next_log_mass[next_key] = logadd(existing_log_mass, new_log_mass)
                if next_det not in next_detector_features:
                    future_feature_started = time.perf_counter()
                    next_detector_features[next_det] = _incremental_child_mismatch_features_from_terms(
                        parent_det_mask=det_mask,
                        detector_response_mask=detector_response0,
                        target_syndrome_int=target_int,
                        parent_features=parent_features,
                        update_terms=row_update_terms,
                    )
                    feature_update_count += 1
                    future_parity_scorer_stats.scorer_time_s += float(
                        time.perf_counter() - future_feature_started
                    )
                if bool(track_viterbi):
                    new_viterbi = viterbi_mass + log_prior0
                    best_viterbi_so_far = next_viterbi_get(next_key, float("-inf"))
                    best_rep_cost_so_far = next_viterbi_rep_cost_get(next_key, sys_maxsize)
                    if new_viterbi > best_viterbi_so_far or (
                        isclose(new_viterbi, best_viterbi_so_far, rel_tol=0.0, abs_tol=1e-15)
                        and viterbi_rep_cost < best_rep_cost_so_far
                    ):
                        next_viterbi[next_key] = new_viterbi
                        next_viterbi_rep_cost[next_key] = viterbi_rep_cost
                        if bool(track_best_path):
                            next_parent[next_key] = (key_int, 0)
                elif bool(track_best_path):
                    next_parent[next_key] = (key_int, 0)

        if prior1_finite:
            transition_count += 1
            candidate_det = det_mask ^ detector_response1
            if ((candidate_det ^ target_int) & close_mask_int) != 0:
                closure_reject_count += 1
            else:
                next_det = candidate_det & active_mask_int
                next_logical = logical_mask ^ logical_response1
                next_key = next_det | (next_logical << logical_shift)
                incoming_count_by_key[next_key] = incoming_get(next_key, 0) + 1
                new_log_mass = log_mass + log_prior1
                existing_log_mass = next_log_mass_get(next_key)
                if existing_log_mass is None:
                    next_log_mass[next_key] = new_log_mass
                else:
                    next_log_mass[next_key] = logadd(existing_log_mass, new_log_mass)
                if next_det not in next_detector_features:
                    future_feature_started = time.perf_counter()
                    next_detector_features[next_det] = _incremental_child_mismatch_features_from_terms(
                        parent_det_mask=det_mask,
                        detector_response_mask=detector_response1,
                        target_syndrome_int=target_int,
                        parent_features=parent_features,
                        update_terms=row_update_terms,
                    )
                    feature_update_count += 1
                    future_parity_scorer_stats.scorer_time_s += float(
                        time.perf_counter() - future_feature_started
                    )
                if bool(track_viterbi):
                    new_viterbi = viterbi_mass + log_prior1
                    new_viterbi_rep_cost = viterbi_rep_cost + 1
                    best_viterbi_so_far = next_viterbi_get(next_key, float("-inf"))
                    best_rep_cost_so_far = next_viterbi_rep_cost_get(next_key, sys_maxsize)
                    if new_viterbi > best_viterbi_so_far or (
                        isclose(new_viterbi, best_viterbi_so_far, rel_tol=0.0, abs_tol=1e-15)
                        and new_viterbi_rep_cost < best_rep_cost_so_far
                    ):
                        next_viterbi[next_key] = new_viterbi
                        next_viterbi_rep_cost[next_key] = new_viterbi_rep_cost
                        if bool(track_best_path):
                            next_parent[next_key] = (key_int, 1)
                elif bool(track_best_path):
                    next_parent[next_key] = (key_int, 1)

    future_parity_scorer_stats.incremental_update_count += int(feature_update_count)
    if not bool(track_viterbi):
        if bool(sparse_viterbi_maps_enabled):
            next_viterbi = next_log_mass
            next_viterbi_rep_cost = {}
        else:
            next_viterbi = dict(next_log_mass)
            next_viterbi_rep_cost = {int(key): 0 for key in next_log_mass.keys()}
    return (
        next_log_mass,
        next_viterbi,
        next_viterbi_rep_cost,
        next_parent,
        next_detector_features,
        incoming_count_by_key,
        int(transition_count),
        int(closure_reject_count),
    )


def _row_target_log_mass(
    *,
    row: int,
    residual_bit: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    allow_infinite: bool = True,
) -> float:
    touch_columns = frontier.row_touch_columns[int(row)]
    pos = bisect.bisect_right(touch_columns, int(column_index))
    if int(len(touch_columns) - int(pos)) <= 0:
        return float("-inf") if bool(allow_infinite) else -1.0e300
    tiny = float(np.finfo(np.float64).tiny)
    if int(residual_bit) == 0:
        prob = float(frontier.row_suffix_even_probs[int(row)][int(pos)])
    else:
        prob = float(frontier.row_suffix_odd_probs[int(row)][int(pos)])
    if float(prob) <= 0.0:
        return float("-inf") if bool(allow_infinite) else -1.0e300
    return float(math.log(max(float(prob), tiny)))


def _future_rowwise_log_mass_from_payload(
    *,
    residual_mask: int,
    payload: FutureParityBoundaryPayload,
    allow_infinite: bool = True,
) -> float:
    total = 0.0
    for metric in payload.row_metrics:
        row_log_mass = float(metric.odd_log_mass) if (int(residual_mask) & int(metric.row_mask)) != 0 else float(metric.even_log_mass)
        if not math.isfinite(float(row_log_mass)):
            return float("-inf") if bool(allow_infinite) else -1.0e300
        total += float(row_log_mass)
    return float(total)


def _project_mask_to_rows(mask: int, row_to_local: dict[int, int]) -> int:
    projected_mask = 0
    value = int(mask)
    while int(value) != 0:
        lsb = int(value & -value)
        row = int(lsb.bit_length() - 1)
        local_index = row_to_local.get(int(row))
        if local_index is not None:
            projected_mask |= 1 << int(local_index)
        value ^= int(lsb)
    return int(projected_mask)


def _component_exact_log_masses(
    *,
    component_rows: tuple[int, ...],
    component_columns: tuple[int, ...],
    columns: list[ProgressiveColumn],
) -> tuple[float, ...]:
    local_width = int(len(component_rows))
    table_size = 1 << int(local_width)
    row_to_local = {int(row): int(index) for index, row in enumerate(component_rows)}
    state_log_mass = np.full(int(table_size), float("-inf"), dtype=np.float64)
    state_log_mass[0] = 0.0
    for future_column_index in component_columns:
        column = columns[int(future_column_index)]
        next_log_mass = np.full(int(table_size), float("-inf"), dtype=np.float64)
        for local_state, log_prior in enumerate(_column_log_priors(column)):
            if not math.isfinite(float(log_prior)):
                continue
            local_mask = _project_mask_to_rows(int(column.detector_response_masks[int(local_state)]), row_to_local)
            rolled = np.full(int(table_size), float("-inf"), dtype=np.float64)
            for prefix_mask, prefix_mass in enumerate(state_log_mass.tolist()):
                if not math.isfinite(float(prefix_mass)):
                    continue
                rolled[int(prefix_mask) ^ int(local_mask)] = _logaddexp_pair(
                    float(rolled[int(prefix_mask) ^ int(local_mask)]),
                    float(prefix_mass) + float(log_prior),
                )
            next_log_mass = np.logaddexp(next_log_mass, rolled)
        state_log_mass = next_log_mass
    return tuple(float(value) for value in state_log_mass.tolist())


def _component_pattern_from_residual_mask(
    *,
    residual_mask: int,
    component_rows: tuple[int, ...],
) -> int:
    local_pattern = 0
    for local_index, row in enumerate(component_rows):
        if (int(residual_mask) & (1 << int(row))) != 0:
            local_pattern |= 1 << int(local_index)
    return int(local_pattern)


def _build_future_component_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
    max_exact_component_rows: int,
) -> FutureComponentHeuristicPayload:
    if int(active_mask) == 0 or int(column_index) + 1 >= len(columns):
        return FutureComponentHeuristicPayload(
            exact_components=tuple(),
            fallback_rows=tuple(),
            components=tuple(),
            component_index_by_row={},
        )

    active_rows = _support_rows_from_mask(int(active_mask))
    if not active_rows:
        return FutureComponentHeuristicPayload(
            exact_components=tuple(),
            fallback_rows=tuple(),
            components=tuple(),
            component_index_by_row={},
        )

    row_to_future_cols: dict[int, list[int]] = {int(row): [] for row in active_rows}
    future_col_rows: dict[int, tuple[int, ...]] = {}
    future_indices = range(int(column_index) + 1, len(columns))
    for future_column_index in future_indices:
        support_mask = int(columns[int(future_column_index)].detector_support_mask) & int(active_mask)
        if int(support_mask) == 0:
            continue
        touched_rows = _support_rows_from_mask(int(support_mask))
        future_col_rows[int(future_column_index)] = tuple(int(row) for row in touched_rows)
        for row in touched_rows:
            row_to_future_cols[int(row)].append(int(future_column_index))

    exact_components: list[FutureExactComponent] = []
    fallback_rows: set[int] = set()
    components: list[FutureComponentBlock] = []
    component_index_by_row: dict[int, int] = {}
    visited_rows: set[int] = set()
    visited_columns: set[int] = set()
    for start_row in active_rows:
        if int(start_row) in visited_rows:
            continue
        row_stack = [int(start_row)]
        component_rows: set[int] = set()
        component_cols: set[int] = set()
        while row_stack:
            row = int(row_stack.pop())
            if int(row) in visited_rows:
                continue
            visited_rows.add(int(row))
            component_rows.add(int(row))
            for future_column_index in row_to_future_cols.get(int(row), []):
                if int(future_column_index) in component_cols:
                    continue
                component_cols.add(int(future_column_index))
                if int(future_column_index) not in visited_columns:
                    visited_columns.add(int(future_column_index))
                for neighbor_row in future_col_rows.get(int(future_column_index), ()):
                    if int(neighbor_row) not in visited_rows:
                        row_stack.append(int(neighbor_row))
        component_rows_tuple = tuple(sorted(int(value) for value in component_rows))
        component_cols_tuple = tuple(sorted(int(value) for value in component_cols))
        row_mask = 0
        for row in component_rows_tuple:
            row_mask |= 1 << int(row)
        if 0 < int(len(component_rows_tuple)) <= int(max_exact_component_rows):
            exact_log_masses_by_pattern = _component_exact_log_masses(
                component_rows=component_rows_tuple,
                component_columns=component_cols_tuple,
                columns=columns,
            )
            exact_components.append(
                FutureExactComponent(
                    rows=component_rows_tuple,
                    row_mask=int(row_mask),
                    log_masses_by_pattern=exact_log_masses_by_pattern,
                )
            )
            components.append(
                FutureComponentBlock(
                    rows=component_rows_tuple,
                    row_mask=int(row_mask),
                    columns=component_cols_tuple,
                    exact_log_masses_by_pattern=exact_log_masses_by_pattern,
                )
            )
        else:
            fallback_rows.update(int(value) for value in component_rows_tuple)
            components.append(
                FutureComponentBlock(
                    rows=component_rows_tuple,
                    row_mask=int(row_mask),
                    columns=component_cols_tuple,
                    exact_log_masses_by_pattern=None,
                )
            )
        component_index = int(len(components) - 1)
        for row in component_rows_tuple:
            component_index_by_row[int(row)] = int(component_index)
    return FutureComponentHeuristicPayload(
        exact_components=tuple(exact_components),
        fallback_rows=tuple(sorted(int(value) for value in fallback_rows)),
        components=tuple(components),
        component_index_by_row=component_index_by_row,
    )


def _column_tick_for_closing_logmass(columns: Sequence[ProgressiveColumn], column_index: int) -> int:
    if int(column_index) < 0 or int(column_index) >= len(columns):
        return int(column_index)
    tick = int(columns[int(column_index)].physical_time_index)
    return int(tick) if int(tick) >= 0 else int(column_index)


def _mixed_closing_eligible_mask(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
    window_ticks: int,
) -> int:
    if int(active_mask) == 0 or int(column_index) + 1 >= len(columns):
        return 0
    boundary_tick = _column_tick_for_closing_logmass(columns, int(column_index))
    tick_limit = int(boundary_tick) + max(0, int(window_ticks))
    eligible_mask = 0
    active_rows = _support_rows_from_mask(int(active_mask))
    for row in active_rows:
        last_column = int(frontier.detector_last_column[int(row)])
        if int(last_column) <= int(column_index) or int(last_column) >= len(columns):
            continue
        last_tick = _column_tick_for_closing_logmass(columns, int(last_column))
        if int(last_tick) <= int(tick_limit):
            eligible_mask |= 1 << int(row)
    return int(eligible_mask)


def _rowwise_log_mass_for_rows(
    *,
    residual_mask: int,
    rows: tuple[int, ...],
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    allow_infinite: bool = True,
) -> float:
    total = 0.0
    for row in rows:
        residual_bit = 1 if ((int(residual_mask) >> int(row)) & 1) else 0
        row_mass = _row_target_log_mass(
            row=int(row),
            residual_bit=int(residual_bit),
            column_index=int(column_index),
            frontier=frontier,
            allow_infinite=bool(allow_infinite),
        )
        if not math.isfinite(float(row_mass)):
            return float("-inf") if bool(allow_infinite) else -1.0e300
        total += float(row_mass)
    return float(total)


def _mixed_future_closing_log_mass(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    payload: FutureComponentHeuristicPayload,
    alpha: float,
    fallback: str = "rowwise",
    allow_infinite: bool = True,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    fallback_key = str(fallback).strip().lower()
    if fallback_key not in {"rowwise", "zero"}:
        raise ValueError("closing logmass fallback must be one of ['rowwise', 'zero']")
    if not payload.components:
        if fallback_key == "zero":
            return 0.0
        return _rowwise_log_mass_for_rows(
            residual_mask=int(residual_mask),
            rows=tuple(int(row) for row in _support_rows_from_mask(int(active_mask))),
            column_index=int(column_index),
            frontier=frontier,
            allow_infinite=bool(allow_infinite),
        )

    exact_row_mask = 0
    exact_total = 0.0
    rowwise_exact_total = 0.0
    for component in payload.components:
        if component.exact_log_masses_by_pattern is None:
            continue
        component_mass = _future_component_block_log_mass(
            component=component,
            residual_mask=int(residual_mask),
            column_index=int(column_index),
            frontier=frontier,
            allow_infinite=bool(allow_infinite),
        )
        if not math.isfinite(float(component_mass)):
            return float("-inf") if bool(allow_infinite) else -1.0e300
        rowwise_component_mass = _rowwise_log_mass_for_rows(
            residual_mask=int(residual_mask),
            rows=tuple(int(row) for row in component.rows),
            column_index=int(column_index),
            frontier=frontier,
            allow_infinite=bool(allow_infinite),
        )
        exact_row_mask |= int(component.row_mask)
        exact_total += float(component_mass)
        rowwise_exact_total += float(rowwise_component_mass)

    if fallback_key == "zero":
        return float(alpha) * float(exact_total)

    active_rows = tuple(int(row) for row in _support_rows_from_mask(int(active_mask)))
    fallback_rows = tuple(int(row) for row in active_rows if (int(exact_row_mask) & (1 << int(row))) == 0)
    fallback_mass = _rowwise_log_mass_for_rows(
        residual_mask=int(residual_mask),
        rows=fallback_rows,
        column_index=int(column_index),
        frontier=frontier,
        allow_infinite=bool(allow_infinite),
    )
    if not math.isfinite(float(fallback_mass)):
        return float("-inf") if bool(allow_infinite) else -1.0e300
    if float(alpha) == 1.0:
        return float(exact_total) + float(fallback_mass)
    rowwise_total = float(rowwise_exact_total) + float(fallback_mass)
    exact_replaced_total = float(exact_total) + float(fallback_mass)
    if not math.isfinite(float(rowwise_total)) or not math.isfinite(float(exact_replaced_total)):
        return float(exact_replaced_total)
    return float(rowwise_total) + float(alpha) * (float(exact_replaced_total) - float(rowwise_total))


def _future_component_log_mass(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    payload: FutureComponentHeuristicPayload,
    allow_infinite: bool = True,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    return _future_component_payload_log_mass(
        residual_mask=int(residual_mask),
        column_index=int(column_index),
        frontier=frontier,
        payload=payload,
        allow_infinite=bool(allow_infinite),
    )


def _future_component_block_log_mass(
    *,
    component: FutureComponentBlock,
    residual_mask: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    allow_infinite: bool = True,
) -> float:
    exact_log_masses_by_pattern = component.exact_log_masses_by_pattern
    if exact_log_masses_by_pattern is not None:
        local_pattern = _component_pattern_from_residual_mask(
            residual_mask=int(residual_mask),
            component_rows=component.rows,
        )
        component_mass = float(exact_log_masses_by_pattern[int(local_pattern)])
        if not math.isfinite(float(component_mass)):
            return float("-inf") if bool(allow_infinite) else -1.0e300
        return float(component_mass)

    total = 0.0
    for row in component.rows:
        residual_bit = 1 if ((int(residual_mask) >> int(row)) & 1) else 0
        row_mass = _row_target_log_mass(
            row=int(row),
            residual_bit=int(residual_bit),
            column_index=int(column_index),
            frontier=frontier,
            allow_infinite=bool(allow_infinite),
        )
        if not math.isfinite(float(row_mass)):
            return float("-inf") if bool(allow_infinite) else -1.0e300
        total += float(row_mass)
    return float(total)


def _future_component_payload_log_mass(
    *,
    residual_mask: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    payload: FutureComponentHeuristicPayload,
    allow_infinite: bool = True,
    component_indices: tuple[int, ...] | None = None,
) -> float:
    components = payload.components
    if component_indices is None:
        selected_components = components
    else:
        selected_components = tuple(
            components[int(component_index)]
            for component_index in component_indices
        )
    total = 0.0
    for component in selected_components:
        component_mass = _future_component_block_log_mass(
            component=component,
            residual_mask=int(residual_mask),
            column_index=int(column_index),
            frontier=frontier,
            allow_infinite=bool(allow_infinite),
        )
        if not math.isfinite(float(component_mass)):
            return float("-inf") if bool(allow_infinite) else -1.0e300
        total += float(component_mass)
    return float(total)


def _future_local_cone_log_mass(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    payload: FutureComponentHeuristicPayload,
    allow_infinite: bool = True,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if int(residual_mask) == 0:
        return 0.0

    touched_components: set[int] = set()
    remaining = int(residual_mask)
    while int(remaining) != 0:
        lsb = int(remaining & -remaining)
        row = int(lsb.bit_length() - 1)
        component_index = payload.component_index_by_row.get(int(row))
        if component_index is None:
            return float("-inf") if bool(allow_infinite) else -1.0e300
        touched_components.add(int(component_index))
        remaining ^= int(lsb)

    return _future_component_payload_log_mass(
        residual_mask=int(residual_mask),
        column_index=int(column_index),
        frontier=frontier,
        payload=payload,
        allow_infinite=bool(allow_infinite),
        component_indices=tuple(sorted(int(value) for value in touched_components)),
    )


def _future_low_error_column_profiles(
    *,
    column: ProgressiveColumn,
    active_mask: int,
) -> tuple[tuple[int, float, int], ...]:
    projected_log_mass: dict[int, float] = {}
    for local_state, log_prior in enumerate(_column_log_priors(column)):
        if not math.isfinite(float(log_prior)):
            continue
        projected_mask = int(column.detector_response_masks[int(local_state)]) & int(active_mask)
        projected_log_mass[int(projected_mask)] = _logaddexp_pair(
            float(projected_log_mass.get(int(projected_mask), float("-inf"))),
            float(log_prior),
        )
    return tuple(
        (
            int(projected_mask),
            float(log_mass),
            0 if int(projected_mask) == 0 else 1,
        )
        for projected_mask, log_mass in sorted(projected_log_mass.items())
        if math.isfinite(float(log_mass))
    )


def _append_union_event_probability_log_term(existing_miss_log_prob: float, event_prob: float) -> float:
    probability = float(event_prob)
    if probability <= 0.0:
        return float(existing_miss_log_prob)
    if probability >= 1.0:
        return float("-inf")
    if not math.isfinite(float(existing_miss_log_prob)):
        return float(existing_miss_log_prob)
    return float(existing_miss_log_prob) + float(math.log1p(-float(probability)))


def _logprob_from_union_event_miss_log_prob(miss_log_prob: float) -> float:
    if not math.isfinite(float(miss_log_prob)):
        return 0.0
    event_prob = -float(math.expm1(float(miss_log_prob)))
    if float(event_prob) <= 0.0:
        return float("-inf")
    return float(math.log(float(event_prob)))


def _future_single_fix_column_probabilities(
    *,
    column: ProgressiveColumn,
    active_mask: int,
) -> tuple[dict[int, float], dict[int, float]]:
    exact_prob_by_pattern: dict[int, float] = {}
    spill_adjusted_prob_by_pattern: dict[int, float] = {}
    for local_state, prior_prob in enumerate(column.prior_probs):
        probability = float(prior_prob)
        if float(probability) <= 0.0:
            continue
        detector_response_mask = int(column.detector_response_masks[int(local_state)])
        projected_mask = int(detector_response_mask) & int(active_mask)
        if int(projected_mask) == 0:
            continue
        exact_prob_by_pattern[int(projected_mask)] = float(exact_prob_by_pattern.get(int(projected_mask), 0.0)) + float(probability)

        spill_count = int((int(detector_response_mask) & ~int(active_mask)).bit_count())
        logical_flip_count = int(int(column.logical_response_masks[int(local_state)]).bit_count())
        penalty_log = (
            float(SINGLE_FIX_SPILL_DETECTOR_LOG_PENALTY) * float(spill_count)
            + float(SINGLE_FIX_LOGICAL_FLIP_LOG_PENALTY) * float(logical_flip_count)
        )
        adjusted_probability = float(probability) * float(math.exp(-float(penalty_log)))
        spill_adjusted_prob_by_pattern[int(projected_mask)] = float(
            spill_adjusted_prob_by_pattern.get(int(projected_mask), 0.0)
        ) + float(adjusted_probability)
    return exact_prob_by_pattern, spill_adjusted_prob_by_pattern


def _build_future_single_fix_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
) -> FutureSingleFixHeuristicPayload:
    active_rows = _support_rows_from_mask(int(active_mask))
    if int(active_mask) == 0 or not active_rows or int(column_index) + 1 >= len(columns):
        return FutureSingleFixHeuristicPayload(
            boundary_column_index=int(column_index),
            active_mask=int(active_mask),
            exact_any_logprob_by_pattern={},
            exact_best_logprob_by_pattern={},
            spill_adjusted_any_logprob_by_pattern={},
        )

    last_relevant_column = max(int(frontier.detector_last_column[int(row)]) for row in active_rows)
    any_miss_log_prob_by_pattern: dict[int, float] = {}
    best_prob_by_pattern: dict[int, float] = {}
    spill_miss_log_prob_by_pattern: dict[int, float] = {}
    for future_column_index in range(int(column_index) + 1, int(last_relevant_column) + 1):
        column = columns[int(future_column_index)]
        if (int(column.detector_support_mask) & int(active_mask)) == 0:
            continue
        exact_prob_by_pattern, spill_adjusted_prob_by_pattern = _future_single_fix_column_probabilities(
            column=column,
            active_mask=int(active_mask),
        )
        for projected_pattern, exact_probability in exact_prob_by_pattern.items():
            clipped_probability = min(max(float(exact_probability), 0.0), 1.0)
            any_miss_log_prob_by_pattern[int(projected_pattern)] = _append_union_event_probability_log_term(
                float(any_miss_log_prob_by_pattern.get(int(projected_pattern), 0.0)),
                float(clipped_probability),
            )
            best_prob_by_pattern[int(projected_pattern)] = max(
                float(best_prob_by_pattern.get(int(projected_pattern), 0.0)),
                float(clipped_probability),
            )
        for projected_pattern, adjusted_probability in spill_adjusted_prob_by_pattern.items():
            clipped_probability = min(max(float(adjusted_probability), 0.0), 1.0)
            spill_miss_log_prob_by_pattern[int(projected_pattern)] = _append_union_event_probability_log_term(
                float(spill_miss_log_prob_by_pattern.get(int(projected_pattern), 0.0)),
                float(clipped_probability),
            )

    exact_any_logprob_by_pattern = {
        int(pattern): float(log_prob)
        for pattern, miss_log_prob in any_miss_log_prob_by_pattern.items()
        if math.isfinite(float(log_prob := _logprob_from_union_event_miss_log_prob(float(miss_log_prob))))
    }
    exact_best_logprob_by_pattern = {
        int(pattern): float(math.log(float(probability)))
        for pattern, probability in best_prob_by_pattern.items()
        if float(probability) > 0.0
    }
    spill_adjusted_any_logprob_by_pattern = {
        int(pattern): float(log_prob)
        for pattern, miss_log_prob in spill_miss_log_prob_by_pattern.items()
        if math.isfinite(float(log_prob := _logprob_from_union_event_miss_log_prob(float(miss_log_prob))))
    }
    return FutureSingleFixHeuristicPayload(
        boundary_column_index=int(column_index),
        active_mask=int(active_mask),
        exact_any_logprob_by_pattern=exact_any_logprob_by_pattern,
        exact_best_logprob_by_pattern=exact_best_logprob_by_pattern,
        spill_adjusted_any_logprob_by_pattern=spill_adjusted_any_logprob_by_pattern,
    )


def _future_single_fix_bonus_from_payload(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    parity_payload: FutureParityBoundaryPayload,
    single_fix_payload: FutureSingleFixHeuristicPayload,
    score_mode_key: str,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if int(residual_mask) == 0:
        return 0.0
    rowwise_log_mass = _future_rowwise_log_mass_from_payload(
        residual_mask=int(residual_mask),
        payload=parity_payload,
        allow_infinite=False,
    )
    if not math.isfinite(float(rowwise_log_mass)):
        return 0.0

    if score_mode_key == "future_parity_logodds_singlefix_best":
        exact_single_fix_log_prob = float(single_fix_payload.exact_best_logprob_by_pattern.get(int(residual_mask), float("-inf")))
    elif score_mode_key == "future_parity_logodds_singlefix_bonus_with_spill_penalty":
        exact_single_fix_log_prob = float(
            single_fix_payload.spill_adjusted_any_logprob_by_pattern.get(int(residual_mask), float("-inf"))
        )
    else:
        exact_single_fix_log_prob = float(single_fix_payload.exact_any_logprob_by_pattern.get(int(residual_mask), float("-inf")))
    if not math.isfinite(float(exact_single_fix_log_prob)):
        return 0.0
    if float(exact_single_fix_log_prob) >= 0.0:
        exact_single_fix_presence_reward = float("inf")
    else:
        exact_single_fix_presence_reward = -float(math.log1p(-float(math.exp(float(exact_single_fix_log_prob)))))
    exact_single_fix_surprise = max(0.0, float(exact_single_fix_log_prob) - float(rowwise_log_mass))
    return float(exact_single_fix_presence_reward) + float(exact_single_fix_surprise)


def _future_quotient_event_candidates(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
) -> tuple[FutureQuotientEvent, ...]:
    active_rows = _support_rows_from_mask(int(active_mask))
    if int(active_mask) == 0 or not active_rows or int(column_index) + 1 >= len(columns):
        return tuple()

    last_relevant_column = max(int(frontier.detector_last_column[int(row)]) for row in active_rows)
    events: list[FutureQuotientEvent] = []
    for future_column_index in range(int(column_index) + 1, int(last_relevant_column) + 1):
        column = columns[int(future_column_index)]
        if (int(column.detector_support_mask) & int(active_mask)) == 0:
            continue
        for local_state, log_prior in enumerate(_column_log_priors(column)):
            if not math.isfinite(float(log_prior)):
                continue
            full_detector_mask = int(column.detector_response_masks[int(local_state)])
            projected_mask = int(full_detector_mask) & int(active_mask)
            if int(projected_mask) == 0:
                continue
            if int(projected_mask.bit_count()) > int(QUOTIENT_MOVE_MAX_PATTERN_WEIGHT):
                continue
            spill_weight = int((int(full_detector_mask) & ~int(active_mask)).bit_count())
            if int(spill_weight) > int(QUOTIENT_MOVE_MAX_SPILL_WEIGHT):
                continue
            logical_mask = int(column.logical_response_masks[int(local_state)])
            adjusted_log_mass = float(log_prior) - (
                float(QUOTIENT_MOVE_SPILL_DETECTOR_LOG_PENALTY) * float(spill_weight)
                + float(QUOTIENT_MOVE_LOGICAL_FLIP_LOG_PENALTY) * float(int(logical_mask).bit_count())
            )
            events.append(
                FutureQuotientEvent(
                    column_index=int(future_column_index),
                    projected_mask=int(projected_mask),
                    full_detector_mask=int(full_detector_mask),
                    logical_mask=int(logical_mask),
                    raw_log_mass=float(log_prior),
                    adjusted_log_mass=float(adjusted_log_mass),
                )
            )
    events.sort(key=lambda event: float(event.adjusted_log_mass), reverse=True)
    return tuple(events[: int(QUOTIENT_MOVE_MAX_CANDIDATE_EVENTS)])


def _build_future_quotient_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
) -> FutureQuotientHeuristicPayload:
    events = _future_quotient_event_candidates(
        columns=columns,
        frontier=frontier,
        column_index=int(column_index),
        active_mask=int(active_mask),
    )
    if not events:
        return FutureQuotientHeuristicPayload(
            boundary_column_index=int(column_index),
            active_mask=int(active_mask),
            best_log_mass_by_pattern={},
        )

    best_log_mass_by_pattern: dict[int, float] = {}

    def _store_pattern(pattern: int, log_mass: float) -> None:
        if int(pattern) == 0:
            return
        if int(pattern.bit_count()) > int(QUOTIENT_MOVE_MAX_PATTERN_WEIGHT):
            return
        previous = best_log_mass_by_pattern.get(int(pattern), float("-inf"))
        best_log_mass_by_pattern[int(pattern)] = max(float(previous), float(log_mass))

    for event in events:
        if int(event.logical_mask) == 0:
            _store_pattern(int(event.projected_mask), float(event.adjusted_log_mass))

    for left_index, left in enumerate(events):
        for right in events[int(left_index) + 1 :]:
            if int(left.column_index) == int(right.column_index):
                continue
            combo_logical_mask = int(left.logical_mask) ^ int(right.logical_mask)
            if int(combo_logical_mask) != 0:
                continue
            combo_full_detector_mask = int(left.full_detector_mask) ^ int(right.full_detector_mask)
            combo_projected_mask = int(combo_full_detector_mask) & int(active_mask)
            if int(combo_projected_mask) == 0:
                continue
            combo_spill_weight = int((int(combo_full_detector_mask) & ~int(active_mask)).bit_count())
            if int(combo_spill_weight) > int(QUOTIENT_MOVE_MAX_SPILL_WEIGHT):
                continue
            combo_log_mass = (
                float(left.raw_log_mass)
                + float(right.raw_log_mass)
                - float(QUOTIENT_MOVE_PAIR_LOG_PENALTY)
                - float(QUOTIENT_MOVE_SPILL_DETECTOR_LOG_PENALTY) * float(combo_spill_weight)
            )
            _store_pattern(int(combo_projected_mask), float(combo_log_mass))

    return FutureQuotientHeuristicPayload(
        boundary_column_index=int(column_index),
        active_mask=int(active_mask),
        best_log_mass_by_pattern={int(pattern): float(log_mass) for pattern, log_mass in best_log_mass_by_pattern.items()},
    )


def _future_quotient_correction_from_payload(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    parity_payload: FutureParityBoundaryPayload,
    quotient_payload: FutureQuotientHeuristicPayload,
) -> float:
    if not quotient_payload.best_log_mass_by_pattern:
        return 0.0
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if int(residual_mask) == 0:
        return 0.0
    base_rowwise_log_mass = _future_rowwise_log_mass_from_payload(
        residual_mask=int(residual_mask),
        payload=parity_payload,
        allow_infinite=False,
    )
    if not math.isfinite(float(base_rowwise_log_mass)):
        return 0.0
    best_adjusted_log_mass = float(base_rowwise_log_mass)
    for pattern, move_log_mass in quotient_payload.best_log_mass_by_pattern.items():
        dressed_residual_mask = int(residual_mask) ^ int(pattern)
        dressed_rowwise_log_mass = _future_rowwise_log_mass_from_payload(
            residual_mask=int(dressed_residual_mask),
            payload=parity_payload,
            allow_infinite=False,
        )
        if not math.isfinite(float(dressed_rowwise_log_mass)):
            continue
        candidate_log_mass = float(move_log_mass) + float(dressed_rowwise_log_mass)
        if float(candidate_log_mass) > float(best_adjusted_log_mass):
            best_adjusted_log_mass = float(candidate_log_mass)
    correction = max(0.0, float(best_adjusted_log_mass) - float(base_rowwise_log_mass))
    return float(min(float(correction), float(QUOTIENT_CORRECTION_MAX_BONUS)))


def _build_future_low_error_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    column_index: int,
    active_mask: int,
    max_active_events: int,
) -> FutureLowErrorHeuristicPayload:
    max_active_events = max(0, int(max_active_events))
    active_rows = _support_rows_from_mask(int(active_mask))
    if int(active_mask) == 0 or not active_rows or int(max_active_events) < 0:
        return FutureLowErrorHeuristicPayload(
            boundary_column_index=int(column_index),
            active_mask=int(active_mask),
            max_active_events=int(max_active_events),
            log_masses_by_event_count=tuple({0: 0.0} if event_count == 0 else {} for event_count in range(int(max_active_events) + 1)),
        )

    last_relevant_column = max(int(frontier.detector_last_column[int(row)]) for row in active_rows)
    state_log_mass_by_event_count: list[dict[int, float]] = [{0: 0.0}] + [{} for _ in range(int(max_active_events))]
    for future_column_index in range(int(column_index) + 1, int(last_relevant_column) + 1):
        column = columns[int(future_column_index)]
        if (int(column.detector_support_mask) & int(active_mask)) == 0:
            continue
        column_profiles = _future_low_error_column_profiles(
            column=column,
            active_mask=int(active_mask),
        )
        if not column_profiles:
            continue
        if len(column_profiles) == 1 and int(column_profiles[0][0]) == 0:
            continue
        next_state_log_mass_by_event_count: list[dict[int, float]] = [
            {} for _ in range(int(max_active_events) + 1)
        ]
        for used_events, state_log_mass in enumerate(state_log_mass_by_event_count):
            if not state_log_mass:
                continue
            for residual_pattern, prefix_log_mass in state_log_mass.items():
                for projected_mask, profile_log_mass, projected_event_cost in column_profiles:
                    next_used_events = int(used_events) + int(projected_event_cost)
                    if int(next_used_events) > int(max_active_events):
                        continue
                    next_pattern = int(residual_pattern) ^ int(projected_mask)
                    bucket = next_state_log_mass_by_event_count[int(next_used_events)]
                    bucket[int(next_pattern)] = _logaddexp_pair(
                        float(bucket.get(int(next_pattern), float("-inf"))),
                        float(prefix_log_mass) + float(profile_log_mass),
                    )
        state_log_mass_by_event_count = next_state_log_mass_by_event_count
    return FutureLowErrorHeuristicPayload(
        boundary_column_index=int(column_index),
        active_mask=int(active_mask),
        max_active_events=int(max_active_events),
        log_masses_by_event_count=tuple(
            {int(pattern): float(log_mass) for pattern, log_mass in bucket.items()}
            for bucket in state_log_mass_by_event_count
        ),
    )


def _future_low_error_log_mass(
    *,
    det_mask: int,
    active_mask: int,
    target_syndrome_int: int,
    payload: FutureLowErrorHeuristicPayload,
    allow_infinite: bool = True,
) -> float:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    total_log_mass = float("-inf")
    for bucket in payload.log_masses_by_event_count:
        bucket_log_mass = float(bucket.get(int(residual_mask), float("-inf")))
        total_log_mass = _logaddexp_pair(float(total_log_mass), float(bucket_log_mass))
    if math.isfinite(float(total_log_mass)):
        return float(total_log_mass)
    return float("-inf") if bool(allow_infinite) else -1.0e300


def _build_future_active_frontier_payload(
    *,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    active_mask: int,
    target_syndrome_int: int,
    clamp_assignments: dict[int, int],
) -> FutureActiveFrontierHeuristicPayload:
    active_rows = tuple(int(row) for row in _support_rows_from_mask(int(active_mask)))
    row_to_local = {
        int(row): int(local_index)
        for local_index, row in enumerate(active_rows)
    }
    projected_target_syndrome_int = _project_mask_to_rows(
        int(target_syndrome_int),
        row_to_local,
    )
    if not active_rows or int(boundary_column_index) + 1 >= len(columns):
        return FutureActiveFrontierHeuristicPayload(
            boundary_column_index=int(boundary_column_index),
            active_mask=int(active_mask),
            active_rows=tuple(int(row) for row in active_rows),
            row_to_local=dict(row_to_local),
            projected_target_syndrome_int=int(projected_target_syndrome_int),
            projected_columns=tuple(),
            projected_layout=build_frontier_layout([], num_detectors=int(len(active_rows))),
        )

    last_relevant_column = max(
        int(frontier.detector_last_column[int(row)])
        for row in active_rows
    )
    projected_columns: list[ProgressiveColumn] = []
    for future_column_index in range(int(boundary_column_index) + 1, int(last_relevant_column) + 1):
        column = columns[int(future_column_index)]
        log_priors = _column_log_priors(column)
        forced_local_state = clamp_assignments.get(int(future_column_index))
        if forced_local_state is None:
            state_iter = enumerate(log_priors)
        else:
            state_iter = ((int(forced_local_state), float(log_priors[int(forced_local_state)])),)

        projected_log_mass_by_mask: dict[int, float] = {}
        projected_support_mask = 0
        for local_state, log_prior in state_iter:
            if not math.isfinite(float(log_prior)):
                continue
            projected_mask = _project_mask_to_rows(
                int(column.detector_response_masks[int(local_state)]),
                row_to_local,
            )
            projected_log_mass_by_mask[int(projected_mask)] = _logaddexp_pair(
                float(projected_log_mass_by_mask.get(int(projected_mask), float("-inf"))),
                float(log_prior),
            )
            projected_support_mask |= int(projected_mask)
        if not projected_log_mass_by_mask:
            continue
        if (
            len(projected_log_mass_by_mask) == 1
            and int(next(iter(projected_log_mass_by_mask.keys()))) == 0
            and math.isclose(
                float(next(iter(projected_log_mass_by_mask.values()))),
                0.0,
                rel_tol=0.0,
                abs_tol=1e-15,
            )
        ):
            continue

        aggregated_items = sorted(
            (int(mask), float(log_mass))
            for mask, log_mass in projected_log_mass_by_mask.items()
        )
        projected_columns.append(
            ProgressiveColumn(
                family=str(column.family),
                index=int(len(projected_columns)),
                label=f"{column.label}_active",
                instruction_offset=int(column.instruction_offset),
                prior_probs=tuple(
                    float(math.exp(float(log_mass)))
                    for _mask, log_mass in aggregated_items
                ),
                detector_response_masks=tuple(
                    int(mask) for mask, _log_mass in aggregated_items
                ),
                logical_response_masks=tuple(
                    0 for _mask, _log_mass in aggregated_items
                ),
                detector_support_mask=int(projected_support_mask),
                prior_log_probs=tuple(
                    float(log_mass) for _mask, log_mass in aggregated_items
                ),
                detector_support_rows=tuple(
                    int(row)
                    for row in _support_rows_from_mask(int(projected_support_mask))
                ),
            )
        )

    projected_layout = build_frontier_layout(
        list(projected_columns),
        num_detectors=int(len(active_rows)),
    )
    if projected_columns:
        corrected_active_masks_after_column: list[int] = []
        corrected_active_width_profile: list[int] = [
            int(sum(1 for value in projected_layout.detector_last_column if int(value) >= 0))
        ]
        max_active_detectors = int(corrected_active_width_profile[0])
        for projected_column_index in range(len(projected_columns)):
            active_after_column = 0
            for local_row, last_touch_column in enumerate(projected_layout.detector_last_column):
                if int(last_touch_column) > int(projected_column_index):
                    active_after_column |= 1 << int(local_row)
            corrected_active_masks_after_column.append(int(active_after_column))
            active_width = int(active_after_column.bit_count())
            corrected_active_width_profile.append(int(active_width))
            max_active_detectors = max(int(max_active_detectors), int(active_width))
        projected_layout = replace(
            projected_layout,
            active_masks_after_column=tuple(int(value) for value in corrected_active_masks_after_column),
            active_width_profile=tuple(int(value) for value in corrected_active_width_profile),
            max_active_detectors=int(max_active_detectors),
        )

    return FutureActiveFrontierHeuristicPayload(
        boundary_column_index=int(boundary_column_index),
        active_mask=int(active_mask),
        active_rows=tuple(int(row) for row in active_rows),
        row_to_local=dict(row_to_local),
        projected_target_syndrome_int=int(projected_target_syndrome_int),
        projected_columns=tuple(projected_columns),
        projected_layout=projected_layout,
    )


def _future_active_frontierk_log_mass_from_payload(
    *,
    initial_projected_det_mask: int,
    payload: FutureActiveFrontierHeuristicPayload,
    beam_size: int | None,
) -> float:
    if not payload.active_rows:
        return 0.0
    if not payload.projected_columns:
        return (
            0.0
            if int(initial_projected_det_mask) == int(payload.projected_target_syndrome_int)
            else float("-inf")
        )

    effective_beam_size = (
        None
        if beam_size is None or int(beam_size) <= 0
        else int(beam_size)
    )
    frozen_row_mask = 0
    for local_row, last_touch_column in enumerate(payload.projected_layout.detector_last_column):
        if int(last_touch_column) < 0:
            frozen_row_mask |= 1 << int(local_row)
    if (
        (
            int(initial_projected_det_mask)
            ^ int(payload.projected_target_syndrome_int)
        )
        & int(frozen_row_mask)
    ) != 0:
        return float("-inf")
    state_log_mass: dict[int, float] = {
        int(int(initial_projected_det_mask) & ~int(frozen_row_mask)): 0.0
    }
    for projected_column_index, column in enumerate(payload.projected_columns):
        close_mask = int(payload.projected_layout.closing_masks[int(projected_column_index)])
        active_mask_after_column = int(
            payload.projected_layout.active_masks_after_column[int(projected_column_index)]
        )
        next_log_mass: dict[int, float] = {}
        log_priors = _column_log_priors(column)
        for det_mask, prefix_log_mass in state_log_mass.items():
            for local_state, log_prior in enumerate(log_priors):
                if not math.isfinite(float(log_prior)):
                    continue
                candidate_det = int(det_mask) ^ int(column.detector_response_masks[int(local_state)])
                if (
                    (
                        int(candidate_det)
                        ^ int(payload.projected_target_syndrome_int)
                    )
                    & int(close_mask)
                ) != 0:
                    continue
                next_det = int(candidate_det) & int(active_mask_after_column)
                next_log_mass[int(next_det)] = _logaddexp_pair(
                    float(next_log_mass.get(int(next_det), float("-inf"))),
                    float(prefix_log_mass) + float(log_prior),
                )
        if not next_log_mass:
            return float("-inf")
        if (
            effective_beam_size is not None
            and int(len(next_log_mass)) > int(effective_beam_size)
            and int(projected_column_index) + 1 < len(payload.projected_columns)
        ):
            rank_value_by_det_mask = {
                int(det_mask): (
                    float(prefix_log_mass)
                    + float(
                        _future_mismatch_features(
                            det_mask=int(det_mask),
                            active_mask=int(active_mask_after_column),
                            target_syndrome_int=int(payload.projected_target_syndrome_int),
                            column_index=int(projected_column_index),
                            frontier=payload.projected_layout,
                        ).parity_logodds
                    ),
                    float(prefix_log_mass),
                    0.0,
                )
                for det_mask, prefix_log_mass in next_log_mass.items()
            }
            ranked_det_masks = sorted(
                next_log_mass.keys(),
                key=lambda det_mask: rank_value_by_det_mask[int(det_mask)],
                reverse=True,
            )[: int(effective_beam_size)]
            state_log_mass = {
                int(det_mask): float(next_log_mass[int(det_mask)])
                for det_mask in ranked_det_masks
            }
            continue
        state_log_mass = next_log_mass
    return float(_logaddexp_many(float(value) for value in state_log_mass.values()))


def _boundary_heuristic_mass(
    *,
    det_key: int,
    score_mode_key: str,
    active_mask: int,
    target_syndrome_int: int,
    boundary_column_index: int,
    beam_size: int | None = None,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    clamp_assignments: dict[int, int],
    features_by_detector: dict[int, FrontierMismatchFeatures],
    parity_payload_cache: dict[int, FutureParityBoundaryPayload],
    component_payload_cache: dict[int, FutureComponentHeuristicPayload],
    pairtree_payload_cache: dict[int, FuturePairtreeHeuristicPayload | FuturePairlogoddsHeuristicPayload],
    low_error_payload_cache: dict[tuple[int, int, int], FutureLowErrorHeuristicPayload],
    active_frontier_payload_cache: dict[tuple[int, int], FutureActiveFrontierHeuristicPayload],
    active_frontier_score_cache: dict[tuple[int, int, int], dict[int, float]],
    single_fix_payload_cache: dict[int, FutureSingleFixHeuristicPayload],
    quotient_payload_cache: dict[int, FutureQuotientHeuristicPayload] | None = None,
    pseudo_payload_cache: dict[tuple[int, int, str], FutureBinarizedOutcomesBoundaryPayload] | None = None,
    learned_score_config: FutureParityLearnedLinearConfig | None = None,
) -> float:
    if quotient_payload_cache is None:
        quotient_payload_cache = {}
    if pseudo_payload_cache is None:
        pseudo_payload_cache = {}
    no_prefix_inner = _no_prefix_inner_score_mode(str(score_mode_key))
    if no_prefix_inner is not None:
        score_mode_key = str(no_prefix_inner)
    low_error_event_cap = _low_error_event_cap_from_score_mode(str(score_mode_key))
    if low_error_event_cap is not None:
        cache_key = (int(boundary_column_index), int(active_mask), int(low_error_event_cap))
        payload = low_error_payload_cache.get(cache_key)
        if payload is None:
            payload = _build_future_low_error_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                max_active_events=int(low_error_event_cap),
            )
            low_error_payload_cache[cache_key] = payload
        return _future_low_error_log_mass(
            det_mask=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            payload=payload,
        )
    active_frontierk_beam = _active_frontierk_beam_from_score_mode(str(score_mode_key))
    if active_frontierk_beam is not None:
        if int(active_mask) == 0:
            return 0.0
        payload_key = (int(boundary_column_index), int(active_mask))
        payload = active_frontier_payload_cache.get(payload_key)
        if payload is None:
            payload = _build_future_active_frontier_payload(
                columns=columns,
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                clamp_assignments=clamp_assignments,
            )
            active_frontier_payload_cache[payload_key] = payload
        score_cache_key = (
            int(boundary_column_index),
            int(active_mask),
            int(active_frontierk_beam),
        )
        score_by_projected_mask = active_frontier_score_cache.setdefault(score_cache_key, {})
        initial_projected_det_mask = _project_mask_to_rows(
            int(det_key),
            payload.row_to_local,
        )
        if int(initial_projected_det_mask) not in score_by_projected_mask:
            score_by_projected_mask[int(initial_projected_det_mask)] = (
                _future_active_frontierk_log_mass_from_payload(
                    initial_projected_det_mask=int(initial_projected_det_mask),
                    payload=payload,
                    beam_size=int(active_frontierk_beam),
                )
            )
        return float(score_by_projected_mask[int(initial_projected_det_mask)])
    features = features_by_detector.get(int(det_key))
    if _is_learned_linear_score_mode(str(score_mode_key)):
        if learned_score_config is None:
            raise ValueError(f"score_mode={score_mode_key!r} requires learned_score_config")
        if str(learned_score_config.score_mode) != str(score_mode_key).strip().lower():
            raise ValueError(
                f"learned_score_config score_mode={learned_score_config.score_mode!r} "
                f"does not match requested score_mode={score_mode_key!r}"
            )
        parity_payload = parity_payload_cache.get(int(boundary_column_index))
        if parity_payload is None:
            parity_payload = _build_future_parity_boundary_payload(
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            parity_payload_cache[int(boundary_column_index)] = parity_payload
        if features is None:
            features = _future_mismatch_features_from_payload(
                det_mask=int(det_key),
                target_syndrome_int=int(target_syndrome_int),
                payload=parity_payload,
            )
            features_by_detector[int(det_key)] = features
        return _future_parity_learned_linear_score(
            det_key=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            boundary_column_index=int(boundary_column_index),
            columns=columns,
            features=features,
            parity_payload=parity_payload,
            learned_score_config=learned_score_config,
        )
    if score_mode_key == "future_touch_count":
        return float(features.touch_bonus) if features is not None else 0.0
    if score_mode_key in {"future_parity_logmass", "future_parity_logmass_only"}:
        parity_payload = parity_payload_cache.get(int(boundary_column_index))
        if parity_payload is None:
            parity_payload = _build_future_parity_boundary_payload(
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            parity_payload_cache[int(boundary_column_index)] = parity_payload
        residual_mask = int(det_key ^ target_syndrome_int) & int(active_mask)
        return _future_rowwise_log_mass_from_payload(
            residual_mask=int(residual_mask),
            payload=parity_payload,
        )
    if score_mode_key in {"deadline_weighted_future_parity_tau16", "z_deadline_weighted_future_parity_tau16"}:
        parity_payload = parity_payload_cache.get(int(boundary_column_index))
        if parity_payload is None:
            parity_payload = _build_future_parity_boundary_payload(
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            parity_payload_cache[int(boundary_column_index)] = parity_payload
        row_terms = _future_parity_row_terms_from_payload(
            det_mask=int(det_key),
            target_syndrome_int=int(target_syndrome_int),
            payload=parity_payload,
            alpha=1.0,
        )
        return _future_parity_deadline_boost_from_row_terms(
            row_terms=tuple(row_terms),
            tau=16.0,
        )
    if score_mode_key in {
        "future_parity_logodds_singlefix_bonus",
        "future_parity_logodds_singlefix_best",
        "future_parity_logodds_singlefix_bonus_with_spill_penalty",
    }:
        parity_payload = parity_payload_cache.get(int(boundary_column_index))
        if parity_payload is None:
            parity_payload = _build_future_parity_boundary_payload(
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            parity_payload_cache[int(boundary_column_index)] = parity_payload
        single_fix_payload = single_fix_payload_cache.get(int(boundary_column_index))
        if single_fix_payload is None:
            single_fix_payload = _build_future_single_fix_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            single_fix_payload_cache[int(boundary_column_index)] = single_fix_payload
        base_score = float(features.parity_logodds) if features is not None else 0.0
        return float(base_score) + float(
            _future_single_fix_bonus_from_payload(
                det_mask=int(det_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                parity_payload=parity_payload,
                single_fix_payload=single_fix_payload,
                score_mode_key=str(score_mode_key),
            )
        )
    pairlogodds_config = _pairlogodds_mode_config_from_score_mode(
        str(score_mode_key),
        beam_size=beam_size,
    )
    support_gate_pairlogodds_config = _mixed_pairlogodds_support_gate_config_from_score_mode(str(score_mode_key))
    pair_frustration_config = _future_pair_frustration_config_from_score_mode(str(score_mode_key))
    closing_logmass_config = _mixed_closing_logmass_config_from_score_mode(str(score_mode_key))
    combined_pair_closing_config = _mixed_factor_pairlogodds_plus_closing_config_from_score_mode(str(score_mode_key))
    binarized_outcomes_config = _mixed_binarized_outcomes_config_from_score_mode(str(score_mode_key))
    pairlogodds_weights = (
        (float(pairlogodds_config.singleton_scale), float(pairlogodds_config.pair_correction_scale))
        if pairlogodds_config is not None
        else None
    )
    logodds_alpha = _future_parity_logodds_alpha_from_score_mode(str(score_mode_key))
    exact_singleton_alpha = _mixed_factor_exact_singleton_alpha_from_score_mode(str(score_mode_key))
    deadline_logodds_config = _future_parity_deadline_logodds_config_from_score_mode(str(score_mode_key))
    if binarized_outcomes_config is not None:
        cache_key = (
            int(boundary_column_index),
            int(active_mask),
            str(binarized_outcomes_config.variant),
        )
        payload = pseudo_payload_cache.get(cache_key)
        if payload is None:
            payload = _build_future_binarized_outcomes_boundary_payload(
                columns=columns,
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                variant=str(binarized_outcomes_config.variant),
            )
            pseudo_payload_cache[cache_key] = payload
        features = _future_mismatch_features_from_payload(
            det_mask=int(det_key),
            target_syndrome_int=int(target_syndrome_int),
            payload=payload.parity_payload,
        )
        return float(binarized_outcomes_config.alpha) * float(features.parity_logodds)
    if score_mode_key in {
        "future_parity_logodds",
        "future_parity_logodds_only",
        STAGE1_RELIABILITY_SCORE_MODE,
        "future_parity_quotient_probe",
        "forward_terminal_lookahead",
        "future_parity_lookahead",
        "future_parity_overflow_lookahead",
            "future_parity_adaptive_lookahead",
            "future_parity_logical_lookahead",
            "future_parity_logical_adaptive_lookahead",
        } or (
        _score_mode_is_forward_cut_state_lookahead_family(score_mode_key)
        or pairlogodds_weights is not None
        or pair_frustration_config is not None
        or support_gate_pairlogodds_config is not None
        or combined_pair_closing_config is not None
        or logodds_alpha is not None
        or exact_singleton_alpha is not None
        or deadline_logodds_config is not None
    ):
        base_score = float(features.parity_logodds) if features is not None else 0.0
        if score_mode_key in {"future_parity_logodds", "future_parity_logodds_only", STAGE1_RELIABILITY_SCORE_MODE}:
            return float(base_score)
        if logodds_alpha is not None:
            return float(logodds_alpha) * float(base_score)
        if exact_singleton_alpha is not None:
            return float(exact_singleton_alpha) * float(base_score)
        if deadline_logodds_config is not None:
            deadline_alpha = float(deadline_logodds_config.alpha)
            base_score = float(deadline_alpha) * float(base_score)
            parity_payload = parity_payload_cache.get(int(boundary_column_index))
            if parity_payload is None:
                parity_payload = _build_future_parity_boundary_payload(
                    frontier=frontier,
                    boundary_column_index=int(boundary_column_index),
                    active_mask=int(active_mask),
                )
                parity_payload_cache[int(boundary_column_index)] = parity_payload
            row_terms = _future_parity_row_terms_from_payload(
                det_mask=int(det_key),
                target_syndrome_int=int(target_syndrome_int),
                payload=parity_payload,
                alpha=float(deadline_alpha),
            )
            if features is None:
                base_score = float(sum(float(term.contribution) for term in tuple(row_terms)))
            deadline_component = _future_parity_deadline_boost_from_row_terms(
                row_terms=tuple(row_terms),
                tau=float(deadline_logodds_config.tau),
            )
            return float(base_score) + float(deadline_logodds_config.beta) * float(deadline_component)
        if pair_frustration_config is not None:
            if features is None:
                parity_payload = parity_payload_cache.get(int(boundary_column_index))
                if parity_payload is None:
                    parity_payload = _build_future_parity_boundary_payload(
                        frontier=frontier,
                        boundary_column_index=int(boundary_column_index),
                        active_mask=int(active_mask),
                    )
                    parity_payload_cache[int(boundary_column_index)] = parity_payload
                features = _future_mismatch_features_from_payload(
                    det_mask=int(det_key),
                    target_syndrome_int=int(target_syndrome_int),
                    payload=parity_payload,
                )
                features_by_detector[int(det_key)] = features
                base_score = float(features.parity_logodds)
            scaled_base_score = float(pair_frustration_config.base_scale) * float(base_score)
            if float(pair_frustration_config.penalty_scale) == 0.0:
                return float(scaled_base_score)
            pair_selection_key = str(pair_frustration_config.pair_selection)
            pairlogodds_max_pairs = int(pair_frustration_config.max_pairs)
            pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
            if not isinstance(pairlogodds_payload, FuturePairlogoddsHeuristicPayload) or (
                str(pairlogodds_payload.pair_selection) != str(pair_selection_key)
                or int(pairlogodds_payload.max_pairs) != int(pairlogodds_max_pairs)
            ):
                _populate_future_pairlogodds_payload_cache(
                    columns=columns,
                    frontier=frontier,
                    clamp_assignments=clamp_assignments,
                    payload_cache=pairtree_payload_cache,
                    pair_selection=str(pair_selection_key),
                    max_pairs=int(pairlogodds_max_pairs),
                )
                pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
            if pairlogodds_payload is None:
                raise RuntimeError("future parity pair-frustration payload cache miss after population")
            penalty = _future_pairlogodds_negative_correction_penalty(
                det_mask=int(det_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                payload=pairlogodds_payload,
            )
            return float(scaled_base_score) - float(pair_frustration_config.penalty_scale) * float(penalty)
        if combined_pair_closing_config is not None:
            combined_pair_config = combined_pair_closing_config.pairlogodds
            combined_pair_weights = (
                float(combined_pair_config.singleton_scale),
                float(combined_pair_config.pair_correction_scale),
            )
            if features is None:
                parity_payload = parity_payload_cache.get(int(boundary_column_index))
                if parity_payload is None:
                    parity_payload = _build_future_parity_boundary_payload(
                        frontier=frontier,
                        boundary_column_index=int(boundary_column_index),
                        active_mask=int(active_mask),
                    )
                    parity_payload_cache[int(boundary_column_index)] = parity_payload
                features = _future_mismatch_features_from_payload(
                    det_mask=int(det_key),
                    target_syndrome_int=int(target_syndrome_int),
                    payload=parity_payload,
                )
                features_by_detector[int(det_key)] = features
                base_score = float(features.parity_logodds)
            if float(combined_pair_weights[1]) == 0.0:
                pairlogodds_score = float(combined_pair_weights[0]) * float(base_score)
            else:
                pair_selection_key = str(combined_pair_config.pair_selection)
                pairlogodds_max_pairs = int(combined_pair_config.max_pairs)
                pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
                if not isinstance(pairlogodds_payload, FuturePairlogoddsHeuristicPayload) or (
                    str(pairlogodds_payload.pair_selection) != str(pair_selection_key)
                    or int(pairlogodds_payload.max_pairs) != int(pairlogodds_max_pairs)
                ):
                    _populate_future_pairlogodds_payload_cache(
                        columns=columns,
                        frontier=frontier,
                        clamp_assignments=clamp_assignments,
                        payload_cache=pairtree_payload_cache,
                        pair_selection=str(pair_selection_key),
                        max_pairs=int(pairlogodds_max_pairs),
                    )
                    pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
                if pairlogodds_payload is None:
                    raise RuntimeError("combined pairlogodds payload cache miss after population")
                pairlogodds_score = _future_pairlogodds_log_mass(
                    det_mask=int(det_key),
                    active_mask=int(active_mask),
                    target_syndrome_int=int(target_syndrome_int),
                    payload=pairlogodds_payload,
                    singleton_scale=float(combined_pair_weights[0]),
                    pair_correction_scale=float(combined_pair_weights[1]),
                )
            combined_closing_config = combined_pair_closing_config.closing
            eligible_mask = _mixed_closing_eligible_mask(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                window_ticks=int(combined_closing_config.window_ticks),
            )
            payload_key = -30_000_000 - (
                (int(boundary_column_index) + 1) * 10_000
                + int(combined_closing_config.window_ticks) * 100
                + int(combined_closing_config.max_exact_component_rows)
            )
            component_payload = component_payload_cache.get(int(payload_key))
            if component_payload is None:
                component_payload = _build_future_component_payload(
                    columns=columns,
                    frontier=frontier,
                    column_index=int(boundary_column_index),
                    active_mask=int(eligible_mask),
                    max_exact_component_rows=int(combined_closing_config.max_exact_component_rows),
                )
                component_payload_cache[int(payload_key)] = component_payload
            closing_score = _mixed_future_closing_log_mass(
                det_mask=int(det_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                column_index=int(boundary_column_index),
                frontier=frontier,
                payload=component_payload,
                alpha=float(combined_closing_config.alpha),
                fallback=str(combined_closing_config.fallback),
            )
            if not math.isfinite(float(closing_score)):
                return float(closing_score)
            if not math.isfinite(float(base_score)):
                return float(pairlogodds_score)
            return float(pairlogodds_score) + (float(closing_score) - float(base_score))
        if pairlogodds_weights is not None:
            if float(pairlogodds_weights[1]) == 0.0:
                if features is None:
                    parity_payload = parity_payload_cache.get(int(boundary_column_index))
                    if parity_payload is None:
                        parity_payload = _build_future_parity_boundary_payload(
                            frontier=frontier,
                            boundary_column_index=int(boundary_column_index),
                            active_mask=int(active_mask),
                        )
                        parity_payload_cache[int(boundary_column_index)] = parity_payload
                    features = _future_mismatch_features_from_payload(
                        det_mask=int(det_key),
                        target_syndrome_int=int(target_syndrome_int),
                        payload=parity_payload,
                    )
                    features_by_detector[int(det_key)] = features
                    base_score = float(features.parity_logodds)
                return float(pairlogodds_weights[0]) * float(base_score)
            pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
            pair_selection_key = (
                str(pairlogodds_config.pair_selection)
                if pairlogodds_config is not None
                else str(PAIRLOGODDS_PAIR_SELECTION_DEFAULT)
            )
            pairlogodds_max_pairs = int(pairlogodds_config.max_pairs) if pairlogodds_config is not None else 0
            if not isinstance(pairlogodds_payload, FuturePairlogoddsHeuristicPayload) or (
                str(pairlogodds_payload.pair_selection) != str(pair_selection_key)
                or int(pairlogodds_payload.max_pairs) != int(pairlogodds_max_pairs)
            ):
                _populate_future_pairlogodds_payload_cache(
                    columns=columns,
                    frontier=frontier,
                    clamp_assignments=clamp_assignments,
                    payload_cache=pairtree_payload_cache,
                    pair_selection=str(pair_selection_key),
                    max_pairs=int(pairlogodds_max_pairs),
                )
                pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
            if pairlogodds_payload is None:
                raise RuntimeError("future_parity_pairlogodds payload cache miss after population")
            return _future_pairlogodds_log_mass(
                det_mask=int(det_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                payload=pairlogodds_payload,
                singleton_scale=float(pairlogodds_weights[0]),
                pair_correction_scale=float(pairlogodds_weights[1]),
            )
        if support_gate_pairlogodds_config is not None:
            support_weights = (
                float(support_gate_pairlogodds_config.singleton_scale),
                float(support_gate_pairlogodds_config.pair_correction_scale),
            )
            if float(support_weights[1]) == 0.0:
                if features is None:
                    parity_payload = parity_payload_cache.get(int(boundary_column_index))
                    if parity_payload is None:
                        parity_payload = _build_future_parity_boundary_payload(
                            frontier=frontier,
                            boundary_column_index=int(boundary_column_index),
                            active_mask=int(active_mask),
                        )
                        parity_payload_cache[int(boundary_column_index)] = parity_payload
                    features = _future_mismatch_features_from_payload(
                        det_mask=int(det_key),
                        target_syndrome_int=int(target_syndrome_int),
                        payload=parity_payload,
                    )
                    features_by_detector[int(det_key)] = features
                    base_score = float(features.parity_logodds)
                pairlogodds_score = float(support_weights[0]) * float(base_score)
            else:
                pair_selection_key = str(support_gate_pairlogodds_config.pair_selection)
                support_pairlogodds_max_pairs = int(support_gate_pairlogodds_config.max_pairs)
                pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
                if not isinstance(pairlogodds_payload, FuturePairlogoddsHeuristicPayload) or (
                    str(pairlogodds_payload.pair_selection) != str(pair_selection_key)
                    or int(pairlogodds_payload.max_pairs) != int(support_pairlogodds_max_pairs)
                ):
                    _populate_future_pairlogodds_payload_cache(
                        columns=columns,
                        frontier=frontier,
                        clamp_assignments=clamp_assignments,
                        payload_cache=pairtree_payload_cache,
                        pair_selection=str(pair_selection_key),
                        max_pairs=int(support_pairlogodds_max_pairs),
                    )
                    pairlogodds_payload = pairtree_payload_cache.get(int(boundary_column_index))
                if pairlogodds_payload is None:
                    raise RuntimeError("mixed pairlogodds support-gate payload cache miss after population")
                pairlogodds_score = _future_pairlogodds_log_mass(
                    det_mask=int(det_key),
                    active_mask=int(active_mask),
                    target_syndrome_int=int(target_syndrome_int),
                    payload=pairlogodds_payload,
                    singleton_scale=float(support_weights[0]),
                    pair_correction_scale=float(support_weights[1]),
                )
            support_payload_key = -10_000_000 - int(boundary_column_index)
            support_payload = pairtree_payload_cache.get(int(support_payload_key))
            if not isinstance(support_payload, FuturePairtreeHeuristicPayload) or not bool(
                support_payload.support_gate_precomputed
            ):
                support_payload = _build_future_pairtree_payload(
                    columns=columns,
                    frontier=frontier,
                    column_index=int(boundary_column_index),
                    active_mask=int(active_mask),
                    target_syndrome_int=int(target_syndrome_int),
                    clamp_assignments=clamp_assignments,
                    include_support_gate=True,
                )
                pairtree_payload_cache[int(support_payload_key)] = support_payload
            residual_mask = int(det_key ^ target_syndrome_int) & int(active_mask)
            if not _support_gate_allows_repair_pattern(
                residual_mask=int(residual_mask),
                payload=support_payload,
            ):
                return float("-inf")
            return float(pairlogodds_score)
        if score_mode_key != "future_parity_quotient_probe":
            return float(base_score)
        parity_payload = parity_payload_cache.get(int(boundary_column_index))
        if parity_payload is None:
            parity_payload = _build_future_parity_boundary_payload(
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            parity_payload_cache[int(boundary_column_index)] = parity_payload
        quotient_payload = quotient_payload_cache.get(int(boundary_column_index))
        if quotient_payload is None:
            quotient_payload = _build_future_quotient_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            quotient_payload_cache[int(boundary_column_index)] = quotient_payload
        return float(base_score) + float(
            _future_quotient_correction_from_payload(
                det_mask=int(det_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                parity_payload=parity_payload,
                quotient_payload=quotient_payload,
            )
        )
    if score_mode_key == "future_repair_min_steps":
        pairtree_payload = pairtree_payload_cache.get(int(boundary_column_index))
        if not isinstance(pairtree_payload, FuturePairtreeHeuristicPayload) or not bool(
            pairtree_payload.support_gate_precomputed
        ):
            pairtree_payload = _build_future_pairtree_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                clamp_assignments=clamp_assignments,
                include_support_gate=True,
            )
            pairtree_payload_cache[int(boundary_column_index)] = pairtree_payload
        min_nonzero_steps = _future_support_gate_min_nonzero_steps(
            det_mask=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            payload=pairtree_payload,
        )
        if min_nonzero_steps is None:
            return float("-inf")
        return -float(min_nonzero_steps)
    if score_mode_key in {"future_component_logmass", "future_local_cone_logmass"}:
        component_payload = component_payload_cache.get(int(boundary_column_index))
        if component_payload is None:
            component_payload = _build_future_component_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                max_exact_component_rows=10,
            )
            component_payload_cache[int(boundary_column_index)] = component_payload
        if score_mode_key == "future_local_cone_logmass":
            return _future_local_cone_log_mass(
                det_mask=int(det_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                column_index=int(boundary_column_index),
                frontier=frontier,
                payload=component_payload,
            )
        return _future_component_log_mass(
            det_mask=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            column_index=int(boundary_column_index),
            frontier=frontier,
            payload=component_payload,
        )
    if closing_logmass_config is not None:
        eligible_mask = _mixed_closing_eligible_mask(
            columns=columns,
            frontier=frontier,
            column_index=int(boundary_column_index),
            active_mask=int(active_mask),
            window_ticks=int(closing_logmass_config.window_ticks),
        )
        payload_key = -20_000_000 - (
            (int(boundary_column_index) + 1) * 10_000
            + int(closing_logmass_config.window_ticks) * 100
            + int(closing_logmass_config.max_exact_component_rows)
        )
        component_payload = component_payload_cache.get(int(payload_key))
        if component_payload is None:
            component_payload = _build_future_component_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(eligible_mask),
                max_exact_component_rows=int(closing_logmass_config.max_exact_component_rows),
            )
            component_payload_cache[int(payload_key)] = component_payload
        return _mixed_future_closing_log_mass(
            det_mask=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            column_index=int(boundary_column_index),
            frontier=frontier,
            payload=component_payload,
            alpha=float(closing_logmass_config.alpha),
            fallback=str(closing_logmass_config.fallback),
        )
    if score_mode_key in {"future_parity_pairtree", "future_parity_pairtree_support_gate"}:
        pairtree_payload = pairtree_payload_cache.get(int(boundary_column_index))
        if not isinstance(pairtree_payload, FuturePairtreeHeuristicPayload) or (
            score_mode_key == "future_parity_pairtree_support_gate"
            and not bool(pairtree_payload.support_gate_precomputed)
        ):
            pairtree_payload = _build_future_pairtree_payload(
                columns=columns,
                frontier=frontier,
                column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                clamp_assignments=clamp_assignments,
                include_support_gate=(score_mode_key == "future_parity_pairtree_support_gate"),
            )
            pairtree_payload_cache[int(boundary_column_index)] = pairtree_payload
        return _future_pairtree_log_mass(
            det_mask=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            payload=pairtree_payload,
            use_support_gate=(score_mode_key == "future_parity_pairtree_support_gate"),
        )
    return 0.0


def _logical_exact_tail_summary_for_state(
    *,
    key: int,
    prefix_log_mass: float,
    start_column_index: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int = 1,
    clamp_assignments: dict[int, int],
    state_budget: int,
    transition_budget: int,
) -> LogicalTailRerankEntry:
    current_logical_mask = _unpack_logical_mask(
        state_key=int(key),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
    )
    (
        tail_status,
        tail_state_log_mass,
        _tail_state_viterbi,
        _tail_state_viterbi_rep_cost,
        _tail_state_min_nonzero_steps,
        _tail_parent_chain,
        _tail_state_counts,
        tail_transition_counts,
        _tail_stop_column_index,
    ) = _exact_tail_solve(
        state_log_mass={int(key): 0.0},
        state_viterbi={int(key): 0.0},
        state_viterbi_rep_cost={int(key): 0},
        state_min_nonzero_steps=None,
        start_column_index=int(start_column_index),
        columns=columns,
        frontier=frontier,
        target_syndrome_int=int(target_syndrome_int),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
        track_best_path=False,
        clamp_assignments=clamp_assignments,
        state_budget=(None if int(state_budget) <= 0 else int(state_budget)),
        transition_budget=(None if int(transition_budget) <= 0 else int(transition_budget)),
    )
    transition_count = int(sum(int(value) for value in tail_transition_counts))
    if str(tail_status) != "ok":
        return LogicalTailRerankEntry(
            key=int(key),
            best_logical=-1,
            best_score=float("-inf"),
            total_score=float("-inf"),
            prefix_score=float(prefix_log_mass),
            transition_count=int(transition_count),
            status=str(tail_status),
        )

    logical_log_mass_map: dict[int, float] = {}
    detector_mask_mask = (1 << int(num_detectors)) - 1
    for terminal_key, log_mass in tail_state_log_mass.items():
        det_mask = _unpack_detector_mask(state_key=int(terminal_key), detector_mask_mask=int(detector_mask_mask))
        logical_mask = _unpack_logical_mask(
            state_key=int(terminal_key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        if int(det_mask) != 0:
            continue
        logical_log_mass_map[int(logical_mask)] = _logaddexp_pair(
            float(logical_log_mass_map.get(int(logical_mask), float("-inf"))),
            float(log_mass),
        )
    if not logical_log_mass_map:
        return LogicalTailRerankEntry(
            key=int(key),
            best_logical=-1,
            best_score=float("-inf"),
            total_score=float("-inf"),
            prefix_score=float(prefix_log_mass),
            transition_count=int(transition_count),
            status="impossible",
        )
    best_logical = max(logical_log_mass_map, key=lambda logical_mask: float(logical_log_mass_map[int(logical_mask)]))
    best_suffix = float(logical_log_mass_map[int(best_logical)])
    total_suffix = float(_logaddexp_many(logical_log_mass_map))
    same_logical_suffix = float(logical_log_mass_map.get(int(current_logical_mask), float("-inf")))
    same_logical_score = (
        float(prefix_log_mass) + float(same_logical_suffix)
        if math.isfinite(float(same_logical_suffix))
        else float("-inf")
    )
    same_logical_logprob = (
        float(same_logical_suffix) - float(total_suffix)
        if math.isfinite(float(same_logical_suffix)) and math.isfinite(float(total_suffix))
        else float("-inf")
    )
    return LogicalTailRerankEntry(
        key=int(key),
        best_logical=int(best_logical),
        best_score=float(prefix_log_mass) + float(best_suffix),
        total_score=float(prefix_log_mass) + float(total_suffix),
        prefix_score=float(prefix_log_mass),
        transition_count=int(transition_count),
        status="ok",
        same_logical_score=float(same_logical_score),
        same_logical_logprob=float(same_logical_logprob),
        logical_log_masses=tuple(
            (int(logical_mask), float(log_mass))
            for logical_mask, log_mass in sorted(logical_log_mass_map.items())
        ),
    )


def _logical_local_cone_summary_for_state(
    *,
    key: int,
    prefix_log_mass: float,
    boundary_column_index: int,
    active_mask: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int = 1,
    clamp_assignments: dict[int, int],
    state_budget: int,
    transition_budget: int,
    component_payload: FutureComponentHeuristicPayload,
) -> LogicalTailRerankEntry:
    detector_mask_mask = (1 << int(num_detectors)) - 1
    det_mask = _unpack_detector_mask(state_key=int(key), detector_mask_mask=int(detector_mask_mask))
    logical_mask = _unpack_logical_mask(
        state_key=int(key),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
    )
    residual_mask = int(det_mask ^ target_syndrome_int) & int(active_mask)
    if int(residual_mask) == 0:
        return LogicalTailRerankEntry(
            key=int(key),
            best_logical=int(logical_mask),
            best_score=float(prefix_log_mass),
            total_score=float(prefix_log_mass),
            prefix_score=float(prefix_log_mass),
            transition_count=0,
            status="ok",
            same_logical_score=float(prefix_log_mass),
            same_logical_logprob=0.0,
        )

    touched_components: list[int] = []
    touched_component_set: set[int] = set()
    remaining = int(residual_mask)
    while int(remaining) != 0:
        lsb = int(remaining & -remaining)
        row = int(lsb.bit_length() - 1)
        component_index = component_payload.component_index_by_row.get(int(row))
        if component_index is None:
            return LogicalTailRerankEntry(
                key=int(key),
                best_logical=-1,
                best_score=float("-inf"),
                total_score=float("-inf"),
                prefix_score=float(prefix_log_mass),
                transition_count=0,
                status="impossible",
            )
        if int(component_index) not in touched_component_set:
            touched_components.append(int(component_index))
            touched_component_set.add(int(component_index))
        remaining ^= int(lsb)

    local_row_mask = 0
    local_columns_set: set[int] = set()
    for component_index in touched_components:
        component = component_payload.components[int(component_index)]
        local_row_mask |= int(component.row_mask)
        local_columns_set.update(int(value) for value in component.columns)
    if int(local_row_mask) == 0 or not local_columns_set:
        return LogicalTailRerankEntry(
            key=int(key),
            best_logical=-1,
            best_score=float("-inf"),
            total_score=float("-inf"),
            prefix_score=float(prefix_log_mass),
            transition_count=0,
            status="impossible",
        )

    local_rows = _support_rows_from_mask(int(local_row_mask))
    row_to_local = {int(row): int(index) for index, row in enumerate(local_rows)}
    local_state_log_mass: dict[tuple[int, int], float] = {
        (int(_project_mask_to_rows(int(residual_mask), row_to_local)), int(logical_mask)): 0.0
    }
    selected_columns = tuple(sorted(int(value) for value in local_columns_set))
    cumulative_transition_count = 0
    state_budget_limit = None if int(state_budget) <= 0 else int(state_budget)
    transition_budget_limit = None if int(transition_budget) <= 0 else int(transition_budget)

    for future_column_index in selected_columns:
        column = columns[int(future_column_index)]
        close_mask = _project_mask_to_rows(
            int(frontier.closing_masks[int(future_column_index)]) & int(local_row_mask),
            row_to_local,
        )
        active_after_mask = _project_mask_to_rows(
            int(frontier.active_masks_after_column[int(future_column_index)]) & int(local_row_mask),
            row_to_local,
        )
        forced_local_state = clamp_assignments.get(int(future_column_index))
        if forced_local_state is None:
            state_iter = enumerate(_column_log_priors(column))
        else:
            forced_log_prior = float(_column_log_priors(column)[int(forced_local_state)])
            state_iter = ((int(forced_local_state), float(forced_log_prior)),)

        next_state_log_mass: dict[tuple[int, int], float] = {}
        transition_count = 0
        for (local_residual_mask, absolute_logical_mask), log_mass in local_state_log_mass.items():
            for local_state, log_prior in state_iter:
                if not math.isfinite(float(log_prior)):
                    continue
                transition_count += 1
                local_detector_response = _project_mask_to_rows(
                    int(column.detector_response_masks[int(local_state)]) & int(local_row_mask),
                    row_to_local,
                )
                candidate_residual_mask = int(local_residual_mask) ^ int(local_detector_response)
                if (int(candidate_residual_mask) & int(close_mask)) != 0:
                    continue
                next_residual_mask = int(candidate_residual_mask) & int(active_after_mask)
                next_logical_mask = int(absolute_logical_mask) ^ int(column.logical_response_masks[int(local_state)])
                next_key = (int(next_residual_mask), int(next_logical_mask))
                next_state_log_mass[next_key] = _logaddexp_pair(
                    float(next_state_log_mass.get(next_key, float("-inf"))),
                    float(log_mass) + float(log_prior),
                )

        if not next_state_log_mass:
            return LogicalTailRerankEntry(
                key=int(key),
                best_logical=-1,
                best_score=float("-inf"),
                total_score=float("-inf"),
                prefix_score=float(prefix_log_mass),
                transition_count=int(cumulative_transition_count + int(transition_count)),
                status="impossible",
            )

        cumulative_transition_count += int(transition_count)
        if (
            (state_budget_limit is not None and int(len(next_state_log_mass)) > int(state_budget_limit))
            or (
                transition_budget_limit is not None
                and int(cumulative_transition_count) > int(transition_budget_limit)
            )
        ):
            return LogicalTailRerankEntry(
                key=int(key),
                best_logical=-1,
                best_score=float("-inf"),
                total_score=float("-inf"),
                prefix_score=float(prefix_log_mass),
                transition_count=int(cumulative_transition_count),
                status="budget_exceeded",
            )
        local_state_log_mass = next_state_log_mass

    logical_log_mass_map: dict[int, float] = {}
    for (local_residual_mask, absolute_logical_mask), log_mass in local_state_log_mass.items():
        if int(local_residual_mask) != 0:
            continue
        logical_log_mass_map[int(absolute_logical_mask)] = _logaddexp_pair(
            float(logical_log_mass_map.get(int(absolute_logical_mask), float("-inf"))),
            float(log_mass),
        )
    if not logical_log_mass_map:
        return LogicalTailRerankEntry(
            key=int(key),
            best_logical=-1,
            best_score=float("-inf"),
            total_score=float("-inf"),
            prefix_score=float(prefix_log_mass),
            transition_count=int(cumulative_transition_count),
            status="impossible",
        )

    best_logical = max(logical_log_mass_map, key=lambda logical_class: float(logical_log_mass_map[int(logical_class)]))
    best_suffix = float(logical_log_mass_map[int(best_logical)])
    total_suffix = float(_logaddexp_many(logical_log_mass_map))
    same_logical_suffix = float(logical_log_mass_map.get(int(logical_mask), float("-inf")))
    same_logical_score = (
        float(prefix_log_mass) + float(same_logical_suffix)
        if math.isfinite(float(same_logical_suffix))
        else float("-inf")
    )
    same_logical_logprob = (
        float(same_logical_suffix) - float(total_suffix)
        if math.isfinite(float(same_logical_suffix)) and math.isfinite(float(total_suffix))
        else float("-inf")
    )
    return LogicalTailRerankEntry(
        key=int(key),
        best_logical=int(best_logical),
        best_score=float(prefix_log_mass) + float(best_suffix),
        total_score=float(prefix_log_mass) + float(total_suffix),
        prefix_score=float(prefix_log_mass),
        transition_count=int(cumulative_transition_count),
        status="ok",
        same_logical_score=float(same_logical_score),
        same_logical_logprob=float(same_logical_logprob),
    )


def _logical_tail_summary_for_state(
    *,
    key: int,
    prefix_log_mass: float,
    start_column_index: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int = 1,
    clamp_assignments: dict[int, int],
    state_budget: int,
    transition_budget: int,
    logical_rerank_mode: str = "exact_tail",
    boundary_column_index: int | None = None,
    active_mask: int | None = None,
    component_payload_cache: dict[int, FutureComponentHeuristicPayload] | None = None,
) -> LogicalTailRerankEntry:
    logical_rerank_mode_key = str(logical_rerank_mode).strip().lower()
    if logical_rerank_mode_key in {"exact_tail", "exact_tail_vector"}:
        return _logical_exact_tail_summary_for_state(
            key=int(key),
            prefix_log_mass=float(prefix_log_mass),
            start_column_index=int(start_column_index),
            columns=columns,
            frontier=frontier,
            target_syndrome_int=int(target_syndrome_int),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
            clamp_assignments=clamp_assignments,
            state_budget=int(state_budget),
            transition_budget=int(transition_budget),
        )
    if logical_rerank_mode_key != "local_cone":
        raise ValueError("logical_rerank_mode must be one of ['exact_tail', 'exact_tail_vector', 'local_cone']")
    if boundary_column_index is None or active_mask is None:
        raise ValueError("local_cone logical rerank requires boundary_column_index and active_mask")
    component_payloads = component_payload_cache if component_payload_cache is not None else {}
    component_payload = component_payloads.get(int(boundary_column_index))
    if component_payload is None:
        component_payload = _build_future_component_payload(
            columns=columns,
            frontier=frontier,
            column_index=int(boundary_column_index),
            active_mask=int(active_mask),
            max_exact_component_rows=10,
        )
        component_payloads[int(boundary_column_index)] = component_payload
    return _logical_local_cone_summary_for_state(
        key=int(key),
        prefix_log_mass=float(prefix_log_mass),
        boundary_column_index=int(boundary_column_index),
        active_mask=int(active_mask),
        columns=columns,
        frontier=frontier,
        target_syndrome_int=int(target_syndrome_int),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
        clamp_assignments=clamp_assignments,
        state_budget=int(state_budget),
        transition_budget=int(transition_budget),
        component_payload=component_payload,
    )


def _logical_rerank_select_keys_exact_tail_vector(
    *,
    rerank_entries: Sequence[LogicalTailRerankEntry],
    beam_size: int,
) -> list[int]:
    if int(beam_size) <= 0:
        return []

    contributions_by_logical: dict[int, list[tuple[float, float, float, int]]] = {}
    for entry in rerank_entries:
        if not entry.logical_log_masses:
            continue
        for logical_mask, suffix_log_mass in entry.logical_log_masses:
            if not math.isfinite(float(suffix_log_mass)):
                continue
            contributions_by_logical.setdefault(int(logical_mask), []).append(
                (
                    float(entry.prefix_score) + float(suffix_log_mass),
                    float(entry.total_score),
                    float(entry.prefix_score),
                    int(entry.key),
                )
            )

    if not contributions_by_logical:
        return []

    best_logical: int | None = None
    best_target_score = float("-inf")
    best_target_entries: list[tuple[float, float, float, int]] = []
    for logical_mask, entries in contributions_by_logical.items():
        ranked_entries = sorted(entries, reverse=True)
        kept_entries = ranked_entries[: max(0, int(beam_size))]
        target_score = float(_logaddexp_many([float(item[0]) for item in kept_entries]))
        target_top_score = float(kept_entries[0][0]) if kept_entries else float("-inf")
        current_tiebreak = (
            float(target_score),
            float(target_top_score),
            int(len(kept_entries)),
            -int(logical_mask),
        )
        best_tiebreak = (
            float(best_target_score),
            float(best_target_entries[0][0]) if best_target_entries else float("-inf"),
            int(len(best_target_entries)),
            -int(best_logical) if best_logical is not None else 0,
        )
        if best_logical is None or current_tiebreak > best_tiebreak:
            best_logical = int(logical_mask)
            best_target_score = float(target_score)
            best_target_entries = list(kept_entries)

    if best_logical is None:
        return []

    selected: list[int] = []
    selected_set: set[int] = set()
    for _, _, _, key in best_target_entries:
        if int(key) in selected_set:
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        if len(selected) >= int(beam_size):
            return selected

    for entry in sorted(
        rerank_entries,
        key=lambda item: (float(item.best_score), float(item.total_score), float(item.prefix_score)),
        reverse=True,
    ):
        if int(entry.key) in selected_set:
            continue
        selected.append(int(entry.key))
        selected_set.add(int(entry.key))
        if len(selected) >= int(beam_size):
            break
    return selected


def _logical_rerank_select_keys(
    *,
    rerank_entries: Sequence[LogicalTailRerankEntry],
    beam_size: int,
    min_classes: int,
    logical_rerank_mode: str = "exact_tail",
) -> list[int]:
    logical_rerank_mode_key = str(logical_rerank_mode).strip().lower()
    if logical_rerank_mode_key == "exact_tail_vector":
        return _logical_rerank_select_keys_exact_tail_vector(
            rerank_entries=rerank_entries,
            beam_size=int(beam_size),
        )
    if logical_rerank_mode_key not in {"exact_tail", "local_cone"}:
        raise ValueError(
            "logical_rerank_mode must be one of ['exact_tail', 'exact_tail_vector', 'local_cone']"
        )
    selected: list[int] = []
    selected_set: set[int] = set()

    best_per_logical: dict[int, LogicalTailRerankEntry] = {}
    for entry in rerank_entries:
        if int(entry.best_logical) < 0 or not math.isfinite(float(entry.best_score)):
            continue
        current = best_per_logical.get(int(entry.best_logical))
        if current is None or (float(entry.best_score), float(entry.total_score), float(entry.prefix_score)) > (
            float(current.best_score),
            float(current.total_score),
            float(current.prefix_score),
        ):
            best_per_logical[int(entry.best_logical)] = entry

    class_entries = sorted(
        best_per_logical.values(),
        key=lambda entry: (float(entry.best_score), float(entry.total_score), float(entry.prefix_score)),
        reverse=True,
    )
    for entry in class_entries[: max(0, int(min_classes))]:
        if int(entry.key) in selected_set:
            continue
        selected.append(int(entry.key))
        selected_set.add(int(entry.key))
        if len(selected) >= int(beam_size):
            return selected

    for entry in sorted(
        rerank_entries,
        key=lambda item: (float(item.best_score), float(item.total_score), float(item.prefix_score)),
        reverse=True,
    ):
        if int(entry.key) in selected_set:
            continue
        selected.append(int(entry.key))
        selected_set.add(int(entry.key))
        if len(selected) >= int(beam_size):
            break
    return selected


def _should_run_logical_rerank(
    *,
    remaining_suffix_columns: int,
    logical_rerank_columns: int,
    logical_rerank_shortlist_size: int,
    logical_rerank_min_classes: int,
    logical_rerank_mode: str,
    logical_rerank_checkpoint_stride: int,
    logical_rerank_max_passes: int,
    logical_rerank_pass_count: int,
    logical_rerank_last_remaining_columns: int,
) -> bool:
    logical_rerank_mode_key = str(logical_rerank_mode).strip().lower()
    if int(logical_rerank_columns) <= 0:
        return False
    if int(logical_rerank_shortlist_size) <= 0:
        return False
    if logical_rerank_mode_key != "exact_tail_vector" and int(logical_rerank_min_classes) <= 0:
        return False
    if int(logical_rerank_max_passes) <= 0:
        return False
    if int(logical_rerank_pass_count) >= int(logical_rerank_max_passes):
        return False
    if int(remaining_suffix_columns) <= 0:
        return False
    if int(remaining_suffix_columns) > int(logical_rerank_columns):
        return False
    if int(logical_rerank_pass_count) <= 0:
        return True
    if int(logical_rerank_checkpoint_stride) <= 0:
        return False
    return int(logical_rerank_last_remaining_columns) - int(remaining_suffix_columns) >= int(
        logical_rerank_checkpoint_stride
    )


def _select_keys_detector_first(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    detector_mask_mask: int,
    max_logicals_per_detector: int,
) -> list[int]:
    if int(beam_size) <= 0 or not ranked_keys:
        return []

    bucket_order: list[int] = []
    bucket_keys: dict[int, list[int]] = {}
    for key in ranked_keys:
        det_key = _unpack_detector_mask(state_key=int(key), detector_mask_mask=int(detector_mask_mask))
        if int(det_key) not in bucket_keys:
            bucket_order.append(int(det_key))
            bucket_keys[int(det_key)] = []
        bucket_keys[int(det_key)].append(int(key))

    selected: list[int] = []
    selected_set: set[int] = set()
    next_index_by_detector: dict[int, int] = {int(det_key): 0 for det_key in bucket_order}

    for det_key in bucket_order:
        bucket = bucket_keys[int(det_key)]
        if not bucket:
            continue
        key = int(bucket[0])
        selected.append(int(key))
        selected_set.add(int(key))
        next_index_by_detector[int(det_key)] = 1
        if len(selected) >= int(beam_size):
            return selected

    while len(selected) < int(beam_size):
        progress = False
        for det_key in bucket_order:
            bucket = bucket_keys[int(det_key)]
            next_index = int(next_index_by_detector[int(det_key)])
            if int(max_logicals_per_detector) > 0 and int(next_index) >= int(max_logicals_per_detector):
                continue
            while int(next_index) < len(bucket) and int(bucket[int(next_index)]) in selected_set:
                next_index += 1
            next_index_by_detector[int(det_key)] = int(next_index)
            if int(next_index) >= len(bucket):
                continue
            if int(max_logicals_per_detector) > 0 and int(next_index) >= int(max_logicals_per_detector):
                continue
            key = int(bucket[int(next_index)])
            selected.append(int(key))
            selected_set.add(int(key))
            next_index_by_detector[int(det_key)] = int(next_index) + 1
            progress = True
            if len(selected) >= int(beam_size):
                return selected
        if not progress:
            break

    if len(selected) < int(beam_size):
        for key in ranked_keys:
            if int(key) in selected_set:
                continue
            selected.append(int(key))
            selected_set.add(int(key))
            if len(selected) >= int(beam_size):
                break
    return selected


def _bucketed_retention_bucket_value_for_state(
    *,
    state_key: int,
    bucket_key: str,
    detector_mask_mask: int,
) -> str:
    key = _normalize_bucketed_retention_key(str(bucket_key))
    det_mask = _unpack_detector_mask(
        state_key=int(state_key),
        detector_mask_mask=int(detector_mask_mask),
    )
    if key == "open_count":
        return str(int(det_mask).bit_count())
    raise AssertionError(f"unhandled bucketed retention key {key!r}")


def _select_keys_bucketed_v1(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    detector_mask_mask: int,
    bucketed_retention_fraction: float,
    bucketed_retention_key: str,
) -> list[int]:
    if int(beam_size) <= 0 or not ranked_keys:
        return []
    if int(beam_size) >= len(ranked_keys):
        return [int(key) for key in ranked_keys]
    fraction = float(bucketed_retention_fraction)
    if math.isnan(float(fraction)) or not math.isfinite(float(fraction)):
        raise ValueError("bucketed_retention_fraction must be finite")
    if float(fraction) <= 0.0:
        return [int(key) for key in ranked_keys[: int(beam_size)]]
    if float(fraction) > 1.0:
        raise ValueError("bucketed_retention_fraction must be in [0, 1]")

    reserve_slots = min(
        int(beam_size),
        max(1, int(math.floor(float(fraction) * float(int(beam_size))))),
    )
    safe_count = max(0, int(beam_size) - int(reserve_slots))
    selected = [int(key) for key in ranked_keys[: int(safe_count)]]
    selected_set = {int(key) for key in selected}

    buckets: dict[str, list[int]] = {}
    bucket_first_rank: dict[str, int] = {}
    represented_buckets = {
        _bucketed_retention_bucket_value_for_state(
            state_key=int(key),
            bucket_key=str(bucketed_retention_key),
            detector_mask_mask=int(detector_mask_mask),
        )
        for key in selected
    }
    for rank_index, key in enumerate(ranked_keys):
        if int(key) in selected_set:
            continue
        bucket_value = _bucketed_retention_bucket_value_for_state(
            state_key=int(key),
            bucket_key=str(bucketed_retention_key),
            detector_mask_mask=int(detector_mask_mask),
        )
        buckets.setdefault(str(bucket_value), []).append(int(key))
        bucket_first_rank.setdefault(str(bucket_value), int(rank_index))

    bucket_order = sorted(
        buckets.keys(),
        key=lambda value: (
            1 if str(value) in represented_buckets else 0,
            int(bucket_first_rank[str(value)]),
            str(value),
        ),
    )
    next_index_by_bucket: dict[str, int] = {str(value): 0 for value in bucket_order}
    while len(selected) < int(beam_size):
        progress = False
        for bucket_value in bucket_order:
            bucket = buckets[str(bucket_value)]
            next_index = int(next_index_by_bucket[str(bucket_value)])
            while int(next_index) < len(bucket) and int(bucket[int(next_index)]) in selected_set:
                next_index += 1
            next_index_by_bucket[str(bucket_value)] = int(next_index)
            if int(next_index) >= len(bucket):
                continue
            key = int(bucket[int(next_index)])
            selected.append(int(key))
            selected_set.add(int(key))
            next_index_by_bucket[str(bucket_value)] = int(next_index) + 1
            progress = True
            if len(selected) >= int(beam_size):
                break
        if not progress:
            break

    if len(selected) < int(beam_size):
        for key in ranked_keys:
            if int(key) in selected_set:
                continue
            selected.append(int(key))
            selected_set.add(int(key))
            if len(selected) >= int(beam_size):
                break
    return selected


def _resolve_prefix_reserve_slots(
    *,
    beam_size: int,
    prefix_reserve_slots: int = 0,
    prefix_reserve_fraction: float = 0.0,
) -> int:
    beam_limit = max(0, int(beam_size))
    if int(beam_limit) <= 0:
        return 0
    slot_count = int(prefix_reserve_slots)
    fraction = float(prefix_reserve_fraction)
    if int(slot_count) < 0:
        raise ValueError("prefix_reserve_slots must be >= 0")
    if math.isnan(float(fraction)) or not math.isfinite(float(fraction)):
        raise ValueError("prefix_reserve_fraction must be finite")
    if float(fraction) < 0.0 or float(fraction) > 1.0:
        raise ValueError("prefix_reserve_fraction must be in [0, 1]")
    if int(slot_count) > 0 and float(fraction) > 0.0:
        raise ValueError("use prefix_reserve_slots or prefix_reserve_fraction, not both")
    if int(slot_count) <= 0 and float(fraction) > 0.0:
        slot_count = int(round(float(fraction) * float(beam_limit)))
    return min(int(beam_limit), max(0, int(slot_count)))


def _select_keys_prefix_reserve_v1(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    prefix_log_mass_by_key: Mapping[int, float],
    rank_value_by_key: Mapping[int, tuple[float, float, float]],
    prefix_reserve_slots: int = 0,
    prefix_reserve_fraction: float = 0.0,
    prefix_reserve_mode: str = "fixed",
    prefix_reserve_max_slots: int = 0,
    prefix_reserve_cutoff_deficit: float = float("inf"),
    prefix_reserve_mass_coverage_tau: float = 0.0,
) -> list[int]:
    ranked = tuple(int(key) for key in tuple(ranked_keys))
    if int(beam_size) <= 0 or not ranked:
        return []
    if int(beam_size) >= len(ranked):
        return [int(key) for key in ranked]
    mode_key = str(prefix_reserve_mode).strip().lower()
    if mode_key in {"", "none", "off"}:
        return [int(key) for key in ranked[: int(beam_size)]]
    if mode_key not in PREFIX_RESERVE_MODES:
        raise ValueError(f"prefix_reserve_mode must be one of {sorted(PREFIX_RESERVE_MODES)}")
    cutoff_deficit_limit = float(prefix_reserve_cutoff_deficit)
    if math.isnan(float(cutoff_deficit_limit)) or float(cutoff_deficit_limit) < 0.0:
        raise ValueError("prefix_reserve_cutoff_deficit must be >= 0 or inf")
    tau = float(prefix_reserve_mass_coverage_tau)
    if math.isnan(float(tau)) or not math.isfinite(float(tau)) or float(tau) < 0.0 or float(tau) > 1.0:
        raise ValueError("prefix_reserve_mass_coverage_tau must be finite and in [0, 1]")

    fixed_slots = _resolve_prefix_reserve_slots(
        beam_size=int(beam_size),
        prefix_reserve_slots=int(prefix_reserve_slots),
        prefix_reserve_fraction=float(prefix_reserve_fraction),
    )
    if int(prefix_reserve_max_slots) < 0:
        raise ValueError("prefix_reserve_max_slots must be >= 0")
    reserve_slots = int(fixed_slots)
    if str(mode_key) == "adaptive_mass_coverage":
        reserve_slots = int(prefix_reserve_max_slots) if int(prefix_reserve_max_slots) > 0 else int(fixed_slots)
        if int(reserve_slots) <= 0 or float(tau) <= 0.0:
            return [int(key) for key in ranked[: int(beam_size)]]
        all_log_mass = _logaddexp_many(float(prefix_log_mass_by_key.get(int(key), float("-inf"))) for key in ranked)
        primary_log_mass = _logaddexp_many(
            float(prefix_log_mass_by_key.get(int(key), float("-inf")))
            for key in ranked[: int(beam_size)]
        )
        retained_fraction = (
            float(math.exp(float(primary_log_mass) - float(all_log_mass)))
            if math.isfinite(float(all_log_mass)) and math.isfinite(float(primary_log_mass))
            else 1.0
        )
        if float(retained_fraction) >= float(tau):
            return [int(key) for key in ranked[: int(beam_size)]]
    if int(reserve_slots) <= 0:
        return [int(key) for key in ranked[: int(beam_size)]]
    reserve_slots = min(int(beam_size), int(reserve_slots))

    primary_count = max(0, int(beam_size) - int(reserve_slots))
    selected: list[int] = [int(key) for key in ranked[: int(primary_count)]]
    selected_set = {int(key) for key in selected}
    primary_rank_by_key = {int(key): int(index) for index, key in enumerate(ranked)}
    remaining = [int(key) for key in ranked if int(key) not in selected_set]
    cutoff_score = (
        float(rank_value_by_key.get(int(ranked[int(primary_count) - 1]), (float("-inf"), 0.0, 0.0))[0])
        if int(primary_count) > 0
        else float("inf")
    )
    prefix_ranked = sorted(
        remaining,
        key=lambda key: (
            float(prefix_log_mass_by_key.get(int(key), float("-inf"))),
            tuple(rank_value_by_key.get(int(key), (float("-inf"), float("-inf"), float("-inf")))),
            -int(primary_rank_by_key.get(int(key), 1 << 60)),
            -int(key),
        ),
        reverse=True,
    )
    for key in prefix_ranked:
        if int(key) in selected_set:
            continue
        rank_primary = float(rank_value_by_key.get(int(key), (float("-inf"), 0.0, 0.0))[0])
        cutoff_deficit = (
            max(0.0, float(cutoff_score) - float(rank_primary))
            if math.isfinite(float(cutoff_score)) and math.isfinite(float(rank_primary))
            else float("inf")
        )
        if str(mode_key) in {"fixed_guarded", "adaptive_mass_coverage"} and float(cutoff_deficit) > float(cutoff_deficit_limit):
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        if len(selected) >= int(beam_size):
            return selected

    for key in ranked:
        if int(key) in selected_set:
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        if len(selected) >= int(beam_size):
            break
    return selected


def _normalize_future_lane_mode(mode: str) -> str:
    key = str(mode).strip().lower()
    if key in {"", "none", "off"}:
        return "off"
    if key not in FUTURE_LANE_MODES:
        raise ValueError(f"future_lane_mode must be one of {sorted((*FUTURE_LANE_MODES, 'off'))}")
    return str(key)


def _normalize_future_lane_trigger(trigger: str) -> str:
    key = str(trigger).strip().lower()
    if key in {"", "none"}:
        key = "off"
    if key not in FUTURE_LANE_TRIGGERS:
        raise ValueError(f"future_lane_trigger must be one of {sorted(FUTURE_LANE_TRIGGERS)}")
    return str(key)


def _normalize_future_lane_score(score: str) -> str:
    key = str(score).strip().lower()
    if key in {"", "current", "current_future", "future_component"}:
        key = "primary_minus_prefix"
    if key not in FUTURE_LANE_SCORES:
        raise ValueError(f"future_lane_score must be one of {sorted(FUTURE_LANE_SCORES)}")
    return str(key)


def _future_lane_score_for_key(
    *,
    key: int,
    prefix_log_mass_by_key: Mapping[int, float],
    rank_value_by_key: Mapping[int, tuple[float, float, float]],
    future_lane_score_by_key: Mapping[int, float] | None = None,
) -> float:
    if future_lane_score_by_key is not None and int(key) in future_lane_score_by_key:
        return float(future_lane_score_by_key[int(key)])
    rank_primary = float(rank_value_by_key.get(int(key), (float("-inf"), 0.0, 0.0))[0])
    prefix_log_mass = float(prefix_log_mass_by_key.get(int(key), float("-inf")))
    if math.isfinite(float(rank_primary)) and math.isfinite(float(prefix_log_mass)):
        return float(rank_primary) - float(prefix_log_mass)
    return float("-inf")


def _future_lane_score_mode_is_raw(score_mode_key: str) -> bool:
    normalized = str(score_mode_key).strip().lower()
    return (
        normalized in {
            "future_parity_logmass_only",
            "future_parity_logodds_only",
            "deadline_weighted_future_parity_tau16",
            "z_deadline_weighted_future_parity_tau16",
            "residual_lex",
            "future_urgency_lex",
            "detector_sparsity_lex",
        }
        or _score_mode_is_no_prefix_survivor_lane(str(normalized))
        or _no_prefix_inner_score_mode(str(normalized)) is not None
    )


def _select_keys_future_lane_v1(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    prefix_log_mass_by_key: Mapping[int, float],
    rank_value_by_key: Mapping[int, tuple[float, float, float]],
    future_lane_score_by_key: Mapping[int, float] | None = None,
    future_lane_mode: str = "off",
    future_lane_slots: int = 0,
    future_lane_cutoff_deficit: float = float("inf"),
    future_lane_prefix_floor_nats: float = float("inf"),
    future_lane_prefix_rank_cap: int = 0,
    future_lane_trigger: str = "off",
    future_lane_future_top_m: int = 0,
    future_lane_missing_future_fraction: float = 0.0,
) -> list[int]:
    ranked = tuple(int(key) for key in tuple(ranked_keys))
    if int(beam_size) <= 0 or not ranked:
        return []
    if int(beam_size) >= len(ranked):
        return [int(key) for key in ranked]
    mode_key = _normalize_future_lane_mode(str(future_lane_mode))
    if str(mode_key) == "off" or int(future_lane_slots) <= 0:
        return [int(key) for key in ranked[: int(beam_size)]]
    trigger_key = _normalize_future_lane_trigger(str(future_lane_trigger))
    slots = min(int(beam_size), max(0, int(future_lane_slots)))
    cutoff_deficit_limit = float(future_lane_cutoff_deficit)
    if math.isnan(float(cutoff_deficit_limit)) or float(cutoff_deficit_limit) < 0.0:
        raise ValueError("future_lane_cutoff_deficit must be >= 0 or inf")
    prefix_floor_nats = float(future_lane_prefix_floor_nats)
    if math.isnan(float(prefix_floor_nats)) or float(prefix_floor_nats) < 0.0:
        raise ValueError("future_lane_prefix_floor_nats must be >= 0 or inf")
    prefix_rank_cap = int(future_lane_prefix_rank_cap)
    if int(prefix_rank_cap) < 0:
        raise ValueError("future_lane_prefix_rank_cap must be >= 0")
    future_top_m = int(future_lane_future_top_m)
    if int(future_top_m) < 0:
        raise ValueError("future_lane_future_top_m must be >= 0")
    missing_fraction_threshold = float(future_lane_missing_future_fraction)
    if (
        math.isnan(float(missing_fraction_threshold))
        or not math.isfinite(float(missing_fraction_threshold))
        or float(missing_fraction_threshold) < 0.0
        or float(missing_fraction_threshold) > 1.0
    ):
        raise ValueError("future_lane_missing_future_fraction must be finite and in [0, 1]")

    primary_topk = tuple(int(key) for key in ranked[: int(beam_size)])
    primary_topk_set = set(primary_topk)
    future_ranked = tuple(
        sorted(
            ranked,
            key=lambda key: (
                _future_lane_score_for_key(
                    key=int(key),
                    prefix_log_mass_by_key=prefix_log_mass_by_key,
                    rank_value_by_key=rank_value_by_key,
                    future_lane_score_by_key=future_lane_score_by_key,
                ),
                tuple(rank_value_by_key.get(int(key), (float("-inf"), float("-inf"), float("-inf")))),
                -int(key),
            ),
            reverse=True,
        )
    )
    if str(trigger_key) == "future_coverage":
        m = min(len(future_ranked), int(future_top_m))
        if int(m) <= 0:
            return [int(key) for key in primary_topk]
        missing = sum(1 for key in future_ranked[: int(m)] if int(key) not in primary_topk_set)
        missing_fraction = float(missing) / float(m)
        if float(missing_fraction) < float(missing_fraction_threshold):
            return [int(key) for key in primary_topk]
    elif str(trigger_key) == "candidate_pressure":
        if int(future_top_m) <= 0 or len(ranked) < int(future_top_m):
            return [int(key) for key in primary_topk]

    primary_count = max(0, int(beam_size) - int(slots))
    selected: list[int] = [int(key) for key in ranked[: int(primary_count)]]
    selected_set = {int(key) for key in selected}
    cutoff_score = (
        float(rank_value_by_key.get(int(ranked[int(primary_count) - 1]), (float("-inf"), 0.0, 0.0))[0])
        if int(primary_count) > 0
        else float("inf")
    )
    best_prefix_log_mass = max(
        (float(prefix_log_mass_by_key.get(int(key), float("-inf"))) for key in ranked),
        default=float("-inf"),
    )
    prefix_rank_by_key = {
        int(key): int(index)
        for index, key in enumerate(
            sorted(
                ranked,
                key=lambda item: (
                    float(prefix_log_mass_by_key.get(int(item), float("-inf"))),
                    tuple(rank_value_by_key.get(int(item), (float("-inf"), float("-inf"), float("-inf")))),
                    -int(item),
                ),
                reverse=True,
            ),
            start=1,
        )
    }
    for key in future_ranked:
        key_int = int(key)
        if key_int in selected_set:
            continue
        candidate_primary = float(rank_value_by_key.get(key_int, (float("-inf"), 0.0, 0.0))[0])
        cutoff_deficit = (
            max(0.0, float(cutoff_score) - float(candidate_primary))
            if math.isfinite(float(cutoff_score)) and math.isfinite(float(candidate_primary))
            else float("inf")
        )
        if float(cutoff_deficit) > float(cutoff_deficit_limit):
            continue
        candidate_prefix = float(prefix_log_mass_by_key.get(key_int, float("-inf")))
        prefix_rank = int(prefix_rank_by_key.get(key_int, 0))
        prefix_floor_ok = (
            math.isinf(float(prefix_floor_nats))
            or (
                math.isfinite(float(best_prefix_log_mass))
                and math.isfinite(float(candidate_prefix))
                and float(candidate_prefix) >= float(best_prefix_log_mass) - float(prefix_floor_nats)
            )
        )
        prefix_rank_ok = int(prefix_rank_cap) > 0 and int(prefix_rank) <= int(prefix_rank_cap)
        if not (bool(prefix_floor_ok) or bool(prefix_rank_ok)):
            continue
        selected.append(key_int)
        selected_set.add(key_int)
        if len(selected) >= int(beam_size):
            return selected

    for key in ranked:
        key_int = int(key)
        if key_int in selected_set:
            continue
        selected.append(key_int)
        selected_set.add(key_int)
        if len(selected) >= int(beam_size):
            break
    return selected


def _resolve_future_lane_slots(
    *,
    beam_size: int,
    future_lane_slots: int = 0,
    future_lane_fraction: float = 0.0,
) -> int:
    beam_limit = max(0, int(beam_size))
    if int(beam_limit) <= 0:
        return 0
    slot_count = int(future_lane_slots)
    fraction = float(future_lane_fraction)
    if int(slot_count) < 0:
        raise ValueError("future_lane_slots must be >= 0")
    if math.isnan(float(fraction)) or not math.isfinite(float(fraction)):
        raise ValueError("future_lane_fraction must be finite")
    if float(fraction) < 0.0 or float(fraction) > 1.0:
        raise ValueError("future_lane_fraction must be in [0, 1]")
    if int(slot_count) > 0 and float(fraction) > 0.0:
        raise ValueError("use future_lane_slots or future_lane_fraction, not both")
    if int(slot_count) <= 0 and float(fraction) > 0.0:
        slot_count = int(round(float(fraction) * float(beam_limit)))
    return min(int(beam_limit), max(0, int(slot_count)))


def _select_keys_no_prefix_future_lane_v1(
    *,
    ranked_keys: Sequence[int],
    candidate_keys: Sequence[int] | None = None,
    beam_size: int,
    prefix_log_mass_by_key: Mapping[int, float],
    primary_rank_value_by_key: Mapping[int, tuple[float, float, float]],
    future_lane_rank_value_by_key: Mapping[int, tuple[float, float, float]] | None = None,
    future_lane_slots: int = 0,
    future_lane_fraction: float = 0.0,
    boundary_column_index: int = -1,
    future_lane_score_mode: str = "future_parity_logodds",
    future_lane_mode: str = "fixed",
    future_lane_cutoff_deficit: float = float("inf"),
    future_lane_prefix_floor_nats: float = float("inf"),
    future_lane_prefix_rank_cap: int = 0,
    future_lane_trigger: str = "off",
    future_lane_future_top_m: int = 0,
    future_lane_missing_future_fraction: float = 0.0,
    phase_lanes_enabled: bool = False,
    phase_lane_schedule: str = "base_75_25_D8",
    phase_early_end: float = 0.33,
    phase_late_start: float = 0.80,
    total_column_count: int = 0,
) -> tuple[list[int], ProgressiveFutureLaneStep | None]:
    ranked = tuple(int(key) for key in ranked_keys)
    candidates_seq: Sequence[int] = candidate_keys if candidate_keys is not None else ranked
    candidate_count = len(candidates_seq)
    if int(beam_size) <= 0 or int(candidate_count) <= 0:
        return [], None
    if not ranked:
        ranked = tuple(
            heapq.nlargest(
                min(int(beam_size), int(candidate_count)),
                candidates_seq,
                key=lambda key: tuple(
                    primary_rank_value_by_key.get(
                        int(key),
                        (float("-inf"), float("-inf"), float("-inf")),
                    )
                ),
            )
        )
    if int(beam_size) >= int(candidate_count):
        return [int(key) for key in ranked[: int(beam_size)]], None
    mode_key = _normalize_future_lane_mode(str(future_lane_mode))
    trigger_key = _normalize_future_lane_trigger(str(future_lane_trigger))
    phase_label = ""
    processed_fraction = float("nan")
    primary_slots_requested = 0
    future_slots_requested = 0
    prefix_slots_requested = 0
    if bool(phase_lanes_enabled):
        total_columns = int(total_column_count)
        if int(total_columns) <= 0:
            total_columns = max(int(boundary_column_index) + 1, int(candidate_count))
        processed_count = max(0, int(boundary_column_index) + 1)
        processed_fraction = float(processed_count) / float(total_columns)
        phase_label = _phase_lane_label(
            processed_column_count=int(processed_count),
            total_column_count=int(total_columns),
            early_end=float(phase_early_end),
            late_start=float(phase_late_start),
        )
        mixture = _phase_lane_mixture_for_schedule(
            str(phase_lane_schedule),
            str(phase_label),
        )
        (
            primary_slots_requested,
            future_slots_requested,
            prefix_slots_requested,
        ) = _phase_lane_budgets(beam_size=int(beam_size), mixture=mixture)
        reserved_slots = int(future_slots_requested) + int(prefix_slots_requested)
    else:
        reserved_slots = _resolve_future_lane_slots(
        beam_size=int(beam_size),
        future_lane_slots=int(future_lane_slots),
        future_lane_fraction=float(future_lane_fraction),
        )
        future_slots_requested = int(reserved_slots)
        primary_slots_requested = max(0, int(beam_size) - int(reserved_slots))
        prefix_slots_requested = 0
    if str(mode_key) == "off" or int(reserved_slots) <= 0:
        return [int(key) for key in ranked[: int(beam_size)]], None
    cutoff_deficit_limit = float(future_lane_cutoff_deficit)
    if math.isnan(float(cutoff_deficit_limit)) or float(cutoff_deficit_limit) < 0.0:
        raise ValueError("future_lane_cutoff_deficit must be >= 0 or inf")
    prefix_floor_nats = float(future_lane_prefix_floor_nats)
    if math.isnan(float(prefix_floor_nats)) or float(prefix_floor_nats) < 0.0:
        raise ValueError("future_lane_prefix_floor_nats must be >= 0 or inf")
    prefix_rank_cap = int(future_lane_prefix_rank_cap)
    if int(prefix_rank_cap) < 0:
        raise ValueError("future_lane_prefix_rank_cap must be >= 0")
    future_top_m = int(future_lane_future_top_m)
    if int(future_top_m) < 0:
        raise ValueError("future_lane_future_top_m must be >= 0")
    missing_fraction_threshold = float(future_lane_missing_future_fraction)
    if (
        math.isnan(float(missing_fraction_threshold))
        or not math.isfinite(float(missing_fraction_threshold))
        or float(missing_fraction_threshold) < 0.0
        or float(missing_fraction_threshold) > 1.0
    ):
        raise ValueError("future_lane_missing_future_fraction must be finite and in [0, 1]")
    reserved_slots = min(int(reserved_slots), int(beam_size))
    primary_count = (
        max(0, int(primary_slots_requested))
        if bool(phase_lanes_enabled)
        else max(0, int(beam_size) - int(reserved_slots))
    )
    primary_keys = [int(key) for key in ranked[: int(primary_count)]]
    primary_set = {int(key) for key in primary_keys}
    ordinary_topk = tuple(int(key) for key in ranked[: int(beam_size)])
    ordinary_topk_set = set(int(key) for key in ordinary_topk)
    primary_rank_by_key = {int(key): int(rank) for rank, key in enumerate(ranked, start=1)}

    def _future_lane_value(key: int) -> tuple[float, float, float]:
        key_int = int(key)
        if future_lane_rank_value_by_key is not None:
            return tuple(
                future_lane_rank_value_by_key.get(
                    key_int,
                    (float("-inf"), float("-inf"), float("-inf")),
                )
            )
        primary_tuple = tuple(
            primary_rank_value_by_key.get(
                key_int,
                (float("-inf"), float("-inf"), float("-inf")),
            )
        )
        primary_score = float(primary_tuple[0]) if primary_tuple else float("-inf")
        prefix_log_mass = float(prefix_log_mass_by_key.get(key_int, float("-inf")))
        if _future_lane_score_mode_is_raw(str(future_lane_score_mode)):
            future_score = float(primary_score)
        else:
            future_score = (
                float(primary_score) - float(prefix_log_mass)
                if math.isfinite(float(primary_score)) and math.isfinite(float(prefix_log_mass))
                else float("-inf")
            )
        return (
            float(future_score),
            float(primary_score),
            float(prefix_log_mass),
        )

    def _future_sort_key(key: int) -> tuple[float, tuple[float, float, float], int, int]:
        key_int = int(key)
        return (
            float(_future_lane_value(key_int)[0]),
            tuple(primary_rank_value_by_key.get(key_int, (float("-inf"), float("-inf"), float("-inf")))),
            -int(primary_rank_by_key.get(key_int, 1 << 60)),
            -key_int,
        )

    def _prefix_sort_key(key: int) -> tuple[float, tuple[float, float, float], int]:
        key_int = int(key)
        return (
            float(prefix_log_mass_by_key.get(key_int, float("-inf"))),
            tuple(primary_rank_value_by_key.get(key_int, (float("-inf"), float("-inf"), float("-inf")))),
            -key_int,
        )

    def _rank_by_key(
        key: int,
        keys: Sequence[int],
        sort_key,
    ) -> int:
        target = sort_key(int(key))
        return 1 + sum(1 for other in keys if sort_key(int(other)) > target)

    triggered = True
    future_top_m_actual = 0
    missing_fraction = float("nan")
    if str(trigger_key) == "future_coverage":
        m = min(int(candidate_count), int(future_top_m))
        future_top_m_actual = int(m)
        if int(m) <= 0:
            triggered = False
        else:
            future_top = heapq.nlargest(int(m), candidates_seq, key=_future_sort_key)
            missing = sum(1 for key in future_top if int(key) not in ordinary_topk_set)
            missing_fraction = float(missing) / float(m)
            triggered = bool(float(missing_fraction) >= float(missing_fraction_threshold))
    elif str(trigger_key) == "candidate_pressure":
        future_top_m_actual = int(future_top_m)
        triggered = bool(int(future_top_m) > 0 and int(candidate_count) >= int(future_top_m))
    if not bool(triggered):
        return [int(key) for key in ordinary_topk], ProgressiveFutureLaneStep(
            processed_columns=int(boundary_column_index) + 1,
            boundary_column_index=int(boundary_column_index),
            mode=str(mode_key),
            future_lane_score_mode=str(future_lane_score_mode),
            beam_size=int(beam_size),
            candidate_count=int(candidate_count),
            primary_count=int(beam_size),
            requested_slots=int(reserved_slots),
            slots_used=0,
            overlap_with_primary=0,
            unique_states=0,
            final_kept_count=int(beam_size),
            primary_cutoff_score=float(
                primary_rank_value_by_key.get(int(ranked[int(beam_size) - 1]), (float("-inf"),))[0]
            ),
            changed_live_set=False,
            selected_candidates=tuple(),
            triggered=False,
            future_top_m=int(future_top_m_actual),
            missing_future_fraction=float(missing_fraction),
        )
    primary_cutoff_score = (
        float(primary_rank_value_by_key.get(int(ranked[int(primary_count) - 1]), (float("-inf"),))[0])
        if int(primary_count) > 0
        else float("inf")
    )
    best_prefix_log_mass = max(
        (float(prefix_log_mass_by_key.get(int(key), float("-inf"))) for key in candidates_seq),
        default=float("-inf"),
    )
    considered = 0
    rejected_cutoff = 0
    rejected_prefix = 0
    rejected_both = 0
    prefix_top_set: set[int] = set()
    if str(mode_key) == "guarded" and int(prefix_rank_cap) > 0:
        prefix_top_set = {
            int(key)
            for key in heapq.nlargest(
                min(int(prefix_rank_cap), int(candidate_count)),
                candidates_seq,
                key=_prefix_sort_key,
            )
        }
    future_heap: list[tuple[tuple[float, tuple[float, float, float], int, int], int]] = []
    if int(future_slots_requested) > 0:
        for key in candidates_seq:
            key_int = int(key)
            if key_int in primary_set:
                continue
            considered += 1
            if str(mode_key) == "guarded":
                candidate_primary = float(primary_rank_value_by_key.get(int(key_int), (float("-inf"),))[0])
                cutoff_deficit = (
                    max(0.0, float(primary_cutoff_score) - float(candidate_primary))
                    if math.isfinite(float(primary_cutoff_score)) and math.isfinite(float(candidate_primary))
                    else float("inf")
                )
                cutoff_ok = bool(float(cutoff_deficit) <= float(cutoff_deficit_limit))
                candidate_prefix = float(prefix_log_mass_by_key.get(int(key_int), float("-inf")))
                prefix_floor_ok = (
                    math.isinf(float(prefix_floor_nats))
                    or (
                        math.isfinite(float(best_prefix_log_mass))
                        and math.isfinite(float(candidate_prefix))
                        and float(candidate_prefix) >= float(best_prefix_log_mass) - float(prefix_floor_nats)
                    )
                )
                prefix_rank_ok = int(prefix_rank_cap) > 0 and int(key_int) in prefix_top_set
                prefix_ok = bool(prefix_floor_ok) or bool(prefix_rank_ok)
                if not bool(cutoff_ok) or not bool(prefix_ok):
                    rejected_cutoff += int(not bool(cutoff_ok))
                    rejected_prefix += int(not bool(prefix_ok))
                    rejected_both += int((not bool(cutoff_ok)) and (not bool(prefix_ok)))
                    continue
            sort_key = _future_sort_key(int(key_int))
            heap_entry = (sort_key, int(key_int))
            if len(future_heap) < int(future_slots_requested):
                heapq.heappush(future_heap, heap_entry)
            elif sort_key > future_heap[0][0]:
                heapq.heapreplace(future_heap, heap_entry)
    future_candidates = [
        int(key)
        for _sort_key, key in sorted(future_heap, key=lambda item: item[0], reverse=True)
    ]
    future_candidate_position_by_key = {
        int(key): int(index)
        for index, key in enumerate(future_candidates, start=1)
    }
    future_keys = list(future_candidates)
    prefix_slots = int(prefix_slots_requested)
    prefix_keys: list[int] = []
    if int(prefix_slots) > 0:
        prefix_keys = [
            int(key)
            for key in heapq.nlargest(
                min(int(prefix_slots), int(candidate_count)),
                candidates_seq,
                key=_prefix_sort_key,
            )
        ]
    selected: list[int] = []
    selected_set: set[int] = set()
    for key in (*primary_keys, *future_keys, *prefix_keys):
        key_int = int(key)
        if key_int in selected_set:
            continue
        selected.append(key_int)
        selected_set.add(key_int)
    for key in ranked:
        key_int = int(key)
        if len(selected) >= int(beam_size):
            break
        if key_int in selected_set:
            continue
        selected.append(key_int)
        selected_set.add(key_int)
    selected = selected[: int(beam_size)]
    selected_set = set(int(key) for key in selected)
    candidate_rows: list[ProgressiveFutureLaneCandidate] = []
    for key in future_keys:
        key_int = int(key)
        primary_score = float(primary_rank_value_by_key.get(int(key_int), (float("-inf"),))[0])
        future_score = float(_future_lane_value(int(key_int))[0])
        prefix_log_mass = float(prefix_log_mass_by_key.get(int(key_int), float("-inf")))
        primary_cutoff_deficit = (
            max(0.0, float(primary_cutoff_score) - float(primary_score))
            if math.isfinite(float(primary_cutoff_score)) and math.isfinite(float(primary_score))
            else float("inf")
        )
        candidate_rows.append(
            ProgressiveFutureLaneCandidate(
                state_key=int(key_int),
                primary_score=float(primary_score),
                future_lane_score=float(future_score),
                prefix_log_mass=float(prefix_log_mass),
                primary_rank=int(primary_rank_by_key.get(int(key_int), 0)),
                future_rank=(
                    int(_rank_by_key(int(key_int), candidates_seq, _future_sort_key))
                    if str(mode_key) == "guarded"
                    else int(future_candidate_position_by_key.get(int(key_int), 0))
                ),
                prefix_rank=(
                    int(_rank_by_key(int(key_int), candidates_seq, _prefix_sort_key))
                    if str(mode_key) == "guarded"
                    else 0
                ),
                primary_cutoff_deficit=float(primary_cutoff_deficit),
                in_ordinary_primary_topk=bool(int(key_int) in ordinary_topk_set),
            )
        )
    final_set = set(int(key) for key in selected)
    changed_live_set = bool(final_set != ordinary_topk_set)
    primary_selected_set = set(int(key) for key in primary_keys)
    future_selected_set = set(int(key) for key in future_keys)
    prefix_selected_set = set(int(key) for key in prefix_keys)
    step = ProgressiveFutureLaneStep(
        processed_columns=int(boundary_column_index) + 1,
        boundary_column_index=int(boundary_column_index),
        mode=str(mode_key),
        future_lane_score_mode=str(future_lane_score_mode),
        beam_size=int(beam_size),
        candidate_count=int(candidate_count),
        primary_count=int(primary_count),
        requested_slots=int(reserved_slots),
        slots_used=int(len(future_keys)),
        overlap_with_primary=int(sum(1 for key in future_keys if int(key) in ordinary_topk_set)),
        unique_states=int(sum(1 for key in future_keys if int(key) not in ordinary_topk_set)),
        final_kept_count=int(len(selected)),
        primary_cutoff_score=float(primary_cutoff_score),
        changed_live_set=bool(changed_live_set),
        selected_candidates=tuple(candidate_rows),
        triggered=True,
        future_top_m=int(future_top_m_actual),
        missing_future_fraction=float(missing_fraction),
        candidate_considered_count=int(considered),
        rejected_cutoff_deficit_count=int(rejected_cutoff),
        rejected_prefix_guard_count=int(rejected_prefix),
        rejected_both_guards_count=int(rejected_both),
        phase_lane_enabled=bool(phase_lanes_enabled),
        phase_lane_schedule=str(phase_lane_schedule) if bool(phase_lanes_enabled) else "",
        phase_label=str(phase_label),
        processed_fraction=float(processed_fraction),
        primary_slots_requested=int(primary_slots_requested),
        primary_slots_used=int(len(primary_keys)),
        future_slots_requested=int(future_slots_requested),
        future_slots_used=int(len(future_keys)),
        prefix_slots_requested=int(prefix_slots_requested),
        prefix_slots_used=int(len(prefix_keys)),
        unique_prefix_states=int(
            sum(
                1
                for key in prefix_keys
                if int(key) not in primary_selected_set and int(key) not in future_selected_set
            )
        ),
        overlap_primary_future=int(len(primary_selected_set & future_selected_set)),
        overlap_primary_prefix=int(len(primary_selected_set & prefix_selected_set)),
        overlap_future_prefix=int(len(future_selected_set & prefix_selected_set)),
    )
    return selected, step


def _normalize_anti_collapse_trigger_policy(policy: str) -> str:
    key = str(policy).strip().lower()
    if key not in ANTI_COLLAPSE_TRIGGER_POLICIES:
        raise ValueError(
            "anti_collapse_trigger_policy must be one of "
            f"{sorted(ANTI_COLLAPSE_TRIGGER_POLICIES)}"
        )
    return str(key)


def _normalize_anti_collapse_signature_mode(mode: str) -> str:
    key = str(mode).strip().lower()
    if key not in ANTI_COLLAPSE_SIGNATURE_MODES:
        raise ValueError(
            "anti_collapse_signature_mode must be one of "
            f"{sorted(ANTI_COLLAPSE_SIGNATURE_MODES)}"
        )
    return str(key)


def _anti_collapse_effective_signature_mode(
    *,
    requested_mode: str,
    num_observables: int,
) -> str:
    requested = _normalize_anti_collapse_signature_mode(str(requested_mode))
    if requested == "hybrid":
        return "active_mask_logical" if int(num_observables) > 0 else "active_mask_band"
    if requested == "active_mask_logical" and int(num_observables) <= 0:
        return "active_mask"
    return str(requested)


def _fixed_width_unsigned_bytes(value: int, minimum_byte_count: int) -> bytes:
    value_int = max(0, int(value))
    byte_count = max(1, int(minimum_byte_count), (int(value_int).bit_length() + 7) // 8)
    return int(value_int).to_bytes(int(byte_count), "little", signed=False)


def _anti_collapse_band_profile_bytes(
    *,
    active_detector_mask: int,
    num_detectors: int,
) -> bytes:
    detector_count = max(0, int(num_detectors))
    if int(detector_count) <= 0:
        return b""
    band_count = min(8, max(1, int(detector_count)))
    parts: list[bytes] = []
    for band_index in range(int(band_count)):
        start = (int(detector_count) * int(band_index)) // int(band_count)
        stop = (int(detector_count) * (int(band_index) + 1)) // int(band_count)
        width = max(0, int(stop) - int(start))
        if int(width) <= 0:
            count = 0
        else:
            band_mask = ((1 << int(width)) - 1) << int(start)
            count = int((int(active_detector_mask) & int(band_mask)).bit_count())
        parts.append(int(count).to_bytes(2, "little", signed=False))
        parts.append(bytes((int(count) & 1,)))
    return b"".join(parts)


def _anti_collapse_signature_for_state(
    *,
    state_key: int,
    detector_mask_mask: int,
    active_mask: int,
    num_detectors: int,
    num_observables: int,
    signature_mode: str,
) -> str:
    effective_mode = _anti_collapse_effective_signature_mode(
        requested_mode=str(signature_mode),
        num_observables=int(num_observables),
    )
    detector_byte_count = max(1, (max(0, int(num_detectors)) + 7) // 8)
    logical_byte_count = max(1, (max(0, int(num_observables)) + 7) // 8)
    detector_mask = _unpack_detector_mask(
        state_key=int(state_key),
        detector_mask_mask=int(detector_mask_mask),
    )
    active_detector_mask = int(detector_mask) & int(active_mask)
    payload = bytearray()
    payload.extend(str(effective_mode).encode("ascii"))
    payload.extend(b"\0")
    payload.extend(int(num_detectors).to_bytes(4, "little", signed=False))
    payload.extend(_fixed_width_unsigned_bytes(int(active_detector_mask), int(detector_byte_count)))
    if str(effective_mode) == "active_mask_logical":
        payload.extend(b"\1")
        payload.extend(int(num_observables).to_bytes(4, "little", signed=False))
        logical_mask = _unpack_logical_mask(
            state_key=int(state_key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        payload.extend(_fixed_width_unsigned_bytes(int(logical_mask), int(logical_byte_count)))
    elif str(effective_mode) == "active_mask_band":
        payload.extend(b"\2")
        payload.extend(
            _anti_collapse_band_profile_bytes(
                active_detector_mask=int(active_detector_mask),
                num_detectors=int(num_detectors),
            )
        )
    return hashlib.blake2b(bytes(payload), digest_size=8).hexdigest()


def _anti_collapse_signature_counts(
    *,
    keys: Sequence[int],
    signature_by_key: Mapping[int, str],
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for key in keys:
        signature = str(signature_by_key[int(key)])
        counts[str(signature)] = int(counts.get(str(signature), 0)) + 1
    return counts


def _anti_collapse_top_signature_share(counts: Mapping[str, int], total_count: int) -> float:
    if int(total_count) <= 0 or not counts:
        return float("nan")
    return float(max(int(value) for value in counts.values())) / float(total_count)


def _anti_collapse_compact_signature_counts(
    counts: Mapping[str, int],
    *,
    max_signature_buckets: int,
) -> tuple[tuple[str, int], ...]:
    limit = max(1, int(max_signature_buckets))
    return tuple(
        (str(signature), int(count))
        for signature, count in sorted(
            counts.items(),
            key=lambda item: (-int(item[1]), str(item[0])),
        )[: int(limit)]
    )


def _select_keys_anti_collapse_v1(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    rank_value_by_key: Mapping[int, tuple[float, float, float]],
    detector_mask_mask: int,
    active_mask: int,
    num_detectors: int,
    num_observables: int,
    anti_collapse_reserve_fraction: float,
    anti_collapse_trigger_policy: str,
    anti_collapse_cutoff_gap_threshold: float,
    anti_collapse_top_signature_share_threshold: float,
    anti_collapse_overflow_ratio_threshold: float,
    anti_collapse_signature_mode: str,
    anti_collapse_repulsion_eta: float,
    anti_collapse_max_signature_buckets: int,
    boundary_column_index: int = -1,
) -> tuple[list[int], ProgressiveAntiCollapseStep]:
    ranked = tuple(int(key) for key in ranked_keys)
    beam_limit = int(beam_size)
    requested_mode = _normalize_anti_collapse_signature_mode(str(anti_collapse_signature_mode))
    effective_mode = _anti_collapse_effective_signature_mode(
        requested_mode=str(requested_mode),
        num_observables=int(num_observables),
    )
    trigger_policy = _normalize_anti_collapse_trigger_policy(str(anti_collapse_trigger_policy))
    if int(beam_limit) <= 0 or not ranked:
        empty_step = ProgressiveAntiCollapseStep(
            processed_columns=int(boundary_column_index) + 1,
            boundary_column_index=int(boundary_column_index),
            beam_size=max(0, int(beam_limit)),
            candidate_count=int(len(ranked)),
            ordinary_kept_count=0,
            final_kept_count=0,
            policy="anti_collapse_v1",
            triggered=False,
            trigger_reasons="",
            cutoff_gap=float("nan"),
            overflow_ratio=float("nan"),
            ordinary_top_signature_share=float("nan"),
            final_top_signature_share=float("nan"),
            reserve_fraction=float(anti_collapse_reserve_fraction),
            reserve_count=0,
            anchor_count=0,
            signature_mode_requested=str(requested_mode),
            signature_mode_effective=str(effective_mode),
            ordinary_distinct_signature_count=0,
            final_distinct_signature_count=0,
            reserve_pick_count=0,
            states_not_in_ordinary_topk_count=0,
            ordinary_signature_counts=tuple(),
            final_signature_counts=tuple(),
        )
        return [], empty_step

    reserve_fraction = float(anti_collapse_reserve_fraction)
    if math.isnan(float(reserve_fraction)) or not math.isfinite(float(reserve_fraction)):
        raise ValueError("anti_collapse_reserve_fraction must be finite")
    if float(reserve_fraction) < 0.0 or float(reserve_fraction) > 0.5:
        raise ValueError("anti_collapse_reserve_fraction must be in [0, 0.5]")
    cutoff_threshold = float(anti_collapse_cutoff_gap_threshold)
    if math.isnan(float(cutoff_threshold)) or not math.isfinite(float(cutoff_threshold)) or float(cutoff_threshold) < 0.0:
        raise ValueError("anti_collapse_cutoff_gap_threshold must be finite and >= 0")
    top_share_threshold = float(anti_collapse_top_signature_share_threshold)
    if (
        math.isnan(float(top_share_threshold))
        or not math.isfinite(float(top_share_threshold))
        or float(top_share_threshold) < 0.0
        or float(top_share_threshold) > 1.0
    ):
        raise ValueError("anti_collapse_top_signature_share_threshold must be in [0, 1]")
    overflow_threshold = float(anti_collapse_overflow_ratio_threshold)
    if math.isnan(float(overflow_threshold)) or not math.isfinite(float(overflow_threshold)) or float(overflow_threshold) < 0.0:
        raise ValueError("anti_collapse_overflow_ratio_threshold must be finite and >= 0")
    repulsion_eta = float(anti_collapse_repulsion_eta)
    if math.isnan(float(repulsion_eta)) or not math.isfinite(float(repulsion_eta)) or float(repulsion_eta) < 0.0:
        raise ValueError("anti_collapse_repulsion_eta must be finite and >= 0")
    max_signature_buckets = int(anti_collapse_max_signature_buckets)
    if int(max_signature_buckets) < 1:
        raise ValueError("anti_collapse_max_signature_buckets must be >= 1")

    target_count = min(int(beam_limit), len(ranked))
    ordinary_topk = tuple(int(key) for key in ranked[: int(target_count)])
    signature_by_key = {
        int(key): _anti_collapse_signature_for_state(
            state_key=int(key),
            detector_mask_mask=int(detector_mask_mask),
            active_mask=int(active_mask),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
            signature_mode=str(effective_mode),
        )
        for key in ranked
    }
    ordinary_counts = _anti_collapse_signature_counts(
        keys=ordinary_topk,
        signature_by_key=signature_by_key,
    )
    ordinary_top_share = _anti_collapse_top_signature_share(
        ordinary_counts,
        int(len(ordinary_topk)),
    )
    cutoff_gap = float("nan")
    cutoff_gap_trigger = False
    if int(beam_limit) > 0 and len(ranked) >= int(beam_limit) + 1:
        cutoff_key = int(ranked[int(beam_limit) - 1])
        overflow_key = int(ranked[int(beam_limit)])
        cutoff_gap = float(rank_value_by_key[int(cutoff_key)][0]) - float(
            rank_value_by_key[int(overflow_key)][0]
        )
        cutoff_gap_trigger = bool(
            math.isfinite(float(cutoff_gap)) and float(cutoff_gap) <= float(cutoff_threshold)
        )
    collapse_trigger = bool(
        len(ordinary_topk) > 0
        and math.isfinite(float(ordinary_top_share))
        and float(ordinary_top_share) >= float(top_share_threshold)
    )
    overflow_ratio = (
        float(len(ranked)) / float(beam_limit)
        if int(beam_limit) > 0
        else float("nan")
    )
    overflow_trigger = bool(
        math.isfinite(float(overflow_ratio)) and float(overflow_ratio) >= float(overflow_threshold)
    )
    trigger_reasons: list[str] = []
    if str(trigger_policy) == "always":
        trigger_reasons.append("always")
    elif str(trigger_policy) == "cutoff_gap":
        if bool(cutoff_gap_trigger):
            trigger_reasons.append("cutoff_gap")
    elif str(trigger_policy) == "collapse":
        if bool(collapse_trigger):
            trigger_reasons.append("collapse")
    elif str(trigger_policy) == "risk_union":
        if bool(cutoff_gap_trigger):
            trigger_reasons.append("cutoff_gap")
        if bool(collapse_trigger):
            trigger_reasons.append("collapse")
        if bool(overflow_trigger):
            trigger_reasons.append("overflow_ratio")
    else:
        raise AssertionError(f"unhandled anti-collapse trigger policy {trigger_policy!r}")
    triggered = bool(trigger_reasons)

    reserve_count = 0
    anchor_count = int(target_count)
    selected: list[int]
    if not bool(triggered):
        selected = [int(key) for key in ordinary_topk]
    else:
        if int(target_count) >= 2:
            reserve_count = min(
                int(target_count) - 1,
                max(1, int(math.ceil(float(beam_limit) * float(reserve_fraction)))),
            )
        anchor_count = max(0, int(target_count) - int(reserve_count))
        selected = [int(key) for key in ranked[: int(anchor_count)]]
        selected_set = {int(key) for key in selected}
        signature_counts = _anti_collapse_signature_counts(
            keys=tuple(int(key) for key in selected),
            signature_by_key=signature_by_key,
        )
        rank_index_by_key = {int(key): int(index) for index, key in enumerate(ranked)}
        remaining = [int(key) for key in ranked[int(anchor_count):] if int(key) not in selected_set]
        while len(selected) < int(target_count) and remaining:
            best_index = min(
                range(len(remaining)),
                key=lambda index: (
                    int(signature_counts.get(str(signature_by_key[int(remaining[int(index)])]), 0)),
                    int(rank_index_by_key[int(remaining[int(index)])]),
                    int(remaining[int(index)]),
                ),
            )
            key = int(remaining.pop(int(best_index)))
            selected.append(int(key))
            selected_set.add(int(key))
            signature = str(signature_by_key[int(key)])
            signature_counts[str(signature)] = int(signature_counts.get(str(signature), 0)) + 1
        if len(selected) < int(target_count):
            for key in ranked:
                if int(key) in selected_set:
                    continue
                selected.append(int(key))
                selected_set.add(int(key))
                if len(selected) >= int(target_count):
                    break

    selected = [int(key) for key in selected[: int(target_count)]]
    final_counts = _anti_collapse_signature_counts(
        keys=tuple(int(key) for key in selected),
        signature_by_key=signature_by_key,
    )
    final_top_share = _anti_collapse_top_signature_share(final_counts, int(len(selected)))
    ordinary_topk_set = {int(key) for key in ordinary_topk}
    step = ProgressiveAntiCollapseStep(
        processed_columns=int(boundary_column_index) + 1,
        boundary_column_index=int(boundary_column_index),
        beam_size=int(beam_limit),
        candidate_count=int(len(ranked)),
        ordinary_kept_count=int(len(ordinary_topk)),
        final_kept_count=int(len(selected)),
        policy="anti_collapse_v1",
        triggered=bool(triggered),
        trigger_reasons="+".join(dict.fromkeys(str(reason) for reason in trigger_reasons)),
        cutoff_gap=float(cutoff_gap),
        overflow_ratio=float(overflow_ratio),
        ordinary_top_signature_share=float(ordinary_top_share),
        final_top_signature_share=float(final_top_share),
        reserve_fraction=float(reserve_fraction),
        reserve_count=int(reserve_count),
        anchor_count=int(anchor_count),
        signature_mode_requested=str(requested_mode),
        signature_mode_effective=str(effective_mode),
        ordinary_distinct_signature_count=int(len(ordinary_counts)),
        final_distinct_signature_count=int(len(final_counts)),
        reserve_pick_count=max(0, int(len(selected)) - int(anchor_count)) if bool(triggered) else 0,
        states_not_in_ordinary_topk_count=sum(1 for key in selected if int(key) not in ordinary_topk_set),
        ordinary_signature_counts=_anti_collapse_compact_signature_counts(
            ordinary_counts,
            max_signature_buckets=int(max_signature_buckets),
        ),
        final_signature_counts=_anti_collapse_compact_signature_counts(
            final_counts,
            max_signature_buckets=int(max_signature_buckets),
        ),
    )
    return selected, step


def _bucketed_retention_step_counts(
    *,
    ranked_keys: Sequence[int],
    kept_keys: Sequence[int],
    bucketed_retention_key: str,
    detector_mask_mask: int,
) -> tuple[tuple[str, str, int, int], ...]:
    bucket_key = _normalize_bucketed_retention_key(str(bucketed_retention_key))
    kept_set = {int(key) for key in kept_keys}
    counts: dict[str, list[int]] = {}
    for key in ranked_keys:
        bucket_value = _bucketed_retention_bucket_value_for_state(
            state_key=int(key),
            bucket_key=str(bucket_key),
            detector_mask_mask=int(detector_mask_mask),
        )
        bucket_counts = counts.setdefault(str(bucket_value), [0, 0])
        bucket_counts[0] += 1
        if int(key) in kept_set:
            bucket_counts[1] += 1
    return tuple(
        (str(bucket_key), str(bucket_value), int(values[0]), int(values[1]))
        for bucket_value, values in sorted(
            counts.items(),
            key=lambda item: (
                0,
                int(item[0]),
            )
            if str(item[0]).isdigit()
            else (
                1,
                str(item[0]),
            ),
        )
    )


def _bucketed_retention_bucket_summaries_from_accumulator(
    accumulator: dict[tuple[str, str], dict[str, int]],
) -> tuple[BucketedRetentionBucketSummary, ...]:
    out: list[BucketedRetentionBucketSummary] = []
    for (bucket_key, bucket_value), values in sorted(
        accumulator.items(),
        key=lambda item: (
            str(item[0][0]),
            0,
            int(item[0][1]),
        )
        if str(item[0][1]).isdigit()
        else (
            str(item[0][0]),
            1,
            str(item[0][1]),
        ),
    ):
        out.append(
            BucketedRetentionBucketSummary(
                bucket_key=str(bucket_key),
                bucket_value=str(bucket_value),
                candidate_step_count=int(values.get("candidate_step_count", 0)),
                retained_step_count=int(values.get("retained_step_count", 0)),
                candidate_state_total=int(values.get("candidate_state_total", 0)),
                retained_state_total=int(values.get("retained_state_total", 0)),
                candidate_state_max=int(values.get("candidate_state_max", 0)),
                retained_state_max=int(values.get("retained_state_max", 0)),
                last_candidate_state_count=int(values.get("last_candidate_state_count", 0)),
                last_retained_state_count=int(values.get("last_retained_state_count", 0)),
            )
        )
    return tuple(out)


def _select_keys_logical_class_quota(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    num_detectors: int,
    num_observables: int = 1,
    top_classes: int,
    reserved_slots: int,
) -> tuple[list[int], int]:
    if int(beam_size) <= 0 or not ranked_keys:
        return [], 0
    target_quota = min(
        int(beam_size),
        max(0, int(top_classes)),
        max(0, int(reserved_slots)),
    )
    if int(target_quota) <= 1:
        return list(int(key) for key in ranked_keys[: int(beam_size)]), 0

    quota_selected: list[int] = []
    seen_classes: set[int] = set()
    for key in ranked_keys:
        logical_mask = _unpack_logical_mask(
            state_key=int(key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        if int(logical_mask) in seen_classes:
            continue
        quota_selected.append(int(key))
        seen_classes.add(int(logical_mask))
        if len(quota_selected) >= int(target_quota):
            break

    if len(quota_selected) <= 1:
        return list(int(key) for key in ranked_keys[: int(beam_size)]), 0

    selected = list(int(key) for key in quota_selected)
    if len(selected) >= int(beam_size):
        return list(int(key) for key in selected[: int(beam_size)]), int(len(selected[: int(beam_size)]))
    selected_set = set(int(key) for key in selected)
    for key in ranked_keys:
        if int(key) in selected_set:
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        if len(selected) >= int(beam_size):
            break
    return selected, int(len(quota_selected))


def _select_keys_lineage_reserve(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    reserved_slots: int,
    lineage_origin_masks_by_key: dict[int, int] | None,
) -> tuple[list[int], int]:
    if int(beam_size) <= 0 or not ranked_keys:
        return [], 0
    if int(reserved_slots) <= 0 or not lineage_origin_masks_by_key:
        return [int(key) for key in ranked_keys[: int(beam_size)]], 0

    safe_count = max(0, int(beam_size) - int(reserved_slots))
    selected = [int(key) for key in ranked_keys[: int(safe_count)]]
    selected_set = {int(key) for key in selected}
    represented_origins = 0
    for key in selected:
        represented_origins |= int(lineage_origin_masks_by_key.get(int(key), 0))

    reserved_count = 0
    for key in ranked_keys[int(safe_count):]:
        if int(key) in selected_set:
            continue
        lineage_mask = int(lineage_origin_masks_by_key.get(int(key), 0))
        if int(lineage_mask) == 0:
            continue
        if (int(lineage_mask) & ~int(represented_origins)) == 0:
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        represented_origins |= int(lineage_mask)
        reserved_count += 1
        if len(selected) >= int(beam_size):
            return selected, int(reserved_count)

    for key in ranked_keys:
        if int(key) in selected_set:
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        if len(selected) >= int(beam_size):
            break
    return selected, int(reserved_count)


def _select_keys_lineage_branch_reserve(
    *,
    ranked_keys: Sequence[int],
    beam_size: int,
    reserved_slots: int,
    lineage_origin_masks_by_key: dict[int, int] | None,
    branch_slots_per_origin: int,
) -> tuple[list[int], int]:
    if int(beam_size) <= 0 or not ranked_keys:
        return [], 0
    if (
        int(reserved_slots) <= 0
        or int(branch_slots_per_origin) <= 0
        or not lineage_origin_masks_by_key
    ):
        return [int(key) for key in ranked_keys[: int(beam_size)]], 0

    safe_count = max(0, int(beam_size) - int(reserved_slots))
    selected = [int(key) for key in ranked_keys[: int(safe_count)]]
    selected_set = {int(key) for key in selected}
    origin_counts: dict[int, int] = {}

    def _add_origin_counts(origin_mask: int) -> None:
        bitset = int(origin_mask)
        while int(bitset) != 0:
            low_bit = int(bitset) & -int(bitset)
            origin_index = int(low_bit.bit_length() - 1)
            origin_counts[int(origin_index)] = int(origin_counts.get(int(origin_index), 0)) + 1
            bitset ^= int(low_bit)

    for key in selected:
        _add_origin_counts(int(lineage_origin_masks_by_key.get(int(key), 0)))

    reserved_count = 0
    for key in ranked_keys[int(safe_count):]:
        if int(key) in selected_set:
            continue
        lineage_mask = int(lineage_origin_masks_by_key.get(int(key), 0))
        if int(lineage_mask) == 0:
            continue
        bitset = int(lineage_mask)
        eligible = False
        while int(bitset) != 0:
            low_bit = int(bitset) & -int(bitset)
            origin_index = int(low_bit.bit_length() - 1)
            if int(origin_counts.get(int(origin_index), 0)) < int(branch_slots_per_origin):
                eligible = True
                break
            bitset ^= int(low_bit)
        if not bool(eligible):
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        _add_origin_counts(int(lineage_mask))
        reserved_count += 1
        if len(selected) >= int(beam_size):
            return selected, int(reserved_count)

    for key in ranked_keys:
        if int(key) in selected_set:
            continue
        selected.append(int(key))
        selected_set.add(int(key))
        if len(selected) >= int(beam_size):
            break
    return selected, int(reserved_count)


def _near_cut_lineage_cutoff_gap(
    *,
    ranked_keys: Sequence[int],
    rank_value_by_key: dict[int, tuple[float, float, float]],
    beam_size: int,
) -> float:
    if int(beam_size) <= 0 or len(ranked_keys) <= int(beam_size):
        return float("inf")
    cutoff_key = int(ranked_keys[int(beam_size) - 1])
    first_pruned_key = int(ranked_keys[int(beam_size)])
    cutoff_score = float(rank_value_by_key[int(cutoff_key)][0])
    first_pruned_score = float(rank_value_by_key[int(first_pruned_key)][0])
    if not math.isfinite(float(cutoff_score)) or not math.isfinite(float(first_pruned_score)):
        return float("inf")
    return float(cutoff_score - first_pruned_score)


def _select_near_cut_lineage_seed_keys(
    *,
    candidate_log_mass: dict[int, float],
    ranked_keys: Sequence[int],
    kept_keys: Collection[int],
    rank_value_by_key: dict[int, tuple[float, float, float]],
    seed_limit: int,
    beam_size: int,
) -> list[int]:
    if int(seed_limit) <= 0 or not candidate_log_mass or int(beam_size) <= 0:
        return []
    if len(ranked_keys) <= int(beam_size):
        return []
    kept_key_set = {int(key) for key in kept_keys}
    cutoff_key = int(ranked_keys[int(beam_size) - 1])
    cutoff_rank_primary = float(rank_value_by_key[int(cutoff_key)][0])
    ranked_seed_scores: list[tuple[float, float, int, int]] = []
    for rank_index, key in enumerate(tuple(int(value) for value in ranked_keys[int(beam_size):]), start=int(beam_size) + 1):
        if int(key) in kept_key_set or int(key) not in candidate_log_mass:
            continue
        prefix_log_mass = float(candidate_log_mass[int(key)])
        rank_primary = float(rank_value_by_key[int(key)][0])
        bad_future_penalty = (
            max(0.0, float(prefix_log_mass) - float(rank_primary))
            if math.isfinite(float(prefix_log_mass)) and math.isfinite(float(rank_primary))
            else 0.0
        )
        cutoff_deficit = (
            max(0.0, float(cutoff_rank_primary) - float(rank_primary))
            if math.isfinite(float(cutoff_rank_primary)) and math.isfinite(float(rank_primary))
            else 0.0
        )
        seed_score = float(prefix_log_mass) + 0.5 * float(bad_future_penalty) - 0.25 * float(cutoff_deficit)
        ranked_seed_scores.append((float(seed_score), float(prefix_log_mass), -int(rank_index), int(key)))
    ranked_seed_scores.sort(reverse=True)
    return [int(key) for _score, _prefix, _neg_rank, key in ranked_seed_scores[: int(seed_limit)]]


def _trim_log_mass_map_topk(
    *,
    state_log_mass: dict[int, float],
    topk: int,
) -> dict[int, float]:
    if int(topk) <= 0 or len(state_log_mass) <= int(topk):
        return {int(key): float(value) for key, value in state_log_mass.items()}
    kept_keys = sorted(
        (int(key) for key in state_log_mass.keys()),
        key=lambda key: (float(state_log_mass[int(key)]), -int(key)),
        reverse=True,
    )[: int(topk)]
    return {
        int(key): float(state_log_mass[int(key)])
        for key in kept_keys
    }


def _select_pruned_prefix_rescue_seed_log_mass(
    *,
    candidate_log_mass: dict[int, float],
    kept_keys: Collection[int],
    seed_limit: int,
    pre_prune_snapshot: ProgressivePrePruneScoreSnapshot | None = None,
) -> dict[int, float]:
    if int(seed_limit) <= 0 or not candidate_log_mass:
        return {}
    kept_key_set = {int(key) for key in kept_keys}
    if pre_prune_snapshot is not None and tuple(pre_prune_snapshot.states):
        ranked_pruned_state_scores: list[tuple[float, float, int]] = []
        for state in tuple(pre_prune_snapshot.states):
            key = int(state.state_key)
            if int(key) in kept_key_set or int(key) not in candidate_log_mass:
                continue
            prefix_log_mass = float(candidate_log_mass[int(key)])
            bad_future_penalty = (
                max(0.0, float(state.prefix_log_mass) - float(state.rank_primary))
                if (
                    math.isfinite(float(state.prefix_log_mass))
                    and math.isfinite(float(state.rank_primary))
                )
                else 0.0
            )
            cutoff_deficit = (
                max(0.0, float(pre_prune_snapshot.cutoff_rank_primary) - float(state.rank_primary))
                if (
                    math.isfinite(float(pre_prune_snapshot.cutoff_rank_primary))
                    and math.isfinite(float(state.rank_primary))
                )
                else 0.0
            )
            seed_score = float(prefix_log_mass) + 0.5 * float(bad_future_penalty) - 0.25 * float(cutoff_deficit)
            ranked_pruned_state_scores.append((float(seed_score), float(prefix_log_mass), int(key)))
        ranked_pruned_state_scores.sort(
            key=lambda item: (float(item[0]), float(item[1]), -int(item[2])),
            reverse=True,
        )
        selected_keys = [int(key) for _score, _prefix, key in ranked_pruned_state_scores[: int(seed_limit)]]
        return {
            int(key): float(candidate_log_mass[int(key)])
            for key in selected_keys
        }
    ranked_pruned_keys = sorted(
        (
            int(key)
            for key in candidate_log_mass.keys()
            if int(key) not in kept_key_set
        ),
        key=lambda key: (float(candidate_log_mass[int(key)]), -int(key)),
        reverse=True,
    )[: int(seed_limit)]
    return {
        int(key): float(candidate_log_mass[int(key)])
        for key in ranked_pruned_keys
    }


def _pruned_prefix_rescue_cutoff_future_abs_share(
    snapshot: ProgressivePrePruneScoreSnapshot | None,
) -> float:
    if snapshot is None:
        return float("nan")
    states = tuple(snapshot.states)
    kept_count = int(snapshot.kept_state_count)
    if int(kept_count) < 1 or int(snapshot.pruned_state_count) < 1 or len(states) <= int(kept_count):
        return float("nan")
    cutoff_state = states[int(kept_count) - 1]
    first_pruned_state = states[int(kept_count)]
    prefix_delta = float(cutoff_state.prefix_log_mass) - float(first_pruned_state.prefix_log_mass)
    cutoff_future = float(cutoff_state.rank_primary_minus_prefix)
    first_pruned_future = float(first_pruned_state.rank_primary_minus_prefix)
    if not (
        math.isfinite(float(prefix_delta))
        and math.isfinite(float(cutoff_future))
        and math.isfinite(float(first_pruned_future))
    ):
        return float("nan")
    future_delta = float(cutoff_future) - float(first_pruned_future)
    denom = abs(float(prefix_delta)) + abs(float(future_delta))
    if float(denom) <= 0.0:
        return float("nan")
    return float(abs(float(future_delta)) / float(denom))


def _pruned_prefix_rescue_should_seed(
    *,
    snapshot: ProgressivePrePruneScoreSnapshot | None,
    trigger_future_abs_share: float,
    trigger_cutoff_gap: float,
) -> bool:
    future_threshold_active = bool(
        math.isfinite(float(trigger_future_abs_share))
        and float(trigger_future_abs_share) > 0.0
    )
    cutoff_threshold_active = bool(math.isfinite(float(trigger_cutoff_gap)))
    if not future_threshold_active and not cutoff_threshold_active:
        return True
    if snapshot is None:
        return False
    if bool(future_threshold_active):
        future_share = _pruned_prefix_rescue_cutoff_future_abs_share(snapshot)
        if math.isfinite(float(future_share)) and float(future_share) >= float(trigger_future_abs_share):
            return True
    if bool(cutoff_threshold_active):
        cutoff_gap = float(snapshot.cutoff_minus_first_pruned)
        if math.isfinite(float(cutoff_gap)) and float(cutoff_gap) <= float(trigger_cutoff_gap):
            return True
    return False


def _advance_pruned_prefix_rescue_frontier_one_column(
    *,
    state_log_mass: dict[int, float],
    column: ProgressiveColumn,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int,
    detector_mask_mask: int,
    logical_mask_mask: int,
    state_key_logical_shift: int,
    state_key_correction_shift: int,
    exact_correction_mode: bool,
    clamp_assignments: dict[int, int],
) -> dict[int, float]:
    if not state_log_mass:
        return {}
    close_mask = int(frontier.closing_masks[int(column_index)])
    active_mask = int(frontier.active_masks_after_column[int(column_index)])
    log_priors = _column_log_priors(column)
    detector_response_masks = column.detector_response_masks
    logical_response_masks = column.logical_response_masks
    correction_masks = _column_correction_masks(column)
    forced_local_state = clamp_assignments.get(int(column_index))
    next_log_mass: dict[int, float] = {}
    for key, log_mass in state_log_mass.items():
        key_int = int(key)
        det_mask = int(key_int & int(detector_mask_mask))
        logical_mask = int((int(key_int) >> int(state_key_logical_shift)) & int(logical_mask_mask))
        correction_mask = (
            _unpack_correction_mask(
                state_key=int(key_int),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            if bool(exact_correction_mode)
            else 0
        )
        if forced_local_state is None:
            state_iter = enumerate(log_priors)
        else:
            state_iter = ((int(forced_local_state), float(log_priors[int(forced_local_state)])),)
        for local_state, log_prior in state_iter:
            if not math.isfinite(float(log_prior)):
                continue
            candidate_det = int(det_mask) ^ int(detector_response_masks[int(local_state)])
            if (((int(candidate_det) ^ int(target_syndrome_int)) & int(close_mask)) != 0):
                continue
            next_det = int(candidate_det & int(active_mask))
            next_logical = int(logical_mask) ^ int(logical_response_masks[int(local_state)])
            next_correction = int(correction_mask) ^ int(correction_masks[int(local_state)])
            next_key_correction = int(next_correction) if bool(exact_correction_mode) else 0
            next_key = int(
                int(next_det)
                | (int(next_logical) << int(state_key_logical_shift))
                | (int(next_key_correction) << int(state_key_correction_shift))
            )
            next_log_mass[int(next_key)] = _logaddexp_pair(
                float(next_log_mass.get(int(next_key), float("-inf"))),
                float(log_mass) + float(log_prior),
            )
    return next_log_mass


def _pruned_prefix_rescue_shadow_transition_eval_count(
    *,
    state_count: int,
    column: ProgressiveColumn,
    column_index: int,
    clamp_assignments: dict[int, int],
) -> int:
    if int(state_count) <= 0:
        return 0
    forced_local_state = clamp_assignments.get(int(column_index))
    log_priors = _column_log_priors(column)
    if forced_local_state is None:
        local_choice_count = sum(1 for value in log_priors if math.isfinite(float(value)))
    else:
        local_choice_count = 1 if math.isfinite(float(log_priors[int(forced_local_state)])) else 0
    return int(state_count) * int(local_choice_count)


def _estimate_block_path_upper_bound(
    *,
    state_count: int,
    columns: list[ProgressiveColumn],
    start_column_index: int,
    stop_column_index: int,
    clamp_assignments: dict[int, int],
) -> int:
    upper_bound = max(1, int(state_count))
    for column_index in range(int(start_column_index), int(stop_column_index)):
        forced_local_state = clamp_assignments.get(int(column_index))
        if forced_local_state is not None:
            continue
        branching = 0
        for log_prior in _column_log_priors(columns[int(column_index)]):
            if math.isfinite(float(log_prior)):
                branching += 1
        upper_bound *= max(1, int(branching))
    return int(upper_bound)


def _collect_detector_features_for_masks(
    *,
    detector_masks: set[int],
    active_mask: int,
    target_syndrome_int: int,
    column_index: int,
    frontier: ProgressiveFrontierLayout,
    parity_payload: FutureParityBoundaryPayload | None = None,
) -> dict[int, FrontierMismatchFeatures]:
    if parity_payload is not None:
        return {
            int(det_mask): _future_mismatch_features_from_payload(
                det_mask=int(det_mask),
                target_syndrome_int=int(target_syndrome_int),
                payload=parity_payload,
            )
            for det_mask in detector_masks
        }
    return {
        int(det_mask): _future_mismatch_features(
            det_mask=int(det_mask),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            column_index=int(column_index),
            frontier=frontier,
        )
        for det_mask in detector_masks
    }


def _stable_partial_topk_keys(
    *,
    ordered_keys: list[int],
    rank_value_by_key: dict[int, tuple[float, float, float]],
    beam_size: int,
) -> list[int]:
    if int(beam_size) <= 0 or not ordered_keys:
        return []
    if int(beam_size) >= len(ordered_keys):
        return list(int(key) for key in ordered_keys)

    heap: list[tuple[tuple[float, float, float, int], int]] = []
    for insertion_index, key in enumerate(ordered_keys):
        rank_value = rank_value_by_key[int(key)]
        comparable = (
            float(rank_value[0]),
            float(rank_value[1]),
            float(rank_value[2]),
            -int(insertion_index),
        )
        item = (comparable, int(key))
        if len(heap) < int(beam_size):
            heapq.heappush(heap, item)
            continue
        if comparable > heap[0][0]:
            heapq.heapreplace(heap, item)

    top_items = sorted(heap, key=lambda item: item[0], reverse=True)
    return [int(key) for _comparable, key in top_items]


def _prune_beam_frontier_primary_topk_fast_path(
    *,
    next_log_mass: dict[int, float],
    next_viterbi: dict[int, float],
    next_parent: dict[int, tuple[int, int]],
    beam_size: int,
    beam_score_gap_threshold: float | None,
    beam_score_gap_policy: BeamScoreGapPolicy | None,
    score_mode_key: str,
    compiled_plan: tuple[float, bool, str],
    boundary_column_index: int,
    frontier: ProgressiveFrontierLayout,
    active_mask: int,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int,
    track_best_path: bool,
    detector_features_by_detector: dict[int, FrontierMismatchFeatures] | None,
    parity_payload_cache: dict[int, FutureParityBoundaryPayload],
    debug_pruning_engine: str,
    diagnostic_truth_logical_mask: int | None,
    logical_rerank_pass_count: int,
    logical_rerank_last_remaining_columns: int,
    future_parity_scorer: str,
    future_parity_scorer_stats: FutureParityScorerStats | None,
):
    """Fast primary global-topK pruning path for compiled singleton future-parity modes."""
    selected_beam_size = int(beam_size)
    score_gap_pruning_enabled = bool(
        _score_gap_threshold_enabled(beam_score_gap_threshold) or beam_score_gap_policy is not None
    )
    candidate_count = int(len(next_log_mass))
    candidate_prefix_mass = 0.0
    truth_logical_candidate_prefix_mass = 0.0
    truth_logical_target_mask = (
        None if diagnostic_truth_logical_mask is None else int(diagnostic_truth_logical_mask)
    )
    logical_mask_shift = int(num_detectors)
    logical_mask_mask = (1 << int(num_observables)) - 1
    truth_logical_accounting_enabled = truth_logical_target_mask is not None

    def _account_candidate_mass_once() -> None:
        nonlocal candidate_prefix_mass, truth_logical_candidate_prefix_mass
        for mass_key, mass_value in next_log_mass.items():
            mass_key_int = int(mass_key)
            prefix_prob = float(math.exp(float(mass_value)))
            candidate_prefix_mass += float(prefix_prob)
            if bool(truth_logical_accounting_enabled) and (
                (mass_key_int >> int(logical_mask_shift)) & int(logical_mask_mask)
            ) == int(truth_logical_target_mask):
                truth_logical_candidate_prefix_mass += float(prefix_prob)

    if not bool(score_gap_pruning_enabled) and candidate_count <= int(selected_beam_size):
        _account_candidate_mass_once()
        return (
            dict(next_log_mass),
            dict(next_viterbi),
            dict(next_parent),
            0,
            0,
            int(logical_rerank_pass_count),
            int(logical_rerank_last_remaining_columns),
            0,
            0,
            0,
            0,
            0,
            0,
            0.0,
            tuple(),
            -1,
            int(selected_beam_size),
            0,
            0,
            int(selected_beam_size),
            float(candidate_prefix_mass),
            float(candidate_prefix_mass),
            0.0,
            float(truth_logical_candidate_prefix_mass),
            float(truth_logical_candidate_prefix_mass),
            0.0,
            0.0,
            0,
            0,
            0,
            None,
            tuple(),
            tuple(),
        )

    detector_mask_mask = (1 << int(num_detectors)) - 1
    features_by_detector: Mapping[int, FrontierMismatchFeatures] | dict[int, FrontierMismatchFeatures]
    features_by_detector = detector_features_by_detector if detector_features_by_detector is not None else {}
    mutable_features_by_detector: dict[int, FrontierMismatchFeatures] | None = None
    parity_payload: FutureParityBoundaryPayload | None = None
    future_parity_scorer_key = _normalize_future_parity_scorer(str(future_parity_scorer))

    def _missing_features_for_detector(det_key: int) -> FrontierMismatchFeatures:
        nonlocal features_by_detector, mutable_features_by_detector, parity_payload
        det_key_int = int(det_key)
        features = features_by_detector.get(det_key_int)
        if features is not None:
            return features
        if mutable_features_by_detector is None:
            mutable_features_by_detector = {
                int(key): value for key, value in dict(features_by_detector).items()
            }
            features_by_detector = mutable_features_by_detector
        scorer_started = time.perf_counter()
        if str(future_parity_scorer_key) == "cached":
            if parity_payload is None or int(parity_payload.active_mask) != int(active_mask):
                cached_payload = parity_payload_cache.get(int(boundary_column_index))
                if cached_payload is None or int(cached_payload.active_mask) != int(active_mask):
                    cached_payload = _build_future_parity_boundary_payload(
                        frontier=frontier,
                        boundary_column_index=int(boundary_column_index),
                        active_mask=int(active_mask),
                    )
                    parity_payload_cache[int(boundary_column_index)] = cached_payload
                    if future_parity_scorer_stats is not None:
                        future_parity_scorer_stats.payload_build_count += 1
                parity_payload = cached_payload
            features = _future_mismatch_features_from_payload(
                det_mask=int(det_key_int),
                target_syndrome_int=int(target_syndrome_int),
                payload=parity_payload,
            )
        else:
            features = _future_mismatch_features(
                det_mask=int(det_key_int),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                column_index=int(boundary_column_index),
                frontier=frontier,
            )
            if future_parity_scorer_stats is not None:
                future_parity_scorer_stats.from_scratch_score_calls += 1
        if future_parity_scorer_stats is not None:
            future_parity_scorer_stats.fallback_score_calls += 1
            future_parity_scorer_stats.scorer_time_s += float(time.perf_counter() - scorer_started)
        assert mutable_features_by_detector is not None
        mutable_features_by_detector[det_key_int] = features
        return features

    alpha, future_only, _heuristic_mode_key = compiled_plan
    compiled_score_by_detector: dict[int, float] = {}
    pruning_engine_key = str(debug_pruning_engine).strip().lower()
    direct_fixed_score_gap = bool(
        beam_score_gap_policy is None
        and _score_gap_threshold_enabled(beam_score_gap_threshold)
        and bool(score_gap_pruning_enabled)
    )
    ordered_keys: list[int] = []
    can_use_partial_topk = False
    if not bool(direct_fixed_score_gap):
        ordered_keys = [int(key) for key in next_log_mass.keys()]
        can_use_partial_topk = bool(
            pruning_engine_key == "optimized"
            and int(selected_beam_size) > 0
            and len(ordered_keys) >= max(2 * int(selected_beam_size), int(selected_beam_size) + 32)
        )
    if bool(direct_fixed_score_gap):
        best_rank_value: tuple[float, float, float] | None = None
        detector_mask_mask_int = int(detector_mask_mask)
        alpha_value = float(alpha)
        future_only_value = bool(future_only)
        features_get = features_by_detector.get
        compiled_score_get = compiled_score_by_detector.get
        for key, raw_prefix_mass in next_log_mass.items():
            key_int = int(key)
            prefix_mass = float(raw_prefix_mass)
            prefix_prob = float(math.exp(prefix_mass))
            candidate_prefix_mass += float(prefix_prob)
            if bool(truth_logical_accounting_enabled) and (
                (key_int >> int(logical_mask_shift)) & int(logical_mask_mask)
            ) == int(truth_logical_target_mask):
                truth_logical_candidate_prefix_mass += float(prefix_prob)
            det_key = int(key_int & detector_mask_mask_int)
            heuristic_mass = compiled_score_get(det_key)
            if heuristic_mass is None:
                features = features_get(det_key)
                if features is None:
                    features = _missing_features_for_detector(det_key)
                if future_parity_scorer_stats is not None:
                    future_parity_scorer_stats.score_calls += 1
                heuristic_mass = alpha_value * float(features.parity_logodds)
                compiled_score_by_detector[det_key] = heuristic_mass
            if future_only_value:
                rank0 = heuristic_mass
            else:
                rank0 = prefix_mass + heuristic_mass
            rank1 = prefix_mass
            rank_value = (rank0, rank1, 0.0)
            if best_rank_value is None or rank_value > best_rank_value:
                best_rank_value = rank_value
        if best_rank_value is None:
            kept_keys = []
        else:
            cutoff = float(best_rank_value[0]) - float(beam_score_gap_threshold)
            if int(selected_beam_size) <= 0:
                kept_keys = []
            else:
                score_gap_keys: list[int] = []
                score_gap_rank0_values: list[float] = []
                score_gap_rank1_values: list[float] = []
                score_gap_count = 0
                top_heap: list[tuple[tuple[float, float, float, int], int]] | None = None
                selected_beam_size_int = int(selected_beam_size)
                for key, raw_prefix_mass in next_log_mass.items():
                    key_int = int(key)
                    prefix_mass = float(raw_prefix_mass)
                    det_key = int(key_int & detector_mask_mask_int)
                    heuristic_mass = compiled_score_by_detector[det_key]
                    if future_only_value:
                        rank0 = heuristic_mass
                    else:
                        rank0 = prefix_mass + heuristic_mass
                    rank1 = prefix_mass
                    if not (rank0 >= cutoff):
                        continue
                    insertion_index = score_gap_count
                    score_gap_count += 1
                    if score_gap_count <= selected_beam_size_int:
                        score_gap_keys.append(key_int)
                        score_gap_rank0_values.append(rank0)
                        score_gap_rank1_values.append(rank1)
                        continue
                    comparable = (rank0, rank1, 0.0, -insertion_index)
                    if top_heap is None:
                        top_heap = [
                            (
                                (
                                    score_gap_rank0_values[index],
                                    score_gap_rank1_values[index],
                                    0.0,
                                    -index,
                                ),
                                score_gap_keys[index],
                            )
                            for index in range(selected_beam_size_int)
                        ]
                        heapq.heapify(top_heap)
                    if comparable > top_heap[0][0]:
                        heapq.heapreplace(top_heap, (comparable, key_int))
                if score_gap_count <= selected_beam_size_int:
                    kept_keys = list(score_gap_keys)
                elif top_heap is None:
                    kept_keys = list(score_gap_keys[:selected_beam_size_int])
                else:
                    kept_keys = [
                        key
                        for _comparable, key in sorted(
                            top_heap,
                            key=lambda item: item[0],
                            reverse=True,
                        )
                    ]
    else:
        rank_value_by_key: dict[int, tuple[float, float, float]] = {}
        for key in ordered_keys:
            key_int = int(key)
            prefix_mass = float(next_log_mass[key_int])
            prefix_prob = float(math.exp(prefix_mass))
            candidate_prefix_mass += float(prefix_prob)
            if bool(truth_logical_accounting_enabled) and (
                (key_int >> int(logical_mask_shift)) & int(logical_mask_mask)
            ) == int(truth_logical_target_mask):
                truth_logical_candidate_prefix_mass += float(prefix_prob)
            det_key = int(key_int & int(detector_mask_mask))
            heuristic_mass = compiled_score_by_detector.get(det_key)
            if heuristic_mass is None:
                features = features_by_detector.get(det_key)
                if features is None:
                    features = _missing_features_for_detector(int(det_key))
                if future_parity_scorer_stats is not None:
                    future_parity_scorer_stats.score_calls += 1
                heuristic_mass = float(alpha) * float(features.parity_logodds)
                compiled_score_by_detector[int(det_key)] = float(heuristic_mass)
            if bool(future_only):
                rank_value_by_key[key_int] = (float(heuristic_mass), float(prefix_mass), 0.0)
            else:
                rank_value_by_key[key_int] = (float(prefix_mass) + float(heuristic_mass), float(prefix_mass), 0.0)

        if bool(score_gap_pruning_enabled):
            ranked_keys = sorted(ordered_keys, key=lambda key: rank_value_by_key[int(key)], reverse=True)
            realized_beam_score_gap_threshold = _realize_beam_score_gap_threshold_from_ranked_keys(
                beam_score_gap_threshold=beam_score_gap_threshold,
                beam_score_gap_policy=beam_score_gap_policy,
                ranked_keys=tuple(int(key) for key in ranked_keys),
                rank_value_by_key=rank_value_by_key,
            )
            score_gap_keys = _select_keys_score_gap(
                ranked_keys=tuple(int(key) for key in ranked_keys),
                rank_value_by_key=rank_value_by_key,
                score_gap_threshold=realized_beam_score_gap_threshold,
                beam_size=None,
            )
            if int(selected_beam_size) > 0 and len(score_gap_keys) > int(selected_beam_size):
                kept_keys = [int(key) for key in score_gap_keys[: int(selected_beam_size)]]
            else:
                kept_keys = list(int(key) for key in score_gap_keys)
        elif bool(can_use_partial_topk):
            kept_keys = _stable_partial_topk_keys(
                ordered_keys=ordered_keys,
                rank_value_by_key=rank_value_by_key,
                beam_size=int(selected_beam_size),
            )
        else:
            ranked_keys = sorted(ordered_keys, key=lambda key: rank_value_by_key[int(key)], reverse=True)
            kept_keys = [int(key) for key in ranked_keys[: int(selected_beam_size)]]

    pruned_count = int(candidate_count - len(kept_keys))
    kept_log_mass: dict[int, float] = {}
    kept_viterbi: dict[int, float] = {}
    kept_parent: dict[int, tuple[int, int]] = {}
    retained_prefix_mass = 0.0
    truth_logical_retained_prefix_mass = 0.0
    for key in kept_keys:
        key_int = int(key)
        log_mass = float(next_log_mass[key_int])
        prefix_prob = float(math.exp(float(log_mass)))
        kept_log_mass[key_int] = log_mass
        kept_viterbi[key_int] = float(next_viterbi[key_int])
        if bool(track_best_path):
            kept_parent[key_int] = next_parent[key_int]
        retained_prefix_mass += float(prefix_prob)
        if bool(truth_logical_accounting_enabled) and (
            (key_int >> int(logical_mask_shift)) & int(logical_mask_mask)
        ) == int(truth_logical_target_mask):
            truth_logical_retained_prefix_mass += float(prefix_prob)
    discarded_prefix_mass = (
        max(0.0, float(candidate_prefix_mass) - float(retained_prefix_mass))
        if int(pruned_count) > 0
        else 0.0
    )
    discarded_prefix_mass_fraction = (
        float(discarded_prefix_mass) / float(candidate_prefix_mass)
        if float(candidate_prefix_mass) > 0.0
        else 0.0
    )
    truth_logical_discarded_prefix_mass = 0.0
    truth_logical_discarded_prefix_mass_fraction = 0.0
    if bool(truth_logical_accounting_enabled):
        truth_logical_discarded_prefix_mass = max(
            0.0,
            float(truth_logical_candidate_prefix_mass) - float(truth_logical_retained_prefix_mass),
        )
        truth_logical_discarded_prefix_mass_fraction = (
            float(truth_logical_discarded_prefix_mass) / float(truth_logical_candidate_prefix_mass)
            if float(truth_logical_candidate_prefix_mass) > 0.0
            else 0.0
        )
    return (
        kept_log_mass,
        kept_viterbi,
        kept_parent,
        int(pruned_count),
        0,
        int(logical_rerank_pass_count),
        int(logical_rerank_last_remaining_columns),
        0,
        0,
        0,
        0,
        0,
        0,
        float(discarded_prefix_mass),
        tuple(),
        -1,
        int(selected_beam_size),
        0,
        0,
        int(selected_beam_size),
        float(candidate_prefix_mass),
        float(retained_prefix_mass),
        float(discarded_prefix_mass_fraction),
        float(truth_logical_candidate_prefix_mass),
        float(truth_logical_retained_prefix_mass),
        float(truth_logical_discarded_prefix_mass),
        float(truth_logical_discarded_prefix_mass_fraction),
        0,
        0,
        0,
        None,
        tuple(),
        tuple(),
    )


