def _normalize_survival_horizons(values: Sequence[object] | None) -> tuple[float, ...]:
    raw_values = tuple(DEFAULT_SURVIVAL_HORIZONS if values is None else values)
    if not raw_values:
        raise ValueError("survival_horizons must not be empty")
    horizons: list[float] = []
    for raw in raw_values:
        text = str(raw).strip().lower()
        if text in {"inf", "+inf", "infinity"}:
            value = float("inf")
        else:
            try:
                value = float(text)
            except ValueError as exc:
                raise ValueError("survival_horizons entries must be positive numbers or 'inf'") from exc
            if math.isnan(float(value)) or not math.isfinite(float(value)) or float(value) <= 0.0:
                raise ValueError("finite survival_horizons entries must be finite and > 0")
        if value not in horizons:
            horizons.append(float(value))
    horizons.sort(key=lambda item: (math.isinf(float(item)), float(item)))
    return tuple(float(value) for value in horizons)


def _survival_horizon_label(horizon: float) -> str:
    if math.isinf(float(horizon)):
        return "inf"
    rounded = int(round(float(horizon)))
    if abs(float(horizon) - float(rounded)) <= 1.0e-12:
        return str(int(rounded))
    return f"{float(horizon):.12g}".replace(".", "p").replace("-", "m")


def _survival_horizon_labels(horizons: Sequence[float]) -> tuple[str, ...]:
    return tuple(_survival_horizon_label(float(value)) for value in tuple(horizons))


def _survival_score_mode_alpha(score_mode_key: str) -> float | None:
    normalized = str(score_mode_key).strip().lower()
    if normalized == "future_parity_logodds":
        return 1.0
    deadline_config = _future_parity_deadline_logodds_config_from_score_mode(normalized)
    if deadline_config is not None:
        return float(deadline_config.alpha)
    return _future_parity_logodds_alpha_from_score_mode(normalized)


def _stable_candidate_key_for_state(state_key: int) -> str:
    value = int(state_key)
    if value < 0:
        raise ValueError("state_key must be non-negative")
    byte_count = max(1, (int(value).bit_length() + 7) // 8)
    payload = int(value).to_bytes(int(byte_count), byteorder="big", signed=False)
    return hashlib.blake2b(payload, digest_size=8, person=b"fk-surv1").hexdigest()


NEARCUT_INJECTION_ROW_MODES = ("proposed", "all")


def _normalize_nearcut_injection_row_mode(mode: str) -> str:
    key = str(mode).strip().lower().replace("-", "_")
    if key in {"", "proposals", "proposal", "proposed_only"}:
        key = "proposed"
    if key in {"full", "all_rows"}:
        key = "all"
    if key not in set(NEARCUT_INJECTION_ROW_MODES):
        raise ValueError(f"nearcut injection row mode must be one of {NEARCUT_INJECTION_ROW_MODES}")
    return str(key)


def _nearcut_teacher_diagnostic_state_key_hash(state_key: int) -> str:
    return hashlib.blake2b(str(int(state_key)).encode("ascii"), digest_size=12).hexdigest()


def _nearcut_zscore(values_by_key: Mapping[int, float], epsilon: float) -> dict[int, float]:
    finite = np.asarray(
        [float(value) for value in values_by_key.values() if math.isfinite(float(value))],
        dtype=np.float64,
    )
    if int(finite.size) == 0:
        return {int(key): float("nan") for key in values_by_key.keys()}
    mean = float(np.mean(finite))
    std = float(np.std(finite))
    denom = max(float(std), float(epsilon))
    return {
        int(key): (
            (float(value) - float(mean)) / float(denom)
            if math.isfinite(float(value))
            else float("nan")
        )
        for key, value in values_by_key.items()
    }


def build_nearcut_runtime_features(
    *,
    candidate_keys: Sequence[int],
    baseline_kept_keys: Sequence[int],
    ranked_keys: Sequence[int],
    rank_value_by_key: Mapping[int, tuple[float, float, float]],
    prefix_log_mass_by_key: Mapping[int, float],
    detector_key_by_state: Mapping[int, int],
    features_by_detector: Mapping[int, FrontierMismatchFeatures],
    boundary_column_index: int,
    total_columns: int,
    active_mask: int,
    num_detectors: int,
    num_observables: int = 1,
    normalization_epsilon: float = 1.0e-9,
) -> dict[int, dict[str, float]]:
    keys = tuple(int(key) for key in tuple(candidate_keys))
    ranked = tuple(int(key) for key in tuple(ranked_keys))
    ranked_index_by_key = {int(key): int(index) for index, key in enumerate(ranked, start=1)}
    baseline_kept = tuple(int(key) for key in tuple(baseline_kept_keys))
    baseline_scores = [
        float(rank_value_by_key[int(key)][0])
        for key in baseline_kept
        if int(key) in rank_value_by_key and math.isfinite(float(rank_value_by_key[int(key)][0]))
    ]
    cutoff_score = min(baseline_scores) if baseline_scores else float("nan")
    prefix_values = {
        int(key): float(prefix_log_mass_by_key.get(int(key), float("-inf")))
        for key in keys
    }
    primary_scores = {
        int(key): float(rank_value_by_key.get(int(key), (float("-inf"), 0.0, 0.0))[0])
        for key in keys
    }
    score_margins = {
        int(key): (
            float(primary_scores[int(key)]) - float(cutoff_score)
            if math.isfinite(float(primary_scores[int(key)])) and math.isfinite(float(cutoff_score))
            else float("nan")
        )
        for key in keys
    }
    future_values: dict[int, float] = {}
    detector_sparsity_values: dict[int, float] = {}
    active_row_count = max(1, int(active_mask).bit_count())
    for key in keys:
        det_key = int(detector_key_by_state.get(int(key), 0))
        features = features_by_detector.get(int(det_key))
        future_values[int(key)] = (
            float(features.parity_logodds) if features is not None else float("nan")
        )
        detector_sparsity_values[int(key)] = float(int(det_key & int(active_mask)).bit_count()) / float(
            active_row_count
        )
    logical_counts: dict[int, int] = {}
    for key in keys:
        logical_mask = _unpack_logical_mask(
            state_key=int(key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        logical_counts[int(logical_mask)] = int(logical_counts.get(int(logical_mask), 0)) + 1
    best_prefix = max(
        (float(value) for value in prefix_values.values() if math.isfinite(float(value))),
        default=float("nan"),
    )
    finite_future = [float(value) for value in future_values.values() if math.isfinite(float(value))]
    future_mean = float(np.mean(np.asarray(finite_future, dtype=np.float64))) if finite_future else float("nan")
    future_best = max(finite_future) if finite_future else float("nan")
    finite_sparsity = [float(value) for value in detector_sparsity_values.values() if math.isfinite(float(value))]
    detector_sparsity_mean = (
        float(np.mean(np.asarray(finite_sparsity, dtype=np.float64)))
        if finite_sparsity
        else float("nan")
    )
    detector_sparsity_best = min(finite_sparsity) if finite_sparsity else float("nan")
    z_score_margin = _nearcut_zscore(score_margins, float(normalization_epsilon))
    z_future = _nearcut_zscore(future_values, float(normalization_epsilon))
    z_detector_sparsity = _nearcut_zscore(detector_sparsity_values, float(normalization_epsilon))
    z_prefix = _nearcut_zscore(prefix_values, float(normalization_epsilon))
    z_current = _nearcut_zscore(primary_scores, float(normalization_epsilon))
    total_columns_value = max(1, int(total_columns))
    processed_fraction = float(int(boundary_column_index) + 1) / float(total_columns_value)
    out: dict[int, dict[str, float]] = {}
    for key in keys:
        logical_mask = _unpack_logical_mask(
            state_key=int(key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        future_value = float(future_values[int(key)])
        detector_sparsity = float(detector_sparsity_values[int(key)])
        prefix_value = float(prefix_values[int(key)])
        current_value = float(primary_scores[int(key)])
        out[int(key)] = {
            "score_margin_vs_cutoff": float(score_margins[int(key)]),
            "z_score_margin_vs_cutoff": float(z_score_margin[int(key)]),
            "future_parity_logodds": float(future_value),
            "z_future_parity_logodds": float(z_future[int(key)]),
            "detector_sparsity": float(detector_sparsity),
            "z_detector_sparsity": float(z_detector_sparsity[int(key)]),
            "same_logical_support_count": float(logical_counts.get(int(logical_mask), 0)),
            "logical_class_support": float(logical_counts.get(int(logical_mask), 0)),
            "prefix_log_mass": float(prefix_value),
            "z_prefix_log_mass": float(z_prefix[int(key)]),
            "current_total_score": float(current_value),
            "current_total_rank_score": float(current_value),
            "z_current_total_score": float(z_current[int(key)]),
            "boundary_column_index": float(boundary_column_index),
            "normalized_boundary_index": float(processed_fraction),
            "processed_fraction": float(processed_fraction),
            "candidate_pool_size": float(len(keys)),
            "candidate_count": float(len(keys)),
            "active_row_count": float(active_row_count),
            "frontier_width": float(active_row_count),
            "current_rank": float(ranked_index_by_key.get(int(key), 0)),
            "rank_within_current_score_order": float(ranked_index_by_key.get(int(key), 0)),
            "prefix_margin_vs_best": (
                float(prefix_value) - float(best_prefix)
                if math.isfinite(float(prefix_value)) and math.isfinite(float(best_prefix))
                else float("nan")
            ),
            "future_parity_margin_vs_mean": (
                float(future_value) - float(future_mean)
                if math.isfinite(float(future_value)) and math.isfinite(float(future_mean))
                else float("nan")
            ),
            "future_parity_margin_vs_best": (
                float(future_value) - float(future_best)
                if math.isfinite(float(future_value)) and math.isfinite(float(future_best))
                else float("nan")
            ),
            "detector_sparsity_margin_vs_mean": (
                float(detector_sparsity) - float(detector_sparsity_mean)
                if math.isfinite(float(detector_sparsity)) and math.isfinite(float(detector_sparsity_mean))
                else float("nan")
            ),
            "detector_sparsity_margin_vs_best": (
                float(detector_sparsity) - float(detector_sparsity_best)
                if math.isfinite(float(detector_sparsity)) and math.isfinite(float(detector_sparsity_best))
                else float("nan")
            ),
        }
    return out


def _nearcut_linear_score_for_features(
    model: NearCutLinearModel,
    features: Mapping[str, float],
) -> float | None:
    score = float(model.intercept)
    coefficient_by_name = {str(name): float(value) for name, value in tuple(model.coefficients)}
    for name in tuple(model.feature_names):
        value = features.get(str(name))
        if value is None or not math.isfinite(float(value)):
            return None
        score += float(coefficient_by_name[str(name)]) * float(value)
    return float(score) if math.isfinite(float(score)) else None


def _nearcut_increment_stat(stats: dict[str, float | int] | None, name: str, amount: float | int = 1) -> None:
    if stats is None:
        return
    if isinstance(amount, float):
        stats[str(name)] = float(stats.get(str(name), 0.0)) + float(amount)
    else:
        stats[str(name)] = int(stats.get(str(name), 0)) + int(amount)


def _apply_nearcut_boundary_policy(
    *,
    mode: str,
    model: NearCutLinearModel,
    candidate_keys: Sequence[int],
    baseline_kept_keys: Sequence[int],
    ranked_keys: Sequence[int],
    rank_value_by_key: Mapping[int, tuple[float, float, float]],
    prefix_log_mass_by_key: Mapping[int, float],
    feature_by_key: Mapping[int, Mapping[str, float]],
    boundary_column_index: int,
    stats: dict[str, float | int] | None = None,
    injection_rows: list[dict[str, object]] | None = None,
    injection_row_mode: str = "proposed",
) -> tuple[int, ...]:
    mode_key = _normalize_nearcut_mode(str(mode))
    if str(mode_key) == "disabled":
        return tuple()
    injection_mode_key = _normalize_nearcut_injection_row_mode(str(injection_row_mode))
    policy = model.policy
    baseline_set = {int(key) for key in tuple(baseline_kept_keys)}
    best_prefix = max(
        (
            float(prefix_log_mass_by_key.get(int(key), float("-inf")))
            for key in tuple(candidate_keys)
            if math.isfinite(float(prefix_log_mass_by_key.get(int(key), float("-inf"))))
        ),
        default=float("-inf"),
    )
    pruned_candidate_keys = [
        int(key)
        for key in tuple(ranked_keys)
        if int(key) in set(int(value) for value in tuple(candidate_keys))
        and (not bool(policy.admit_only_pruned_nearcut_states) or int(key) not in baseline_set)
    ]
    _nearcut_increment_stat(stats, "nearcut_candidates_seen", int(len(pruned_candidate_keys)))
    scored: list[tuple[float, float, float, str, int]] = []
    rejected_by_gap = 0
    rejected_by_prefix = 0
    rejected_by_feature = 0
    rows_to_append: list[dict[str, object]] = []
    rank_by_key = {int(key): int(rank) for rank, key in enumerate(tuple(ranked_keys), start=1)}
    for key in pruned_candidate_keys:
        features = dict(feature_by_key.get(int(key), {}))
        margin = float(features.get("score_margin_vs_cutoff", float("nan")))
        prefix_log_mass = float(prefix_log_mass_by_key.get(int(key), float("-inf")))
        primary_score = float(rank_value_by_key.get(int(key), (float("-inf"), 0.0, 0.0))[0])
        learned_score = float("nan")
        reason = ""
        if (
            not math.isfinite(float(margin))
            or float(margin) < -float(policy.candidate_gap)
            or float(margin) > float(policy.candidate_positive_slack)
        ):
            rejected_by_gap += 1
            reason = "gap"
        elif (
            not math.isfinite(float(prefix_log_mass))
            or (
                math.isfinite(float(best_prefix))
                and float(prefix_log_mass) < float(best_prefix) - float(policy.prefix_gap_from_best)
            )
        ):
            rejected_by_prefix += 1
            reason = "prefix_guard"
        else:
            candidate_score = _nearcut_linear_score_for_features(model, features)
            if candidate_score is None:
                rejected_by_feature += 1
                reason = "feature_guard"
            else:
                learned_score = float(candidate_score)
                if policy.min_learned_score is not None and float(learned_score) < float(policy.min_learned_score):
                    rejected_by_feature += 1
                    reason = "min_score"
                else:
                    scored.append(
                        (
                            -float(learned_score),
                            -float(primary_score),
                            -float(prefix_log_mass),
                            _stable_candidate_key_for_state(int(key)),
                            int(key),
                        )
                    )
        rows_to_append.append(
            {
                "_state_key": int(key),
                "boundary_column_index": int(boundary_column_index),
                "state_key_hash": _stable_candidate_key_for_state(int(key)),
                "diagnostic_state_key_hash": _nearcut_teacher_diagnostic_state_key_hash(int(key)),
                "candidate_baseline_rank": int(rank_by_key.get(int(key), 0)),
                "candidate_primary_score": float(primary_score),
                "candidate_prefix_log_mass": float(prefix_log_mass),
                "score_margin_vs_cutoff": float(margin),
                "learned_score": float(learned_score),
                "accepted": False,
                "rejection_reason": str(reason or "not_selected"),
                "feature_values_json": json.dumps(
                    {
                        str(name): float(features[str(name)])
                        for name in tuple(model.feature_names)
                        if str(name) in features and math.isfinite(float(features[str(name)]))
                    },
                    sort_keys=True,
                ),
            }
        )
    _nearcut_increment_stat(stats, "nearcut_rejected_by_gap", int(rejected_by_gap))
    _nearcut_increment_stat(stats, "nearcut_rejected_by_prefix_guard", int(rejected_by_prefix))
    _nearcut_increment_stat(stats, "nearcut_rejected_by_feature_guard", int(rejected_by_feature))
    scored.sort()
    _nearcut_increment_stat(stats, "nearcut_candidates_eligible", int(len(scored)))
    remaining_total_budget = max(
        0,
        int(policy.max_extra_states) - int(0 if stats is None else stats.get("nearcut_extra_states_total", 0)),
    )
    per_boundary_budget = max(0, min(int(policy.max_extra_states_per_boundary), int(remaining_total_budget)))
    proposed = tuple(int(item[-1]) for item in tuple(scored[: int(per_boundary_budget)]))
    _nearcut_increment_stat(stats, "nearcut_candidates_proposed", int(len(proposed)))
    accepted: tuple[int, ...] = tuple()
    if str(mode_key) == "guarded_union" and proposed:
        accepted = tuple(int(key) for key in proposed if int(key) not in baseline_set)
        _nearcut_increment_stat(stats, "nearcut_candidates_accepted", int(len(accepted)))
        _nearcut_increment_stat(stats, "nearcut_extra_states_total", int(len(accepted)))
        if accepted:
            _nearcut_increment_stat(stats, "nearcut_boundaries_with_acceptance", 1)
            if stats is not None:
                stats["nearcut_max_extra_states_at_boundary"] = max(
                    int(stats.get("nearcut_max_extra_states_at_boundary", 0)),
                    int(len(accepted)),
                )
    accepted_set = {int(key) for key in accepted}
    proposed_set = {int(value) for value in proposed}
    for row in rows_to_append:
        row_key = int(row.pop("_state_key", -1))
        if int(row_key) in accepted_set:
            row["accepted"] = True
            row["rejection_reason"] = ""
        elif int(row_key) in proposed_set:
            row["rejection_reason"] = "shadow" if str(mode_key) == "shadow" else str(row["rejection_reason"])
        if injection_rows is not None:
            should_append = str(injection_mode_key) == "all" or int(row_key) in proposed_set or int(row_key) in accepted_set
            if bool(should_append):
                injection_rows.append(dict(row))
    return tuple(int(key) for key in accepted)


def _stable_survival_shuffle_key(*, seed: int, boundary_column_index: int, column_index: int) -> bytes:
    seed64 = int(seed) & ((1 << 64) - 1)
    payload = (
        int(seed64).to_bytes(8, byteorder="big", signed=False)
        + int(boundary_column_index).to_bytes(8, byteorder="big", signed=False)
        + int(column_index).to_bytes(8, byteorder="big", signed=False)
    )
    return hashlib.blake2b(payload, digest_size=16, person=b"fk-hordr").digest()


def _survival_horizon_deadline_distance_by_row(
    *,
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    active_rows: Sequence[int],
    horizon_order_source: str,
    shuffle_seed: int = 0,
) -> dict[int, int]:
    source = _normalize_survival_horizon_order_source(str(horizon_order_source))
    boundary = int(boundary_column_index)
    total_columns = int(len(tuple(frontier.column_row_updates)))
    future_len = max(0, int(total_columns) - int(boundary) - 1)
    active_row_set = {int(row) for row in tuple(active_rows)}
    out: dict[int, int] = {}
    if not active_row_set or future_len <= 0:
        return out

    for row in active_row_set:
        touch_columns = tuple(int(value) for value in frontier.row_touch_columns[int(row)])
        pos = bisect.bisect_right(touch_columns, int(boundary))
        future_touch_columns = touch_columns[int(pos):]
        if not future_touch_columns:
            continue
        if source == "actual":
            out[int(row)] = int(future_touch_columns[-1]) - int(boundary)
        elif source == "reverse":
            first_distance = int(future_touch_columns[0]) - int(boundary)
            out[int(row)] = int(future_len) - int(first_distance) + 1

    if source != "shuffle":
        return out

    future_columns = tuple(range(int(boundary) + 1, int(total_columns)))
    shuffled_columns = sorted(
        future_columns,
        key=lambda column: _stable_survival_shuffle_key(
            seed=int(shuffle_seed),
            boundary_column_index=int(boundary),
            column_index=int(column),
        ),
    )
    position_by_column = {int(column): int(position) for position, column in enumerate(shuffled_columns, start=1)}
    for row in active_row_set:
        touch_columns = tuple(int(value) for value in frontier.row_touch_columns[int(row)])
        pos = bisect.bisect_right(touch_columns, int(boundary))
        future_touch_columns = touch_columns[int(pos):]
        if not future_touch_columns:
            continue
        out[int(row)] = max(int(position_by_column[int(column)]) for column in future_touch_columns)
    return out


def _score_for_descending_sort(value: float) -> float:
    number = float(value)
    if math.isnan(float(number)):
        return float("-inf")
    return float(number)


def _finite_beam_survival_primary_order(
    *,
    candidate_keys: Sequence[int],
    primary_rank_value_by_key: Mapping[int, tuple[float, float, float]],
    stable_candidate_key_by_key: Mapping[int, str],
) -> tuple[int, ...]:
    return tuple(
        int(key)
        for key in sorted(
            (int(value) for value in tuple(candidate_keys)),
            key=lambda key: (
                -float(_score_for_descending_sort(primary_rank_value_by_key[int(key)][0])),
                -float(_score_for_descending_sort(primary_rank_value_by_key[int(key)][1])),
                -float(_score_for_descending_sort(primary_rank_value_by_key[int(key)][2])),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
    )


def _finite_beam_survival_kth_cutoff(
    *,
    scores: Sequence[float],
    beam_size: int,
    cutoff_source: str,
) -> float:
    finite_or_inf = [float(value) for value in tuple(scores) if not math.isnan(float(value))]
    if not finite_or_inf:
        return float("-inf")
    ordered = sorted(finite_or_inf, reverse=True)
    if str(cutoff_source) == "current_pool_quantile":
        if len(ordered) == 1:
            return float(ordered[0])
        q = max(0.0, min(1.0, 1.0 - (float(beam_size) - 1.0) / float(max(1, len(ordered) - 1))))
        return float(np.quantile(np.asarray(ordered, dtype=np.float64), float(q), method="linear"))
    index = min(max(0, int(beam_size) - 1), len(ordered) - 1)
    return float(ordered[int(index)])


def _finite_beam_survival_softmin(
    values: Sequence[float],
    *,
    temperature: float,
) -> float:
    margins = np.asarray([float(value) for value in tuple(values)], dtype=np.float64)
    if margins.size == 0:
        return 0.0
    if float(temperature) <= 0.0:
        return float(np.min(margins))
    scaled = -margins / float(temperature)
    max_scaled = float(np.max(scaled))
    if not math.isfinite(float(max_scaled)):
        return float(np.min(margins))
    return -float(temperature) * float(
        max_scaled + math.log(float(np.sum(np.exp(scaled - float(max_scaled)))))
    )


def _finite_beam_survival_cutoff_gap(
    *,
    ranked_keys: Sequence[int],
    score_by_key: Mapping[int, float],
    beam_size: int,
) -> float:
    ranked = tuple(int(key) for key in tuple(ranked_keys))
    if int(beam_size) <= 0 or len(ranked) <= int(beam_size):
        return float("nan")
    cutoff = float(score_by_key[int(ranked[int(beam_size) - 1])])
    first_pruned = float(score_by_key[int(ranked[int(beam_size)])])
    if math.isfinite(float(cutoff)) and math.isfinite(float(first_pruned)):
        return float(cutoff) - float(first_pruned)
    return float("nan")


def _finite_beam_survival_distinct_active_masks(
    *,
    keys: Sequence[int],
    active_mask: int,
    detector_mask_mask: int,
) -> int:
    masks: set[int] = set()
    for key in tuple(keys):
        det_mask = _unpack_detector_mask(
            state_key=int(key),
            detector_mask_mask=int(detector_mask_mask),
        )
        masks.add(int(det_mask) & int(active_mask))
    return int(len(masks))


def _future_parity_row_terms_from_payload(
    *,
    det_mask: int,
    target_syndrome_int: int,
    payload: FutureParityBoundaryPayload,
    alpha: float,
    deadline_distance_by_row: Mapping[int, int] | None = None,
) -> tuple[FiniteBeamSurvivalRowTerm, ...]:
    residual_mask = int(det_mask ^ target_syndrome_int) & int(payload.active_mask)
    override_distances = (
        {}
        if deadline_distance_by_row is None
        else {int(row): int(distance) for row, distance in dict(deadline_distance_by_row).items()}
    )
    terms: list[FiniteBeamSurvivalRowTerm] = []
    for metric in payload.row_metrics:
        if (int(residual_mask) & int(metric.row_mask)) == 0:
            continue
        deadline_distance = int(override_distances.get(int(metric.row), int(metric.deadline_distance)))
        terms.append(
            FiniteBeamSurvivalRowTerm(
                row=int(metric.row),
                contribution=float(alpha) * float(metric.parity_logodds),
                deadline_distance=int(deadline_distance),
                first_touch_distance=int(metric.first_touch_distance),
                last_touch_distance=int(metric.last_touch_distance),
            )
        )
    return tuple(terms)


def _future_parity_horizon_logodds_from_row_terms(
    *,
    row_terms: Sequence[FiniteBeamSurvivalRowTerm],
    horizons: Sequence[float],
) -> dict[str, float]:
    out: dict[str, float] = {}
    terms = tuple(row_terms)
    for horizon in tuple(float(value) for value in tuple(horizons)):
        label = _survival_horizon_label(float(horizon))
        if math.isinf(float(horizon)):
            total = sum(float(term.contribution) for term in terms)
        else:
            total = sum(
                float(term.contribution)
                for term in terms
                if int(term.deadline_distance) <= int(math.ceil(float(horizon)))
            )
        out[str(label)] = float(total)
    return out


def _future_parity_deadline_boost_from_row_terms(
    *,
    row_terms: Sequence[FiniteBeamSurvivalRowTerm],
    tau: float,
) -> float:
    if float(tau) <= 0.0 or not math.isfinite(float(tau)):
        return 0.0
    return float(
        sum(
            math.exp(-float(max(0, int(term.deadline_distance))) / float(tau))
            * float(term.contribution)
            for term in tuple(row_terms)
        )
    )


def _learned_linear_feature_value(
    *,
    feature_name: str,
    det_key: int,
    active_mask: int,
    target_syndrome_int: int,
    boundary_column_index: int,
    columns: Sequence[ProgressiveColumn],
    features: FrontierMismatchFeatures,
    parity_payload: FutureParityBoundaryPayload,
) -> float:
    name = str(feature_name).strip().lower()
    total_columns = max(1, len(tuple(columns)))
    active_row_count = int(len(tuple(parity_payload.active_rows)))
    mismatch_count = int(features.mismatch_count)
    if name in {"parity_logodds", "future_parity_logodds", "future_total_logodds", "horizon_logodds_inf"}:
        return float(features.parity_logodds)
    alpha = _future_parity_logodds_alpha_from_score_mode(str(name))
    if alpha is not None:
        return float(alpha) * float(features.parity_logodds)
    if name == "future_parity_logodds_a0p8":
        return 0.8 * float(features.parity_logodds)
    if name == "mismatch_count":
        return float(mismatch_count)
    if name == "mismatch_fraction":
        return float(mismatch_count) / float(max(1, active_row_count))
    if name == "touch_bonus":
        return float(features.touch_bonus)
    if name == "urgency_penalty":
        return float(features.urgency_penalty)
    if name == "negative_urgency_penalty":
        return -float(features.urgency_penalty)
    if name == "active_row_count":
        return float(active_row_count)
    if name == "active_fraction":
        return float(active_row_count) / float(max(1, int(active_mask).bit_count()))
    if name == "closing_row_count":
        return float(len(tuple(parity_payload.closing_rows)))
    if name == "touched_row_count":
        return float(len(tuple(parity_payload.touched_rows)))
    if name == "closure_block_touched_row_count":
        return float(len(tuple(parity_payload.closure_block_touched_rows)))
    if name == "boundary_column_index":
        return float(boundary_column_index)
    if name == "processed_fraction":
        return float(int(boundary_column_index) + 1) / float(total_columns)
    if name == "remaining_columns":
        return float(max(0, int(total_columns) - int(boundary_column_index) - 1))
    if name == "remaining_fraction":
        return float(max(0, int(total_columns) - int(boundary_column_index) - 1)) / float(total_columns)

    residual_mask = int(det_key ^ target_syndrome_int) & int(parity_payload.active_mask)
    if name.startswith("horizon_logodds_h"):
        suffix = str(name[len("horizon_logodds_h"):]).strip()
        horizon = int(suffix)
        return float(
            sum(
                float(metric.parity_logodds)
                for metric in tuple(parity_payload.row_metrics)
                if (int(residual_mask) & int(metric.row_mask)) != 0
                and int(metric.deadline_distance) <= int(horizon)
            )
        )
    if name.startswith("deadline_boost_tau"):
        token = str(name[len("deadline_boost_tau"):]).strip()
        tau = _parse_pairlogodds_weight_token(token)
        if tau is None or float(tau) <= 0.0:
            raise ValueError(f"invalid learned score deadline feature {name!r}")
        return float(
            sum(
                math.exp(-float(max(0, int(metric.deadline_distance))) / float(tau))
                * float(metric.parity_logodds)
                for metric in tuple(parity_payload.row_metrics)
                if (int(residual_mask) & int(metric.row_mask)) != 0
            )
        )
    raise ValueError(f"unsupported learned score feature {name!r}")


def _future_parity_learned_linear_score(
    *,
    det_key: int,
    active_mask: int,
    target_syndrome_int: int,
    boundary_column_index: int,
    columns: Sequence[ProgressiveColumn],
    features: FrontierMismatchFeatures,
    parity_payload: FutureParityBoundaryPayload,
    learned_score_config: FutureParityLearnedLinearConfig,
) -> float:
    score = float(learned_score_config.intercept)
    for feature_name, coefficient in tuple(learned_score_config.coefficients):
        value = _learned_linear_feature_value(
            feature_name=str(feature_name),
            det_key=int(det_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            boundary_column_index=int(boundary_column_index),
            columns=columns,
            features=features,
            parity_payload=parity_payload,
        )
        if not math.isfinite(float(value)):
            if float(coefficient) == 0.0:
                continue
            return float("-inf") if float(value) < 0.0 else float("inf")
        score += float(coefficient) * float(value)
    clip = float(learned_score_config.score_clip)
    if math.isfinite(float(clip)):
        score = max(-float(clip), min(float(clip), float(score)))
    return float(score)


def _finite_beam_survival_rank_candidates(
    *,
    candidate_keys: Sequence[int],
    primary_rank_value_by_key: Mapping[int, tuple[float, float, float]],
    horizon_logodds_by_key: Mapping[int, Mapping[str, float]],
    beam_size: int,
    boundary_column_index: int,
    active_mask: int,
    detector_mask_mask: int,
    survival_lambda: float = 0.25,
    survival_clip: float = 2.0,
    survival_softmin_temperature: float = 0.0,
    survival_cutoff_source: str = "current_pool_kth",
    survival_horizon_order_source: str = "actual",
    survival_horizon_shuffle_seed: int = 0,
    survival_deadline_boost_beta: float = 0.0,
    survival_deadline_boost_tau: float = 4.0,
    deadline_boost_by_key: Mapping[int, float] | None = None,
    horizons: Sequence[float] = DEFAULT_SURVIVAL_HORIZONS,
    diagnostics: bool = False,
    payload_seconds: float = 0.0,
    degraded_to_primary: bool = False,
    degradation_reason: str = "",
    diagnostic_truth_state_key: int | None = None,
    diagnostic_truth_logical_mask: int | None = None,
) -> tuple[dict[int, tuple[float, float, float]], tuple[int, ...], ProgressiveFiniteBeamSurvivalStep | None]:
    keys = tuple(int(key) for key in tuple(candidate_keys))
    horizon_values = _normalize_survival_horizons(tuple(horizons))
    horizon_labels = _survival_horizon_labels(tuple(horizon_values))
    cutoff_source_key = _normalize_survival_cutoff_source(str(survival_cutoff_source))
    horizon_order_source_key = _normalize_survival_horizon_order_source(str(survival_horizon_order_source))
    stable_candidate_key_by_key = {int(key): _stable_candidate_key_for_state(int(key)) for key in keys}
    primary_ranked = _finite_beam_survival_primary_order(
        candidate_keys=keys,
        primary_rank_value_by_key=primary_rank_value_by_key,
        stable_candidate_key_by_key=stable_candidate_key_by_key,
    )
    primary_rank_by_key = {int(key): int(index) + 1 for index, key in enumerate(primary_ranked)}
    primary_score_by_key = {
        int(key): float(primary_rank_value_by_key[int(key)][0])
        for key in keys
    }
    prefix_score_by_key = {
        int(key): float(primary_rank_value_by_key[int(key)][1])
        for key in keys
    }
    if (
        bool(degraded_to_primary)
        or int(beam_size) <= 0
        or len(keys) <= int(beam_size)
    ):
        ranked = tuple(int(key) for key in primary_ranked)
        step = None
        if bool(diagnostics):
            kept_count = min(len(keys), max(0, int(beam_size)))
            top_keys = tuple(int(key) for key in ranked[: int(kept_count)])
            survival_values = [0.0 for _key in keys]
            step = ProgressiveFiniteBeamSurvivalStep(
                processed_columns=int(boundary_column_index) + 1,
                boundary_column_index=int(boundary_column_index),
                beam_size=int(beam_size),
                candidate_count=int(len(keys)),
                kept_count=int(kept_count),
                horizons=tuple(horizon_labels),
                horizon_unit="future_columns",
                survival_lambda=float(survival_lambda),
                survival_clip=float(survival_clip),
                survival_softmin_temperature=float(survival_softmin_temperature),
                survival_cutoff_source=str(cutoff_source_key),
                horizon_order_source=str(horizon_order_source_key),
                horizon_shuffle_seed=int(survival_horizon_shuffle_seed),
                survival_deadline_boost_beta=float(survival_deadline_boost_beta),
                survival_deadline_boost_tau=float(survival_deadline_boost_tau),
                ordinary_cutoff_gap=float("nan"),
                adjusted_cutoff_gap=float("nan"),
                changed_survivor_count=0,
                primary_topk_distinct_active_masks=_finite_beam_survival_distinct_active_masks(
                    keys=top_keys,
                    active_mask=int(active_mask),
                    detector_mask_mask=int(detector_mask_mask),
                ),
                adjusted_topk_distinct_active_masks=_finite_beam_survival_distinct_active_masks(
                    keys=top_keys,
                    active_mask=int(active_mask),
                    detector_mask_mask=int(detector_mask_mask),
                ),
                mean_survival_value_topk=0.0,
                mean_survival_value_pool=0.0 if survival_values else float("nan"),
                min_survival_value_topk=0.0 if top_keys else float("nan"),
                max_survival_value_topk=0.0 if top_keys else float("nan"),
                survival_payload_seconds=float(payload_seconds),
                degraded_to_primary=bool(degraded_to_primary),
                degradation_reason=(
                    str(degradation_reason)
                    if str(degradation_reason)
                    else ("no_truncation" if len(keys) <= int(beam_size) else "")
                ),
                diagnostic_truth_descendant_kept_by_primary=bool(
                    diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in set(top_keys)
                ),
                diagnostic_truth_descendant_kept_by_survival=bool(
                    diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in set(top_keys)
                ),
                diagnostic_truth_descendant_rank_primary=(
                    0
                    if diagnostic_truth_state_key is None
                    else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
                ),
                diagnostic_truth_descendant_rank_survival=(
                    0
                    if diagnostic_truth_state_key is None
                    else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
                ),
                candidate_samples=tuple(),
            )
        return dict(primary_rank_value_by_key), ranked, step

    clip_value = float(survival_clip)
    if math.isnan(float(clip_value)) or not math.isfinite(float(clip_value)) or float(clip_value) < 0.0:
        raise ValueError("survival_clip must be finite and >= 0")
    if math.isnan(float(survival_lambda)) or not math.isfinite(float(survival_lambda)):
        raise ValueError("survival_lambda must be finite")
    if (
        math.isnan(float(survival_softmin_temperature))
        or not math.isfinite(float(survival_softmin_temperature))
        or float(survival_softmin_temperature) < 0.0
    ):
        raise ValueError("survival_softmin_temperature must be finite and >= 0")
    if (
        math.isnan(float(survival_deadline_boost_beta))
        or not math.isfinite(float(survival_deadline_boost_beta))
    ):
        raise ValueError("survival_deadline_boost_beta must be finite")

    horizon_partial_scores_by_label: dict[str, dict[int, float]] = {str(label): {} for label in horizon_labels}
    for key in keys:
        prefix_score = float(prefix_score_by_key[int(key)])
        per_horizon = horizon_logodds_by_key.get(int(key), {})
        for label in horizon_labels:
            horizon_logodds = float(per_horizon.get(str(label), 0.0))
            horizon_partial_scores_by_label[str(label)][int(key)] = float(prefix_score) + float(horizon_logodds)

    ordinary_topk = tuple(int(key) for key in primary_ranked[: int(beam_size)])
    ordinary_topk_set = {int(key) for key in ordinary_topk}
    cutoffs_by_label: dict[str, float] = {}
    for label in horizon_labels:
        if str(cutoff_source_key) == "ordinary_topk":
            score_values = [float(horizon_partial_scores_by_label[str(label)][int(key)]) for key in ordinary_topk]
            source_for_cutoff = "current_pool_kth"
        else:
            score_values = [float(horizon_partial_scores_by_label[str(label)][int(key)]) for key in keys]
            source_for_cutoff = str(cutoff_source_key)
        cutoffs_by_label[str(label)] = _finite_beam_survival_kth_cutoff(
            scores=score_values,
            beam_size=min(max(1, int(beam_size)), max(1, len(score_values))),
            cutoff_source=str(source_for_cutoff),
        )

    horizon_margins_by_key: dict[int, dict[str, float]] = {}
    survival_value_by_key: dict[int, float] = {}
    adjusted_score_by_key: dict[int, float] = {}
    deadline_boost_map = {} if deadline_boost_by_key is None else {int(k): float(v) for k, v in deadline_boost_by_key.items()}
    for key in keys:
        clipped_margins: list[float] = []
        raw_margins: dict[str, float] = {}
        for label in horizon_labels:
            partial_score = float(horizon_partial_scores_by_label[str(label)][int(key)])
            cutoff = float(cutoffs_by_label[str(label)])
            margin = float(partial_score) - float(cutoff)
            if not math.isfinite(float(margin)):
                margin = -float(clip_value)
            clipped = max(-float(clip_value), min(float(clip_value), float(margin)))
            raw_margins[str(label)] = float(clipped)
            clipped_margins.append(float(clipped))
        horizon_margins_by_key[int(key)] = dict(raw_margins)
        survival_value = _finite_beam_survival_softmin(
            clipped_margins,
            temperature=float(survival_softmin_temperature),
        )
        survival_value_by_key[int(key)] = float(survival_value)
        adjusted_score_by_key[int(key)] = (
            float(primary_score_by_key[int(key)])
            + float(survival_lambda) * float(survival_value)
            + float(survival_deadline_boost_beta) * float(deadline_boost_map.get(int(key), 0.0))
        )

    adjusted_ranked = tuple(
        int(key)
        for key in sorted(
            keys,
            key=lambda key: (
                -float(_score_for_descending_sort(adjusted_score_by_key[int(key)])),
                -float(_score_for_descending_sort(primary_score_by_key[int(key)])),
                int(primary_rank_by_key[int(key)]),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
    )
    adjusted_rank_by_key = {int(key): int(index) + 1 for index, key in enumerate(adjusted_ranked)}
    adjusted_rank_value_by_key = {
        int(key): (
            float(adjusted_score_by_key[int(key)]),
            float(primary_score_by_key[int(key)]),
            -float(primary_rank_by_key[int(key)]),
        )
        for key in keys
    }
    adjusted_topk = tuple(int(key) for key in adjusted_ranked[: int(beam_size)])
    adjusted_topk_set = {int(key) for key in adjusted_topk}
    changed_survivor_count = int(len(ordinary_topk_set.symmetric_difference(adjusted_topk_set)))
    step = None
    if bool(diagnostics):
        sample_indices: set[int] = set()
        for ranked in (primary_ranked, adjusted_ranked):
            if len(ranked) > int(beam_size):
                start = max(0, int(beam_size) - 11)
                stop = min(len(ranked), int(beam_size) + 10)
            else:
                start = 0
                stop = len(ranked)
            for index in range(int(start), int(stop)):
                sample_indices.add(int(index))
        sample_keys: set[int] = set()
        for index in sample_indices:
            if 0 <= int(index) < len(primary_ranked):
                sample_keys.add(int(primary_ranked[int(index)]))
            if 0 <= int(index) < len(adjusted_ranked):
                sample_keys.add(int(adjusted_ranked[int(index)]))
        if diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in keys:
            sample_keys.add(int(diagnostic_truth_state_key))
        ordered_sample_keys = sorted(
            sample_keys,
            key=lambda key: (
                min(int(primary_rank_by_key.get(int(key), 10**9)), int(adjusted_rank_by_key.get(int(key), 10**9))),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
        candidate_samples: list[FiniteBeamSurvivalCandidateSample] = []
        for key in ordered_sample_keys:
            per_horizon = horizon_logodds_by_key.get(int(key), {})
            future_total = float(per_horizon.get("inf", per_horizon.get(horizon_labels[-1], 0.0)))
            candidate_samples.append(
                FiniteBeamSurvivalCandidateSample(
                    processed_columns=int(boundary_column_index) + 1,
                    boundary_column_index=int(boundary_column_index),
                    candidate_key=str(stable_candidate_key_by_key[int(key)]),
                    state_key=int(key),
                    primary_rank=int(primary_rank_by_key.get(int(key), 0)),
                    adjusted_rank=int(adjusted_rank_by_key.get(int(key), 0)),
                    primary_score=float(primary_score_by_key[int(key)]),
                    adjusted_score=float(adjusted_score_by_key[int(key)]),
                    prefix_score=float(prefix_score_by_key[int(key)]),
                    future_total_logodds=float(future_total),
                    survival_value=float(survival_value_by_key[int(key)]),
                    deadline_boost_component=float(deadline_boost_map.get(int(key), 0.0)),
                    horizon_logodds_items=tuple(
                        (str(label), float(per_horizon.get(str(label), 0.0)))
                        for label in horizon_labels
                    ),
                    horizon_margin_items=tuple(
                        (str(label), float(horizon_margins_by_key[int(key)].get(str(label), float("nan"))))
                        for label in horizon_labels
                    ),
                    ordinary_topk_member=bool(int(key) in ordinary_topk_set),
                    adjusted_topk_member=bool(int(key) in adjusted_topk_set),
                    selected_by_survival_not_primary=bool(
                        int(key) in adjusted_topk_set and int(key) not in ordinary_topk_set
                    ),
                    selected_by_primary_not_survival=bool(
                        int(key) in ordinary_topk_set and int(key) not in adjusted_topk_set
                    ),
                    diagnostic_truth_descendant=bool(
                        diagnostic_truth_state_key is not None and int(key) == int(diagnostic_truth_state_key)
                    ),
                    diagnostic_truth_logical=(
                        -1 if diagnostic_truth_logical_mask is None else int(diagnostic_truth_logical_mask)
                    ),
                )
            )
        topk_survival_values = [float(survival_value_by_key[int(key)]) for key in adjusted_topk]
        pool_survival_values = [float(survival_value_by_key[int(key)]) for key in keys]
        step = ProgressiveFiniteBeamSurvivalStep(
            processed_columns=int(boundary_column_index) + 1,
            boundary_column_index=int(boundary_column_index),
            beam_size=int(beam_size),
            candidate_count=int(len(keys)),
            kept_count=int(min(len(keys), int(beam_size))),
            horizons=tuple(horizon_labels),
            horizon_unit="future_columns",
            survival_lambda=float(survival_lambda),
            survival_clip=float(survival_clip),
            survival_softmin_temperature=float(survival_softmin_temperature),
            survival_cutoff_source=str(cutoff_source_key),
            horizon_order_source=str(horizon_order_source_key),
            horizon_shuffle_seed=int(survival_horizon_shuffle_seed),
            survival_deadline_boost_beta=float(survival_deadline_boost_beta),
            survival_deadline_boost_tau=float(survival_deadline_boost_tau),
            ordinary_cutoff_gap=_finite_beam_survival_cutoff_gap(
                ranked_keys=primary_ranked,
                score_by_key=primary_score_by_key,
                beam_size=int(beam_size),
            ),
            adjusted_cutoff_gap=_finite_beam_survival_cutoff_gap(
                ranked_keys=adjusted_ranked,
                score_by_key=adjusted_score_by_key,
                beam_size=int(beam_size),
            ),
            changed_survivor_count=int(changed_survivor_count),
            primary_topk_distinct_active_masks=_finite_beam_survival_distinct_active_masks(
                keys=ordinary_topk,
                active_mask=int(active_mask),
                detector_mask_mask=int(detector_mask_mask),
            ),
            adjusted_topk_distinct_active_masks=_finite_beam_survival_distinct_active_masks(
                keys=adjusted_topk,
                active_mask=int(active_mask),
                detector_mask_mask=int(detector_mask_mask),
            ),
            mean_survival_value_topk=(
                float(np.mean(np.asarray(topk_survival_values, dtype=np.float64)))
                if topk_survival_values
                else float("nan")
            ),
            mean_survival_value_pool=(
                float(np.mean(np.asarray(pool_survival_values, dtype=np.float64)))
                if pool_survival_values
                else float("nan")
            ),
            min_survival_value_topk=float(min(topk_survival_values)) if topk_survival_values else float("nan"),
            max_survival_value_topk=float(max(topk_survival_values)) if topk_survival_values else float("nan"),
            survival_payload_seconds=float(payload_seconds),
            degraded_to_primary=False,
            degradation_reason="",
            diagnostic_truth_descendant_kept_by_primary=bool(
                diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
            ),
            diagnostic_truth_descendant_kept_by_survival=bool(
                diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in adjusted_topk_set
            ),
            diagnostic_truth_descendant_rank_primary=(
                0
                if diagnostic_truth_state_key is None
                else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
            ),
            diagnostic_truth_descendant_rank_survival=(
                0
                if diagnostic_truth_state_key is None
                else int(adjusted_rank_by_key.get(int(diagnostic_truth_state_key), 0))
            ),
            candidate_samples=tuple(candidate_samples),
        )
    return adjusted_rank_value_by_key, adjusted_ranked, step


def _pressure_microbank_window_column_indices(
    *,
    processed_columns: int,
    total_columns: int,
    window_size: int,
    window_order: str,
) -> tuple[tuple[int, ...], tuple[int, ...]]:
    order_key = _normalize_microbank_window_order(str(window_order))
    start = max(0, min(int(total_columns), int(processed_columns)))
    stop = max(int(start), min(int(total_columns), int(start) + max(0, int(window_size))))
    actual_window = tuple(int(index) for index in range(int(start), int(stop)))
    if str(order_key) == "actual_window":
        micro_window = tuple(actual_window)
    else:
        micro_window = tuple(reversed(actual_window))
    return tuple(actual_window), tuple(micro_window)


def _pressure_microbank_future_score(
    *,
    det_key: int,
    processed_columns: int,
    score_mode_key: str,
    target_syndrome_int: int,
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    clamp_assignments: dict[int, int],
    parity_payload_cache: dict[int, FutureParityBoundaryPayload],
    component_payload_cache: dict[int, FutureComponentHeuristicPayload],
    pairtree_payload_cache: dict[int, FuturePairtreeHeuristicPayload | FuturePairlogoddsHeuristicPayload],
    low_error_payload_cache: dict[tuple[int, int, int], FutureLowErrorHeuristicPayload],
    active_frontier_payload_cache: dict[tuple[int, int], FutureActiveFrontierHeuristicPayload],
    active_frontier_score_cache: dict[tuple[int, int, int], dict[int, float]],
    single_fix_payload_cache: dict[int, FutureSingleFixHeuristicPayload],
    quotient_payload_cache: dict[int, FutureQuotientHeuristicPayload],
    beam_size: int | None,
) -> float:
    if int(processed_columns) >= len(columns):
        return 0.0
    boundary_column_index = int(processed_columns) - 1
    if int(boundary_column_index) < 0:
        active_mask = 0
    else:
        active_mask = int(frontier.active_masks_after_column[int(boundary_column_index)])
    endpoint_features: dict[int, FrontierMismatchFeatures] = {}
    mode_key = str(score_mode_key).strip().lower()
    if _score_mode_uses_future_parity_features(str(mode_key)):
        parity_payload = parity_payload_cache.get(int(boundary_column_index))
        if parity_payload is None:
            parity_payload = _build_future_parity_boundary_payload(
                frontier=frontier,
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
            )
            parity_payload_cache[int(boundary_column_index)] = parity_payload
        endpoint_features[int(det_key)] = _future_mismatch_features_from_payload(
            det_mask=int(det_key),
            target_syndrome_int=int(target_syndrome_int),
            payload=parity_payload,
        )
    return float(
        _boundary_heuristic_mass(
            det_key=int(det_key),
            score_mode_key=str(mode_key),
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            boundary_column_index=int(boundary_column_index),
            beam_size=beam_size,
            columns=columns,
            frontier=frontier,
            clamp_assignments=clamp_assignments,
            features_by_detector=endpoint_features,
            parity_payload_cache=parity_payload_cache,
            component_payload_cache=component_payload_cache,
            pairtree_payload_cache=pairtree_payload_cache,
            low_error_payload_cache=low_error_payload_cache,
            active_frontier_payload_cache=active_frontier_payload_cache,
            active_frontier_score_cache=active_frontier_score_cache,
            single_fix_payload_cache=single_fix_payload_cache,
            quotient_payload_cache=quotient_payload_cache,
        )
    )


def _pressure_microbank_rollout_root_value(
    *,
    root_key: int,
    root_log_mass: float,
    processed_columns: int,
    actual_window_column_indices: Sequence[int],
    micro_window_column_indices: Sequence[int],
    columns: list[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int,
    clamp_assignments: dict[int, int],
    microbank_beam_cap: int,
    score_mode_key: str,
    parity_payload_cache: dict[int, FutureParityBoundaryPayload],
    component_payload_cache: dict[int, FutureComponentHeuristicPayload],
    pairtree_payload_cache: dict[int, FuturePairtreeHeuristicPayload | FuturePairlogoddsHeuristicPayload],
    low_error_payload_cache: dict[tuple[int, int, int], FutureLowErrorHeuristicPayload],
    active_frontier_payload_cache: dict[tuple[int, int], FutureActiveFrontierHeuristicPayload],
    active_frontier_score_cache: dict[tuple[int, int, int], dict[int, float]],
    single_fix_payload_cache: dict[int, FutureSingleFixHeuristicPayload],
    quotient_payload_cache: dict[int, FutureQuotientHeuristicPayload],
    beam_size: int | None,
) -> tuple[float, int, float]:
    detector_mask_mask = (1 << int(num_detectors)) - 1
    local_log_mass: dict[int, float] = {int(root_key): float(root_log_mass)}
    beam_cap = max(1, int(microbank_beam_cap))
    for column_index in tuple(int(value) for value in tuple(micro_window_column_indices)):
        column = columns[int(column_index)]
        log_priors = _column_log_priors(column)
        detector_response_masks = tuple(int(value) for value in column.detector_response_masks)
        logical_response_masks = tuple(int(value) for value in column.logical_response_masks)
        correction_masks = _column_correction_masks(column)
        forced_local_state = clamp_assignments.get(int(column_index))
        state_iter = (
            ((int(forced_local_state), float(log_priors[int(forced_local_state)])),)
            if forced_local_state is not None
            else tuple((int(index), float(value)) for index, value in enumerate(log_priors))
        )
        next_local_log_mass: dict[int, float] = {}
        for state_key, log_mass in tuple(local_log_mass.items()):
            det_mask = _unpack_detector_mask(
                state_key=int(state_key),
                detector_mask_mask=int(detector_mask_mask),
            )
            logical_mask = _unpack_logical_mask(
                state_key=int(state_key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            correction_mask = _unpack_correction_mask(
                state_key=int(state_key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            for local_state, log_prior in state_iter:
                if not math.isfinite(float(log_prior)):
                    continue
                next_det = int(det_mask) ^ int(detector_response_masks[int(local_state)])
                next_logical = int(logical_mask) ^ int(logical_response_masks[int(local_state)])
                next_correction = int(correction_mask) ^ int(correction_masks[int(local_state)])
                next_key = _pack_state_key(
                    det_mask=int(next_det),
                    logical_mask=int(next_logical),
                    correction_mask=int(next_correction),
                    num_detectors=int(num_detectors),
                    num_observables=int(num_observables),
                )
                next_log = float(log_mass) + float(log_prior)
                next_local_log_mass[int(next_key)] = _logaddexp_pair(
                    float(next_local_log_mass.get(int(next_key), float("-inf"))),
                    float(next_log),
                )
        if len(next_local_log_mass) > int(beam_cap):
            kept = sorted(
                next_local_log_mass.items(),
                key=lambda item: (-float(item[1]), int(item[0])),
            )[: int(beam_cap)]
            local_log_mass = {int(key): float(value) for key, value in kept}
        else:
            local_log_mass = dict(next_local_log_mass)
        if not local_log_mass:
            break

    endpoint_processed_columns = int(processed_columns) + len(tuple(actual_window_column_indices))
    endpoint_boundary = int(endpoint_processed_columns) - 1
    endpoint_active_mask = (
        0
        if int(endpoint_boundary) < 0
        else int(frontier.active_masks_after_column[int(endpoint_boundary)])
    )
    root_boundary = int(processed_columns) - 1
    root_active_mask = (
        0
        if int(root_boundary) < 0
        else int(frontier.active_masks_after_column[int(root_boundary)])
    )
    touched_mask = 0
    for column_index in tuple(int(value) for value in tuple(actual_window_column_indices)):
        touched_mask |= int(columns[int(column_index)].detector_support_mask)
    closed_mask = (int(root_active_mask) | int(touched_mask)) & ~int(endpoint_active_mask)
    endpoint_log_mass: dict[int, float] = {}
    for state_key, log_mass in tuple(local_log_mass.items()):
        det_mask = _unpack_detector_mask(
            state_key=int(state_key),
            detector_mask_mask=int(detector_mask_mask),
        )
        if (((int(det_mask) ^ int(target_syndrome_int)) & int(closed_mask)) != 0):
            continue
        logical_mask = _unpack_logical_mask(
            state_key=int(state_key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        correction_mask = _unpack_correction_mask(
            state_key=int(state_key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        endpoint_key = _pack_state_key(
            det_mask=int(det_mask) & int(endpoint_active_mask),
            logical_mask=int(logical_mask),
            correction_mask=int(correction_mask),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        endpoint_log_mass[int(endpoint_key)] = _logaddexp_pair(
            float(endpoint_log_mass.get(int(endpoint_key), float("-inf"))),
            float(log_mass),
        )
    endpoint_scores: list[float] = []
    for state_key, log_mass in tuple(endpoint_log_mass.items()):
        det_key = _unpack_detector_mask(
            state_key=int(state_key),
            detector_mask_mask=int(detector_mask_mask),
        )
        future_score = _pressure_microbank_future_score(
            det_key=int(det_key),
            processed_columns=int(endpoint_processed_columns),
            score_mode_key=str(score_mode_key),
            target_syndrome_int=int(target_syndrome_int),
            columns=columns,
            frontier=frontier,
            clamp_assignments=clamp_assignments,
            parity_payload_cache=parity_payload_cache,
            component_payload_cache=component_payload_cache,
            pairtree_payload_cache=pairtree_payload_cache,
            low_error_payload_cache=low_error_payload_cache,
            active_frontier_payload_cache=active_frontier_payload_cache,
            active_frontier_score_cache=active_frontier_score_cache,
            single_fix_payload_cache=single_fix_payload_cache,
            quotient_payload_cache=quotient_payload_cache,
            beam_size=beam_size,
        )
        endpoint_scores.append(float(log_mass) + float(future_score))
    endpoint_logsum = _logaddexp_many(endpoint_log_mass)
    return float(_logaddexp_many(tuple(endpoint_scores))), int(len(endpoint_log_mass)), float(endpoint_logsum)


def _pressure_microbank_cutoff_gap(
    *,
    ranked_keys: Sequence[int],
    primary_score_by_key: Mapping[int, float],
    beam_size: int,
) -> float:
    ranked = tuple(int(key) for key in tuple(ranked_keys))
    if int(beam_size) <= 0 or len(ranked) <= int(beam_size):
        return float("nan")
    cutoff = float(primary_score_by_key[int(ranked[int(beam_size) - 1])])
    first_pruned = float(primary_score_by_key[int(ranked[int(beam_size)])])
    if math.isfinite(float(cutoff)) and math.isfinite(float(first_pruned)):
        return float(cutoff) - float(first_pruned)
    return float("nan")


def _normalize_probability_vector(values: Sequence[float]) -> tuple[float, ...]:
    arr = np.asarray(tuple(float(value) for value in values), dtype=np.float64)
    arr = np.where(np.isfinite(arr) & (arr > 0.0), arr, 0.0)
    total = float(np.sum(arr))
    if float(total) <= 0.0:
        return tuple(float(1.0 / max(1, int(arr.size))) for _ in range(int(arr.size)))
    return tuple(float(value / total) for value in arr.tolist())


def _suffix_bethe_build_graph(
    *,
    boundary_column_index: int,
    columns: Sequence[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    required_rows_mask: int,
    num_detectors: int,
    clamp_assignments: Mapping[int, int],
) -> SuffixBetheFactorGraph:
    constraint_to_local: dict[int, int] = {}
    target_rows: list[int] = []
    check_base_target: list[int] = []
    check_edges: list[list[int]] = []
    priors: list[tuple[float, ...]] = []
    var_edges: list[list[int]] = []
    edge_var: list[int] = []
    edge_response_bits: list[tuple[int, ...]] = []

    def local_check(row: int) -> int:
        row_i = int(row)
        existing = constraint_to_local.get(row_i)
        if existing is not None:
            return int(existing)
        local = int(len(target_rows))
        constraint_to_local[int(row_i)] = int(local)
        target_rows.append(int(row_i))
        check_base_target.append(0)
        check_edges.append([])
        return int(local)

    for row in _support_rows_from_mask(int(required_rows_mask)):
        if 0 <= int(row) < int(num_detectors):
            local_check(int(row))

    projected_columns = 0
    suffix_columns = tuple(columns)[int(boundary_column_index) + 1 :]
    for column_index, column in enumerate(suffix_columns, start=int(boundary_column_index) + 1):
        log_priors = tuple(float(value) for value in _column_log_priors(column))
        forced_local_state = clamp_assignments.get(int(column_index))
        if forced_local_state is None:
            state_iter = tuple(range(len(log_priors)))
        else:
            forced = int(forced_local_state)
            state_iter = (int(forced),) if 0 <= int(forced) < len(log_priors) else tuple()
        allowed_states = tuple(
            int(local_state)
            for local_state in state_iter
            if math.isfinite(float(log_priors[int(local_state)]))
        )
        if not allowed_states:
            continue
        probs = _normalize_probability_vector(
            tuple(math.exp(float(log_priors[int(local_state)])) for local_state in allowed_states)
        )
        masks = tuple(int(column.detector_response_masks[int(local_state)]) for local_state in allowed_states)
        union_mask = 0
        intersection_mask = (1 << int(num_detectors)) - 1
        for mask in masks:
            union_mask |= int(mask)
            intersection_mask &= int(mask)
        constant_one_mask = int(intersection_mask)
        variable_mask = int(union_mask) ^ int(intersection_mask)
        for row in _support_rows_from_mask(int(constant_one_mask)):
            if 0 <= int(row) < int(num_detectors):
                check = local_check(int(row))
                check_base_target[int(check)] ^= 1
        if int(variable_mask) == 0:
            continue
        projected_columns += 1
        var = int(len(priors))
        priors.append(tuple(float(prob) for prob in probs))
        var_edges.append([])
        for row in _support_rows_from_mask(int(variable_mask)):
            if not (0 <= int(row) < int(num_detectors)):
                continue
            check = local_check(int(row))
            bits = tuple(1 if (int(mask) & (1 << int(row))) else 0 for mask in masks)
            edge = int(len(edge_var))
            edge_var.append(int(var))
            edge_response_bits.append(tuple(int(bit) for bit in bits))
            var_edges[int(var)].append(int(edge))
            check_edges[int(check)].append(int(edge))

    return SuffixBetheFactorGraph(
        priors=tuple(tuple(float(value) for value in prior) for prior in priors),
        edge_var=tuple(int(value) for value in edge_var),
        edge_response_bits=tuple(tuple(int(bit) for bit in bits) for bits in edge_response_bits),
        var_edges=tuple(tuple(int(value) for value in edges) for edges in var_edges),
        check_edges=tuple(tuple(int(value) for value in edges) for edges in check_edges),
        check_base_target=tuple(int(value) for value in check_base_target),
        target_rows=tuple(int(value) for value in target_rows),
        variable_count=int(len(priors)),
        check_count=int(len(check_base_target)),
        edge_count=int(len(edge_var)),
        projected_columns=int(projected_columns),
    )


def _suffix_bethe_target_array(
    *,
    graph: SuffixBetheFactorGraph,
    residual_target_mask: int,
) -> np.ndarray:
    targets = np.asarray(tuple(int(value) for value in graph.check_base_target), dtype=np.int8).copy()
    for local, row in enumerate(tuple(graph.target_rows)):
        if int(residual_target_mask) & (1 << int(row)):
            targets[int(local)] ^= 1
    return targets


def _suffix_bethe_log_partition(
    *,
    graph: SuffixBetheFactorGraph,
    targets: np.ndarray,
    max_iters: int = 16,
    damping: float = 0.35,
    tol: float = 1.0e-5,
) -> SuffixBetheResult:
    if int(graph.edge_count) == 0:
        for check, target in enumerate(tuple(targets.tolist())):
            if int(target) != 0:
                return SuffixBetheResult(
                    log_z=float("-inf"),
                    iterations=0,
                    converged=True,
                    max_delta=0.0,
                )
        return SuffixBetheResult(log_z=0.0, iterations=0, converged=True, max_delta=0.0)

    m_vc: list[np.ndarray] = []
    m_cv: list[np.ndarray] = []
    for edge, var in enumerate(tuple(graph.edge_var)):
        prior = np.asarray(tuple(graph.priors[int(var)]), dtype=np.float64)
        m_vc.append(np.asarray(_normalize_probability_vector(prior.tolist()), dtype=np.float64))
        m_cv.append(np.full(prior.shape, 1.0 / max(1, int(prior.size)), dtype=np.float64))

    damp = min(max(float(damping), 0.0), 0.999)
    converged = False
    max_delta = float("inf")
    iteration = 0
    for iteration in range(1, int(max_iters) + 1):
        old_vc = [arr.copy() for arr in m_vc]
        old_cv = [arr.copy() for arr in m_cv]

        for check, edges in enumerate(tuple(graph.check_edges)):
            if not edges:
                continue
            signs: list[float] = []
            for edge in edges:
                msg = m_vc[int(edge)]
                bits = tuple(graph.edge_response_bits[int(edge)])
                signs.append(
                    float(
                        sum(
                            float(msg[int(state)]) * (1.0 if int(bits[int(state)]) == 0 else -1.0)
                            for state in range(int(msg.size))
                        )
                    )
                )
            degree = int(len(edges))
            prefix = np.ones(degree + 1, dtype=np.float64)
            suffix = np.ones(degree + 1, dtype=np.float64)
            for idx in range(degree):
                prefix[int(idx) + 1] = float(prefix[int(idx)]) * float(signs[int(idx)])
            for idx in range(degree - 1, -1, -1):
                suffix[int(idx)] = float(suffix[int(idx) + 1]) * float(signs[int(idx)])
            target = int(targets[int(check)])
            for idx, edge in enumerate(tuple(edges)):
                prod_except = float(prefix[int(idx)] * suffix[int(idx) + 1])
                bits = tuple(graph.edge_response_bits[int(edge)])
                q = np.empty(m_cv[int(edge)].shape, dtype=np.float64)
                for state, bit in enumerate(bits):
                    needed = int(target) ^ int(bit)
                    sign = -1.0 if int(needed) else 1.0
                    q[int(state)] = 0.5 * (1.0 + float(sign) * float(prod_except))
                q = np.asarray(_normalize_probability_vector(q.tolist()), dtype=np.float64)
                if damp > 0.0:
                    q = np.asarray(
                        _normalize_probability_vector(
                            (float(damp) * old_cv[int(edge)] + (1.0 - float(damp)) * q).tolist()
                        ),
                        dtype=np.float64,
                    )
                m_cv[int(edge)] = q

        for var, edges in enumerate(tuple(graph.var_edges)):
            if not edges:
                continue
            prior = np.asarray(tuple(graph.priors[int(var)]), dtype=np.float64)
            for edge in tuple(edges):
                q = prior.copy()
                for other in tuple(edges):
                    if int(other) == int(edge):
                        continue
                    q *= m_cv[int(other)]
                q = np.asarray(_normalize_probability_vector(q.tolist()), dtype=np.float64)
                if damp > 0.0:
                    q = np.asarray(
                        _normalize_probability_vector(
                            (float(damp) * old_vc[int(edge)] + (1.0 - float(damp)) * q).tolist()
                        ),
                        dtype=np.float64,
                    )
                m_vc[int(edge)] = q

        max_delta = 0.0
        for edge in range(int(graph.edge_count)):
            max_delta = max(
                float(max_delta),
                float(np.max(np.abs(m_vc[int(edge)] - old_vc[int(edge)]))),
                float(np.max(np.abs(m_cv[int(edge)] - old_cv[int(edge)]))),
            )
        if float(max_delta) <= float(tol):
            converged = True
            break

    tiny = 1.0e-300
    log_z = 0.0
    for check, edges in enumerate(tuple(graph.check_edges)):
        if not edges:
            if int(targets[int(check)]) != 0:
                return SuffixBetheResult(
                    log_z=float("-inf"),
                    iterations=int(iteration),
                    converged=bool(converged),
                    max_delta=float(max_delta),
                )
            continue
        sign_prod = 1.0
        for edge in tuple(edges):
            msg = m_vc[int(edge)]
            bits = tuple(graph.edge_response_bits[int(edge)])
            sign_prod *= float(
                sum(
                    float(msg[int(state)]) * (1.0 if int(bits[int(state)]) == 0 else -1.0)
                    for state in range(int(msg.size))
                )
            )
        parity_sign = -1.0 if int(targets[int(check)]) else 1.0
        z_check = 0.5 * (1.0 + float(parity_sign) * float(sign_prod))
        log_z += math.log(max(float(z_check), tiny))

    for var, edges in enumerate(tuple(graph.var_edges)):
        prior = np.asarray(tuple(graph.priors[int(var)]), dtype=np.float64)
        z_var = prior.copy()
        for edge in tuple(edges):
            z_var *= m_cv[int(edge)]
        log_z += math.log(max(float(np.sum(z_var)), tiny))

    for edge in range(int(graph.edge_count)):
        z_edge = float(np.sum(m_vc[int(edge)] * m_cv[int(edge)]))
        log_z -= math.log(max(float(z_edge), tiny))

    return SuffixBetheResult(
        log_z=float(log_z),
        iterations=int(iteration),
        converged=bool(converged),
        max_delta=float(max_delta),
    )


def _bounded_suffix_message_logical_distribution(
    *,
    state_key: int,
    boundary_column_index: int,
    columns: Sequence[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    target_syndrome_int: int,
    num_detectors: int,
    num_observables: int,
    clamp_assignments: Mapping[int, int],
    suffix_state_cap: int,
) -> SuffixMessageLogicalDistributionResult:
    if int(boundary_column_index) < 0:
        active_mask = 0
    else:
        active_mask = int(frontier.active_masks_after_column[int(boundary_column_index)])
    active_rows = _support_rows_from_mask(int(active_mask))
    row_to_local = {int(row): int(local) for local, row in enumerate(active_rows)}
    detector_rows = int(len(active_rows))
    logical_rows = int(num_observables)
    logical_count = 1 << int(logical_rows)
    logical_mask_all = ((1 << int(logical_rows)) - 1) << int(detector_rows)
    detector_mask_mask = (1 << int(num_detectors)) - 1
    state_detector = _unpack_detector_mask(
        state_key=int(state_key),
        detector_mask_mask=int(detector_mask_mask),
    )
    state_logical = _unpack_logical_mask(
        state_key=int(state_key),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
    )
    initial_mask = _project_mask_to_rows(int(state_detector), row_to_local)
    target_detector_mask = _project_mask_to_rows(int(target_syndrome_int), row_to_local)

    projected_columns: list[dict[int, float]] = []
    last_detector_touch = [-1 for _ in range(int(detector_rows))]
    for column_index, column in enumerate(tuple(columns)[int(boundary_column_index) + 1 :], start=int(boundary_column_index) + 1):
        local_mass: dict[int, float] = {}
        log_priors = _column_log_priors(column)
        forced_local_state = clamp_assignments.get(int(column_index))
        if forced_local_state is None:
            state_iter = tuple(range(len(tuple(log_priors))))
        else:
            forced_value = int(forced_local_state)
            if int(forced_value) < 0 or int(forced_value) >= len(tuple(log_priors)):
                state_iter = tuple()
            else:
                state_iter = (int(forced_value),)
        detector_support_mask = 0
        for local_state in state_iter:
            log_prior = float(log_priors[int(local_state)])
            if not math.isfinite(float(log_prior)):
                continue
            det_part = _project_mask_to_rows(
                int(column.detector_response_masks[int(local_state)]),
                row_to_local,
            )
            logical_part = int(column.logical_response_masks[int(local_state)]) << int(detector_rows)
            projected = int(det_part) | int(logical_part)
            local_mass[int(projected)] = _logaddexp_pair(
                float(local_mass.get(int(projected), float("-inf"))),
                float(log_prior),
            )
            detector_support_mask |= int(det_part)
        if not local_mass:
            continue
        if len(local_mass) == 1 and 0 in local_mass and math.isclose(
            float(local_mass[0]),
            0.0,
            abs_tol=1e-15,
        ):
            continue
        projected_index = int(len(projected_columns))
        for row in range(int(detector_rows)):
            if (int(detector_support_mask) >> int(row)) & 1:
                last_detector_touch[int(row)] = int(projected_index)
        projected_columns.append(dict(local_mass))

    empty = [float("-inf") for _ in range(int(logical_count))]
    if not projected_columns:
        if int(initial_mask) == int(target_detector_mask):
            empty[int(state_logical)] = 0.0
        return SuffixMessageLogicalDistributionResult(
            logical_log_mass=tuple(float(value) for value in empty),
            exact_within_cap=True,
            prune_steps=0,
            max_states=1,
            active_detector_rows=int(detector_rows),
            projected_rows=int(detector_rows + logical_rows),
            projected_columns=0,
        )

    frozen_detector_mask = 0
    for row, last in enumerate(tuple(last_detector_touch)):
        if int(last) < 0:
            frozen_detector_mask |= 1 << int(row)
    if ((int(initial_mask) ^ int(target_detector_mask)) & int(frozen_detector_mask)) != 0:
        return SuffixMessageLogicalDistributionResult(
            logical_log_mass=tuple(float(value) for value in empty),
            exact_within_cap=True,
            prune_steps=0,
            max_states=1,
            active_detector_rows=int(detector_rows),
            projected_rows=int(detector_rows + logical_rows),
            projected_columns=int(len(projected_columns)),
        )
    initial_mask &= ~int(frozen_detector_mask)
    target_detector_mask &= ~int(frozen_detector_mask)

    state_log_mass: dict[int, float] = {int(initial_mask): 0.0}
    prune_steps = 0
    max_states = 1
    exact = True
    cap = int(suffix_state_cap)
    for projected_index, local_mass in enumerate(tuple(projected_columns)):
        close_mask = 0
        active_after = int(logical_mask_all)
        for row, last in enumerate(tuple(last_detector_touch)):
            if int(last) == int(projected_index):
                close_mask |= 1 << int(row)
            elif int(last) > int(projected_index):
                active_after |= 1 << int(row)
        next_log_mass: dict[int, float] = {}
        for mask, prefix in tuple(state_log_mass.items()):
            for delta_mask, log_prior in tuple(local_mass.items()):
                candidate = int(mask) ^ int(delta_mask)
                if ((int(candidate) ^ int(target_detector_mask)) & int(close_mask)) != 0:
                    continue
                next_mask = int(candidate) & int(active_after)
                next_log_mass[int(next_mask)] = _logaddexp_pair(
                    float(next_log_mass.get(int(next_mask), float("-inf"))),
                    float(prefix) + float(log_prior),
                )
        state_log_mass = dict(next_log_mass)
        max_states = max(int(max_states), int(len(state_log_mass)))
        if not state_log_mass:
            return SuffixMessageLogicalDistributionResult(
                logical_log_mass=tuple(float(value) for value in empty),
                exact_within_cap=True,
                prune_steps=int(prune_steps),
                max_states=int(max_states),
                active_detector_rows=int(detector_rows),
                projected_rows=int(detector_rows + logical_rows),
                projected_columns=int(len(projected_columns)),
            )
        if int(cap) > 0 and len(state_log_mass) > int(cap):
            exact = False
            prune_steps += 1
            kept = sorted(
                state_log_mass.items(),
                key=lambda item: (float(item[1]), -int(item[0])),
                reverse=True,
            )[: int(cap)]
            state_log_mass = {int(mask): float(log_mass) for mask, log_mass in kept}

    logical_log_mass = [float("-inf") for _ in range(int(logical_count))]
    future_mask_limit = (1 << int(logical_rows)) - 1
    for mask, log_mass in tuple(state_log_mass.items()):
        future_logical = (int(mask) >> int(detector_rows)) & int(future_mask_limit)
        terminal_logical = int(state_logical) ^ int(future_logical)
        logical_log_mass[int(terminal_logical)] = _logaddexp_pair(
            float(logical_log_mass[int(terminal_logical)]),
            float(log_mass),
        )
    return SuffixMessageLogicalDistributionResult(
        logical_log_mass=tuple(float(value) for value in logical_log_mass),
        exact_within_cap=bool(exact),
        prune_steps=int(prune_steps),
        max_states=int(max_states),
        active_detector_rows=int(detector_rows),
        projected_rows=int(detector_rows + logical_rows),
        projected_columns=int(len(projected_columns)),
    )


def _suffix_message_distribution_summary(
    logical_log_mass: Sequence[float],
) -> tuple[int, float, int, float]:
    finite = [
        (int(index), float(value))
        for index, value in enumerate(tuple(logical_log_mass))
        if math.isfinite(float(value))
    ]
    if not finite:
        return -1, float("-inf"), 0, float("nan")
    top_logical, top_log_mass = max(finite, key=lambda item: (float(item[1]), -int(item[0])))
    total = _logaddexp_many(tuple(float(value) for _logical, value in finite))
    entropy = 0.0
    if math.isfinite(float(total)):
        for _logical, value in finite:
            probability = float(math.exp(float(value) - float(total)))
            if float(probability) > 0.0 and math.isfinite(float(probability)):
                entropy -= float(probability) * float(math.log(float(probability)))
    else:
        entropy = float("nan")
    return int(top_logical), float(top_log_mass), int(len(finite)), float(entropy)


def _suffix_message_reserve_rank_candidates(
    *,
    candidate_keys: Sequence[int],
    primary_rank_value_by_key: Mapping[int, tuple[float, float, float]],
    prefix_log_mass_by_key: Mapping[int, float],
    beam_size: int,
    boundary_column_index: int,
    num_detectors: int,
    num_observables: int,
    suffix_message_trigger_policy: str,
    suffix_message_cutoff_gap_threshold: float,
    suffix_message_overflow_ratio_threshold: float,
    suffix_message_near_cut_width: int,
    suffix_message_reserve_slots: int,
    suffix_message_state_cap: int,
    suffix_message_max_roots: int,
    suffix_message_lambda: float,
    suffix_message_clip: float,
    trigger_allowed: bool,
    evaluator,
    diagnostics: bool = False,
    diagnostic_truth_state_key: int | None = None,
) -> tuple[list[int], ProgressiveSuffixMessageReserveStep | None]:
    keys = tuple(int(key) for key in tuple(candidate_keys))
    trigger_policy_key = _normalize_suffix_message_trigger_policy(str(suffix_message_trigger_policy))
    if int(beam_size) <= 0:
        return list(keys), None
    stable_candidate_key_by_key = {int(key): _stable_candidate_key_for_state(int(key)) for key in keys}
    primary_ranked = _finite_beam_survival_primary_order(
        candidate_keys=keys,
        primary_rank_value_by_key=primary_rank_value_by_key,
        stable_candidate_key_by_key=stable_candidate_key_by_key,
    )
    primary_rank_by_key = {int(key): int(index) + 1 for index, key in enumerate(primary_ranked)}
    primary_score_by_key = {
        int(key): float(primary_rank_value_by_key[int(key)][0])
        for key in keys
    }
    ordinary_topk = tuple(int(key) for key in primary_ranked[: int(beam_size)])
    ordinary_topk_set = {int(key) for key in ordinary_topk}
    cutoff_gap = _pressure_microbank_cutoff_gap(
        ranked_keys=primary_ranked,
        primary_score_by_key=primary_score_by_key,
        beam_size=int(beam_size),
    )
    overflow_ratio = float(len(keys)) / float(max(1, int(beam_size)))
    trigger_reasons: list[str] = []
    if str(trigger_policy_key) == "always":
        trigger_reasons.append("always")
    else:
        if math.isfinite(float(cutoff_gap)) and float(cutoff_gap) <= float(suffix_message_cutoff_gap_threshold):
            trigger_reasons.append("cutoff_gap")
        if (
            str(trigger_policy_key) == "risk_union"
            and float(overflow_ratio) >= float(suffix_message_overflow_ratio_threshold)
        ):
            trigger_reasons.append("overflow_ratio")
    trigger_fired = bool(len(keys) > int(beam_size) and bool(trigger_reasons) and bool(trigger_allowed))
    degradation_reason = ""
    degraded_to_primary = False
    if len(keys) <= int(beam_size):
        degradation_reason = "no_truncation"
    elif not bool(trigger_allowed):
        degradation_reason = "max_triggered_boundaries"
        degraded_to_primary = True
    elif not bool(trigger_reasons):
        degradation_reason = "trigger_not_fired"

    if not bool(trigger_fired):
        step = None
        if bool(diagnostics) or bool(degraded_to_primary):
            truth_rank = 0 if diagnostic_truth_state_key is None else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
            step = ProgressiveSuffixMessageReserveStep(
                processed_columns=int(boundary_column_index) + 1,
                boundary_column_index=int(boundary_column_index),
                beam_size=int(beam_size),
                candidate_count=int(len(keys)),
                cutoff_gap=float(cutoff_gap),
                overflow_ratio=float(overflow_ratio),
                trigger_fired=False,
                trigger_reasons=tuple(trigger_reasons),
                protected_count=0,
                reserve_slots=int(suffix_message_reserve_slots),
                near_cut_pool_size=0,
                evaluated_roots=0,
                suffix_state_cap=int(suffix_message_state_cap),
                suffix_lambda=float(suffix_message_lambda),
                suffix_clip=float(suffix_message_clip),
                changed_survivor_count=0,
                selected_new_not_in_primary_topk=0,
                distinct_suffix_top_logicals=0,
                suffix_payload_s=0.0,
                degraded_to_primary=bool(degraded_to_primary),
                degradation_reason=str(degradation_reason),
                diagnostic_truth_descendant_kept_by_primary=bool(
                    diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
                ),
                diagnostic_truth_descendant_kept_by_suffix=bool(
                    diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
                ),
                diagnostic_truth_descendant_rank_primary=int(truth_rank),
                diagnostic_truth_descendant_rank_suffix=int(truth_rank),
                candidate_samples=tuple(),
            )
        return list(int(key) for key in ordinary_topk), step

    clip_value = float(suffix_message_clip)
    if math.isnan(float(clip_value)) or not math.isfinite(float(clip_value)) or float(clip_value) < 0.0:
        raise ValueError("suffix_message_clip must be finite and >= 0")
    if math.isnan(float(suffix_message_lambda)) or not math.isfinite(float(suffix_message_lambda)):
        raise ValueError("suffix_message_lambda must be finite")
    protected_count = max(0, int(beam_size) - max(0, int(suffix_message_reserve_slots)))
    protected = tuple(int(key) for key in primary_ranked[: int(protected_count)])
    protected_set = {int(key) for key in protected}
    near_stop = min(len(primary_ranked), int(beam_size) + max(0, int(suffix_message_near_cut_width)))
    near_cut_pool = tuple(int(key) for key in primary_ranked[int(protected_count) : int(near_stop)])
    if int(suffix_message_max_roots) > 0 and len(near_cut_pool) > int(suffix_message_max_roots):
        near_cut_pool = tuple(int(key) for key in near_cut_pool[: int(suffix_message_max_roots)])
    ordinary_unprotected = tuple(int(key) for key in primary_ranked[int(protected_count) : int(beam_size)])
    universe: list[int] = []
    seen: set[int] = set()
    for key in (*near_cut_pool, *ordinary_unprotected):
        if int(key) in protected_set or int(key) in seen:
            continue
        seen.add(int(key))
        universe.append(int(key))

    payload_started = time.perf_counter()
    suffix_result_by_key: dict[int, SuffixMessageLogicalDistributionResult] = {}
    suffix_score_by_key: dict[int, float] = {}
    suffix_margin_by_key: dict[int, float] = {}
    adjusted_score_by_key: dict[int, float] = {}
    suffix_top_logical_by_key: dict[int, int] = {}
    suffix_top_log_mass_by_key: dict[int, float] = {}
    suffix_distinct_by_key: dict[int, int] = {}
    suffix_entropy_by_key: dict[int, float] = {}
    for key in near_cut_pool:
        result = evaluator(int(key))
        suffix_result_by_key[int(key)] = result
        top_logical, top_log_mass, distinct, entropy = _suffix_message_distribution_summary(
            result.logical_log_mass
        )
        suffix_top_logical_by_key[int(key)] = int(top_logical)
        suffix_top_log_mass_by_key[int(key)] = float(top_log_mass)
        suffix_distinct_by_key[int(key)] = int(distinct)
        suffix_entropy_by_key[int(key)] = float(entropy)
        prefix_score = float(prefix_log_mass_by_key.get(int(key), float("-inf")))
        suffix_score_by_key[int(key)] = (
            float(prefix_score) + float(top_log_mass)
            if math.isfinite(float(prefix_score)) and math.isfinite(float(top_log_mass))
            else float("-inf")
        )
    payload_s = float(time.perf_counter() - float(payload_started))

    for key in universe:
        primary_score = float(primary_score_by_key[int(key)])
        if int(key) in suffix_score_by_key:
            raw_margin = float(suffix_score_by_key[int(key)]) - float(primary_score)
            if not math.isfinite(float(raw_margin)):
                raw_margin = -float(clip_value)
            margin = max(-float(clip_value), min(float(clip_value), float(raw_margin)))
        else:
            margin = 0.0
        suffix_margin_by_key[int(key)] = float(margin)
        adjusted_score_by_key[int(key)] = float(primary_score) + float(suffix_message_lambda) * float(margin)

    adjusted_unprotected = tuple(
        int(key)
        for key in sorted(
            universe,
            key=lambda key: (
                -float(_score_for_descending_sort(adjusted_score_by_key[int(key)])),
                -float(_score_for_descending_sort(suffix_score_by_key.get(int(key), float("-inf")))),
                -float(_score_for_descending_sort(primary_score_by_key[int(key)])),
                int(primary_rank_by_key[int(key)]),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
    )
    selected: list[int] = list(int(key) for key in protected)
    selected_seen: set[int] = set(selected)
    represented_logicals: set[int] = {
        int(
            _unpack_logical_mask(
                state_key=int(key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
        )
        for key in protected
    }
    reserve_slots = max(0, int(beam_size) - int(protected_count))
    for key in adjusted_unprotected:
        if len(selected) >= int(beam_size) or len(selected) - int(protected_count) >= int(reserve_slots):
            break
        suffix_top = int(suffix_top_logical_by_key.get(int(key), -1))
        if int(suffix_top) < 0 or int(suffix_top) in represented_logicals:
            continue
        if int(key) in selected_seen:
            continue
        selected.append(int(key))
        selected_seen.add(int(key))
        represented_logicals.add(int(suffix_top))
    for key in adjusted_unprotected:
        if len(selected) >= int(beam_size):
            break
        if int(key) in selected_seen:
            continue
        selected.append(int(key))
        selected_seen.add(int(key))
        suffix_top = int(suffix_top_logical_by_key.get(int(key), -1))
        if int(suffix_top) >= 0:
            represented_logicals.add(int(suffix_top))
    if len(selected) < int(beam_size):
        for key in primary_ranked:
            if len(selected) >= int(beam_size):
                break
            if int(key) in selected_seen:
                continue
            selected.append(int(key))
            selected_seen.add(int(key))
    selected = list(int(key) for key in selected[: int(beam_size)])
    selected_set = {int(key) for key in selected}
    changed_survivor_count = int(len(ordinary_topk_set.symmetric_difference(selected_set)))
    selected_new_not_in_primary_topk = int(sum(1 for key in selected_set if int(key) not in ordinary_topk_set))
    adjusted_ranked_all = tuple(
        int(key)
        for key in sorted(
            keys,
            key=lambda key: (
                -float(_score_for_descending_sort(adjusted_score_by_key.get(int(key), primary_score_by_key[int(key)]))),
                -float(_score_for_descending_sort(suffix_score_by_key.get(int(key), float("-inf")))),
                -float(_score_for_descending_sort(primary_score_by_key[int(key)])),
                int(primary_rank_by_key[int(key)]),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
    )
    adjusted_rank_by_key = {int(key): int(index) + 1 for index, key in enumerate(adjusted_ranked_all)}

    candidate_samples: list[SuffixMessageReserveCandidateSample] = []
    if bool(diagnostics):
        sample_keys = set(int(key) for key in universe)
        sample_keys.update(int(key) for key in ordinary_topk)
        if diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in keys:
            sample_keys.add(int(diagnostic_truth_state_key))
        ordered_sample_keys = sorted(
            sample_keys,
            key=lambda key: (
                min(int(primary_rank_by_key.get(int(key), 10**9)), int(adjusted_rank_by_key.get(int(key), 10**9))),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
        for key in ordered_sample_keys:
            suffix_result = suffix_result_by_key.get(int(key))
            candidate_samples.append(
                SuffixMessageReserveCandidateSample(
                    processed_columns=int(boundary_column_index) + 1,
                    boundary_column_index=int(boundary_column_index),
                    candidate_key=str(stable_candidate_key_by_key[int(key)]),
                    state_key=int(key),
                    primary_rank=int(primary_rank_by_key.get(int(key), 0)),
                    adjusted_rank=int(adjusted_rank_by_key.get(int(key), 0)),
                    primary_score=float(primary_score_by_key[int(key)]),
                    suffix_score=float(suffix_score_by_key.get(int(key), float("nan"))),
                    suffix_margin=float(suffix_margin_by_key.get(int(key), 0.0)),
                    adjusted_score=float(adjusted_score_by_key.get(int(key), primary_score_by_key[int(key)])),
                    prefix_score=float(prefix_log_mass_by_key.get(int(key), float("nan"))),
                    suffix_top_logical=int(suffix_top_logical_by_key.get(int(key), -1)),
                    suffix_top_log_mass=float(suffix_top_log_mass_by_key.get(int(key), float("nan"))),
                    suffix_distinct_logicals=int(suffix_distinct_by_key.get(int(key), 0)),
                    suffix_entropy=float(suffix_entropy_by_key.get(int(key), float("nan"))),
                    suffix_exact_within_cap=(
                        bool(suffix_result.exact_within_cap) if suffix_result is not None else False
                    ),
                    suffix_prune_steps=int(suffix_result.prune_steps) if suffix_result is not None else 0,
                    suffix_max_states=int(suffix_result.max_states) if suffix_result is not None else 0,
                    ordinary_topk_member=bool(int(key) in ordinary_topk_set),
                    suffix_topk_member=bool(int(key) in selected_set),
                    selected_by_suffix_not_primary=bool(
                        int(key) in selected_set and int(key) not in ordinary_topk_set
                    ),
                    selected_by_primary_not_suffix=bool(
                        int(key) in ordinary_topk_set and int(key) not in selected_set
                    ),
                    diagnostic_truth_descendant=bool(
                        diagnostic_truth_state_key is not None and int(key) == int(diagnostic_truth_state_key)
                    ),
                )
            )

    step = ProgressiveSuffixMessageReserveStep(
        processed_columns=int(boundary_column_index) + 1,
        boundary_column_index=int(boundary_column_index),
        beam_size=int(beam_size),
        candidate_count=int(len(keys)),
        cutoff_gap=float(cutoff_gap),
        overflow_ratio=float(overflow_ratio),
        trigger_fired=True,
        trigger_reasons=tuple(trigger_reasons),
        protected_count=int(protected_count),
        reserve_slots=int(suffix_message_reserve_slots),
        near_cut_pool_size=int(len(near_cut_pool)),
        evaluated_roots=int(len(suffix_result_by_key)),
        suffix_state_cap=int(suffix_message_state_cap),
        suffix_lambda=float(suffix_message_lambda),
        suffix_clip=float(suffix_message_clip),
        changed_survivor_count=int(changed_survivor_count),
        selected_new_not_in_primary_topk=int(selected_new_not_in_primary_topk),
        distinct_suffix_top_logicals=int(
            len({int(value) for value in suffix_top_logical_by_key.values() if int(value) >= 0})
        ),
        suffix_payload_s=float(payload_s),
        degraded_to_primary=False,
        degradation_reason="",
        diagnostic_truth_descendant_kept_by_primary=bool(
            diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
        ),
        diagnostic_truth_descendant_kept_by_suffix=bool(
            diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in selected_set
        ),
        diagnostic_truth_descendant_rank_primary=(
            0
            if diagnostic_truth_state_key is None
            else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
        ),
        diagnostic_truth_descendant_rank_suffix=(
            0
            if diagnostic_truth_state_key is None
            else int(adjusted_rank_by_key.get(int(diagnostic_truth_state_key), 0))
        ),
        candidate_samples=tuple(candidate_samples),
    )
    return selected, step


def _pressure_microbank_rank_candidates(
    *,
    candidate_keys: Sequence[int],
    primary_rank_value_by_key: Mapping[int, tuple[float, float, float]],
    beam_size: int,
    boundary_column_index: int,
    microbank_trigger_policy: str,
    microbank_cutoff_gap_threshold: float,
    microbank_overflow_ratio_threshold: float,
    microbank_near_cut_width: int,
    microbank_rerank_slots: int,
    microbank_window_size: int,
    microbank_window_order: str,
    microbank_beam_cap: int,
    microbank_max_roots: int,
    microbank_lambda: float,
    microbank_clip: float,
    trigger_allowed: bool,
    evaluator,
    diagnostics: bool = False,
    diagnostic_truth_state_key: int | None = None,
) -> tuple[list[int], ProgressivePressureMicrobankStep | None]:
    keys = tuple(int(key) for key in tuple(candidate_keys))
    trigger_policy_key = _normalize_microbank_trigger_policy(str(microbank_trigger_policy))
    window_order_key = _normalize_microbank_window_order(str(microbank_window_order))
    if int(beam_size) <= 0:
        return list(keys), None
    stable_candidate_key_by_key = {int(key): _stable_candidate_key_for_state(int(key)) for key in keys}
    primary_ranked = _finite_beam_survival_primary_order(
        candidate_keys=keys,
        primary_rank_value_by_key=primary_rank_value_by_key,
        stable_candidate_key_by_key=stable_candidate_key_by_key,
    )
    primary_rank_by_key = {int(key): int(index) + 1 for index, key in enumerate(primary_ranked)}
    primary_score_by_key = {
        int(key): float(primary_rank_value_by_key[int(key)][0])
        for key in keys
    }
    ordinary_topk = tuple(int(key) for key in primary_ranked[: int(beam_size)])
    ordinary_topk_set = {int(key) for key in ordinary_topk}
    cutoff_gap = _pressure_microbank_cutoff_gap(
        ranked_keys=primary_ranked,
        primary_score_by_key=primary_score_by_key,
        beam_size=int(beam_size),
    )
    overflow_ratio = float(len(keys)) / float(max(1, int(beam_size)))
    trigger_reasons: list[str] = []
    if str(trigger_policy_key) == "always":
        trigger_reasons.append("always")
    else:
        if math.isfinite(float(cutoff_gap)) and float(cutoff_gap) <= float(microbank_cutoff_gap_threshold):
            trigger_reasons.append("cutoff_gap")
        if (
            str(trigger_policy_key) == "risk_union"
            and float(overflow_ratio) >= float(microbank_overflow_ratio_threshold)
        ):
            trigger_reasons.append("overflow_ratio")
    trigger_fired = bool(len(keys) > int(beam_size) and bool(trigger_reasons) and bool(trigger_allowed))
    degradation_reason = ""
    degraded_to_primary = False
    if len(keys) <= int(beam_size):
        degradation_reason = "no_truncation"
    elif not bool(trigger_allowed):
        degradation_reason = "max_triggered_boundaries"
        degraded_to_primary = True
    elif not bool(trigger_reasons):
        degradation_reason = "trigger_not_fired"

    if not bool(trigger_fired):
        step = None
        if bool(diagnostics) or bool(degraded_to_primary):
            truth_rank = 0 if diagnostic_truth_state_key is None else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
            step = ProgressivePressureMicrobankStep(
                processed_columns=int(boundary_column_index) + 1,
                boundary_column_index=int(boundary_column_index),
                beam_size=int(beam_size),
                candidate_count=int(len(keys)),
                cutoff_gap=float(cutoff_gap),
                overflow_ratio=float(overflow_ratio),
                trigger_fired=False,
                trigger_reasons=tuple(trigger_reasons),
                protected_count=0,
                rerank_slots=int(microbank_rerank_slots),
                near_cut_pool_size=0,
                evaluated_roots=0,
                microbank_window_size=int(microbank_window_size),
                microbank_window_order=str(window_order_key),
                microbank_beam_cap=int(microbank_beam_cap),
                microbank_lambda=float(microbank_lambda),
                microbank_clip=float(microbank_clip),
                changed_survivor_count=0,
                selected_new_not_in_primary_topk=0,
                microbank_payload_s=0.0,
                degraded_to_primary=bool(degraded_to_primary),
                degradation_reason=str(degradation_reason),
                diagnostic_truth_descendant_kept_by_primary=bool(
                    diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
                ),
                diagnostic_truth_descendant_kept_by_microbank=bool(
                    diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
                ),
                diagnostic_truth_descendant_rank_primary=int(truth_rank),
                diagnostic_truth_descendant_rank_microbank=int(truth_rank),
                candidate_samples=tuple(),
            )
        return list(int(key) for key in ordinary_topk), step

    clip_value = float(microbank_clip)
    if math.isnan(float(clip_value)) or not math.isfinite(float(clip_value)) or float(clip_value) < 0.0:
        raise ValueError("microbank_clip must be finite and >= 0")
    if math.isnan(float(microbank_lambda)) or not math.isfinite(float(microbank_lambda)):
        raise ValueError("microbank_lambda must be finite")
    protected_count = max(0, int(beam_size) - max(0, int(microbank_rerank_slots)))
    protected = tuple(int(key) for key in primary_ranked[: int(protected_count)])
    protected_set = {int(key) for key in protected}
    near_stop = min(len(primary_ranked), int(beam_size) + max(0, int(microbank_near_cut_width)))
    near_cut_pool = tuple(int(key) for key in primary_ranked[int(protected_count) : int(near_stop)])
    if int(microbank_max_roots) > 0 and len(near_cut_pool) > int(microbank_max_roots):
        near_cut_pool = tuple(int(key) for key in near_cut_pool[: int(microbank_max_roots)])
    ordinary_unprotected = tuple(int(key) for key in primary_ranked[int(protected_count) : int(beam_size)])
    universe: list[int] = []
    seen: set[int] = set()
    for key in (*near_cut_pool, *ordinary_unprotected):
        if int(key) in protected_set or int(key) in seen:
            continue
        seen.add(int(key))
        universe.append(int(key))

    payload_started = time.perf_counter()
    microbank_value_by_key: dict[int, float] = {}
    endpoint_count_by_key: dict[int, int] = {}
    endpoint_logsum_by_key: dict[int, float] = {}
    for key in near_cut_pool:
        value, endpoint_count, endpoint_logsum = evaluator(int(key))
        microbank_value_by_key[int(key)] = float(value)
        endpoint_count_by_key[int(key)] = int(endpoint_count)
        endpoint_logsum_by_key[int(key)] = float(endpoint_logsum)
    payload_s = float(time.perf_counter() - float(payload_started))

    values = [float(value) for value in microbank_value_by_key.values() if not math.isnan(float(value))]
    if values:
        sorted_values = sorted(values, reverse=True)
        unprotected_slots = max(1, int(beam_size) - int(protected_count))
        if len(sorted_values) >= int(unprotected_slots):
            micro_cutoff = float(sorted_values[int(unprotected_slots) - 1])
        else:
            micro_cutoff = float(np.median(np.asarray(sorted_values, dtype=np.float64)))
    else:
        micro_cutoff = float("-inf")
    microbank_margin_by_key: dict[int, float] = {}
    adjusted_score_by_key: dict[int, float] = {}
    for key in universe:
        primary_score = float(primary_score_by_key[int(key)])
        if int(key) in microbank_value_by_key:
            raw_margin = float(microbank_value_by_key[int(key)]) - float(micro_cutoff)
            if not math.isfinite(float(raw_margin)):
                raw_margin = -float(clip_value)
            margin = max(-float(clip_value), min(float(clip_value), float(raw_margin)))
        else:
            margin = 0.0
        microbank_margin_by_key[int(key)] = float(margin)
        adjusted_score_by_key[int(key)] = float(primary_score) + float(microbank_lambda) * float(margin)

    adjusted_unprotected = tuple(
        int(key)
        for key in sorted(
            universe,
            key=lambda key: (
                -float(_score_for_descending_sort(adjusted_score_by_key[int(key)])),
                -float(_score_for_descending_sort(primary_score_by_key[int(key)])),
                int(primary_rank_by_key[int(key)]),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
    )
    unprotected_slots = max(0, int(beam_size) - int(protected_count))
    selected: list[int] = list(int(key) for key in protected)
    selected_seen: set[int] = set(selected)
    for key in adjusted_unprotected:
        if len(selected) >= int(beam_size):
            break
        if int(key) in selected_seen:
            continue
        selected.append(int(key))
        selected_seen.add(int(key))
    if len(selected) < int(beam_size):
        for key in primary_ranked:
            if len(selected) >= int(beam_size):
                break
            if int(key) in selected_seen:
                continue
            selected.append(int(key))
            selected_seen.add(int(key))
    selected = list(int(key) for key in selected[: int(beam_size)])
    selected_set = {int(key) for key in selected}
    changed_survivor_count = int(len(ordinary_topk_set.symmetric_difference(selected_set)))
    selected_new_not_in_primary_topk = int(sum(1 for key in selected_set if int(key) not in ordinary_topk_set))

    candidate_samples: list[PressureMicrobankCandidateSample] = []
    adjusted_ranked_all = tuple(
        int(key)
        for key in sorted(
            keys,
            key=lambda key: (
                -float(_score_for_descending_sort(adjusted_score_by_key.get(int(key), primary_score_by_key[int(key)]))),
                -float(_score_for_descending_sort(primary_score_by_key[int(key)])),
                int(primary_rank_by_key[int(key)]),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
    )
    adjusted_rank_by_key = {int(key): int(index) + 1 for index, key in enumerate(adjusted_ranked_all)}
    if bool(diagnostics):
        sample_keys = set(int(key) for key in universe)
        sample_keys.update(int(key) for key in ordinary_topk)
        if diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in keys:
            sample_keys.add(int(diagnostic_truth_state_key))
        ordered_sample_keys = sorted(
            sample_keys,
            key=lambda key: (
                min(int(primary_rank_by_key.get(int(key), 10**9)), int(adjusted_rank_by_key.get(int(key), 10**9))),
                str(stable_candidate_key_by_key[int(key)]),
            ),
        )
        for key in ordered_sample_keys:
            microbank_value = float(microbank_value_by_key.get(int(key), float("nan")))
            margin = float(microbank_margin_by_key.get(int(key), 0.0))
            adjusted_score = float(adjusted_score_by_key.get(int(key), primary_score_by_key[int(key)]))
            candidate_samples.append(
                PressureMicrobankCandidateSample(
                    processed_columns=int(boundary_column_index) + 1,
                    boundary_column_index=int(boundary_column_index),
                    candidate_key=str(stable_candidate_key_by_key[int(key)]),
                    state_key=int(key),
                    primary_rank=int(primary_rank_by_key.get(int(key), 0)),
                    adjusted_rank=int(adjusted_rank_by_key.get(int(key), 0)),
                    primary_score=float(primary_score_by_key[int(key)]),
                    microbank_value=float(microbank_value),
                    microbank_margin=float(margin),
                    adjusted_score=float(adjusted_score),
                    ordinary_topk_member=bool(int(key) in ordinary_topk_set),
                    microbank_topk_member=bool(int(key) in selected_set),
                    selected_by_microbank_not_primary=bool(
                        int(key) in selected_set and int(key) not in ordinary_topk_set
                    ),
                    selected_by_primary_not_microbank=bool(
                        int(key) in ordinary_topk_set and int(key) not in selected_set
                    ),
                    endpoint_count=int(endpoint_count_by_key.get(int(key), 0)),
                    endpoint_logsum=float(endpoint_logsum_by_key.get(int(key), float("nan"))),
                    diagnostic_truth_descendant=bool(
                        diagnostic_truth_state_key is not None and int(key) == int(diagnostic_truth_state_key)
                    ),
                )
            )
    step = ProgressivePressureMicrobankStep(
        processed_columns=int(boundary_column_index) + 1,
        boundary_column_index=int(boundary_column_index),
        beam_size=int(beam_size),
        candidate_count=int(len(keys)),
        cutoff_gap=float(cutoff_gap),
        overflow_ratio=float(overflow_ratio),
        trigger_fired=True,
        trigger_reasons=tuple(trigger_reasons),
        protected_count=int(protected_count),
        rerank_slots=int(microbank_rerank_slots),
        near_cut_pool_size=int(len(near_cut_pool)),
        evaluated_roots=int(len(microbank_value_by_key)),
        microbank_window_size=int(microbank_window_size),
        microbank_window_order=str(window_order_key),
        microbank_beam_cap=int(microbank_beam_cap),
        microbank_lambda=float(microbank_lambda),
        microbank_clip=float(microbank_clip),
        changed_survivor_count=int(changed_survivor_count),
        selected_new_not_in_primary_topk=int(selected_new_not_in_primary_topk),
        microbank_payload_s=float(payload_s),
        degraded_to_primary=False,
        degradation_reason="",
        diagnostic_truth_descendant_kept_by_primary=bool(
            diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in ordinary_topk_set
        ),
        diagnostic_truth_descendant_kept_by_microbank=bool(
            diagnostic_truth_state_key is not None and int(diagnostic_truth_state_key) in selected_set
        ),
        diagnostic_truth_descendant_rank_primary=(
            0
            if diagnostic_truth_state_key is None
            else int(primary_rank_by_key.get(int(diagnostic_truth_state_key), 0))
        ),
        diagnostic_truth_descendant_rank_microbank=(
            0
            if diagnostic_truth_state_key is None
            else int(adjusted_rank_by_key.get(int(diagnostic_truth_state_key), 0))
        ),
        candidate_samples=tuple(candidate_samples),
    )
    return selected, step


def _logical_distribution_metrics_from_state_keys(
    *,
    state_keys: Sequence[int],
    state_log_mass: dict[int, float],
    num_detectors: int,
    num_observables: int,
) -> tuple[float, float]:
    logical_log_mass_by_mask: dict[int, float] = {}
    for key in state_keys:
        log_mass = float(state_log_mass.get(int(key), float("-inf")))
        if not math.isfinite(float(log_mass)):
            continue
        logical_mask = _unpack_logical_mask(
            state_key=int(key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        previous = logical_log_mass_by_mask.get(int(logical_mask), float("-inf"))
        logical_log_mass_by_mask[int(logical_mask)] = _logaddexp_pair(float(previous), float(log_mass))
    if not logical_log_mass_by_mask:
        return float("nan"), float("nan")
    total_log_mass = float("-inf")
    for value in logical_log_mass_by_mask.values():
        total_log_mass = _logaddexp_pair(float(total_log_mass), float(value))
    if not math.isfinite(float(total_log_mass)):
        return float("nan"), float("nan")
    probabilities = [
        float(math.exp(float(log_mass) - float(total_log_mass)))
        for log_mass in logical_log_mass_by_mask.values()
        if math.isfinite(float(log_mass))
    ]
    finite_probabilities = [
        float(value)
        for value in probabilities
        if math.isfinite(float(value)) and float(value) > 0.0
    ]
    if not finite_probabilities:
        return float("nan"), float("nan")
    entropy = -sum(
        float(probability) * float(math.log(float(probability)))
        for probability in finite_probabilities
    )
    return (
        float(math.exp(max(0.0, float(entropy)))),
        float(max(finite_probabilities)),
    )


def _bridge_block_beam_overrides_from_columns(
    columns: Sequence[ProgressiveColumn],
    *,
    bridge_block_beam_size: int,
    bridge_block_round_span_min: int = 2,
) -> dict[int, int]:
    if int(bridge_block_beam_size) <= 0:
        return {}
    if int(bridge_block_round_span_min) < 2:
        raise ValueError("bridge_block_round_span_min must be >= 2")
    overrides: dict[int, int] = {}
    for boundary_column_index, column in enumerate(tuple(columns)):
        round_span = _progressive_column_round_span_from_label(column)
        if round_span is None:
            continue
        round_start, round_stop = round_span
        span = int(round_stop) - int(round_start) + 1
        if int(span) < int(bridge_block_round_span_min):
            continue
        if int(round_stop) <= int(round_start):
            continue
        overrides[int(boundary_column_index)] = int(bridge_block_beam_size)
    return overrides


def _adaptive_sparse_block_beam_override(
    *,
    columns: Sequence[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    candidate_state_count: int,
    beam_limit: int,
    cutoff_gap: float,
    adaptive_sparse_block_beam_size: int,
    adaptive_sparse_block_trigger_mode: str = "cutoff_gap",
    adaptive_sparse_block_gap_threshold: float = 0.0,
    adaptive_sparse_block_overflow_ratio_min: float = 0.0,
    adaptive_sparse_block_overflow_ratio_max: float = float("inf"),
    adaptive_sparse_block_support_gap_threshold: float = 0.0,
    adaptive_sparse_block_candidate_top1_share_max: float = 1.0,
    candidate_logical_effective_support: float = float("nan"),
    kept_logical_effective_support: float = float("nan"),
    candidate_logical_top1_share: float = float("nan"),
    kept_logical_top1_share: float = float("nan"),
    adaptive_sparse_block_max_closing_count: int = 0,
    adaptive_sparse_block_min_closure_block_len: int = 0,
    adaptive_sparse_block_bridge_round_span_min: int = 0,
) -> int:
    decision = _adaptive_sparse_block_beam_decision(
        columns=columns,
        frontier=frontier,
        boundary_column_index=boundary_column_index,
        candidate_state_count=candidate_state_count,
        beam_limit=beam_limit,
        cutoff_gap=cutoff_gap,
        adaptive_sparse_block_beam_size=adaptive_sparse_block_beam_size,
        adaptive_sparse_block_trigger_mode=adaptive_sparse_block_trigger_mode,
        adaptive_sparse_block_gap_threshold=adaptive_sparse_block_gap_threshold,
        adaptive_sparse_block_overflow_ratio_min=adaptive_sparse_block_overflow_ratio_min,
        adaptive_sparse_block_overflow_ratio_max=adaptive_sparse_block_overflow_ratio_max,
        adaptive_sparse_block_support_gap_threshold=adaptive_sparse_block_support_gap_threshold,
        adaptive_sparse_block_candidate_top1_share_max=adaptive_sparse_block_candidate_top1_share_max,
        candidate_logical_effective_support=candidate_logical_effective_support,
        kept_logical_effective_support=kept_logical_effective_support,
        candidate_logical_top1_share=candidate_logical_top1_share,
        kept_logical_top1_share=kept_logical_top1_share,
        adaptive_sparse_block_max_closing_count=adaptive_sparse_block_max_closing_count,
        adaptive_sparse_block_min_closure_block_len=adaptive_sparse_block_min_closure_block_len,
        adaptive_sparse_block_bridge_round_span_min=adaptive_sparse_block_bridge_round_span_min,
    )
    return int(decision.widened_beam_size)


def _adaptive_sparse_block_beam_decision(
    *,
    columns: Sequence[ProgressiveColumn],
    frontier: ProgressiveFrontierLayout,
    boundary_column_index: int,
    candidate_state_count: int,
    beam_limit: int,
    cutoff_gap: float,
    adaptive_sparse_block_beam_size: int,
    adaptive_sparse_block_trigger_mode: str = "cutoff_gap",
    adaptive_sparse_block_gap_threshold: float = 0.0,
    adaptive_sparse_block_overflow_ratio_min: float = 0.0,
    adaptive_sparse_block_overflow_ratio_max: float = float("inf"),
    adaptive_sparse_block_support_gap_threshold: float = 0.0,
    adaptive_sparse_block_candidate_top1_share_max: float = 1.0,
    candidate_logical_effective_support: float = float("nan"),
    kept_logical_effective_support: float = float("nan"),
    candidate_logical_top1_share: float = float("nan"),
    kept_logical_top1_share: float = float("nan"),
    adaptive_sparse_block_max_closing_count: int = 0,
    adaptive_sparse_block_min_closure_block_len: int = 0,
    adaptive_sparse_block_bridge_round_span_min: int = 0,
) -> AdaptiveSparseBlockBeamDecision:
    gate_enabled = bool(int(adaptive_sparse_block_beam_size) > 0)
    trigger_mode = _normalize_adaptive_sparse_block_trigger_mode(str(adaptive_sparse_block_trigger_mode))
    beam_limit_value = int(beam_limit)
    target_beam_size = max(0, int(adaptive_sparse_block_beam_size))
    candidate_overflow = bool(int(candidate_state_count) > int(beam_limit_value))
    overflow_ratio = (
        float(int(candidate_state_count)) / float(max(1, int(beam_limit_value)))
        if int(beam_limit_value) > 0
        else float("nan")
    )
    support_gap = (
        float(candidate_logical_effective_support) - float(kept_logical_effective_support)
        if math.isfinite(float(candidate_logical_effective_support))
        and math.isfinite(float(kept_logical_effective_support))
        else float("nan")
    )
    gap_threshold = float(adaptive_sparse_block_gap_threshold)
    overflow_ratio_min = float(adaptive_sparse_block_overflow_ratio_min)
    overflow_ratio_max = float(adaptive_sparse_block_overflow_ratio_max)
    support_gap_threshold = float(adaptive_sparse_block_support_gap_threshold)
    candidate_top1_share_max = float(adaptive_sparse_block_candidate_top1_share_max)
    signal_value = float("nan")
    signal_threshold_low = float("nan")
    signal_threshold_high = float("nan")
    signal_ok = False
    closing_count = -1
    closure_block_len = 0
    round_span = 0
    long_sparse_signal = False
    bridge_signal = False
    structural_ok = False
    gap_ok = False
    def _decision(*, widened_beam_size: int, triggered: bool, reason: str, structural_ok_value: bool) -> AdaptiveSparseBlockBeamDecision:
        return AdaptiveSparseBlockBeamDecision(
            widened_beam_size=int(widened_beam_size),
            gate_enabled=bool(gate_enabled),
            beam_limit=int(beam_limit_value),
            target_beam_size=int(target_beam_size),
            candidate_overflow=bool(candidate_overflow),
            overflow_ratio=float(overflow_ratio),
            cutoff_gap=float(cutoff_gap),
            gap_threshold=float(gap_threshold),
            gap_ok=bool(gap_ok),
            trigger_mode=str(trigger_mode),
            signal_value=float(signal_value),
            signal_threshold_low=float(signal_threshold_low),
            signal_threshold_high=float(signal_threshold_high),
            signal_ok=bool(signal_ok),
            candidate_logical_effective_support=float(candidate_logical_effective_support),
            kept_logical_effective_support=float(kept_logical_effective_support),
            support_gap=float(support_gap),
            candidate_logical_top1_share=float(candidate_logical_top1_share),
            kept_logical_top1_share=float(kept_logical_top1_share),
            closing_count=int(closing_count),
            closure_block_len=int(closure_block_len),
            round_span=int(round_span),
            long_sparse_signal=bool(long_sparse_signal),
            bridge_signal=bool(bridge_signal),
            structural_ok=bool(structural_ok_value),
            triggered=bool(triggered),
            reason=str(reason),
        )

    if int(adaptive_sparse_block_beam_size) <= 0:
        return _decision(widened_beam_size=0, triggered=False, reason="disabled", structural_ok_value=False)
    if int(beam_limit) <= 0 or int(adaptive_sparse_block_beam_size) <= int(beam_limit):
        return _decision(
            widened_beam_size=0,
            triggered=False,
            reason=("no_beam_limit" if int(beam_limit) <= 0 else "target_not_larger"),
            structural_ok_value=False,
        )
    if int(candidate_state_count) <= int(beam_limit):
        return _decision(widened_beam_size=0, triggered=False, reason="no_overflow", structural_ok_value=False)
    if math.isnan(float(adaptive_sparse_block_gap_threshold)):
        raise ValueError("adaptive_sparse_block_gap_threshold must not be NaN")
    if math.isfinite(float(adaptive_sparse_block_gap_threshold)) and float(adaptive_sparse_block_gap_threshold) < 0.0:
        raise ValueError("adaptive_sparse_block_gap_threshold must be >= 0 when finite")
    if math.isnan(float(overflow_ratio_min)) or not math.isfinite(float(overflow_ratio_min)) or float(overflow_ratio_min) < 0.0:
        raise ValueError("adaptive_sparse_block_overflow_ratio_min must be finite and >= 0")
    if math.isnan(float(overflow_ratio_max)) or float(overflow_ratio_max) < float(overflow_ratio_min):
        raise ValueError("adaptive_sparse_block_overflow_ratio_max must be >= adaptive_sparse_block_overflow_ratio_min")
    if math.isfinite(float(overflow_ratio_max)) and float(overflow_ratio_max) < 0.0:
        raise ValueError("adaptive_sparse_block_overflow_ratio_max must be >= 0 when finite")
    if math.isnan(float(support_gap_threshold)) or not math.isfinite(float(support_gap_threshold)) or float(support_gap_threshold) < 0.0:
        raise ValueError("adaptive_sparse_block_support_gap_threshold must be finite and >= 0")
    if math.isnan(float(candidate_top1_share_max)) or not math.isfinite(float(candidate_top1_share_max)):
        raise ValueError("adaptive_sparse_block_candidate_top1_share_max must be finite")
    if float(candidate_top1_share_max) < 0.0 or float(candidate_top1_share_max) > 1.0:
        raise ValueError("adaptive_sparse_block_candidate_top1_share_max must be in [0, 1]")
    if int(adaptive_sparse_block_max_closing_count) < 0:
        raise ValueError("adaptive_sparse_block_max_closing_count must be >= 0")
    if int(adaptive_sparse_block_min_closure_block_len) < 0:
        raise ValueError("adaptive_sparse_block_min_closure_block_len must be >= 0")
    if int(adaptive_sparse_block_bridge_round_span_min) not in (0, 1) and int(
        adaptive_sparse_block_bridge_round_span_min
    ) < 2:
        raise ValueError("adaptive_sparse_block_bridge_round_span_min must be 0 or >= 2")
    if int(boundary_column_index) < 0 or int(boundary_column_index) >= len(columns):
        return _decision(widened_beam_size=0, triggered=False, reason="out_of_range", structural_ok_value=False)
    closing_count = int(int(frontier.closing_masks[int(boundary_column_index)]).bit_count())
    if int(closing_count) > int(adaptive_sparse_block_max_closing_count):
        return _decision(
            widened_beam_size=0,
            triggered=False,
            reason="closure_too_dense",
            structural_ok_value=False,
        )
    block_start = int(frontier.closure_block_start_by_column[int(boundary_column_index)])
    block_end = int(frontier.closure_block_end_by_column[int(boundary_column_index)])
    closure_block_len = max(1, int(block_end) - int(block_start) + 1)
    structural_signals: list[bool] = []
    if int(adaptive_sparse_block_min_closure_block_len) > 0:
        long_sparse_signal = bool(int(closure_block_len) >= int(adaptive_sparse_block_min_closure_block_len))
        structural_signals.append(bool(long_sparse_signal))
    if int(adaptive_sparse_block_bridge_round_span_min) >= 2:
        round_span_pair = _progressive_column_round_span_from_label(columns[int(boundary_column_index)])
        bridge_ok = False
        if round_span_pair is not None:
            round_start, round_stop = round_span_pair
            span = int(round_stop) - int(round_start) + 1
            round_span = int(span)
            bridge_ok = bool(
                int(round_stop) > int(round_start)
                and int(span) >= int(adaptive_sparse_block_bridge_round_span_min)
            )
        bridge_signal = bool(bridge_ok)
        structural_signals.append(bool(bridge_signal))
    structural_ok = bool(not structural_signals or any(bool(value) for value in structural_signals))
    if not bool(structural_ok):
        return _decision(widened_beam_size=0, triggered=False, reason="not_structural", structural_ok_value=False)

    if str(trigger_mode) in {"cutoff_gap", "underfill_cutoff_gap"}:
        signal_value = float(cutoff_gap)
        signal_threshold_high = float(gap_threshold)
        gap_ok = bool(math.isfinite(float(cutoff_gap)) and float(cutoff_gap) <= float(gap_threshold))
        signal_ok = bool(gap_ok)
        if not math.isfinite(float(cutoff_gap)):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="nonfinite_gap",
                structural_ok_value=True,
            )
        if not bool(signal_ok):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="gap_too_large",
                structural_ok_value=True,
            )
    elif str(trigger_mode) == "overflow_ratio":
        signal_value = float(overflow_ratio)
        signal_threshold_low = float(overflow_ratio_min)
        signal_threshold_high = float(overflow_ratio_max)
        signal_ok = bool(
            math.isfinite(float(overflow_ratio))
            and float(overflow_ratio) >= float(overflow_ratio_min)
            and float(overflow_ratio) <= float(overflow_ratio_max)
        )
        if not math.isfinite(float(overflow_ratio)):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="nonfinite_signal",
                structural_ok_value=True,
            )
        if not bool(signal_ok):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="overflow_ratio_out_of_band",
                structural_ok_value=True,
            )
    elif str(trigger_mode) == "support_gap":
        signal_value = float(support_gap)
        signal_threshold_low = float(support_gap_threshold)
        signal_ok = bool(
            math.isfinite(float(support_gap))
            and float(support_gap) >= float(support_gap_threshold)
        )
        if not math.isfinite(float(support_gap)):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="nonfinite_signal",
                structural_ok_value=True,
            )
        if not bool(signal_ok):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="support_gap_too_small",
                structural_ok_value=True,
            )
    elif str(trigger_mode) == "candidate_top1_share":
        signal_value = float(candidate_logical_top1_share)
        signal_threshold_high = float(candidate_top1_share_max)
        signal_ok = bool(
            math.isfinite(float(candidate_logical_top1_share))
            and float(candidate_logical_top1_share) <= float(candidate_top1_share_max)
        )
        if not math.isfinite(float(candidate_logical_top1_share)):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="nonfinite_signal",
                structural_ok_value=True,
            )
        if not bool(signal_ok):
            return _decision(
                widened_beam_size=0,
                triggered=False,
                reason="top1_share_too_high",
                structural_ok_value=True,
            )
    else:
        raise AssertionError(f"unexpected adaptive sparse trigger mode: {trigger_mode}")

    return _decision(widened_beam_size=int(adaptive_sparse_block_beam_size), triggered=True, reason="triggered", structural_ok_value=True)


def _normalize_beam_score_gap_policy(policy: BeamScoreGapPolicy | None) -> BeamScoreGapPolicy | None:
    if policy is None:
        return None
    mode = str(policy.mode).strip().lower()
    allowed_modes = {
        "fixed",
        "linear_columns",
        "active_log",
        "candidate_log",
        "probe_width_log",
        "boundary_gap",
        "boundary_largest_gap",
    }
    if mode not in allowed_modes:
        raise ValueError(f"beam_score_gap_policy.mode must be one of {sorted(allowed_modes)}")
    base_threshold = float(policy.base_threshold)
    if math.isnan(float(base_threshold)) or not math.isfinite(float(base_threshold)) or float(base_threshold) < 0.0:
        raise ValueError("beam_score_gap_policy.base_threshold must be finite and >= 0")
    final_threshold = float(policy.final_threshold)
    if mode in {"linear_columns", "probe_width_log", "boundary_gap"}:
        if math.isnan(float(final_threshold)) or not math.isfinite(float(final_threshold)) or float(final_threshold) < 0.0:
            raise ValueError(
                "beam_score_gap_policy.final_threshold must be finite and >= 0 for "
                "linear_columns/probe_width_log/boundary_gap modes"
            )
    if mode == "boundary_gap" and float(final_threshold) < float(base_threshold):
        raise ValueError("beam_score_gap_policy.final_threshold must be >= base_threshold for boundary_gap")
    slope = float(policy.slope)
    if math.isnan(float(slope)) or not math.isfinite(float(slope)):
        raise ValueError("beam_score_gap_policy.slope must be finite")
    reference_count = float(policy.reference_count)
    if math.isnan(float(reference_count)) or not math.isfinite(float(reference_count)) or float(reference_count) <= 0.0:
        raise ValueError("beam_score_gap_policy.reference_count must be finite and > 0")
    min_threshold = float(policy.min_threshold)
    max_threshold = float(policy.max_threshold)
    if math.isnan(float(min_threshold)) or float(min_threshold) < 0.0:
        raise ValueError("beam_score_gap_policy.min_threshold must be >= 0")
    if math.isnan(float(max_threshold)) or float(max_threshold) < float(min_threshold):
        raise ValueError("beam_score_gap_policy.max_threshold must be >= min_threshold")
    return BeamScoreGapPolicy(
        mode=str(mode),
        base_threshold=float(base_threshold),
        final_threshold=float(final_threshold),
        slope=float(slope),
        reference_count=float(reference_count),
        min_threshold=float(min_threshold),
        max_threshold=float(max_threshold),
    )


def _resolve_beam_score_gap_threshold_for_boundary(
    *,
    beam_score_gap_threshold: float | None,
    beam_score_gap_overrides_by_boundary: dict[int, float] | None = None,
    beam_score_gap_policy: BeamScoreGapPolicy | None,
    boundary_column_index: int,
    total_columns: int,
    active_mask: int,
    candidate_state_count: int,
) -> float | None:
    if beam_score_gap_overrides_by_boundary is not None and int(boundary_column_index) in beam_score_gap_overrides_by_boundary:
        override = float(beam_score_gap_overrides_by_boundary[int(boundary_column_index)])
        if not _score_gap_threshold_enabled(override):
            return None
        return float(override)
    if beam_score_gap_policy is None:
        if not _score_gap_threshold_enabled(beam_score_gap_threshold):
            return None
        return float(beam_score_gap_threshold)
    policy = beam_score_gap_policy
    mode = str(policy.mode)
    if mode == "probe_width_log":
        return None
    threshold = float(policy.base_threshold)
    if mode == "linear_columns":
        if int(total_columns) <= 1:
            progress = 1.0
        else:
            progress = float(int(boundary_column_index)) / float(max(1, int(total_columns) - 1))
            progress = min(1.0, max(0.0, float(progress)))
        threshold = float(policy.base_threshold) + float(progress) * float(
            float(policy.final_threshold) - float(policy.base_threshold)
        )
    elif mode == "active_log":
        active_count = int(int(active_mask).bit_count())
        threshold = float(policy.base_threshold) + float(policy.slope) * float(
            math.log1p(float(active_count) / float(policy.reference_count))
        )
    elif mode == "candidate_log":
        threshold = float(policy.base_threshold) + float(policy.slope) * float(
            math.log1p(float(max(0, int(candidate_state_count))) / float(policy.reference_count))
        )
    threshold = max(float(policy.min_threshold), min(float(threshold), float(policy.max_threshold)))
    return float(threshold)


def _realize_beam_score_gap_threshold_from_ranked_keys(
    *,
    beam_score_gap_threshold: float | None,
    beam_score_gap_policy: BeamScoreGapPolicy | None,
    ranked_keys: Sequence[int],
    rank_value_by_key: dict[int, tuple[float, float, float]],
) -> float | None:
    if beam_score_gap_policy is None:
        if not _score_gap_threshold_enabled(beam_score_gap_threshold):
            return None
        return float(beam_score_gap_threshold)
    policy = _normalize_beam_score_gap_policy(beam_score_gap_policy)
    if policy is None:
        if not _score_gap_threshold_enabled(beam_score_gap_threshold):
            return None
        return float(beam_score_gap_threshold)
    mode = str(policy.mode)
    if mode == "boundary_gap":
        base_threshold = (
            float(beam_score_gap_threshold)
            if _score_gap_threshold_enabled(beam_score_gap_threshold)
            else float(policy.base_threshold)
        )
        base_threshold = max(
            float(policy.min_threshold),
            min(float(base_threshold), float(policy.max_threshold)),
        )
        max_threshold = max(
            float(base_threshold),
            min(float(policy.final_threshold), float(policy.max_threshold)),
        )
        if not ranked_keys or float(max_threshold) <= float(base_threshold):
            return float(base_threshold)
        max_extra = int(math.floor(float(policy.reference_count)))
        if int(max_extra) <= 0:
            return float(base_threshold)
        best_score = float(rank_value_by_key[int(ranked_keys[0])][0])
        gaps: list[float] = []
        for key in ranked_keys:
            score = float(rank_value_by_key[int(key)][0])
            gaps.append(float(best_score - score))
        eps = 1.0e-12
        base_count = 0
        for gap in gaps:
            if float(gap) <= float(base_threshold) + eps:
                base_count += 1
            else:
                break
        if int(base_count) >= len(gaps):
            return float(base_threshold)
        if float(gaps[int(base_count)]) > float(max_threshold) + eps:
            return float(base_threshold)
        last_extra_index = min(len(gaps) - 1, int(base_count) + int(max_extra) - 1)
        min_post_gap = max(0.0, float(policy.slope))
        chosen_index: int | None = None
        for index in range(int(base_count), int(last_extra_index) + 1):
            if float(gaps[int(index)]) > float(max_threshold) + eps:
                break
            if int(index) + 1 >= len(gaps):
                break
            post_gap = float(gaps[int(index) + 1] - gaps[int(index)])
            if float(post_gap) >= float(min_post_gap):
                chosen_index = int(index)
                break
        if chosen_index is None:
            return float(base_threshold)
        threshold = max(float(base_threshold), float(gaps[int(chosen_index)]))
        threshold = max(float(policy.min_threshold), min(float(threshold), float(policy.max_threshold)))
        return float(threshold)
    if mode == "boundary_largest_gap":
        base_threshold = (
            float(beam_score_gap_threshold)
            if _score_gap_threshold_enabled(beam_score_gap_threshold)
            else float(policy.base_threshold)
        )
        base_threshold = max(
            float(policy.min_threshold),
            min(float(base_threshold), float(policy.max_threshold)),
        )
        if not ranked_keys:
            return float(base_threshold)
        window = max(0.0, float(policy.reference_count))
        lower_threshold = max(float(policy.min_threshold), float(base_threshold) - float(window))
        upper_threshold = min(float(policy.max_threshold), float(base_threshold) + float(window))
        if float(upper_threshold) < float(lower_threshold):
            return float(base_threshold)
        best_score = float(rank_value_by_key[int(ranked_keys[0])][0])
        gaps: list[float] = []
        for key in ranked_keys:
            score = float(rank_value_by_key[int(key)][0])
            gaps.append(float(best_score - score))
        min_adjacent_gap = max(0.0, float(policy.slope))
        eps = 1.0e-12
        best_cut_threshold: float | None = None
        best_adjacent_gap = -1.0
        for index in range(0, len(gaps) - 1):
            left_gap = float(gaps[int(index)])
            right_gap = float(gaps[int(index) + 1])
            if float(right_gap) <= float(left_gap) + eps:
                continue
            if float(left_gap) > float(upper_threshold) + eps:
                break
            if float(left_gap) < float(lower_threshold) - eps:
                continue
            adjacent_gap = float(right_gap - left_gap)
            if float(adjacent_gap) < float(min_adjacent_gap) - eps:
                continue
            cut_threshold = min(float(left_gap), float(upper_threshold))
            if float(cut_threshold) >= float(right_gap) - eps:
                continue
            if float(adjacent_gap) > float(best_adjacent_gap) + eps:
                best_adjacent_gap = float(adjacent_gap)
                best_cut_threshold = float(cut_threshold)
        if best_cut_threshold is None:
            return float(base_threshold)
        threshold = max(float(policy.min_threshold), min(float(best_cut_threshold), float(policy.max_threshold)))
        return float(threshold)
    if mode != "probe_width_log":
        if not _score_gap_threshold_enabled(beam_score_gap_threshold):
            return None
        return float(beam_score_gap_threshold)
    if not ranked_keys:
        return float(
            max(float(policy.min_threshold), min(float(policy.base_threshold), float(policy.max_threshold)))
        )
    probe_threshold = float(policy.final_threshold)
    best_score = float(rank_value_by_key[int(ranked_keys[0])][0])
    probe_cutoff = float(best_score - float(probe_threshold))
    probe_width = sum(
        1
        for key in ranked_keys
        if float(rank_value_by_key[int(key)][0]) >= float(probe_cutoff)
    )
    threshold = float(policy.base_threshold) + float(policy.slope) * float(
        math.log1p(float(probe_width) / float(policy.reference_count))
    )
    threshold = max(float(policy.min_threshold), min(float(threshold), float(policy.max_threshold)))
    return float(threshold)


def _select_keys_score_gap(
    *,
    ranked_keys: Sequence[int],
    rank_value_by_key: dict[int, tuple[float, float, float]],
    score_gap_threshold: float | None,
    beam_size: int | None = None,
) -> list[int]:
    if not ranked_keys:
        return []
    if not _score_gap_threshold_enabled(score_gap_threshold):
        return [int(key) for key in ranked_keys]
    threshold = float(score_gap_threshold)
    best_score = float(rank_value_by_key[int(ranked_keys[0])][0])
    cutoff = float(best_score - threshold)
    kept_keys = [
        int(key)
        for key in ranked_keys
        if float(rank_value_by_key[int(key)][0]) >= float(cutoff)
    ]
    if beam_size is None:
        return kept_keys
    beam_limit = int(beam_size)
    if beam_limit <= 0 or len(kept_keys) <= beam_limit:
        return kept_keys
    return [int(key) for key in kept_keys[:beam_limit]]


def _finalize_multi_score_survivor_union_kept_keys(
    *,
    primary_ranked_keys: Sequence[int],
    union_set: set[int],
    eligible_union_set: set[int],
    target_beam_size: int,
    fill_mode_key: str,
) -> list[int]:
    target = int(target_beam_size)
    if target <= 0:
        return []
    fill_mode = str(fill_mode_key)
    kept = [int(key) for key in primary_ranked_keys if int(key) in union_set]
    if fill_mode in {
        "strict_budget_union",
        "threshold_union_full",
        "threshold_intersection_full",
    }:
        return [int(key) for key in kept[:target]]
    if len(kept) < target:
        kept_set = {int(key) for key in kept}
        for key in primary_ranked_keys:
            key_int = int(key)
            if key_int in kept_set:
                continue
            if fill_mode == "threshold_union" and key_int not in eligible_union_set:
                continue
            kept.append(int(key_int))
            kept_set.add(int(key_int))
            if len(kept) >= target:
                break
    if len(kept) > target:
        kept = [int(key) for key in kept[:target]]
    return kept


def _normalize_multi_score_survivor_fill_mode(mode: str) -> str:
    key = str(mode).strip().lower()
    if not key:
        return "topoff"
    aliases = {
        "default": "topoff",
        "primary": "topoff",
        "primary_topoff": "topoff",
        "threshold": "threshold_union",
        "threshold-union": "threshold_union",
        "gap": "threshold_union",
        "gap_union": "threshold_union",
        "threshold_full": "threshold_union_full",
        "threshold-full": "threshold_union_full",
        "full_threshold": "threshold_union_full",
        "full-threshold": "threshold_union_full",
        "gap_full": "threshold_union_full",
        "full_gap": "threshold_union_full",
        "threshold_intersection": "threshold_intersection_full",
        "threshold-intersection": "threshold_intersection_full",
        "intersection": "threshold_intersection_full",
        "intersection_full": "threshold_intersection_full",
        "intersection-full": "threshold_intersection_full",
        "full_intersection": "threshold_intersection_full",
        "full-intersection": "threshold_intersection_full",
        "gap_intersection": "threshold_intersection_full",
        "intersection_gap": "threshold_intersection_full",
        "all_threshold": "threshold_intersection_full",
        "all-threshold": "threshold_intersection_full",
        "strict": "strict_budget_union",
        "strict_budget": "strict_budget_union",
        "strict-budget": "strict_budget_union",
        "budget_union": "strict_budget_union",
        "budget-union": "strict_budget_union",
        "primary_count": "primary_count_topoff",
        "primary-count": "primary_count_topoff",
        "primary_count_topoff": "primary_count_topoff",
        "primary-count-topoff": "primary_count_topoff",
        "baseline_count": "primary_count_topoff",
        "baseline-count": "primary_count_topoff",
        "baseline_count_topoff": "primary_count_topoff",
        "baseline-count-topoff": "primary_count_topoff",
        "ordinary_count": "primary_count_topoff",
        "ordinary-count": "primary_count_topoff",
    }
    key = aliases.get(key, key)
    if key not in {
        "topoff",
        "threshold_union",
        "threshold_union_full",
        "threshold_intersection_full",
        "strict_budget_union",
        "primary_count_topoff",
    }:
        raise ValueError(
            "multi_score_survivor_fill_mode must be 'topoff', 'threshold_union', "
            "'threshold_union_full', 'threshold_intersection_full', "
            "'strict_budget_union', or 'primary_count_topoff'"
        )
    return str(key)


