    if int(near_cut_lineage_reserve_reserved_slots) < 0:
        raise ValueError("near_cut_lineage_reserve_reserved_slots must be >= 0")
    if int(near_cut_lineage_reserve_ttl) < 0:
        raise ValueError("near_cut_lineage_reserve_ttl must be >= 0")
    if int(near_cut_lineage_reserve_branch_slots_per_origin) < 1:
        raise ValueError("near_cut_lineage_reserve_branch_slots_per_origin must be >= 1")
    if int(near_cut_lineage_reserve_trace_min_boundary) < 0:
        raise ValueError("near_cut_lineage_reserve_trace_min_boundary must be >= 0")
    if int(near_cut_lineage_reserve_trace_max_boundary) < -1:
        raise ValueError("near_cut_lineage_reserve_trace_max_boundary must be >= -1")
    if int(near_cut_lineage_reserve_trace_top_origins) < 0:
        raise ValueError("near_cut_lineage_reserve_trace_top_origins must be >= 0")
    if int(near_cut_lineage_reserve_trace_min_boundary) < 0:
        raise ValueError("near_cut_lineage_reserve_trace_min_boundary must be >= 0")
    if int(near_cut_lineage_reserve_trace_max_boundary) < -1:
        raise ValueError("near_cut_lineage_reserve_trace_max_boundary must be >= -1")
    prefix_reserve_slots_value = int(prefix_reserve_slots)
    prefix_reserve_fraction_value = float(prefix_reserve_fraction)
    if int(prefix_reserve_slots_value) < 0:
        raise ValueError("prefix_reserve_slots must be >= 0")
    if (
        math.isnan(float(prefix_reserve_fraction_value))
        or not math.isfinite(float(prefix_reserve_fraction_value))
        or float(prefix_reserve_fraction_value) < 0.0
        or float(prefix_reserve_fraction_value) > 1.0
    ):
        raise ValueError("prefix_reserve_fraction must be finite and in [0, 1]")
    if int(prefix_reserve_slots_value) > 0 and float(prefix_reserve_fraction_value) > 0.0:
        raise ValueError("use prefix_reserve_slots or prefix_reserve_fraction, not both")
    prefix_reserve_mode_key = str(prefix_reserve_mode).strip().lower()
