    forward_guidance_mode_key = _normalize_forward_guidance_mode(str(forward_guidance_mode))
    forward_guidance_trigger_mode_key = _normalize_forward_guidance_trigger_mode(
        str(forward_guidance_trigger_mode)
    )
    forward_cut_state_lookahead_mode_config = _forward_cut_state_lookahead_mode_config_from_score_mode(
        str(score_mode_key)
    )
    forward_cut_state_lookahead_active = forward_cut_state_lookahead_mode_config is not None
    forward_terminal_lookahead_active = bool(str(score_mode_key).strip().lower() == "forward_terminal_lookahead")
    if int(forward_guidance_hamming_radius) < 0 or int(forward_guidance_hamming_radius) > 2:
        raise ValueError("forward_guidance_hamming_radius must be in [0, 2]")
    if math.isnan(float(forward_guidance_nearcut_gap)) or not math.isfinite(float(forward_guidance_nearcut_gap)):
        raise ValueError("forward_guidance_nearcut_gap must be finite")
    if float(forward_guidance_nearcut_gap) < 0.0:
        raise ValueError("forward_guidance_nearcut_gap must be >= 0")
    if int(forward_guidance_pool_trigger_min_positive_nearcut) < 0:
        raise ValueError("forward_guidance_pool_trigger_min_positive_nearcut must be >= 0")
    forward_guidance_diversity_fallback_key = _normalize_forward_guidance_diversity_fallback(
        str(forward_guidance_diversity_fallback)
    )
    normalized_beam_size_overrides_by_boundary = _normalize_beam_size_overrides_by_boundary(
        beam_size_overrides_by_boundary
    )
    if int(parent_topn_child_reserve_top_n) < 0:
        raise ValueError("parent_topn_child_reserve_top_n must be >= 0")
    if int(adaptive_sparse_block_beam_size) < 0:
        raise ValueError("adaptive_sparse_block_beam_size must be >= 0")
    _normalize_adaptive_sparse_block_trigger_mode(str(adaptive_sparse_block_trigger_mode))
    if math.isnan(float(adaptive_sparse_block_gap_threshold)):
        raise ValueError("adaptive_sparse_block_gap_threshold must not be NaN")
    if math.isfinite(float(adaptive_sparse_block_gap_threshold)) and float(adaptive_sparse_block_gap_threshold) < 0.0:
        raise ValueError("adaptive_sparse_block_gap_threshold must be >= 0 when finite")
    if (
        math.isnan(float(adaptive_sparse_block_overflow_ratio_min))
        or not math.isfinite(float(adaptive_sparse_block_overflow_ratio_min))
        or float(adaptive_sparse_block_overflow_ratio_min) < 0.0
    ):
        raise ValueError("adaptive_sparse_block_overflow_ratio_min must be finite and >= 0")
    if math.isnan(float(adaptive_sparse_block_overflow_ratio_max)):
        raise ValueError("adaptive_sparse_block_overflow_ratio_max must not be NaN")
    if float(adaptive_sparse_block_overflow_ratio_max) < float(adaptive_sparse_block_overflow_ratio_min):
        raise ValueError(
            "adaptive_sparse_block_overflow_ratio_max must be >= adaptive_sparse_block_overflow_ratio_min"
        )
    if (
        math.isnan(float(adaptive_sparse_block_support_gap_threshold))
        or not math.isfinite(float(adaptive_sparse_block_support_gap_threshold))
        or float(adaptive_sparse_block_support_gap_threshold) < 0.0
    ):
        raise ValueError("adaptive_sparse_block_support_gap_threshold must be finite and >= 0")
    if (
        math.isnan(float(adaptive_sparse_block_candidate_top1_share_max))
        or not math.isfinite(float(adaptive_sparse_block_candidate_top1_share_max))
        or float(adaptive_sparse_block_candidate_top1_share_max) < 0.0
        or float(adaptive_sparse_block_candidate_top1_share_max) > 1.0
    ):
        raise ValueError("adaptive_sparse_block_candidate_top1_share_max must be in [0, 1]")
    if int(adaptive_sparse_block_max_closing_count) < 0:
        raise ValueError("adaptive_sparse_block_max_closing_count must be >= 0")
    if int(adaptive_sparse_block_min_closure_block_len) < 0:
        raise ValueError("adaptive_sparse_block_min_closure_block_len must be >= 0")
    if int(adaptive_sparse_block_bridge_round_span_min) not in (0, 1) and int(
        adaptive_sparse_block_bridge_round_span_min
    ) < 2:
        raise ValueError("adaptive_sparse_block_bridge_round_span_min must be 0 or >= 2")
    boundary_beam_override = int(
        normalized_beam_size_overrides_by_boundary.get(int(boundary_column_index), 0)
    )
    delayed_pruning_enabled = bool(
        int(base_beam_size) > 0
        and not bool(score_gap_pruning_enabled)
        and math.isfinite(float(delayed_pruning_gap_threshold))
        and float(delayed_pruning_gap_threshold) > 0.0
        and int(delayed_pruning_factor) > 1
    )
    delayed_pruning_active = bool(
        bool(delayed_pruning_enabled)
        and int(delayed_pruning_active_beam_size) > int(base_beam_size)
        and int(boundary_column_index) < int(delayed_pruning_hold_until_boundary_exclusive)
    )
    delayed_pruning_effective_beam_size = (
        int(delayed_pruning_active_beam_size) if bool(delayed_pruning_active) else int(base_beam_size)
    )
    effective_beam_size = max(
        int(delayed_pruning_effective_beam_size),
        int(boundary_beam_override),
    )
    selected_beam_size = int(effective_beam_size)
    prefix_reserve_fixed_slots = _resolve_prefix_reserve_slots(
        beam_size=int(selected_beam_size),
        prefix_reserve_slots=int(prefix_reserve_slots_value),
        prefix_reserve_fraction=float(prefix_reserve_fraction_value),
    )
    prefix_reserve_active = False
    if str(prefix_reserve_mode_key) in {"fixed", "fixed_guarded"}:
        prefix_reserve_active = bool(int(prefix_reserve_fixed_slots) > 0)
    elif str(prefix_reserve_mode_key) == "adaptive_mass_coverage":
        prefix_reserve_active = bool(
            float(prefix_reserve_mass_coverage_tau_value) > 0.0
            and (int(prefix_reserve_max_slots_value) > 0 or int(prefix_reserve_fixed_slots) > 0)
        )
    if bool(future_lane_active) and bool(prefix_reserve_active):
        raise ValueError("future_lane is not supported with prefix_reserve")
    if bool(future_lane_active) and (
        bool(detector_bucket_pruning)
        or str(retention_policy_key) != "global_topk"
        or bool(mixed_retention_active)
        or bool(finite_beam_survival_active)
        or bool(pressure_microbank_active)
        or bool(suffix_message_active)
        or bool(near_cut_lineage_reserve_active)
        or bool(order_scout_support_active)
    ):
        raise ValueError("future_lane currently supports only primary global top-K pruning")
    if (
        not bool(score_gap_pruning_enabled)
        and int(effective_beam_size) <= 0
        and not bool(anti_collapse_active)
        and not bool(finite_beam_survival_active)
        and not bool(pressure_microbank_active)
        and not bool(suffix_message_active)
        and not bool(collect_pre_prune_score_trace)
    ):
        candidate_prefix_mass = float(_log_mass_map_total_prob(next_log_mass))
        truth_logical_candidate_prefix_mass = (
            float(
                _logical_class_prefix_mass_from_state_log_mass(
                    state_log_mass=next_log_mass,
                    logical_mask=int(diagnostic_truth_logical_mask),
                    num_detectors=int(num_detectors),
                    num_observables=int(num_observables),
                )
            )
            if diagnostic_truth_logical_mask is not None
            else 0.0
        )
        return (
            dict(next_log_mass),
            dict(next_viterbi),
            dict(next_parent),
            0,
            0,
            int(logical_rerank_pass_count),
            int(logical_rerank_last_remaining_columns),
            0,
            0,
            0,
            0,
            0,
            0,
            0.0,
            tuple(),
            -1,
            int(delayed_pruning_effective_beam_size),
            0,
            0,
            int(delayed_pruning_effective_beam_size),
            float(candidate_prefix_mass),
            float(candidate_prefix_mass),
            0.0,
            float(truth_logical_candidate_prefix_mass),
            float(truth_logical_candidate_prefix_mass),
            0.0,
            0.0,
            0,
            0,
            0,
            None,
            tuple(),
            tuple(),
        )
    if (
        not bool(score_gap_pruning_enabled)
        and beam_size is not None
        and len(next_log_mass) <= int(effective_beam_size)
        and not bool(anti_collapse_active)
        and not bool(finite_beam_survival_active)
        and not bool(pressure_microbank_active)
        and not bool(suffix_message_active)
        and not bool(collect_pre_prune_score_trace)
    ):
        candidate_prefix_mass = float(_log_mass_map_total_prob(next_log_mass))
        truth_logical_candidate_prefix_mass = (
            float(
                _logical_class_prefix_mass_from_state_log_mass(
                    state_log_mass=next_log_mass,
                    logical_mask=int(diagnostic_truth_logical_mask),
                    num_detectors=int(num_detectors),
                    num_observables=int(num_observables),
                )
            )
            if diagnostic_truth_logical_mask is not None
            else 0.0
        )
        return (
            dict(next_log_mass),
            dict(next_viterbi),
            dict(next_parent),
            0,
            0,
            int(logical_rerank_pass_count),
            int(logical_rerank_last_remaining_columns),
            0,
            0,
            0,
            0,
            0,
            0,
            0.0,
            tuple(),
            int(delayed_pruning_hold_until_boundary_exclusive) if bool(delayed_pruning_active) else -1,
            int(delayed_pruning_effective_beam_size),
            0,
            1
            if bool(delayed_pruning_active) and int(delayed_pruning_effective_beam_size) > int(base_beam_size)
            else 0,
            int(delayed_pruning_effective_beam_size),
            float(candidate_prefix_mass),
            float(candidate_prefix_mass),
            0.0,
            float(truth_logical_candidate_prefix_mass),
            float(truth_logical_candidate_prefix_mass),
            0.0,
            0.0,
            0,
            0,
            0,
            None,
            tuple(),
            tuple(),
        )

    pruning_engine_key = str(debug_pruning_engine).strip().lower()
    if pruning_engine_key not in {"legacy", "optimized"}:
        raise ValueError("debug_pruning_engine must be one of ['legacy', 'optimized']")
    future_parity_scorer_key = _normalize_future_parity_scorer(str(future_parity_scorer))

    compiled_primary_topk_plan = _compiled_singleton_future_parity_rank_plan(str(score_mode_key))
    reliability_adjustment_active_for_fast_path = bool(
        float(stage1_reliability_correction_mu) != 0.0
        and stage1_reliability_llr is not None
        and representative_correction_by_key is not None
    )
    primary_topk_fast_path_enabled = bool(
        compiled_primary_topk_plan is not None
        and not _prune_primary_topk_fast_path_disabled()
        and beam_size is not None
        and int(selected_beam_size) > 0
        and not _score_gap_threshold_enabled(beam_score_gap_no_path_guard_threshold)
        and str(prune_ranker_key) == "primary"
        and str(retention_policy_key) == "global_topk"
        and str(mixed_retention_mode_key) == "none"
        and not bool(detector_bucket_pruning)
        and int(lookahead_depth) == 0
        and int(lookahead_shortlist_size) == 0
        and int(logical_class_reserve_min_classes) == 0
        and int(logical_class_reserve_max_replacements) == 0
        and int(logical_class_quota_top_classes) == 0
        and int(logical_class_quota_reserved_slots) == 0
        and int(lineage_reserve_reserved_slots) == 0
        and int(logical_rerank_columns) == 0
        and int(logical_rerank_shortlist_size) == 0
        and int(logical_rerank_min_classes) == 0
        and not bool(collect_debug_metrics)
        and not tuple(debug_shadow_score_modes or tuple())
        and not bool(normalized_multi_score_survivor_lanes)
        and not bool(phase_lanes_enabled)
        and not bool(order_scout_support_active)
        and not bool(prefix_reserve_active)
        and not bool(future_lane_active)
        and not bool(no_prefix_future_lane_active)
        and not bool(anti_collapse_active)
        and not bool(finite_beam_survival_active)
        and not bool(pressure_microbank_active)
        and not bool(suffix_message_active)
        and not bool(near_cut_lineage_reserve_active)
        and not bool(delayed_pruning_enabled)
        and not bool(normalized_beam_size_overrides_by_boundary)
        and int(adaptive_sparse_block_beam_size) <= int(selected_beam_size)
        and not bool(disable_prune_fast_path)
        and not (truth_path_trace is not None and diagnostic_truth_column_identity_mask is not None)
        and not bool(collect_pre_prune_score_trace)
        and pruning_debug_payload is None
        and boundary_state_trace is None
        and not bool(boundary_state_kbest_active)
        and not str(selective_secondary_score_mode_key).strip()
        and int(selective_secondary_band_size) == 0
        and str(selective_local_lookahead_mode_key).strip().lower() in {"", "none"}
        and str(selective_local_lookahead_score_mode_key).strip() == ""
        and int(selective_local_lookahead_max_candidates) == 0
        and not bool(forward_guidance_by_processed_columns)
        and float(forward_guidance_weight) == 0.0
        and not bool(forward_checkpoint_enable)
        and forward_guidance_replay_columns is None
        and forward_guidance_replay_layout is None
        and not bool(forward_cut_state_lookahead_active)
        and not bool(forward_terminal_lookahead_active)
        and not bool(reliability_adjustment_active_for_fast_path)
        and learned_score_config is None
        and not bool(nearcut_active)
    )
    if bool(primary_topk_fast_path_enabled):
        return _prune_beam_frontier_primary_topk_fast_path(
            next_log_mass=next_log_mass,
            next_viterbi=next_viterbi,
            next_parent=next_parent,
            beam_size=int(selected_beam_size),
            beam_score_gap_threshold=beam_score_gap_threshold,
            beam_score_gap_policy=beam_score_gap_policy,
            score_mode_key=str(score_mode_key),
            compiled_plan=compiled_primary_topk_plan,
            boundary_column_index=int(boundary_column_index),
            frontier=frontier,
            active_mask=int(active_mask),
            target_syndrome_int=int(target_syndrome_int),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
            track_best_path=bool(track_best_path),
            detector_features_by_detector=detector_features_by_detector,
            parity_payload_cache=parity_payload_cache,
            debug_pruning_engine=str(pruning_engine_key),
            diagnostic_truth_logical_mask=diagnostic_truth_logical_mask,
            logical_rerank_pass_count=int(logical_rerank_pass_count),
            logical_rerank_last_remaining_columns=int(logical_rerank_last_remaining_columns),
            future_parity_scorer=str(future_parity_scorer_key),
            future_parity_scorer_stats=future_parity_scorer_stats,
        )

    features_by_detector = dict(detector_features_by_detector) if detector_features_by_detector is not None else {}
    detector_mask_mask = (1 << int(num_detectors)) - 1
    ordered_keys = [int(key) for key in next_log_mass.keys()]
    detector_key_by_state = {
        int(key): _unpack_detector_mask(state_key=int(key), detector_mask_mask=int(detector_mask_mask))
        for key in ordered_keys
    }
    logical_support_count_by_key: dict[int, int] | None = None

    def _same_logical_support_count_for_key(key: int) -> int:
        nonlocal logical_support_count_by_key
        if logical_support_count_by_key is None:
            logical_mask_by_key: dict[int, int] = {}
            logical_counts: dict[int, int] = {}
            for candidate_key in ordered_keys:
                logical_mask = _unpack_logical_mask(
                    state_key=int(candidate_key),
                    num_detectors=int(num_detectors),
                    num_observables=int(num_observables),
                )
                logical_mask_by_key[int(candidate_key)] = int(logical_mask)
                logical_counts[int(logical_mask)] = int(logical_counts.get(int(logical_mask), 0)) + 1
            logical_support_count_by_key = {
                int(candidate_key): int(logical_counts[int(logical_mask)])
                for candidate_key, logical_mask in logical_mask_by_key.items()
            }
        return int(logical_support_count_by_key.get(int(key), 1))

    truth_cut_state_key = _sampled_truth_cut_state_key(
        columns=columns,
        frontier=frontier,
        boundary_column_index=int(boundary_column_index),
        target_syndrome_int=int(target_syndrome_int),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
        sampled_column_identity_mask=diagnostic_truth_column_identity_mask,
        include_correction_mask=bool(diagnostic_truth_column_identity_include_correction),
    )
    truth_cut_state_candidate_present = bool(
        int(truth_cut_state_key) >= 0 and int(truth_cut_state_key) in next_log_mass
    )
    detector_keys = {int(det_key) for det_key in detector_key_by_state.values()}
    shadow_score_mode_keys = (
        tuple(str(mode).strip().lower() for mode in debug_shadow_score_modes)
        if bool(collect_debug_metrics)
        else tuple()
    )
    lane_score_mode_keys = tuple(str(lane.score_mode) for lane in normalized_multi_score_survivor_lanes)
    future_lane_score_mode_keys = tuple(
        mode
        for mode in (
            str(future_lane_score_key) if bool(future_lane_active) else "",
            str(no_prefix_future_lane_score_key) if bool(no_prefix_future_lane_active) else "",
        )
        if str(mode)
    )
    score_union_mode_keys = (
        (str(score_union_primary_score_key), *score_union_aux_score_values)
        if str(mixed_retention_mode_key) in {"score_union", "score_union_logical_diversity"}
        else tuple()
    )
    parity_feature_modes = tuple(
        {
            str(score_mode_key),
            *shadow_score_mode_keys,
            *lane_score_mode_keys,
            *future_lane_score_mode_keys,
            *score_union_mode_keys,
            *(
                ("future_parity_logodds",)
                if _nearcut_model_uses_future_parity_features(nearcut_model if bool(nearcut_active) else None)
                else tuple()
            ),
        }
    )
    need_future_parity_features = any(_score_mode_uses_future_parity_features(mode) for mode in parity_feature_modes)
    parity_payload = None
    if bool(need_future_parity_features):
        missing_detector_keys = [int(det_key) for det_key in detector_keys if int(det_key) not in features_by_detector]
        if missing_detector_keys:
            scorer_started = time.perf_counter()
            if bool(future_parity_scorer_key == "cached"):
                parity_payload = parity_payload_cache.get(int(boundary_column_index))
                if parity_payload is None or int(parity_payload.active_mask) != int(active_mask):
                    parity_payload = _build_future_parity_boundary_payload(
                        frontier=frontier,
                        boundary_column_index=int(boundary_column_index),
                        active_mask=int(active_mask),
                    )
                    parity_payload_cache[int(boundary_column_index)] = parity_payload
                    if future_parity_scorer_stats is not None:
                        future_parity_scorer_stats.payload_build_count += 1
                for det_key in missing_detector_keys:
                    features_by_detector[int(det_key)] = _future_mismatch_features_from_payload(
                        det_mask=int(det_key),
                        target_syndrome_int=int(target_syndrome_int),
                        payload=parity_payload,
                    )
            else:
                for det_key in missing_detector_keys:
                    features_by_detector[int(det_key)] = _future_mismatch_features(
                        det_mask=int(det_key),
                        active_mask=int(active_mask),
                        target_syndrome_int=int(target_syndrome_int),
                        column_index=int(boundary_column_index),
                        frontier=frontier,
                    )
                if future_parity_scorer_stats is not None:
                    future_parity_scorer_stats.from_scratch_score_calls += int(len(missing_detector_keys))
            if future_parity_scorer_stats is not None:
                future_parity_scorer_stats.fallback_score_calls += int(len(missing_detector_keys))
                future_parity_scorer_stats.scorer_time_s += float(time.perf_counter() - scorer_started)

    heuristic_mass_cache_by_mode: dict[str, dict[int, float]] = {}
    compiled_parity_heuristic_cache_by_mode: dict[str, dict[int, float]] = {}
    ranker_by_mode: dict[str, object] = {}
    logical_primary_entry_cache: dict[str, dict[int, LogicalTailRerankEntry]] = {}
    primary_logical_transition_count = 0
    prefix_nonzero_steps_by_key = (
        {} if next_min_nonzero_steps is None else {int(key): int(value) for key, value in next_min_nonzero_steps.items()}
    )

    def _heuristic_mass(score_mode_to_use: str, det_key: int) -> float:
        mode_key = str(score_mode_to_use).strip().lower()
        per_mode_cache = heuristic_mass_cache_by_mode.setdefault(str(mode_key), {})
        if int(det_key) not in per_mode_cache:
            if future_parity_scorer_stats is not None and _score_mode_uses_future_parity_features(str(mode_key)):
                future_parity_scorer_stats.score_calls += 1
            per_mode_cache[int(det_key)] = _boundary_heuristic_mass(
                det_key=int(det_key),
                score_mode_key=str(mode_key),
                active_mask=int(active_mask),
                target_syndrome_int=int(target_syndrome_int),
                boundary_column_index=int(boundary_column_index),
                beam_size=(int(selected_beam_size) if int(selected_beam_size) > 0 else None),
                columns=columns,
                frontier=frontier,
                clamp_assignments=clamp_assignments,
                features_by_detector=features_by_detector,
                parity_payload_cache=parity_payload_cache,
                component_payload_cache=component_payload_cache,
                pairtree_payload_cache=pairtree_payload_cache,
                low_error_payload_cache=low_error_payload_cache,
                active_frontier_payload_cache=active_frontier_payload_cache,
                active_frontier_score_cache=active_frontier_score_cache,
                single_fix_payload_cache=single_fix_payload_cache,
                quotient_payload_cache=quotient_payload_cache,
                pseudo_payload_cache=pseudo_payload_cache,
                learned_score_config=learned_score_config,
            )
        return float(per_mode_cache[int(det_key)])

    reliability_adjustment_active = bool(
        float(stage1_reliability_correction_mu) != 0.0
        and stage1_reliability_llr is not None
        and representative_correction_by_key is not None
    )

    def _reliability_adjustment_for_key(key: int) -> float:
        if not bool(reliability_adjustment_active):
            return 0.0
        if representative_correction_by_key is None:
            return 0.0
        correction_mask = representative_correction_by_key.get(int(key))
        if correction_mask is None:
            return 0.0
        return float(stage1_reliability_correction_mu) * float(
            _stage1_reliability_selected_fault_log_score(
                correction_mask=int(correction_mask),
                stage1_reliability_llr=stage1_reliability_llr,
                llr_clip=float(stage1_reliability_llr_clip),
            )
        )

    def _compiled_parity_heuristic_mass(mode_key: str, det_key: int, alpha: float) -> float:
        per_mode_cache = compiled_parity_heuristic_cache_by_mode.setdefault(str(mode_key), {})
        det_key_int = int(det_key)
        cached = per_mode_cache.get(det_key_int)
        if cached is not None:
            return float(cached)
        features = features_by_detector.get(det_key_int)
        if features is None:
            value = float(_heuristic_mass(str(mode_key), det_key_int))
        else:
            if future_parity_scorer_stats is not None:
                future_parity_scorer_stats.score_calls += 1
            value = float(alpha) * float(features.parity_logodds)
        per_mode_cache[det_key_int] = float(value)
        return float(value)

    def _logical_primary_entry(score_mode_to_use: str, key: int) -> LogicalTailRerankEntry:
        nonlocal primary_logical_transition_count
        mode_key = str(score_mode_to_use).strip().lower()
        per_mode_cache = logical_primary_entry_cache.setdefault(str(mode_key), {})
        if int(key) not in per_mode_cache:
            if mode_key != "future_parity_logodds_local_cone_delta0":
                raise ValueError("unsupported logical primary score mode")
            entry = _logical_tail_summary_for_state(
                key=int(key),
                prefix_log_mass=float(next_log_mass[int(key)]),
                start_column_index=int(boundary_column_index) + 1,
                columns=columns,
                frontier=frontier,
                target_syndrome_int=int(target_syndrome_int),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
                clamp_assignments=clamp_assignments,
                state_budget=int(logical_rerank_state_budget),
                transition_budget=int(logical_rerank_transition_budget),
                logical_rerank_mode="local_cone",
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                component_payload_cache=component_payload_cache,
            )
            per_mode_cache[int(key)] = entry
            primary_logical_transition_count += int(entry.transition_count)
        return per_mode_cache[int(key)]

    def _make_rank_score_no_probe_for_mode(score_mode_to_use: str):
        mode_key = str(score_mode_to_use).strip().lower()
        compiled_plan = _compiled_singleton_future_parity_rank_plan(str(mode_key))
        if compiled_plan is not None:
            alpha, future_only, heuristic_mode_key = compiled_plan

            def _compiled_rank_score(key: int) -> tuple[float, float, float]:
                key_int = int(key)
                prefix_mass = float(next_log_mass[key_int])
                det_key = int(detector_key_by_state[key_int])
                heuristic_mass = float(
                    _compiled_parity_heuristic_mass(str(heuristic_mode_key), int(det_key), float(alpha))
                )
                reliability_adjustment = float(_reliability_adjustment_for_key(key_int))
                if bool(future_only):
                    return (
                        float(heuristic_mass + reliability_adjustment),
                        float(prefix_mass),
                        0.0,
                    )
                return (
                    float(prefix_mass + heuristic_mass + reliability_adjustment),
                    float(prefix_mass),
                    0.0,
                )

            return _compiled_rank_score

        prefix_beta = _future_parity_logodds_prefix_beta_from_score_mode(str(mode_key))
        if prefix_beta is not None:

            def _prefix_beta_rank_score(key: int) -> tuple[float, float, float]:
                key_int = int(key)
                prefix_mass = float(next_log_mass[key_int])
                det_key = int(detector_key_by_state[key_int])
                heuristic_mass = float(
                    _compiled_parity_heuristic_mass("future_parity_logodds", int(det_key), 1.0)
                )
                reliability_adjustment = float(_reliability_adjustment_for_key(key_int))
                return (
                    float(float(prefix_beta) * prefix_mass + heuristic_mass + reliability_adjustment),
                    float(prefix_mass),
                    0.0,
                )

            return _prefix_beta_rank_score

        prefix_taper_config = _future_parity_logodds_prefix_taper_config_from_score_mode(str(mode_key))
        if prefix_taper_config is not None:
            prefix_taper_beta = _future_parity_logodds_prefix_taper_beta(
                prefix_taper_config,
                boundary_column_index=int(boundary_column_index),
                total_columns=int(len(columns)),
            )

            def _prefix_taper_rank_score(key: int) -> tuple[float, float, float]:
                key_int = int(key)
                prefix_mass = float(next_log_mass[key_int])
                det_key = int(detector_key_by_state[key_int])
                heuristic_mass = float(
                    _compiled_parity_heuristic_mass("future_parity_logodds", int(det_key), 1.0)
                )
                reliability_adjustment = float(_reliability_adjustment_for_key(key_int))
                return (
                    float(float(prefix_taper_beta) * prefix_mass + heuristic_mass + reliability_adjustment),
                    float(prefix_mass),
                    0.0,
                )

            return _prefix_taper_rank_score

        no_prefix_inner_for_support = _no_prefix_inner_score_mode(str(mode_key))
        support_mode_key = str(no_prefix_inner_for_support) if no_prefix_inner_for_support is not None else str(mode_key)
        support_config = _future_parity_logodds_logsupport_config_from_score_mode(str(support_mode_key))
        if support_config is not None:
            support_alpha, support_coefficient = support_config
            support_future_only = no_prefix_inner_for_support is not None

            def _logical_support_rank_score(key: int) -> tuple[float, float, float]:
                key_int = int(key)
                prefix_mass = float(next_log_mass[key_int])
                det_key = int(detector_key_by_state[key_int])
                heuristic_mass = float(
                    _compiled_parity_heuristic_mass(
                        "future_parity_logodds",
                        int(det_key),
                        float(support_alpha),
                    )
                )
                support_count = max(1, int(_same_logical_support_count_for_key(key_int)))
                support_bonus = float(support_coefficient) * float(math.log(float(support_count)))
                reliability_adjustment = float(_reliability_adjustment_for_key(key_int))
                if bool(support_future_only):
                    return (
                        float(heuristic_mass + support_bonus + reliability_adjustment),
                        float(prefix_mass),
                        0.0,
                    )
                return (
                    float(prefix_mass + heuristic_mass + support_bonus + reliability_adjustment),
                    float(prefix_mass),
                    float(support_bonus),
                )

            return _logical_support_rank_score

        no_prefix_inner_for_compact = _no_prefix_inner_score_mode(str(mode_key))
        compact_mode_key = str(no_prefix_inner_for_compact) if no_prefix_inner_for_compact is not None else str(mode_key)
        compact_config = _future_parity_logodds_compact_feature_config_from_score_mode(str(compact_mode_key))
        if compact_config is not None:
            compact_future_only = no_prefix_inner_for_compact is not None

            def _compact_feature_rank_score(key: int) -> tuple[float, float, float]:
                key_int = int(key)
                prefix_mass = float(next_log_mass[key_int])
                det_key = int(detector_key_by_state[key_int])
                detector_weight = float(int(det_key).bit_count())
                heuristic_mass = float(
                    _compiled_parity_heuristic_mass(
                        "future_parity_logodds",
                        int(det_key),
                        float(compact_config.alpha),
                    )
                )
                support_count = max(1, int(_same_logical_support_count_for_key(key_int)))
                support_log = float(math.log(float(support_count)))
                if str(compact_config.feature) == "detweight":
                    feature_value = -float(detector_weight)
                elif str(compact_config.feature) == "lowsupport":
                    feature_value = -float(support_log)
                elif str(compact_config.feature) == "compactsupport":
                    feature_value = float(support_log) - float(compact_config.gamma) * float(detector_weight)
                else:
                    feature_value = 0.0
                feature_bonus = float(compact_config.coefficient) * float(feature_value)
                reliability_adjustment = float(_reliability_adjustment_for_key(key_int))
                if bool(compact_future_only):
                    return (
                        float(heuristic_mass + feature_bonus + reliability_adjustment),
                        float(prefix_mass),
                        float(feature_bonus),
                    )
                return (
                    float(prefix_mass + heuristic_mass + feature_bonus + reliability_adjustment),
                    float(prefix_mass),
                    float(feature_bonus),
                )

            return _compact_feature_rank_score

        no_prefix_inner = _no_prefix_inner_score_mode(str(mode_key))
        heuristic_mode_key = str(no_prefix_inner) if no_prefix_inner is not None else str(mode_key)
        no_prefix_rank = bool(no_prefix_inner is not None)
        no_prefix_survivor_lane = bool(_score_mode_is_no_prefix_survivor_lane(str(mode_key)))

        def _generic_rank_score(key: int) -> tuple[float, float, float]:
            key_int = int(key)
            prefix_mass = float(next_log_mass[key_int])
            det_key = int(detector_key_by_state[key_int])
            heuristic_mass = float(_heuristic_mass(str(heuristic_mode_key), int(det_key)))
            reliability_adjustment = float(_reliability_adjustment_for_key(key_int))
            if bool(no_prefix_rank):
                return (
                    float(heuristic_mass + reliability_adjustment),
                    float(prefix_mass),
                    0.0,
                )
            if mode_key == "future_repair_steps_lex":
                repair_step_score = float(_heuristic_mass("future_repair_min_steps", int(det_key)))
                pairtree_mass = float(_heuristic_mass("future_parity_pairtree_support_gate", int(det_key)))
                if not math.isfinite(float(repair_step_score)):
                    return float("-inf"), float(prefix_mass + pairtree_mass), float(prefix_mass)
                prefix_nonzero_steps = int(prefix_nonzero_steps_by_key.get(key_int, 0))
                future_nonzero_steps = int(round(-float(repair_step_score)))
                total_nonzero_steps = int(prefix_nonzero_steps) + int(future_nonzero_steps)
                return (
                    float(-total_nonzero_steps) + float(reliability_adjustment),
                    float(prefix_mass + pairtree_mass),
                    float(prefix_mass),
                )
            if mode_key == "future_parity_logodds_local_cone_delta0":
                baseline_mass = float(_heuristic_mass("future_parity_logodds", int(det_key)))
                logical_entry = _logical_primary_entry(str(mode_key), key_int)
                logical_state_count = max(1, 1 << int(num_observables))
                logical_term_floor = (
                    0.0 if int(logical_state_count) <= 1 else -float(math.log(float(logical_state_count)))
                )
                if str(logical_entry.status) == "budget_exceeded":
                    logical_term = 0.0
                else:
                    logical_term = float(logical_entry.same_logical_logprob)
                    if not math.isfinite(float(logical_term)):
                        logical_term = float(logical_term_floor)
                    else:
                        logical_term = max(float(logical_term), float(logical_term_floor))
                return (
                    float(prefix_mass + baseline_mass + logical_term + reliability_adjustment),
                    float(prefix_mass + baseline_mass),
                    float(prefix_mass),
                )
            if bool(no_prefix_survivor_lane):
                return (
                    float(heuristic_mass + reliability_adjustment),
                    float(prefix_mass),
                    0.0,
                )
            features = features_by_detector.get(int(det_key))
            if mode_key == "residual_lex":
                mismatch_count = int(features.mismatch_count) if features is not None else 0
                return (
                    float(-mismatch_count) + float(reliability_adjustment),
                    float(prefix_mass),
                    float(heuristic_mass),
                )
            if mode_key == "future_urgency_lex":
                urgency_penalty = float(features.urgency_penalty) if features is not None else 0.0
                return (
                    float(-urgency_penalty) + float(reliability_adjustment),
                    float(prefix_mass),
                    float(heuristic_mass),
                )
            if mode_key == "detector_sparsity_lex":
                detector_count = int(det_key).bit_count()
                return (
                    float(-detector_count) + float(reliability_adjustment),
                    float(prefix_mass),
                    float(heuristic_mass),
                )
            return float(prefix_mass + heuristic_mass + reliability_adjustment), float(prefix_mass), 0.0

        return _generic_rank_score

    def _ranker_for_mode(score_mode_to_use: str):
        mode_key = str(score_mode_to_use).strip().lower()
        ranker = ranker_by_mode.get(str(mode_key))
        if ranker is None:
            ranker = _make_rank_score_no_probe_for_mode(str(mode_key))
            ranker_by_mode[str(mode_key)] = ranker
        return ranker

    def _rank_score_no_probe_for_mode(score_mode_to_use: str, key: int) -> tuple[float, float, float]:
        return _ranker_for_mode(str(score_mode_to_use))(int(key))

