    def _project_guidance_log_mass(
        snapshot: ProgressiveGuidanceSnapshot,
        *,
        projection_mask: int,
    ) -> tuple[dict[int, float], float]:
        projected_log_mass: dict[int, float] = {}
        for det_mask, log_mass in tuple(snapshot.detector_log_mass_items):
            projected_det = int(det_mask) & int(projection_mask)
            projected_log_mass[int(projected_det)] = _logaddexp_pair(
                float(projected_log_mass.get(int(projected_det), float("-inf"))),
                float(log_mass),
            )
        return projected_log_mass, float(_logaddexp_many(projected_log_mass))

    def _project_guidance_state_log_mass(
        snapshot: ProgressiveGuidanceSnapshot,
        *,
        projection_mask: int,
    ) -> tuple[dict[int, float], float]:
        projected_log_mass: dict[int, float] = {}
        for state_key, log_mass in tuple(snapshot.state_log_mass_items):
            det_mask = _unpack_detector_mask(
                state_key=int(state_key),
                detector_mask_mask=int(detector_mask_mask),
            )
            logical_mask = _unpack_logical_mask(
                state_key=int(state_key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            correction_mask = _unpack_correction_mask(
                state_key=int(state_key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            projected_key = _pack_state_key(
                det_mask=int(det_mask) & int(projection_mask),
                logical_mask=int(logical_mask),
                correction_mask=int(correction_mask),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            projected_log_mass[int(projected_key)] = _logaddexp_pair(
                float(projected_log_mass.get(int(projected_key), float("-inf"))),
                float(log_mass),
            )
        return projected_log_mass, float(_logaddexp_many(projected_log_mass))

