def sample_midswap_lossy_shots_from_metadata(
    *,
    stim_path: str | Path,
    sector: str,
    error_rate: float,
    loss_rate: float,
    measurement_metadata: Sequence[MeasurementOutcomeMetadata],
    lifecycles: Sequence[StimMeasurementLifecycle],
    backend: str = "midswap_metadata",
    shots: int = 1,
    seed: int | None = None,
    progress_callback=None,
    progress_period: int = 100,
) -> tuple[MeasurementLifecycleLossyShot, ...]:
    if int(shots) < 0:
        raise ValueError(f"shots must be >= 0, got {shots!r}")
    if int(progress_period) < 1:
        raise ValueError(f"progress_period must be >= 1, got {progress_period!r}")
    rng = np.random.default_rng(seed)
    out: list[MeasurementLifecycleLossyShot] = []
    for shot_index in range(int(shots)):
        out.append(
            sample_midswap_lossy_shot_from_metadata(
                stim_path=stim_path,
                sector=str(sector),
                error_rate=float(error_rate),
                loss_rate=float(loss_rate),
                measurement_metadata=measurement_metadata,
                lifecycles=lifecycles,
                backend=str(backend),
                rng=rng,
            )
        )
        completed = int(shot_index) + 1
        if progress_callback is not None and (
            int(completed) == 1 or int(completed) == int(shots) or int(completed) % int(progress_period) == 0
        ):
            progress_callback(f"sampled {int(completed)}/{int(shots)} metadata-driven mid-swap lossy shots")
    return tuple(out)


def sample_midswap_lossy_shot(
    *,
    backend: str,
    sector: str,
    error_rate: float,
    loss_rate: float,
    seed: int | None = None,
    rng: np.random.Generator | None = None,
    forced_loss_branch_ranks_by_lifecycle: dict[int, int] | None = None,
) -> MeasurementLifecycleLossyShot:
    if rng is not None and seed is not None:
        raise ValueError("provide at most one of rng and seed")
    p_loss = float(loss_rate)
    if p_loss < 0.0 or p_loss >= 1.0:
        raise ValueError(f"loss_rate must lie in [0, 1), got {loss_rate!r}")

    bundle = _build_rotated_surface_midswap_sampling_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    generator = rng if rng is not None else np.random.default_rng(seed)
