def _simulate_stim_measurement_loss_branch_effect(
    *,
    stim_path: str | Path,
    lifecycle: StimMeasurementLifecycle,
    candidate_site: StimMeasurementLifecycleSite,
    detector_from_measurements: np.ndarray,
    logical_from_measurements: np.ndarray,
    reference_measurements: np.ndarray,
) -> tuple[int, int]:
    import stim  # type: ignore

    circuit = stim.Circuit.from_file(str(Path(stim_path).expanduser().resolve()))
    flat = tuple(circuit.flattened())
    dummy_qubit = int(circuit.num_qubits)
    modified = stim.Circuit()
    for instruction_index, inst in enumerate(flat):
        name = str(inst.name)
        if name in {"DEPOLARIZE1", "DEPOLARIZE2", "X_ERROR", "Y_ERROR", "Z_ERROR", "PAULI_CHANNEL_1"}:
            continue
        if int(instruction_index) < int(candidate_site.instruction_index):
            _append_instruction_without_noise_local(modified, inst)
            continue
        if int(instruction_index) > int(lifecycle.measurement_instruction_index):
            _append_instruction_without_noise_local(modified, inst)
            continue
        if int(instruction_index) < int(lifecycle.measurement_instruction_index):
            if int(lifecycle.qubit) not in tuple(
                int(value)
                for _group_index, qubits, _group_targets in _instruction_qubit_groups(inst)
                for value in qubits
            ):
                _append_instruction_without_noise_local(modified, inst)
                continue
            kept_targets = _filter_instruction_targets_excluding_qubit(inst, lost_qubit=int(lifecycle.qubit))
            if kept_targets:
                if str(name) in {"M", "MR", "MX", "MRX", "MY", "MRY"}:
                    modified.append(name, kept_targets, [])
                else:
                    modified.append(name, kept_targets, inst.gate_args_copy())
            continue

        if name not in {"M", "MR", "MX", "MRX"}:
            raise NotImplementedError(
                f"unsupported terminating instruction {name!r} for lifecycle loss simulation at measurement index "
                f"{int(lifecycle.raw_measurement_index)}"
            )
        for prep_gate, prep_targets in _build_loss_measurement_replacement_prefix(
            measurement_gate=str(name),
            dummy_qubit=int(dummy_qubit),
            reference_bit=int(lifecycle.reference_measurement_bit),
        ):
            modified.append(str(prep_gate), list(int(value) for value in prep_targets), [])
        replacement_targets = []
        for target in tuple(inst.targets_copy()):
            if not bool(getattr(target, "is_qubit_target")):
                replacement_targets.append(target)
                continue
            replacement_targets.append(
                stim.GateTarget(int(dummy_qubit)) if int(target.qubit_value) == int(lifecycle.qubit) else target
            )
        modified.append(str(name), tuple(replacement_targets), [])
        reset_gate = _reset_gate_for_measurement_gate(str(name))
        if reset_gate is not None:
            modified.append(str(reset_gate), [int(lifecycle.qubit)], [])

    modified_measurements = np.asarray(modified.compile_sampler(seed=1).sample(shots=1)[0], dtype=np.uint8)
    if modified_measurements.shape != reference_measurements.shape:
        raise ValueError(
            "modified lifecycle-loss circuit changed the measurement count: "
            f"{modified_measurements.shape} vs {reference_measurements.shape}"
        )
    measurement_delta = np.bitwise_xor(modified_measurements, reference_measurements)
    detector_bits = (
        np.asarray(detector_from_measurements, dtype=np.uint8) @ np.asarray(measurement_delta, dtype=np.uint8)
    ) % np.uint8(2)
    logical_bits = (
        np.asarray(logical_from_measurements, dtype=np.uint8) @ np.asarray(measurement_delta, dtype=np.uint8)
    ) % np.uint8(2)
    return (
        _bitmask_from_support_rows(np.flatnonzero(detector_bits).tolist()),
        _bitmask_from_support_rows(np.flatnonzero(logical_bits).tolist()),
    )


