@dataclass(slots=True)
class _LifecycleBuilder:
    role_kind: str
    role_id: int
    round_index: int
    start_instruction_exclusive: int
    segment_qubit: int
    segment_start_instruction_index: int
    candidate_sites: list[StimMeasurementLifecycleSite] = field(default_factory=list)
    segments: list[StimMeasurementLifecycleSegment] = field(default_factory=list)

    def record_site(self, *, instruction_index: int, target_group_index: int, instruction_name: str) -> None:
        self.candidate_sites.append(
            StimMeasurementLifecycleSite(
                instruction_index=int(instruction_index),
                target_group_index=int(target_group_index),
                instruction_name=str(instruction_name),
                qubit=int(self.segment_qubit),
            )
        )

    def move_to_qubit(self, *, qubit: int, instruction_index: int) -> None:
        if int(qubit) == int(self.segment_qubit):
            return
        self.segments.append(
            StimMeasurementLifecycleSegment(
                qubit=int(self.segment_qubit),
                start_instruction_index=int(self.segment_start_instruction_index),
                end_instruction_index_exclusive=int(instruction_index) + 1,
            )
        )
        self.segment_qubit = int(qubit)
        self.segment_start_instruction_index = int(instruction_index) + 1

    def finish(
        self,
        *,
        lifecycle_id: int,
        sector: str,
        raw_measurement_index: int,
        measurement_instruction_index: int,
        measurement_gate: str,
        reference_measurement_bit: int,
    ) -> StimMeasurementLifecycle:
        segments = list(self.segments)
        segments.append(
            StimMeasurementLifecycleSegment(
                qubit=int(self.segment_qubit),
                start_instruction_index=int(self.segment_start_instruction_index),
                end_instruction_index_exclusive=int(measurement_instruction_index) + 1,
            )
        )
        return StimMeasurementLifecycle(
            lifecycle_id=int(lifecycle_id),
            sector=str(sector),
            qubit=int(self.segment_qubit),
            raw_measurement_index=int(raw_measurement_index),
            measurement_instruction_index=int(measurement_instruction_index),
            measurement_gate=str(measurement_gate),
            start_instruction_exclusive=int(self.start_instruction_exclusive),
            end_instruction_inclusive=int(measurement_instruction_index),
            reference_measurement_bit=int(reference_measurement_bit),
            candidate_sites=tuple(self.candidate_sites),
            role_kind=str(self.role_kind),
            role_id=int(self.role_id),
            round_index=int(self.round_index),
            trajectory_segments=tuple(segments),
        )


@lru_cache(maxsize=16)
def _build_stim_split_sector_conditional_bundle(
    *,
    backend: str,
    sector: str,
    error_rate: float,
) -> StimSplitSectorConditionalBundle:
    _ensure_real_grosscode_package()
    from grosscode.dem.builder import build_split_sector_problem
    from grosscode.dem.stim_fault_pipeline import analyze_gross_split_sector_circuit

    problem = build_split_sector_problem(backend=str(backend), error_rate=float(error_rate))
    spec, analysis = analyze_gross_split_sector_circuit(
        sector=str(sector),
        backend=str(backend),
        error_rate=float(error_rate),
    )
    detector = problem.D_X if str(sector).upper() == "X" else problem.D_Z
    logical = problem.O_X if str(sector).upper() == "X" else problem.O_Z
    priors = problem.priors_X if str(sector).upper() == "X" else problem.priors_Z
    detector_csc = detector.tocsc()
    logical_csc = logical.tocsc()

    merged_by_signature: dict[tuple[int, int], object] = {}
    for merged in tuple(analysis.merged_columns):
        signature = (
            _bitmask_from_support_rows([index for index, bit in enumerate(tuple(merged.detector_bits)) if int(bit) != 0]),
            _bitmask_from_support_rows([index for index, bit in enumerate(tuple(merged.logical_bits)) if int(bit) != 0]),
        )
        if signature in merged_by_signature:
            raise ValueError(f"duplicate merged signature encountered while building fault metadata: {signature!r}")
        merged_by_signature[signature] = merged

    time_ordered_entries: list[tuple[int, int, ProgressiveColumn, tuple[int, ...]]] = []
    for source_column in range(int(detector.shape[1])):
        det_start = int(detector_csc.indptr[int(source_column)])
        det_stop = int(detector_csc.indptr[int(source_column) + 1])
        det_rows = detector_csc.indices[det_start:det_stop].astype(np.int32, copy=False)
        log_start = int(logical_csc.indptr[int(source_column)])
        log_stop = int(logical_csc.indptr[int(source_column) + 1])
        log_rows = logical_csc.indices[log_start:log_stop].astype(np.int32, copy=False)
        detector_mask = _bitmask_from_support_rows(det_rows.tolist())
        logical_mask = _bitmask_from_support_rows(log_rows.tolist())
        merged = merged_by_signature.get((int(detector_mask), int(logical_mask)))
        if merged is None:
            raise ValueError(
                "could not match split-sector DEM column to Stim merged fault metadata for "
                f"backend={backend!r} sector={sector!r} column={int(source_column)}"
            )
        if not math.isclose(float(merged.probability), float(priors[int(source_column)]), rel_tol=0.0, abs_tol=1e-12):
            raise ValueError(
                "split-sector prior mismatch against Stim merged fault metadata for "
                f"backend={backend!r} sector={sector!r} column={int(source_column)}: "
                f"{float(priors[int(source_column)]):.18g} vs {float(merged.probability):.18g}"
            )
        source_fault_ids = tuple(int(value) for value in tuple(merged.raw_fault_ids))
        source_faults = [analysis.faults[int(raw_id)] for raw_id in source_fault_ids]
        touched_physical_qubits = tuple(
            sorted(
                {
                    int(qubit)
                    for fault in source_faults
                    for qubit in tuple(int(value) for value in fault.qubits)
                }
            )
        )
        physical_time_index = min((int(fault.instruction_index) for fault in source_faults), default=int(source_column))
        q = float(priors[int(source_column)])
        prior_probs = (float(1.0 - q), float(q))
        column = ProgressiveColumn(
            family=f"stim_split_sector_{str(backend)}",
            index=-1,
            label=f"stim_dem_c{int(source_column)}",
            instruction_offset=int(physical_time_index),
            prior_probs=prior_probs,
            prior_log_probs=tuple(
                float("-inf") if float(value) <= 0.0 else float(math.log(float(value)))
                for value in prior_probs
            ),
            detector_response_masks=(0, int(detector_mask)),
            logical_response_masks=(0, int(logical_mask)),
            detector_support_mask=int(detector_mask),
            detector_support_rows=tuple(int(value) for value in det_rows.tolist()),
            kind="pauli",
            sector=str(sector).upper(),
            physical_time_index=int(physical_time_index),
            touched_physical_qubits=tuple(int(value) for value in touched_physical_qubits),
            original_column_index=int(source_column),
        )
        time_ordered_entries.append(
            (
                int(physical_time_index),
                int(source_column),
                column,
                tuple(int(value) for value in source_fault_ids),
            )
        )

    time_ordered_entries.sort(key=lambda item: (int(item[0]), int(item[1])))
    columns_time_ordered = tuple(
        replace(column, index=int(order_index))
        for order_index, (_time_index, _source_column, column, _source_fault_ids) in enumerate(time_ordered_entries)
    )
    source_fault_ids_by_column = tuple(
        tuple(int(value) for value in source_fault_ids)
        for _time_index, _source_column, _column, source_fault_ids in time_ordered_entries
    )

    standard_detector_metadata, measurement_metadata = build_stim_worldline_conditioning_metadata(
        stim_path=str(spec.stim_path),
        sector=str(sector).upper(),
    )
    lifecycles = build_stim_measurement_lifecycles(
        stim_path=str(spec.stim_path),
        sector=str(sector).upper(),
    )
    return StimSplitSectorConditionalBundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
        stim_path=str(spec.stim_path),
        columns_time_ordered=tuple(columns_time_ordered),
        source_fault_ids_by_column=tuple(source_fault_ids_by_column),
        standard_detector_metadata=tuple(standard_detector_metadata),
        measurement_metadata=tuple(measurement_metadata),
        lifecycles=tuple(lifecycles),
        faults=tuple(analysis.faults),
        detector_from_measurements=np.asarray(spec.detector_from_channels, dtype=np.uint8),
        logical_from_measurements=np.asarray(spec.logical_from_channels, dtype=np.uint8),
        reference_measurements=np.asarray(analysis.raw_measurement_reference, dtype=np.uint8),
    )


def _fault_touches_lifecycle(
    *,
    fault: object,
    lifecycle: StimMeasurementLifecycle,
) -> bool:
    instruction_index = int(fault.instruction_index)
    fault_qubits = {int(value) for value in tuple(fault.qubits)}
    for segment in tuple(lifecycle.trajectory_segments):
        if not (
            int(segment.start_instruction_index)
            <= int(instruction_index)
            < int(segment.end_instruction_index_exclusive)
        ):
            continue
        if int(segment.qubit) in fault_qubits:
            return True
    return False


def _analyze_circuit_faults_relaxed_raw_measurements(
    *,
    circuit: object,
    detector_names: Sequence[str],
    logical_names: Sequence[str],
    measurement_channel_names: Sequence[str],
    detector_from_channels: np.ndarray,
    logical_from_channels: np.ndarray,
) -> object:
    _ensure_real_grosscode_package()
    from grosscode.dem.stim_fault_pipeline import (
        CircuitFaultAnalysis,
        compute_fault_measurement_flip_matrix,
        enumerate_fault_locations,
        merge_column_statistics,
        merge_identical_fault_columns,
        stim_dem_columns,
    )

    faults = enumerate_fault_locations(circuit)
    no_noise_circuit = circuit.without_noise()
    reference_measurements = np.asarray(no_noise_circuit.compile_sampler(seed=1).sample(shots=1)[0], dtype=np.uint8)
    raw_probabilities = np.asarray([fault.probability for fault in faults], dtype=np.float64)
    raw_measurement_channel_matrix = compute_fault_measurement_flip_matrix(circuit, faults)
    raw_detector_matrix = (
        np.asarray(detector_from_channels, dtype=np.uint8) @ np.asarray(raw_measurement_channel_matrix, dtype=np.uint8)
    ) % np.uint8(2)
    raw_logical_matrix = (
        np.asarray(logical_from_channels, dtype=np.uint8) @ np.asarray(raw_measurement_channel_matrix, dtype=np.uint8)
    ) % np.uint8(2)
    merged_columns = merge_identical_fault_columns(
        faults=faults,
        raw_detector_matrix=raw_detector_matrix,
        raw_logical_matrix=raw_logical_matrix,
        raw_probabilities=raw_probabilities,
        drop_invisible=True,
    )
    merge_statistics = merge_column_statistics(
        faults=faults,
        raw_detector_matrix=raw_detector_matrix,
        raw_logical_matrix=raw_logical_matrix,
        raw_probabilities=raw_probabilities,
        merged_columns=merged_columns,
    )
    return CircuitFaultAnalysis(
        faults=tuple(faults),
        raw_probabilities=np.asarray(raw_probabilities, dtype=np.float64),
        raw_detector_matrix=np.asarray(raw_detector_matrix, dtype=np.uint8),
        raw_logical_matrix=np.asarray(raw_logical_matrix, dtype=np.uint8),
        merged_columns=tuple(merged_columns),
        stim_columns=tuple(stim_dem_columns(circuit)),
        detector_names=tuple(str(value) for value in detector_names),
        logical_names=tuple(str(value) for value in logical_names),
        measurement_channel_names=tuple(str(value) for value in measurement_channel_names),
        raw_measurement_channel_matrix=np.asarray(raw_measurement_channel_matrix, dtype=np.uint8),
        detector_from_channels=np.asarray(detector_from_channels, dtype=np.uint8),
        logical_from_channels=np.asarray(logical_from_channels, dtype=np.uint8),
        raw_measurement_reference=np.asarray(reference_measurements, dtype=np.uint8),
        measurement_channel_reference=np.asarray(reference_measurements, dtype=np.uint8),
        merge_statistics=merge_statistics,
    )


@lru_cache(maxsize=16)
def _build_rotated_surface_midswap_split_sector_conditional_bundle(
    *,
    backend: str,
    sector: str,
    error_rate: float,
) -> StimSplitSectorConditionalBundle:
    import stim  # type: ignore

    _ensure_real_grosscode_package()
    from grosscode.dem.builder import load_dem_side_with_metadata_from_stim
    from grosscode.dem.stim_fault_pipeline import (
        circuit_measurement_names,
        circuit_record_to_detector_logical_matrices,
    )

    schedule_bundle = _build_rotated_surface_midswap_sampling_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    loaded_side = load_dem_side_with_metadata_from_stim(
        stim_path=str(schedule_bundle.stim_path),
        backend=f"{str(backend)}_midswap",
        sector=str(schedule_bundle.sector),
        error_rate=float(error_rate),
        noisy_rounds=int(schedule_bundle.syndrome_rounds),
        perfect_rounds=0,
    )
    circuit = stim.Circuit.from_file(str(schedule_bundle.stim_path))
    measurement_names = circuit_measurement_names(circuit)
    detector_from_measurements, logical_from_measurements, detector_names, logical_names = (
        circuit_record_to_detector_logical_matrices(circuit)
    )
    analysis = _analyze_circuit_faults_relaxed_raw_measurements(
        circuit=circuit,
        detector_names=tuple(detector_names),
        logical_names=tuple(logical_names),
        measurement_channel_names=tuple(measurement_names),
        detector_from_channels=np.asarray(detector_from_measurements, dtype=np.uint8),
        logical_from_channels=np.asarray(logical_from_measurements, dtype=np.uint8),
    )

    detector = loaded_side.check_matrix
    logical = loaded_side.observables_matrix
    priors = loaded_side.priors
    detector_csc = detector.tocsc()
    logical_csc = logical.tocsc()

    merged_by_signature: dict[tuple[int, int], object] = {}
    for merged in tuple(analysis.merged_columns):
        signature = (
            _bitmask_from_support_rows([index for index, bit in enumerate(tuple(merged.detector_bits)) if int(bit) != 0]),
            _bitmask_from_support_rows([index for index, bit in enumerate(tuple(merged.logical_bits)) if int(bit) != 0]),
        )
        if signature in merged_by_signature:
            raise ValueError(f"duplicate mid-swap merged signature encountered: {signature!r}")
        merged_by_signature[signature] = merged

    time_ordered_entries: list[tuple[int, int, ProgressiveColumn, tuple[int, ...]]] = []
    for source_column in range(int(detector.shape[1])):
        det_start = int(detector_csc.indptr[int(source_column)])
        det_stop = int(detector_csc.indptr[int(source_column) + 1])
        det_rows = detector_csc.indices[det_start:det_stop].astype(np.int32, copy=False)
        log_start = int(logical_csc.indptr[int(source_column)])
        log_stop = int(logical_csc.indptr[int(source_column) + 1])
        log_rows = logical_csc.indices[log_start:log_stop].astype(np.int32, copy=False)
        detector_mask = _bitmask_from_support_rows(det_rows.tolist())
        logical_mask = _bitmask_from_support_rows(log_rows.tolist())
        merged = merged_by_signature.get((int(detector_mask), int(logical_mask)))
        if merged is None:
            raise ValueError(
                "could not match mid-swap DEM column to Stim merged fault metadata for "
                f"backend={backend!r} sector={sector!r} column={int(source_column)}"
            )
        if not math.isclose(float(merged.probability), float(priors[int(source_column)]), rel_tol=0.0, abs_tol=1e-12):
            raise ValueError(
                "mid-swap prior mismatch against Stim merged fault metadata for "
                f"backend={backend!r} sector={sector!r} column={int(source_column)}: "
                f"{float(priors[int(source_column)]):.18g} vs {float(merged.probability):.18g}"
            )
        source_fault_ids = tuple(int(value) for value in tuple(merged.raw_fault_ids))
        source_faults = [analysis.faults[int(raw_id)] for raw_id in source_fault_ids]
        touched_physical_qubits = tuple(
            sorted(
                {
                    int(qubit)
                    for fault in source_faults
                    for qubit in tuple(int(value) for value in fault.qubits)
                }
            )
        )
        physical_time_index = min((int(fault.instruction_index) for fault in source_faults), default=int(source_column))
        q = float(priors[int(source_column)])
        prior_probs = (float(1.0 - q), float(q))
        column = ProgressiveColumn(
            family=f"stim_split_sector_midswap_{str(backend)}",
            index=-1,
            label=f"stim_midswap_dem_c{int(source_column)}",
            instruction_offset=int(physical_time_index),
            prior_probs=prior_probs,
            prior_log_probs=tuple(
                float("-inf") if float(value) <= 0.0 else float(math.log(float(value)))
                for value in prior_probs
            ),
            detector_response_masks=(0, int(detector_mask)),
            logical_response_masks=(0, int(logical_mask)),
            detector_support_mask=int(detector_mask),
            detector_support_rows=tuple(int(value) for value in det_rows.tolist()),
            kind="pauli",
            sector=str(sector).upper(),
            physical_time_index=int(physical_time_index),
            touched_physical_qubits=tuple(int(value) for value in touched_physical_qubits),
            original_column_index=int(source_column),
        )
        time_ordered_entries.append(
            (
                int(physical_time_index),
                int(source_column),
                column,
                tuple(int(value) for value in source_fault_ids),
            )
        )

    time_ordered_entries.sort(key=lambda item: (int(item[0]), int(item[1])))
    columns_time_ordered = tuple(
        replace(column, index=int(order_index))
        for order_index, (_time_index, _source_column, column, _source_fault_ids) in enumerate(time_ordered_entries)
    )
    source_fault_ids_by_column = tuple(
        tuple(int(value) for value in source_fault_ids)
        for _time_index, _source_column, _column, source_fault_ids in time_ordered_entries
    )
    return StimSplitSectorConditionalBundle(
        backend=f"{str(backend)}_midswap",
        sector=str(sector).upper(),
        error_rate=float(error_rate),
        stim_path=str(schedule_bundle.stim_path),
        columns_time_ordered=tuple(columns_time_ordered),
        source_fault_ids_by_column=tuple(source_fault_ids_by_column),
        standard_detector_metadata=tuple(schedule_bundle.standard_detector_metadata),
        measurement_metadata=tuple(schedule_bundle.measurement_metadata),
        lifecycles=tuple(schedule_bundle.lifecycles),
        faults=tuple(analysis.faults),
        detector_from_measurements=np.asarray(detector_from_measurements, dtype=np.uint8),
        logical_from_measurements=np.asarray(logical_from_measurements, dtype=np.uint8),
        reference_measurements=np.asarray(analysis.raw_measurement_reference, dtype=np.uint8),
    )


def _simulate_rotated_surface_midswap_loss_branch_effect(
    *,
    bundle: StimSplitSectorConditionalBundle,
    schedule_bundle: RotatedSurfaceMidSwapScheduleBundle,
    lifecycle: StimMeasurementLifecycle,
    branch_rank: int,
) -> tuple[int, int]:
    modified = _build_rotated_surface_midswap_lossy_circuit_for_selected_lifecycles(
        bundle=schedule_bundle,
        selected_branch_ranks_by_lifecycle={int(lifecycle.lifecycle_id): int(branch_rank)},
    )
    modified_measurements = np.asarray(modified.compile_sampler(seed=1).sample(shots=1)[0], dtype=np.uint8)
    if modified_measurements.shape != bundle.reference_measurements.shape:
        raise ValueError(
            "mid-swap modified lifecycle-loss circuit changed the measurement count: "
            f"{modified_measurements.shape} vs {bundle.reference_measurements.shape}"
        )
    measurement_delta = np.bitwise_xor(modified_measurements, bundle.reference_measurements)
    detector_bits = (
        np.asarray(bundle.detector_from_measurements, dtype=np.uint8) @ np.asarray(measurement_delta, dtype=np.uint8)
    ) % np.uint8(2)
    logical_bits = (
        np.asarray(bundle.logical_from_measurements, dtype=np.uint8) @ np.asarray(measurement_delta, dtype=np.uint8)
    ) % np.uint8(2)
    return (
        _bitmask_from_support_rows(np.flatnonzero(detector_bits).tolist()),
        _bitmask_from_support_rows(np.flatnonzero(logical_bits).tolist()),
    )


def enumerate_rotated_surface_loss_branch_specs(
    *,
    backend: str,
    sector: str,
    error_rate: float,
    raw_measurement_outcomes: Sequence[object],
    loss_rate: float,
) -> tuple[tuple[LossBranchSpec, ...], dict[int, tuple[int, ...]]]:
    _ensure_real_grosscode_package()
    from grosscode.codes.rotated_surface import is_rotated_surface_backend

    if not is_rotated_surface_backend(str(backend)):
        raise ValueError(f"backend must be a rotated-surface backend, got {backend!r}")
    p_loss = float(loss_rate)
    if p_loss < 0.0 or p_loss >= 1.0:
        raise ValueError(f"loss_rate must lie in [0, 1), got {loss_rate!r}")

    bundle = _build_stim_split_sector_conditional_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    raw_outcomes = tuple(raw_measurement_outcomes)
    if len(raw_outcomes) != int(bundle.reference_measurements.shape[0]):
        raise ValueError(
            "raw_measurement_outcomes length must match the circuit raw measurement count: "
            f"got {len(raw_outcomes)} vs {int(bundle.reference_measurements.shape[0])}"
        )

    flagged_lifecycles = []
    for lifecycle in tuple(bundle.lifecycles):
        is_loss, _bit = _coerce_ternary_measurement(raw_outcomes[int(lifecycle.raw_measurement_index)])
        if bool(is_loss):
            flagged_lifecycles.append(lifecycle)

    branch_specs: list[LossBranchSpec] = []
    lifecycle_by_id = {int(lifecycle.lifecycle_id): lifecycle for lifecycle in flagged_lifecycles}
    for lifecycle in tuple(flagged_lifecycles):
        candidate_sites = tuple(lifecycle.candidate_sites)
        if not candidate_sites:
            raise ValueError(
                f"flagged rotated-surface lifecycle {int(lifecycle.lifecycle_id)} on qubit {int(lifecycle.qubit)} "
                "has no candidate loss sites"
            )
        if float(p_loss) <= 0.0:
            raise ValueError(
                "flagged rotated-surface lifecycles require loss_rate > 0 in the current first-loss model"
            )
        for rank, site in enumerate(candidate_sites):
            detector_mask, logical_mask = _simulate_stim_measurement_loss_branch_effect(
                stim_path=str(bundle.stim_path),
                lifecycle=lifecycle,
                candidate_site=site,
                detector_from_measurements=bundle.detector_from_measurements,
                logical_from_measurements=bundle.logical_from_measurements,
                reference_measurements=bundle.reference_measurements,
            )
            branch_specs.append(
                LossBranchSpec(
                    lifecycle_id=int(lifecycle.lifecycle_id),
                    branch_rank_within_lifecycle=int(rank),
                    physical_time_index=int(site.instruction_index),
                    standard_detector_mask=int(detector_mask),
                    logical_mask=int(logical_mask),
                    raw_mass=float(p_loss * ((1.0 - p_loss) ** int(rank))),
                    label=(
                        f"loss_m{int(lifecycle.raw_measurement_index)}_q{int(lifecycle.qubit)}_"
                        f"i{int(site.instruction_index)}_g{int(site.target_group_index)}"
                    ),
                    sector=str(bundle.sector),
                    touched_physical_qubits=(int(lifecycle.qubit),),
                )
            )

    pauli_touched_lifecycles: dict[int, tuple[int, ...]] = {}
    if lifecycle_by_id:
        flagged_items = tuple(lifecycle_by_id.items())
        for column, source_fault_ids in zip(
            tuple(bundle.columns_time_ordered),
            tuple(bundle.source_fault_ids_by_column),
            strict=True,
        ):
            touched = set()
            for raw_fault_id in tuple(source_fault_ids):
                fault = bundle.faults[int(raw_fault_id)]
                for lifecycle_id, lifecycle in flagged_items:
                    if int(lifecycle.qubit) not in tuple(int(value) for value in fault.qubits):
                        continue
                    if not (
                        int(lifecycle.start_instruction_exclusive) < int(fault.instruction_index)
                        <= int(lifecycle.end_instruction_inclusive)
                    ):
                        continue
                    touched.add(int(lifecycle_id))
            if touched:
                pauli_touched_lifecycles[int(column.index)] = tuple(sorted(int(value) for value in touched))
    return tuple(branch_specs), pauli_touched_lifecycles


def build_rotated_surface_conditional_loss_dem(
    *,
    backend: str,
    sector: str,
    error_rate: float,
    raw_measurement_outcomes: Sequence[object],
    loss_rate: float,
) -> ConditionalLossDEM:
    _ensure_real_grosscode_package()
    from grosscode.codes.rotated_surface import is_rotated_surface_backend

    if not is_rotated_surface_backend(str(backend)):
        raise ValueError(f"backend must be a rotated-surface backend, got {backend!r}")
    bundle = _build_stim_split_sector_conditional_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    raw_outcomes = tuple(raw_measurement_outcomes)
    if len(raw_outcomes) != int(bundle.reference_measurements.shape[0]):
        raise ValueError(
            "raw_measurement_outcomes length must match the circuit raw measurement count: "
            f"got {len(raw_outcomes)} vs {int(bundle.reference_measurements.shape[0])}"
        )
    endpoint_outcomes = project_raw_ternary_measurements_to_worldline_endpoints(
        measurement_metadata=bundle.measurement_metadata,
        raw_measurement_outcomes=raw_outcomes,
    )
    branch_specs, pauli_touched_lifecycles = enumerate_rotated_surface_loss_branch_specs(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
        raw_measurement_outcomes=raw_outcomes,
        loss_rate=float(loss_rate),
    )
    return build_conditional_loss_dem(
        columns_time_ordered=bundle.columns_time_ordered,
        standard_detector_metadata=bundle.standard_detector_metadata,
        measurement_metadata=bundle.measurement_metadata,
        measurement_outcomes=endpoint_outcomes,
        loss_branch_specs=tuple(branch_specs),
        pauli_touched_lifecycles=pauli_touched_lifecycles,
        sector=str(bundle.sector),
    )


def enumerate_rotated_surface_midswap_loss_branch_specs(
    *,
    backend: str,
    sector: str,
    error_rate: float,
    raw_measurement_outcomes: Sequence[object],
    loss_rate: float,
) -> tuple[tuple[LossBranchSpec, ...], dict[int, tuple[int, ...]]]:
    _ensure_real_grosscode_package()
    from grosscode.codes.rotated_surface import is_rotated_surface_backend

    if not is_rotated_surface_backend(str(backend)):
        raise ValueError(f"backend must be a rotated-surface backend, got {backend!r}")
    p_loss = float(loss_rate)
    if p_loss < 0.0 or p_loss >= 1.0:
        raise ValueError(f"loss_rate must lie in [0, 1), got {loss_rate!r}")

    bundle = _build_rotated_surface_midswap_split_sector_conditional_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    schedule_bundle = _build_rotated_surface_midswap_sampling_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    raw_outcomes = tuple(raw_measurement_outcomes)
    if len(raw_outcomes) != int(bundle.reference_measurements.shape[0]):
        raise ValueError(
            "raw_measurement_outcomes length must match the mid-swap circuit raw measurement count: "
            f"got {len(raw_outcomes)} vs {int(bundle.reference_measurements.shape[0])}"
        )

    flagged_lifecycles = []
    for lifecycle in tuple(bundle.lifecycles):
        is_loss, _bit = _coerce_ternary_measurement(raw_outcomes[int(lifecycle.raw_measurement_index)])
        if bool(is_loss):
            flagged_lifecycles.append(lifecycle)

    branch_specs: list[LossBranchSpec] = []
    lifecycle_by_id = {int(lifecycle.lifecycle_id): lifecycle for lifecycle in flagged_lifecycles}
    for lifecycle in tuple(flagged_lifecycles):
        candidate_sites = tuple(lifecycle.candidate_sites)
        if not candidate_sites:
            raise ValueError(
                f"flagged mid-swap lifecycle {int(lifecycle.lifecycle_id)} has no candidate loss sites"
            )
        if float(p_loss) <= 0.0:
            raise ValueError("flagged mid-swap lifecycles require loss_rate > 0 in the current first-loss model")
        for rank, site in enumerate(candidate_sites):
            detector_mask, logical_mask = _simulate_rotated_surface_midswap_loss_branch_effect(
                bundle=bundle,
                schedule_bundle=schedule_bundle,
                lifecycle=lifecycle,
                branch_rank=int(rank),
            )
            branch_specs.append(
                LossBranchSpec(
                    lifecycle_id=int(lifecycle.lifecycle_id),
                    branch_rank_within_lifecycle=int(rank),
                    physical_time_index=int(site.instruction_index),
                    standard_detector_mask=int(detector_mask),
                    logical_mask=int(logical_mask),
                    raw_mass=float(p_loss * ((1.0 - p_loss) ** int(rank))),
                    label=(
                        f"midswap_loss_{str(lifecycle.role_kind)}{int(lifecycle.role_id)}_"
                        f"r{int(lifecycle.round_index)}_m{int(lifecycle.raw_measurement_index)}_"
                        f"i{int(site.instruction_index)}_g{int(site.target_group_index)}"
                    ),
                    sector=str(bundle.sector),
                    touched_physical_qubits=(int(site.qubit),),
                )
            )

    pauli_touched_lifecycles: dict[int, tuple[int, ...]] = {}
    if lifecycle_by_id:
        flagged_items = tuple(lifecycle_by_id.items())
        for column, source_fault_ids in zip(
            tuple(bundle.columns_time_ordered),
            tuple(bundle.source_fault_ids_by_column),
            strict=True,
        ):
            touched = set()
            for raw_fault_id in tuple(source_fault_ids):
                fault = bundle.faults[int(raw_fault_id)]
                for lifecycle_id, lifecycle in flagged_items:
                    if _fault_touches_lifecycle(fault=fault, lifecycle=lifecycle):
                        touched.add(int(lifecycle_id))
            if touched:
                pauli_touched_lifecycles[int(column.index)] = tuple(sorted(int(value) for value in touched))
    return tuple(branch_specs), pauli_touched_lifecycles


def build_rotated_surface_midswap_conditional_loss_dem(
    *,
    backend: str,
    sector: str,
    error_rate: float,
    raw_measurement_outcomes: Sequence[object],
    loss_rate: float,
) -> ConditionalLossDEM:
    _ensure_real_grosscode_package()
    from grosscode.codes.rotated_surface import is_rotated_surface_backend

    if not is_rotated_surface_backend(str(backend)):
        raise ValueError(f"backend must be a rotated-surface backend, got {backend!r}")
    bundle = _build_rotated_surface_midswap_split_sector_conditional_bundle(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
    )
    raw_outcomes = tuple(raw_measurement_outcomes)
    if len(raw_outcomes) != int(bundle.reference_measurements.shape[0]):
        raise ValueError(
            "raw_measurement_outcomes length must match the mid-swap circuit raw measurement count: "
            f"got {len(raw_outcomes)} vs {int(bundle.reference_measurements.shape[0])}"
        )
    endpoint_outcomes = project_raw_ternary_measurements_to_worldline_endpoints(
        measurement_metadata=bundle.measurement_metadata,
        raw_measurement_outcomes=raw_outcomes,
    )
    branch_specs, pauli_touched_lifecycles = enumerate_rotated_surface_midswap_loss_branch_specs(
        backend=str(backend),
        sector=str(sector).upper(),
        error_rate=float(error_rate),
        raw_measurement_outcomes=raw_outcomes,
        loss_rate=float(loss_rate),
    )
    return build_conditional_loss_dem(
        columns_time_ordered=bundle.columns_time_ordered,
        standard_detector_metadata=bundle.standard_detector_metadata,
        measurement_metadata=bundle.measurement_metadata,
        measurement_outcomes=endpoint_outcomes,
        loss_branch_specs=tuple(branch_specs),
        pauli_touched_lifecycles=pauli_touched_lifecycles,
        sector=str(bundle.sector),
    )


def build_loss_row_transform(
    *,
    standard_detector_metadata: Sequence[StandardDetectorRowMetadata],
    measurement_metadata: Sequence[MeasurementOutcomeMetadata],
    measurement_outcomes: Sequence[object],
) -> tuple[sp.csr_matrix, tuple[int, ...], tuple[ConditionalDetectorRowMetadata, ...], int]:
    standard_rows = tuple(sorted(tuple(standard_detector_metadata), key=lambda item: int(item.row_index)))
    measurements = tuple(sorted(tuple(measurement_metadata), key=lambda item: int(item.measurement_index)))
    if len(measurements) != len(tuple(measurement_outcomes)):
        raise ValueError(
            "measurement_outcomes length must match measurement_metadata length: "
            f"got {len(tuple(measurement_outcomes))} vs {len(measurements)}"
        )
    if standard_rows and tuple(int(item.row_index) for item in standard_rows) != tuple(range(len(standard_rows))):
        raise ValueError("standard_detector_metadata row_index values must be dense 0..N-1")
    if measurements and tuple(int(item.measurement_index) for item in measurements) != tuple(range(len(measurements))):
        raise ValueError("measurement_metadata measurement_index values must be dense 0..M-1")

    loss_flags: dict[int, bool] = {}
    binary_bits: dict[int, int] = {}
    for meta, raw_value in zip(measurements, tuple(measurement_outcomes), strict=True):
        is_loss, bit = _coerce_ternary_measurement(raw_value)
        loss_flags[int(meta.measurement_index)] = bool(is_loss)
        binary_bits[int(meta.measurement_index)] = int(bit)

    measurement_by_worldline: dict[int, list[MeasurementOutcomeMetadata]] = {}
    for meta in measurements:
        measurement_by_worldline.setdefault(int(meta.worldline_id), []).append(meta)
    for worldline_id in tuple(measurement_by_worldline.keys()):
        measurement_by_worldline[int(worldline_id)] = sorted(
            measurement_by_worldline[int(worldline_id)],
            key=lambda item: (int(item.time_index), int(item.measurement_index)),
        )

    standard_rows_by_worldline: dict[int, list[StandardDetectorRowMetadata]] = {}
    for meta in standard_rows:
        standard_rows_by_worldline.setdefault(int(meta.worldline_id), []).append(meta)
    for worldline_id in tuple(standard_rows_by_worldline.keys()):
        standard_rows_by_worldline[int(worldline_id)] = sorted(
            standard_rows_by_worldline[int(worldline_id)],
            key=lambda item: (int(item.start_time_index), int(item.end_time_index), int(item.row_index)),
        )

    conditional_entries: list[tuple[tuple[int, int, int, int, int], tuple[int, ...], int, ConditionalDetectorRowMetadata]] = []

    for worldline_id, worldline_measurements in sorted(measurement_by_worldline.items()):
        surviving = [
            meta
            for meta in tuple(worldline_measurements)
            if not bool(loss_flags[int(meta.measurement_index)])
        ]
        if len(surviving) < 2:
            continue
        worldline_rows = tuple(standard_rows_by_worldline.get(int(worldline_id), ()))
        for prev_meta, next_meta in zip(surviving[:-1], surviving[1:], strict=True):
            source_rows = tuple(
                int(row.row_index)
                for row in worldline_rows
                if int(row.start_time_index) >= int(prev_meta.time_index)
                and int(row.end_time_index) <= int(next_meta.time_index)
            )
            if not source_rows:
                raise ValueError(
                    "could not bridge surviving measurements on worldline "
                    f"{int(worldline_id)} between measurement indices "
                    f"{int(prev_meta.measurement_index)} and {int(next_meta.measurement_index)}"
                )
            direct_bit = int(binary_bits[int(prev_meta.measurement_index)]) ^ int(binary_bits[int(next_meta.measurement_index)])
            conditional_metadata = (
                ConditionalDetectorRowMetadata(
                    row_index=-1,
                    sector=str(prev_meta.sector or next_meta.sector),
                    worldline_id=int(worldline_id),
                    start_measurement_index=int(prev_meta.measurement_index),
                    end_measurement_index=int(next_meta.measurement_index),
                    start_time_index=int(prev_meta.time_index),
                    end_time_index=int(next_meta.time_index),
                    source_standard_rows=tuple(int(row) for row in source_rows),
                    boundary_kind=str(prev_meta.boundary_kind or next_meta.boundary_kind),
                )
            )
            conditional_entries.append(
                (
                    (
                        int(min(source_rows)),
                        int(max(source_rows)),
                        int(worldline_id),
                        int(prev_meta.time_index),
                        int(next_meta.time_index),
                    ),
                    tuple(int(row) for row in source_rows),
                    int(direct_bit),
                    conditional_metadata,
                )
            )

    conditional_entries.sort(key=lambda item: item[0])
    row_indices: list[int] = []
    col_indices: list[int] = []
    data: list[np.uint8] = []
    row_masks: list[int] = []
    conditional_metadata_rows: list[ConditionalDetectorRowMetadata] = []
    target_syndrome_bits = 0
    for conditional_row_index, (_sort_key, source_rows, direct_bit, metadata) in enumerate(conditional_entries):
        row_mask = _dense_row_mask_from_rows(source_rows)
        row_masks.append(int(row_mask))
        for source_row in source_rows:
            row_indices.append(int(conditional_row_index))
            col_indices.append(int(source_row))
            data.append(np.uint8(1))
        if int(direct_bit) != 0:
            target_syndrome_bits |= 1 << int(conditional_row_index)
        conditional_metadata_rows.append(
            replace(
                metadata,
                row_index=int(conditional_row_index),
            )
        )

    row_transform = sp.csr_matrix(
        (
            np.asarray(data, dtype=np.uint8),
            (
                np.asarray(row_indices, dtype=np.int32),
                np.asarray(col_indices, dtype=np.int32),
            ),
        ),
        shape=(int(len(conditional_entries)), len(standard_rows)),
        dtype=np.uint8,
    )
    return (
        row_transform,
        tuple(int(mask) for mask in row_masks),
        tuple(conditional_metadata_rows),
        int(target_syndrome_bits),
    )


def build_conditional_loss_dem(
    *,
    columns_time_ordered: Sequence[ProgressiveColumn],
    standard_detector_metadata: Sequence[StandardDetectorRowMetadata],
    measurement_metadata: Sequence[MeasurementOutcomeMetadata],
    measurement_outcomes: Sequence[object],
    loss_branch_specs: Sequence[LossBranchSpec] = (),
    standard_target_syndrome: int | np.ndarray | list[int] | tuple[int, ...] | None = None,
    pauli_touched_lifecycles: dict[int, Sequence[int]] | None = None,
    pauli_touched_physical_qubits: dict[int, Sequence[int]] | None = None,
    sector: str = "",
) -> ConditionalLossDEM:
    (
        row_transform,
        row_transform_row_masks,
        detector_metadata_r,
        direct_target_syndrome_r,
    ) = build_loss_row_transform(
        standard_detector_metadata=standard_detector_metadata,
        measurement_metadata=measurement_metadata,
        measurement_outcomes=measurement_outcomes,
    )

    if standard_target_syndrome is not None:
        standard_target_mask = _syndrome_to_int(standard_target_syndrome)
        transformed_target = _apply_row_transform_to_mask(
            standard_mask=int(standard_target_mask),
            row_transform_row_masks=row_transform_row_masks,
        )
        if int(transformed_target) != int(direct_target_syndrome_r):
            raise ValueError(
                "standard_target_syndrome transformed by R(r) disagrees with the direct target syndrome "
                f"({int(transformed_target)} vs {int(direct_target_syndrome_r)})"
            )
    target_syndrome_r = int(direct_target_syndrome_r)

    transformed_columns: list[tuple[int, int, ProgressiveColumn]] = []
    original_columns = tuple(columns_time_ordered)
    pauli_touch_map = {int(key): tuple(int(value) for value in values) for key, values in dict(pauli_touched_lifecycles or {}).items()}
    pauli_qubit_map = {
        int(key): tuple(int(value) for value in values)
        for key, values in dict(pauli_touched_physical_qubits or {}).items()
    }
    insertion_counter = 0
    for raw_column in original_columns:
        detector_masks = tuple(
            int(
                _apply_row_transform_to_mask(
                    standard_mask=int(mask),
                    row_transform_row_masks=row_transform_row_masks,
                )
            )
            for mask in tuple(raw_column.detector_response_masks)
        )
        support_mask = _support_mask_from_detector_responses(detector_masks)
        original_index = (
            int(raw_column.original_column_index)
            if int(raw_column.original_column_index) >= 0
            else int(raw_column.index)
        )
        transformed = replace(
            raw_column,
            detector_response_masks=detector_masks,
            detector_support_mask=int(support_mask),
            detector_support_rows=_support_rows_from_mask(int(support_mask)),
            kind="pauli",
            sector=str(raw_column.sector or sector),
            physical_time_index=(
                int(raw_column.physical_time_index)
                if int(raw_column.physical_time_index) >= 0
                else int(raw_column.instruction_offset)
            ),
            touched_lifecycles=(
                tuple(int(value) for value in raw_column.touched_lifecycles)
                if tuple(raw_column.touched_lifecycles)
                else tuple(pauli_touch_map.get(int(original_index), tuple()))
            ),
            touched_physical_qubits=(
                tuple(int(value) for value in raw_column.touched_physical_qubits)
                if tuple(raw_column.touched_physical_qubits)
                else tuple(pauli_qubit_map.get(int(original_index), tuple()))
            ),
            lifecycle_id=-1,
            branch_rank_within_lifecycle=-1,
            raw_mass=0.0,
            suffix_remaining_mass=0.0,
            opens_flagged_lifecycle=-1,
            closes_flagged_lifecycle=tuple(),
            original_column_index=int(original_index),
        )
        transformed_columns.append((int(transformed.physical_time_index), int(insertion_counter), transformed))
        insertion_counter += 1

    grouped_branches: dict[int, list[LossBranchSpec]] = {}
    for spec in tuple(loss_branch_specs):
        grouped_branches.setdefault(int(spec.lifecycle_id), []).append(spec)
    branch_columns: list[ProgressiveColumn] = []
    for lifecycle_id in sorted(grouped_branches.keys()):
        ordered_specs = tuple(
            sorted(
                grouped_branches[int(lifecycle_id)],
                key=lambda item: (
                    int(item.branch_rank_within_lifecycle),
                    int(item.physical_time_index),
                    str(item.label),
                ),
            )
        )
        raw_masses = [float(spec.raw_mass) for spec in ordered_specs]
        suffix_mass = 0.0
        suffix_masses = [0.0 for _ in raw_masses]
        for offset in range(len(raw_masses) - 1, -1, -1):
            suffix_mass += float(raw_masses[offset])
            suffix_masses[offset] = float(suffix_mass)
        for spec, branch_suffix_mass in zip(ordered_specs, tuple(suffix_masses), strict=True):
            if float(branch_suffix_mass) <= 0.0:
                raise ValueError(
                    f"loss lifecycle {int(lifecycle_id)} has non-positive suffix mass at rank "
                    f"{int(spec.branch_rank_within_lifecycle)}"
                )
            branch_raw_mass = float(spec.raw_mass)
            branch_off_mass = float(branch_suffix_mass) - float(branch_raw_mass)
            on_prob = float(branch_raw_mass / branch_suffix_mass)
            off_prob = float(branch_off_mass / branch_suffix_mass)
            detector_on = _apply_row_transform_to_mask(
                standard_mask=int(spec.standard_detector_mask),
                row_transform_row_masks=row_transform_row_masks,
            )
            branch_column = ProgressiveColumn(
                family="conditional_loss",
                index=-1,
                label=str(spec.label or f"loss_q{int(lifecycle_id)}_r{int(spec.branch_rank_within_lifecycle)}"),
                instruction_offset=int(spec.physical_time_index),
                prior_probs=(float(off_prob), float(on_prob)),
                prior_log_probs=(
                    float("-inf") if float(off_prob) <= 0.0 else float(math.log(float(off_prob))),
                    float("-inf") if float(on_prob) <= 0.0 else float(math.log(float(on_prob))),
                ),
                detector_response_masks=(0, int(detector_on)),
                logical_response_masks=(0, int(spec.logical_mask)),
                detector_support_mask=int(detector_on),
                detector_support_rows=_support_rows_from_mask(int(detector_on)),
                kind="loss_branch",
                sector=str(spec.sector or sector),
                physical_time_index=int(spec.physical_time_index),
                touched_lifecycles=(int(lifecycle_id),),
                touched_physical_qubits=tuple(int(value) for value in spec.touched_physical_qubits),
                lifecycle_id=int(lifecycle_id),
                branch_rank_within_lifecycle=int(spec.branch_rank_within_lifecycle),
                raw_mass=float(branch_raw_mass),
                suffix_remaining_mass=float(branch_suffix_mass),
                opens_flagged_lifecycle=-1,
                closes_flagged_lifecycle=tuple(),
                original_column_index=-1,
            )
            transformed_columns.append((int(branch_column.physical_time_index), int(insertion_counter), branch_column))
            branch_columns.append(branch_column)
            insertion_counter += 1

    ordered = sorted(transformed_columns, key=lambda item: (int(item[0]), int(item[1])))
    combined_columns = [replace(column, index=int(new_index)) for new_index, (_time_index, _order, column) in enumerate(ordered)]

    lifecycle_metadata: list[LossLifecycleMetadata] = []
    openings_by_column: dict[int, list[int]] = {}
    closings_by_column: dict[int, list[int]] = {}
    for lifecycle_id in sorted(grouped_branches.keys()):
        touching_columns = [
            int(column_index)
            for column_index, column in enumerate(combined_columns)
            if int(lifecycle_id) == int(column.lifecycle_id)
            or int(lifecycle_id) in tuple(int(value) for value in column.touched_lifecycles)
        ]
        branch_column_indices = [
            int(column_index)
            for column_index, column in enumerate(combined_columns)
            if int(column.lifecycle_id) == int(lifecycle_id) and str(column.kind) == "loss_branch"
        ]
        if not branch_column_indices:
            raise ValueError(f"flagged lifecycle {int(lifecycle_id)} has no loss branch columns")
        branch_columns_for_lifecycle = [combined_columns[int(index)] for index in branch_column_indices]
        first_column_index = int(min(branch_column_indices))
        last_column_index = int(max(touching_columns))
        openings_by_column.setdefault(int(first_column_index), []).append(int(lifecycle_id))
        closings_by_column.setdefault(int(last_column_index), []).append(int(lifecycle_id))
        lifecycle_metadata.append(
            LossLifecycleMetadata(
                lifecycle_id=int(lifecycle_id),
                sector=str(branch_columns_for_lifecycle[0].sector),
                column_indices=tuple(int(value) for value in touching_columns),
                branch_column_indices=tuple(int(value) for value in branch_column_indices),
                branch_ranks=tuple(int(column.branch_rank_within_lifecycle) for column in branch_columns_for_lifecycle),
                raw_masses=tuple(float(column.raw_mass) for column in branch_columns_for_lifecycle),
                total_raw_mass=float(sum(float(column.raw_mass) for column in branch_columns_for_lifecycle)),
                first_column_index=int(first_column_index),
                last_column_index=int(last_column_index),
            )
        )

    lifecycle_open_label_by_column = {
        int(column_index): tuple(sorted(int(value) for value in lifecycle_ids))
        for column_index, lifecycle_ids in openings_by_column.items()
    }
    lifecycle_close_label_by_column = {
        int(column_index): tuple(sorted(int(value) for value in lifecycle_ids))
        for column_index, lifecycle_ids in closings_by_column.items()
    }
    for column_index, column in enumerate(tuple(combined_columns)):
        opening_ids = lifecycle_open_label_by_column.get(int(column_index), tuple())
        closing_ids = lifecycle_close_label_by_column.get(int(column_index), tuple())
        combined_columns[int(column_index)] = replace(
            column,
            opens_flagged_lifecycle=(int(opening_ids[0]) if len(opening_ids) == 1 else -1),
            closes_flagged_lifecycle=tuple(int(value) for value in closing_ids),
        )

    num_conditional_rows = int(row_transform.shape[0])
    num_columns = int(len(combined_columns))
    detector_dense = np.zeros((num_conditional_rows, num_columns), dtype=np.uint8)
    logical_row_count = max(
        1,
        max(
            (
                max((int(mask).bit_length() for mask in tuple(column.logical_response_masks)), default=0)
                for column in tuple(combined_columns)
            ),
            default=0,
        ),
    )
    logical_dense = np.zeros((int(logical_row_count), num_columns), dtype=np.uint8)
    for column_index, column in enumerate(tuple(combined_columns)):
        activated_state = 1 if len(tuple(column.detector_response_masks)) > 1 else 0
        detector_mask = int(column.detector_response_masks[int(activated_state)])
        for row in _support_rows_from_mask(int(detector_mask)):
            detector_dense[int(row), int(column_index)] = np.uint8(1)
        logical_mask = int(column.logical_response_masks[int(activated_state)])
        for logical_index in _support_rows_from_mask(int(logical_mask)):
            logical_dense[int(logical_index), int(column_index)] = np.uint8(1)

    return ConditionalLossDEM(
        D_r=sp.csr_matrix(detector_dense, dtype=np.uint8),
        O_r=sp.csr_matrix(logical_dense, dtype=np.uint8),
        columns=tuple(combined_columns),
        target_syndrome_r=int(target_syndrome_r),
        detector_metadata_r=tuple(detector_metadata_r),
        loss_metadata=tuple(lifecycle_metadata),
        row_transform=row_transform,
        row_transform_row_masks=tuple(int(mask) for mask in row_transform_row_masks),
        standard_detector_metadata=tuple(standard_detector_metadata),
        measurement_metadata=tuple(measurement_metadata),
    )


def build_loss_aware_frontier_layout(
    columns: Sequence[ProgressiveColumn],
    *,
    num_detectors: int,
    loss_metadata: Sequence[LossLifecycleMetadata],
) -> ProgressiveFrontierLayout:
    base_layout = build_frontier_layout(list(columns), num_detectors=int(num_detectors))
    if not tuple(loss_metadata):
        return replace(
            base_layout,
            loss_mode=False,
            open_lifecycle_ids_before_column=tuple(tuple() for _ in range(len(columns))),
            open_lifecycle_ids_after_column=tuple(tuple() for _ in range(len(columns))),
            opening_lifecycle_ids_by_column=tuple(tuple() for _ in range(len(columns))),
            closing_lifecycle_ids_by_column=tuple(tuple() for _ in range(len(columns))),
            remaining_open_lifecycle_raw_mass_after_column=tuple(tuple() for _ in range(len(columns))),
        )

    opening_ids_by_column = {
        int(meta.first_column_index): tuple(
            sorted(
                int(item.lifecycle_id)
                for item in tuple(loss_metadata)
                if int(item.first_column_index) == int(meta.first_column_index)
            )
        )
        for meta in tuple(loss_metadata)
    }
    closing_ids_by_column = {
        int(meta.last_column_index): tuple(
            sorted(
                int(item.lifecycle_id)
                for item in tuple(loss_metadata)
                if int(item.last_column_index) == int(meta.last_column_index)
            )
        )
        for meta in tuple(loss_metadata)
    }
    lifecycle_meta_by_id = {int(meta.lifecycle_id): meta for meta in tuple(loss_metadata)}
    current_open: list[int] = []
    open_before: list[tuple[int, ...]] = []
    open_after: list[tuple[int, ...]] = []
    opening_by_column: list[tuple[int, ...]] = []
    closing_by_column: list[tuple[int, ...]] = []
    remaining_after: list[tuple[float, ...]] = []
    for column_index in range(len(tuple(columns))):
        opening_ids = tuple(int(value) for value in opening_ids_by_column.get(int(column_index), tuple()))
        for lifecycle_id in opening_ids:
            current_open.append(int(lifecycle_id))
        open_before.append(tuple(int(value) for value in current_open))
        opening_by_column.append(tuple(int(value) for value in opening_ids))
        closing_ids = tuple(int(value) for value in closing_ids_by_column.get(int(column_index), tuple()))
        closing_by_column.append(tuple(int(value) for value in closing_ids))
        current_open = [int(value) for value in current_open if int(value) not in set(closing_ids)]
        open_after_ids = tuple(int(value) for value in current_open)
        open_after.append(open_after_ids)
        remaining_after.append(
            tuple(
                float(
                    sum(
                        float(raw_mass)
                        for branch_column_index, raw_mass in zip(
                            lifecycle_meta_by_id[int(lifecycle_id)].branch_column_indices,
                            lifecycle_meta_by_id[int(lifecycle_id)].raw_masses,
                            strict=True,
                        )
                        if int(branch_column_index) > int(column_index)
                    )
                )
                for lifecycle_id in open_after_ids
            )
        )
    return replace(
        base_layout,
        loss_mode=True,
        open_lifecycle_ids_before_column=tuple(tuple(value) for value in open_before),
        open_lifecycle_ids_after_column=tuple(tuple(value) for value in open_after),
        opening_lifecycle_ids_by_column=tuple(tuple(value) for value in opening_by_column),
        closing_lifecycle_ids_by_column=tuple(tuple(value) for value in closing_by_column),
        remaining_open_lifecycle_raw_mass_after_column=tuple(tuple(value) for value in remaining_after),
    )


def _infer_loss_metadata_from_columns(columns: Sequence[ProgressiveColumn]) -> tuple[LossLifecycleMetadata, ...]:
    grouped_branch_positions: dict[int, list[int]] = {}
    grouped_touched_positions: dict[int, list[int]] = {}
    grouped_branch_columns: dict[int, list[ProgressiveColumn]] = {}
    for column_index, column in enumerate(tuple(columns)):
        for lifecycle_id in tuple(int(value) for value in column.touched_lifecycles):
            grouped_touched_positions.setdefault(int(lifecycle_id), []).append(int(column_index))
        if str(column.kind) == "loss_branch" and int(column.lifecycle_id) >= 0:
            lifecycle_id = int(column.lifecycle_id)
            grouped_branch_positions.setdefault(int(lifecycle_id), []).append(int(column_index))
            grouped_branch_columns.setdefault(int(lifecycle_id), []).append(column)
            grouped_touched_positions.setdefault(int(lifecycle_id), []).append(int(column_index))
    out: list[LossLifecycleMetadata] = []
    for lifecycle_id in sorted(grouped_branch_positions.keys()):
        branch_positions = tuple(int(value) for value in grouped_branch_positions[int(lifecycle_id)])
        touching_positions = tuple(sorted(set(int(value) for value in grouped_touched_positions[int(lifecycle_id)])))
        branch_columns = tuple(
            sorted(
                grouped_branch_columns[int(lifecycle_id)],
                key=lambda item: (
                    int(item.branch_rank_within_lifecycle),
                    int(item.physical_time_index),
                    int(item.index),
                ),
            )
        )
        out.append(
            LossLifecycleMetadata(
                lifecycle_id=int(lifecycle_id),
                sector=str(branch_columns[0].sector),
                column_indices=tuple(int(value) for value in touching_positions),
                branch_column_indices=tuple(int(value) for value in branch_positions),
                branch_ranks=tuple(int(column.branch_rank_within_lifecycle) for column in branch_columns),
                raw_masses=tuple(float(column.raw_mass) for column in branch_columns),
                total_raw_mass=float(sum(float(column.raw_mass) for column in branch_columns)),
                first_column_index=int(min(branch_positions)),
                last_column_index=int(max(touching_positions)),
            )
        )
    return tuple(out)


def _lifecycle_mask_to_selected_map(
    lifecycle_mask: int,
    lifecycle_ids: Sequence[int],
) -> dict[int, bool]:
    return {
        int(lifecycle_id): bool((int(lifecycle_mask) >> int(offset)) & 1)
        for offset, lifecycle_id in enumerate(tuple(int(value) for value in lifecycle_ids))
    }


def _selected_map_to_lifecycle_mask(
    selected_by_lifecycle: dict[int, bool],
    lifecycle_ids: Sequence[int],
) -> int:
    out = 0
    for offset, lifecycle_id in enumerate(tuple(int(value) for value in lifecycle_ids)):
        if bool(selected_by_lifecycle.get(int(lifecycle_id), False)):
            out |= 1 << int(offset)
    return int(out)


def _loss_pruning_score(
    *,
    state_key: int,
    prefix_log_mass: float,
    boundary_column_index: int,
    frontier: ProgressiveFrontierLayout,
    num_detectors: int,
    num_observables: int,
) -> float:
    if int(boundary_column_index) < 0 or int(boundary_column_index) >= len(frontier.open_lifecycle_ids_after_column):
        return float(prefix_log_mass)
    open_ids = tuple(int(value) for value in frontier.open_lifecycle_ids_after_column[int(boundary_column_index)])
    remaining_raw_masses = tuple(
        float(value) for value in frontier.remaining_open_lifecycle_raw_mass_after_column[int(boundary_column_index)]
    )
    lifecycle_mask = _unpack_lifecycle_mask(
        state_key=int(state_key),
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
        lifecycle_bit_count=int(len(open_ids)),
    )
    score = float(prefix_log_mass)
    for offset, remaining_raw_mass in enumerate(remaining_raw_masses):
        if ((int(lifecycle_mask) >> int(offset)) & 1) != 0:
            continue
        if float(remaining_raw_mass) <= 0.0:
            return float("-inf")
        score += float(math.log(float(remaining_raw_mass)))
    return float(score)


def _decode_progressive_loss_conditioned(
    columns: list[ProgressiveColumn],
    *,
    target_syndrome: int | np.ndarray | list[int] | tuple[int, ...],
    num_detectors: int,
    num_observables: int = 1,
    beam_size: int | None = None,
    layout: ProgressiveFrontierLayout | None = None,
    track_best_path: bool = True,
    score_mode: str = "prefix",
    lookahead_depth: int = 0,
    superstep_mode: str = "none",
    superstep_path_budget: int = 0,
    superstep_state_budget: int = 0,
    superstep_transition_budget: int = 0,
    lookahead_shortlist_size: int = 0,
    tail_exact_columns: int = 0,
    logical_rerank_columns: int = 0,
    logical_rerank_shortlist_size: int = 0,
    logical_rerank_min_classes: int = 0,
    logical_rerank_state_budget: int = 0,
    logical_rerank_transition_budget: int = 0,
) -> ProgressiveDecodeResult:
    if int(num_observables) < 1:
        raise ValueError("num_observables must be >= 1")
    if beam_size is not None and int(beam_size) < 1:
        raise ValueError("beam_size must be >= 1 when provided")
    score_mode_key = str(score_mode).strip().lower()
    if str(score_mode_key) not in {"prefix", "loss_prefix", "future_parity_logodds", "future_parity"}:
        raise ValueError(
            "loss-conditioned forward decoding currently supports only simple prefix-style pruning scores"
        )
    if int(lookahead_depth) != 0 or int(lookahead_shortlist_size) != 0:
        raise ValueError("loss-conditioned forward decoding currently supports only lookahead_depth=0")
    if str(superstep_mode).strip().lower() != "none":
        raise ValueError("loss-conditioned forward decoding currently supports only superstep_mode='none'")
    if int(tail_exact_columns) != 0:
        raise ValueError("loss-conditioned forward decoding currently supports only tail_exact_columns=0")
    if int(logical_rerank_columns) != 0 or int(logical_rerank_shortlist_size) != 0:
        raise ValueError("loss-conditioned forward decoding currently supports only logical_rerank_columns=0")

    loss_metadata = _infer_loss_metadata_from_columns(columns)
    frontier = (
        layout
        if layout is not None
        else build_loss_aware_frontier_layout(
            columns=list(columns),
            num_detectors=int(num_detectors),
            loss_metadata=loss_metadata,
        )
    )
    if (
        len(tuple(frontier.open_lifecycle_ids_before_column)) != len(tuple(columns))
        or len(tuple(frontier.open_lifecycle_ids_after_column)) != len(tuple(columns))
        or (not bool(frontier.loss_mode) and tuple(loss_metadata))
    ):
        frontier = build_loss_aware_frontier_layout(
            columns=list(columns),
            num_detectors=int(num_detectors),
            loss_metadata=loss_metadata,
        )

    target_syndrome_int = _syndrome_to_int(target_syndrome)
    logical_state_count = 1 << int(num_observables)
    detector_mask_mask = (1 << int(num_detectors)) - 1
    initial_state_key = _pack_state_key(
        det_mask=0,
        logical_mask=0,
        num_detectors=int(num_detectors),
        num_observables=int(num_observables),
        lifecycle_mask=0,
        lifecycle_bit_count=0,
    )
    state_log_mass: dict[int, float] = {int(initial_state_key): 0.0}
    state_viterbi: dict[int, float] = {int(initial_state_key): 0.0}
    parent_chain: list[dict[int, tuple[int, int]]] = []
    state_count_by_column = [1]
    pruned_state_count_by_column: list[int] = []
    expanded_transition_count_by_column: list[int] = []
    lookahead_transition_count_by_column: list[int] = []

    for column_index, column in enumerate(tuple(columns)):
        previous_open_ids = (
            tuple()
            if int(column_index) == 0
            else tuple(int(value) for value in frontier.open_lifecycle_ids_after_column[int(column_index) - 1])
        )
        current_open_ids = tuple(int(value) for value in frontier.open_lifecycle_ids_before_column[int(column_index)])
        next_open_ids = tuple(int(value) for value in frontier.open_lifecycle_ids_after_column[int(column_index)])
        opening_ids = tuple(int(value) for value in frontier.opening_lifecycle_ids_by_column[int(column_index)])
        closing_ids = tuple(int(value) for value in frontier.closing_lifecycle_ids_by_column[int(column_index)])
        if tuple(current_open_ids) != tuple(previous_open_ids) + tuple(opening_ids):
            previous_open_set = set(int(value) for value in previous_open_ids)
            opening_set = set(int(value) for value in opening_ids)
            if set(int(value) for value in current_open_ids) != previous_open_set | opening_set:
                raise ValueError("loss-aware layout lifecycle intervals are inconsistent at column boundary")
        close_mask = int(frontier.closing_masks[int(column_index)])
        active_mask = int(frontier.active_masks_after_column[int(column_index)])
        log_priors = _column_log_priors(column)
        next_log_mass: dict[int, float] = {}
        next_viterbi: dict[int, float] = {}
        next_parent: dict[int, tuple[int, int]] = {}
        transition_count = 0
        closure_reject_count = 0
        for key, log_mass in state_log_mass.items():
            det_mask = _unpack_detector_mask(state_key=int(key), detector_mask_mask=int(detector_mask_mask))
            logical_mask = _unpack_logical_mask(
                state_key=int(key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
            )
            lifecycle_mask = _unpack_lifecycle_mask(
                state_key=int(key),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
                lifecycle_bit_count=int(len(previous_open_ids)),
            )
            selected_by_lifecycle = _lifecycle_mask_to_selected_map(
                int(lifecycle_mask),
                previous_open_ids,
            )
            for lifecycle_id in opening_ids:
                selected_by_lifecycle.setdefault(int(lifecycle_id), False)
            if set(int(value) for value in current_open_ids) != set(int(value) for value in selected_by_lifecycle.keys()):
                raise ValueError("loss-aware frontier state is inconsistent with the expected open lifecycle set")
            viterbi_mass = float(state_viterbi[int(key)])

            forced_local_state: int | None = None
            if str(column.kind) == "loss_branch":
                lifecycle_id = int(column.lifecycle_id)
                if bool(selected_by_lifecycle.get(int(lifecycle_id), False)):
                    forced_local_state = 0
            else:
                if any(
                    bool(selected_by_lifecycle.get(int(lifecycle_id), False))
                    for lifecycle_id in tuple(int(value) for value in column.touched_lifecycles)
                    if int(lifecycle_id) in set(int(value) for value in current_open_ids)
                ):
                    forced_local_state = 0

            state_iter: Sequence[tuple[int, float]]
            if forced_local_state is not None:
                state_iter = ((int(forced_local_state), 0.0),)
            else:
                state_iter = tuple((int(local_state), float(log_prior)) for local_state, log_prior in enumerate(log_priors))

            for local_state, log_prior in tuple(state_iter):
                if not math.isfinite(float(log_prior)):
                    continue
                transition_count += 1
                candidate_det = int(det_mask) ^ int(column.detector_response_masks[int(local_state)])
                if (((int(candidate_det) ^ int(target_syndrome_int)) & int(close_mask)) != 0):
                    closure_reject_count += 1
                    continue
                child_selected_by_lifecycle = dict(selected_by_lifecycle)
                if str(column.kind) == "loss_branch" and int(local_state) == 1:
                    child_selected_by_lifecycle[int(column.lifecycle_id)] = True
                for lifecycle_id in closing_ids:
                    if not bool(child_selected_by_lifecycle.get(int(lifecycle_id), False)):
                        closure_reject_count += 1
                        break
                else:
                    for lifecycle_id in closing_ids:
                        child_selected_by_lifecycle.pop(int(lifecycle_id), None)
                    next_det = int(candidate_det & int(active_mask))
                    next_logical = int(logical_mask) ^ int(column.logical_response_masks[int(local_state)])
                    next_lifecycle_mask = _selected_map_to_lifecycle_mask(
                        child_selected_by_lifecycle,
                        next_open_ids,
                    )
                    next_key = _pack_state_key(
                        det_mask=int(next_det),
                        logical_mask=int(next_logical),
                        num_detectors=int(num_detectors),
                        num_observables=int(num_observables),
                        lifecycle_mask=int(next_lifecycle_mask),
                        lifecycle_bit_count=int(len(next_open_ids)),
                    )
                    new_log_mass = float(log_mass) + float(log_prior)
                    next_log_mass[int(next_key)] = _logaddexp_pair(
                        float(next_log_mass.get(int(next_key), float("-inf"))),
                        float(new_log_mass),
                    )
                    new_viterbi = float(viterbi_mass) + float(log_prior)
                    if float(new_viterbi) > float(next_viterbi.get(int(next_key), float("-inf"))):
                        next_viterbi[int(next_key)] = float(new_viterbi)
                        if bool(track_best_path):
                            next_parent[int(next_key)] = (int(key), int(local_state))

        pruned_count = 0
        if beam_size is not None and len(next_log_mass) > int(beam_size):
            ranked = sorted(
                tuple(next_log_mass.keys()),
                key=lambda item: (
                    _loss_pruning_score(
                        state_key=int(item),
                        prefix_log_mass=float(next_log_mass[int(item)]),
                        boundary_column_index=int(column_index),
                        frontier=frontier,
                        num_detectors=int(num_detectors),
                        num_observables=int(num_observables),
                    ),
                    float(next_log_mass[int(item)]),
                    float(next_viterbi.get(int(item), float("-inf"))),
                ),
                reverse=True,
            )
            kept = set(int(value) for value in ranked[: int(beam_size)])
            pruned_count = int(len(next_log_mass) - len(kept))
            next_log_mass = {int(key): float(value) for key, value in next_log_mass.items() if int(key) in kept}
            next_viterbi = {int(key): float(value) for key, value in next_viterbi.items() if int(key) in kept}
            if bool(track_best_path):
                next_parent = {int(key): tuple(value) for key, value in next_parent.items() if int(key) in kept}

        parent_chain.append(dict(next_parent))
        state_log_mass = dict(next_log_mass)
        state_viterbi = dict(next_viterbi)
        state_count_by_column.append(int(len(state_log_mass)))
        pruned_state_count_by_column.append(int(pruned_count))
        expanded_transition_count_by_column.append(int(transition_count))
        lookahead_transition_count_by_column.append(0)
        if not state_log_mass:
            break

    logical_log_mass_map = {int(mask): float("-inf") for mask in range(int(logical_state_count))}
    best_terminal_key_by_logical: dict[int, int] = {}
    best_terminal_viterbi_by_logical: dict[int, float] = {}
    for key, log_mass in state_log_mass.items():
        det_mask = _unpack_detector_mask(state_key=int(key), detector_mask_mask=int(detector_mask_mask))
        if int(det_mask) != 0:
            continue
        logical_mask = _unpack_logical_mask(
            state_key=int(key),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
        )
        logical_log_mass_map[int(logical_mask)] = _logaddexp_pair(
            float(logical_log_mass_map[int(logical_mask)]),
            float(log_mass),
        )
        viterbi_mass = float(state_viterbi.get(int(key), float("-inf")))
        if float(viterbi_mass) > float(best_terminal_viterbi_by_logical.get(int(logical_mask), float("-inf"))):
            best_terminal_viterbi_by_logical[int(logical_mask)] = float(viterbi_mass)
            best_terminal_key_by_logical[int(logical_mask)] = int(key)

    finite_logical_items = {
        int(logical_mask): float(log_mass)
        for logical_mask, log_mass in logical_log_mass_map.items()
        if math.isfinite(float(log_mass))
    }
    if not finite_logical_items:
        return ProgressiveDecodeResult(
            status="no_path",
            target_syndrome=int(target_syndrome_int),
            logical_hat=0,
            logical_posteriors=tuple(0.0 for _ in range(int(logical_state_count))),
            log_evidence=float("-inf"),
            state_count_by_column=tuple(int(value) for value in state_count_by_column),
            pruned_state_count_by_column=tuple(int(value) for value in pruned_state_count_by_column),
            expanded_transition_count_by_column=tuple(int(value) for value in expanded_transition_count_by_column),
            lookahead_transition_count_by_column=tuple(int(value) for value in lookahead_transition_count_by_column),
            max_state_count=max((int(value) for value in state_count_by_column), default=0),
            beam_size=None if beam_size is None else int(beam_size),
            lookahead_depth=0,
            score_mode=str(score_mode_key),
            superstep_mode="none",
            superstep_path_budget=int(superstep_path_budget),
            superstep_state_budget=int(superstep_state_budget),
            superstep_transition_budget=int(superstep_transition_budget),
            lookahead_shortlist_size=0,
            tail_exact_columns=0,
            tail_exact_start_column=-1,
            logical_rerank_columns=0,
            logical_rerank_shortlist_size=0,
            logical_rerank_min_classes=0,
            logical_rerank_state_budget=int(logical_rerank_state_budget),
            logical_rerank_transition_budget=int(logical_rerank_transition_budget),
            best_path_states=tuple(),
            best_path_log_prob=float("-inf"),
        )

    log_evidence = _logaddexp_many(finite_logical_items)
    logical_posteriors = tuple(
        (
            0.0
            if not math.isfinite(float(logical_log_mass_map[int(logical_mask)]))
            else float(math.exp(float(logical_log_mass_map[int(logical_mask)]) - float(log_evidence)))
        )
        for logical_mask in range(int(logical_state_count))
    )
    logical_hat = max(
        range(int(logical_state_count)),
        key=lambda logical_mask: (
            float(logical_log_mass_map[int(logical_mask)]),
            float(best_terminal_viterbi_by_logical.get(int(logical_mask), float("-inf"))),
            -int(logical_mask),
        ),
    )
    best_path_states: tuple[int, ...] = tuple()
    best_path_log_prob = float(best_terminal_viterbi_by_logical.get(int(logical_hat), float("-inf")))
    if bool(track_best_path) and int(logical_hat) in best_terminal_key_by_logical:
        current_key = int(best_terminal_key_by_logical[int(logical_hat)])
        reversed_states: list[int] = []
        for parent_map in reversed(tuple(parent_chain)):
            parent_entry = parent_map.get(int(current_key))
            if parent_entry is None:
                reversed_states = []
                break
            parent_key, local_state = parent_entry
            reversed_states.append(int(local_state))
            current_key = int(parent_key)
        if len(reversed_states) == len(tuple(columns)):
            best_path_states = tuple(reversed(reversed_states))

    return ProgressiveDecodeResult(
        status="ok",
        target_syndrome=int(target_syndrome_int),
        logical_hat=int(logical_hat),
        logical_posteriors=tuple(float(value) for value in logical_posteriors),
        log_evidence=float(log_evidence),
        state_count_by_column=tuple(int(value) for value in state_count_by_column),
        pruned_state_count_by_column=tuple(int(value) for value in pruned_state_count_by_column),
        expanded_transition_count_by_column=tuple(int(value) for value in expanded_transition_count_by_column),
        lookahead_transition_count_by_column=tuple(int(value) for value in lookahead_transition_count_by_column),
        max_state_count=max((int(value) for value in state_count_by_column), default=0),
        beam_size=None if beam_size is None else int(beam_size),
        lookahead_depth=0,
        score_mode=str(score_mode_key),
        superstep_mode="none",
        superstep_path_budget=int(superstep_path_budget),
        superstep_state_budget=int(superstep_state_budget),
        superstep_transition_budget=int(superstep_transition_budget),
        lookahead_shortlist_size=0,
        tail_exact_columns=0,
        tail_exact_start_column=-1,
        logical_rerank_columns=0,
        logical_rerank_shortlist_size=0,
        logical_rerank_min_classes=0,
        logical_rerank_state_budget=int(logical_rerank_state_budget),
        logical_rerank_transition_budget=int(logical_rerank_transition_budget),
        best_path_states=tuple(int(value) for value in best_path_states),
        best_path_log_prob=float(best_path_log_prob),
    )


def decode_progressive_loss_conditioned(
    conditional_dem: ConditionalLossDEM,
    *,
    beam_size: int | None = None,
    track_best_path: bool = True,
    score_mode: str = "prefix",
) -> ProgressiveDecodeResult:
    layout = build_loss_aware_frontier_layout(
        conditional_dem.columns,
        num_detectors=int(conditional_dem.D_r.shape[0]),
        loss_metadata=conditional_dem.loss_metadata,
    )
    return _decode_progressive_loss_conditioned(
        list(conditional_dem.columns),
        target_syndrome=int(conditional_dem.target_syndrome_r),
        num_detectors=int(conditional_dem.D_r.shape[0]),
        num_observables=max(1, int(conditional_dem.O_r.shape[0])),
        beam_size=(None if beam_size is None else int(beam_size)),
        layout=layout,
        track_best_path=bool(track_best_path),
        score_mode=str(score_mode),
    )


_FRONTIER_LAYOUT_CACHE: dict[
    tuple[int, tuple[int, ...]],
    tuple[tuple[ProgressiveColumn, ...], ProgressiveFrontierLayout],
] = {}
_FRONTIER_LAYOUT_STRUCTURAL_CACHE: dict[
    tuple[int, tuple[tuple[int, tuple[int, ...], tuple[float, ...], tuple[int, ...]], ...]],
    ProgressiveFrontierLayout,
] = {}


def _frontier_layout_column_cache_key(
    column: ProgressiveColumn,
) -> tuple[int, tuple[int, ...], tuple[float, ...], tuple[int, ...]]:
    support_rows = _column_support_rows(column)
    support_mask = 0
    for row in support_rows:
        support_mask |= 1 << int(row)
    return (
        int(support_mask),
        tuple(int(row) for row in support_rows),
        tuple(float(value) for value in column.prior_probs),
        tuple(int(value) for value in column.detector_response_masks),
    )


def build_frontier_layout(columns: list[ProgressiveColumn], *, num_detectors: int) -> ProgressiveFrontierLayout:
    if int(num_detectors) < 1:
        raise ValueError("num_detectors must be >= 1")
    columns_tuple = tuple(columns)
    column_identity = tuple(id(column) for column in columns_tuple)
    layout_cache_key = (int(num_detectors), column_identity)
    cached_entry = _FRONTIER_LAYOUT_CACHE.get(layout_cache_key)
    if cached_entry is not None and all(
        cached_column is column
        for cached_column, column in zip(cached_entry[0], columns_tuple, strict=True)
    ):
        _BINARY_MODEL_ORDER_CACHE_STATS.layout_hit_count += 1
        return cached_entry[1]
    structural_cache_key = (
        int(num_detectors),
        tuple(_frontier_layout_column_cache_key(column) for column in columns_tuple),
    )
    structural_cached = _FRONTIER_LAYOUT_STRUCTURAL_CACHE.get(structural_cache_key)
    if structural_cached is not None:
        _BINARY_MODEL_ORDER_CACHE_STATS.layout_hit_count += 1
        if len(_FRONTIER_LAYOUT_CACHE) >= 64:
            _FRONTIER_LAYOUT_CACHE.clear()
        _FRONTIER_LAYOUT_CACHE[layout_cache_key] = (columns_tuple, structural_cached)
        return structural_cached
    _BINARY_MODEL_ORDER_CACHE_STATS.layout_miss_count += 1
    build_started = time.perf_counter()
    if not columns:
        layout = ProgressiveFrontierLayout(
            detector_first_column=tuple(-1 for _ in range(int(num_detectors))),
            detector_last_column=tuple(-1 for _ in range(int(num_detectors))),
            closing_masks=tuple(),
            active_masks_after_column=tuple(),
            closure_block_start_by_column=tuple(),
            closure_block_end_by_column=tuple(),
            disjoint_detector_run_start_by_column=tuple(),
            disjoint_detector_run_end_by_column=tuple(),
            max_active_detectors=0,
            active_width_profile=(0,),
            column_row_updates=tuple(),
            row_touch_columns=tuple(tuple() for _ in range(int(num_detectors))),
            row_suffix_even_probs=tuple((1.0,) for _ in range(int(num_detectors))),
            row_suffix_odd_probs=tuple((0.0,) for _ in range(int(num_detectors))),
        )
        if len(_FRONTIER_LAYOUT_CACHE) >= 64:
            _FRONTIER_LAYOUT_CACHE.clear()
        if len(_FRONTIER_LAYOUT_STRUCTURAL_CACHE) >= 64:
            _FRONTIER_LAYOUT_STRUCTURAL_CACHE.clear()
        _FRONTIER_LAYOUT_CACHE[layout_cache_key] = (columns_tuple, layout)
        _FRONTIER_LAYOUT_STRUCTURAL_CACHE[structural_cache_key] = layout
        _BINARY_MODEL_ORDER_CACHE_STATS.layout_build_time_s += float(
            time.perf_counter() - build_started
        )
        return layout

    first = [-1 for _ in range(int(num_detectors))]
    last = [-1 for _ in range(int(num_detectors))]
    for column_index, column in enumerate(columns):
        support_rows = tuple(int(row) for row in column.detector_support_rows)
        if not support_rows:
            support = int(column.detector_support_mask)
            support_rows = _support_rows_from_mask(int(support))
        for row in support_rows:
            if int(first[int(row)]) < 0:
                first[int(row)] = int(column_index)
            last[int(row)] = int(column_index)

    rows_start: list[list[int]] = [[] for _ in range(len(columns))]
    rows_end: list[list[int]] = [[] for _ in range(len(columns))]
    for row in range(int(num_detectors)):
        if int(first[int(row)]) >= 0:
            rows_start[int(first[int(row)])].append(int(row))
        if int(last[int(row)]) >= 0:
            rows_end[int(last[int(row)])].append(int(row))

    closing_masks: list[int] = []
    active_masks_after_column: list[int] = []
    closure_block_start_by_column = [0 for _ in range(len(columns))]
    closure_block_end_by_column = [0 for _ in range(len(columns))]
    disjoint_detector_run_start_by_column = [0 for _ in range(len(columns))]
    disjoint_detector_run_end_by_column = [0 for _ in range(len(columns))]
    active_width_profile: list[int] = [0]
    max_active_detectors = 0
    active_mask = 0
    for column_index in range(len(columns)):
        close_mask = 0
        for row in rows_start[int(column_index)]:
            if int(last[int(row)]) > int(column_index):
                active_mask |= 1 << int(row)
        for row in rows_end[int(column_index)]:
            close_mask |= 1 << int(row)
            active_mask &= ~(1 << int(row))
        closing_masks.append(int(close_mask))
        active_masks_after_column.append(int(active_mask))
        active_width = int(active_mask.bit_count())
        active_width_profile.append(int(active_width))
        if int(active_width) > int(max_active_detectors):
            max_active_detectors = int(active_width)

    block_start = 0
    while int(block_start) < len(columns):
        block_end = int(block_start)
        while int(block_end) + 1 < len(columns) and int(closing_masks[int(block_end)]) == 0:
            block_end += 1
        for column_index in range(int(block_start), int(block_end) + 1):
            closure_block_start_by_column[int(column_index)] = int(block_start)
            closure_block_end_by_column[int(column_index)] = int(block_end)
        block_start = int(block_end) + 1

    run_start = 0
    while int(run_start) < len(columns):
        run_end = int(run_start)
        seen_support_mask = int(_column_detector_support_mask(columns[int(run_start)]))
        while int(run_end) + 1 < len(columns):
            next_support_mask = int(_column_detector_support_mask(columns[int(run_end) + 1]))
            if int(seen_support_mask & next_support_mask) != 0:
                break
            seen_support_mask |= int(next_support_mask)
            run_end += 1
        for column_index in range(int(run_start), int(run_end) + 1):
            disjoint_detector_run_start_by_column[int(column_index)] = int(run_start)
            disjoint_detector_run_end_by_column[int(column_index)] = int(run_end)
        run_start = int(run_end) + 1

    row_touch_columns, row_suffix_even_probs, row_suffix_odd_probs = _build_row_future_statistics(
        columns,
        num_detectors=int(num_detectors),
    )
    tiny = float(np.finfo(np.float64).tiny)
    column_row_updates_lists: list[list[FrontierRowUpdate]] = [[] for _ in range(len(columns))]
    for row in range(int(num_detectors)):
        touch_columns = row_touch_columns[int(row)]
        if not touch_columns:
            continue
        suffix_even = row_suffix_even_probs[int(row)]
        suffix_odd = row_suffix_odd_probs[int(row)]
        total_touches = int(len(touch_columns))
        row_mask = 1 << int(row)
        for offset, column_index in enumerate(touch_columns):
            active_before = bool(int(offset) > 0)
            active_after = bool(int(offset) + 1 < int(total_touches))
            if bool(active_before):
                before_even = float(suffix_even[int(offset)])
                before_odd = float(suffix_odd[int(offset)])
                before_touch_bonus = float(math.log(float(total_touches - int(offset))))
                before_urgency = float(1.0 / float(total_touches - int(offset)))
                before_parity_logodds = float(math.log(max(before_odd, tiny)) - math.log(max(before_even, tiny)))
            else:
                before_touch_bonus = 0.0
                before_urgency = 0.0
                before_parity_logodds = 0.0
            if bool(active_after):
                after_even = float(suffix_even[int(offset) + 1])
                after_odd = float(suffix_odd[int(offset) + 1])
                after_touch_bonus = float(math.log(float(total_touches - int(offset) - 1)))
                after_urgency = float(1.0 / float(total_touches - int(offset) - 1))
                after_parity_logodds = float(math.log(max(after_odd, tiny)) - math.log(max(after_even, tiny)))
            else:
                after_touch_bonus = 0.0
                after_urgency = 0.0
                after_parity_logodds = 0.0
            column_row_updates_lists[int(column_index)].append(
                FrontierRowUpdate(
                    row=int(row),
                    row_mask=int(row_mask),
                    active_before=bool(active_before),
                    active_after=bool(active_after),
                    touch_bonus_before=float(before_touch_bonus),
                    touch_bonus_after=float(after_touch_bonus),
                    urgency_before=float(before_urgency),
                    urgency_after=float(after_urgency),
                    parity_logodds_before=float(before_parity_logodds),
                    parity_logodds_after=float(after_parity_logodds),
                )
            )
    layout = ProgressiveFrontierLayout(
        detector_first_column=tuple(int(value) for value in first),
        detector_last_column=tuple(int(value) for value in last),
        closing_masks=tuple(int(value) for value in closing_masks),
        active_masks_after_column=tuple(int(value) for value in active_masks_after_column),
        closure_block_start_by_column=tuple(int(value) for value in closure_block_start_by_column),
        closure_block_end_by_column=tuple(int(value) for value in closure_block_end_by_column),
        disjoint_detector_run_start_by_column=tuple(int(value) for value in disjoint_detector_run_start_by_column),
        disjoint_detector_run_end_by_column=tuple(int(value) for value in disjoint_detector_run_end_by_column),
        max_active_detectors=int(max_active_detectors),
        active_width_profile=tuple(int(value) for value in active_width_profile),
        column_row_updates=tuple(
            tuple(update for update in updates)
            for updates in column_row_updates_lists
        ),
        row_touch_columns=tuple(tuple(int(value) for value in row) for row in row_touch_columns),
        row_suffix_even_probs=tuple(tuple(float(value) for value in row) for row in row_suffix_even_probs),
        row_suffix_odd_probs=tuple(tuple(float(value) for value in row) for row in row_suffix_odd_probs),
    )
    if len(_FRONTIER_LAYOUT_CACHE) >= 64:
        _FRONTIER_LAYOUT_CACHE.clear()
    if len(_FRONTIER_LAYOUT_STRUCTURAL_CACHE) >= 64:
        _FRONTIER_LAYOUT_STRUCTURAL_CACHE.clear()
    _FRONTIER_LAYOUT_CACHE[layout_cache_key] = (columns_tuple, layout)
    _FRONTIER_LAYOUT_STRUCTURAL_CACHE[structural_cache_key] = layout
    _BINARY_MODEL_ORDER_CACHE_STATS.layout_build_time_s += float(
        time.perf_counter() - build_started
    )
    return layout


