    def _capture_guidance_snapshot_if_requested(
        *,
        boundary_column_index: int,
        active_mask: int,
        kept_state_log_mass: dict[int, float] | None = None,
        pre_prune_state_log_mass: dict[int, float] | None = None,
        pre_prune_state_viterbi: dict[int, float] | None = None,
        pre_prune_state_viterbi_rep_cost: dict[int, int] | None = None,
        pre_prune_state_min_nonzero_steps: dict[int, int] | None = None,
    ) -> None:
        if not bool(capture_guidance_snapshots):
            return
        processed_columns = int(boundary_column_index) + 1
        primary_source = str(forward_guidance_snapshot_source_key)
        if str(primary_source) == "pre_prune" and pre_prune_state_log_mass is not None:
            primary_state_log_mass = dict(pre_prune_state_log_mass)
        else:
            primary_state_log_mass = (
                dict(state_log_mass)
                if kept_state_log_mass is None
                else dict(kept_state_log_mass)
            )
        checkpoint_source_state_log_mass: dict[int, float] | None = None
        checkpoint_summary: ForwardCheckpoint | None = None
        checkpoint_resume_state: ProgressiveResumeState | None = None
        if bool(forward_checkpoint_enabled) and _should_record_posterior_trace_checkpoint(
            processed_columns=int(processed_columns),
            total_columns=int(len(columns)),
            checkpoint_stride=int(forward_checkpoint_period),
        ):
            checkpoint_source_state_log_mass = (
                dict(pre_prune_state_log_mass)
                if str(forward_checkpoint_source_key) == "pre_prune" and pre_prune_state_log_mass is not None
                else (
                    dict(state_log_mass)
                    if kept_state_log_mass is None
                    else dict(kept_state_log_mass)
                )
            )
            checkpoint_processed_indices = _progressive_processed_original_index_set(
                columns,
                processed_columns=int(processed_columns),
            )
            checkpoint_boundary_mask = _progressive_middle_join_boundary_mask(
                columns=columns,
                processed_original_indices=checkpoint_processed_indices,
                all_original_indices=_progressive_original_column_index_set(columns),
            )
            if int(checkpoint_boundary_mask) != 0 and checkpoint_source_state_log_mass:
                checkpoint_summary = _capture_forward_checkpoint(
                    state_log_mass=dict(checkpoint_source_state_log_mass),
                    cut_ctx=CutContext(
                        cut_index=int(processed_columns),
                        active_rows=tuple(
                            int(row)
                            for row in _support_rows_from_mask(int(checkpoint_boundary_mask))
                        ),
                        boundary_mask=int(checkpoint_boundary_mask),
                    ),
                    detector_mask_mask=int(detector_mask_mask),
                    num_detectors=int(num_detectors),
                    num_observables=int(num_observables),
                    exact_correction_mode=bool(exact_correction_mode),
                    gap=float(forward_checkpoint_gap),
                    max_keys=int(forward_checkpoint_max_keys),
                )
                if str(forward_checkpoint_source_key) == "pre_prune" and pre_prune_state_log_mass is not None:
                    if pre_prune_state_viterbi is not None:
                        checkpoint_resume_state = _freeze_resume_state(
                            state_log_mass=dict(pre_prune_state_log_mass),
                            state_viterbi=dict(pre_prune_state_viterbi),
                            state_viterbi_rep_cost=(
                                None
                                if pre_prune_state_viterbi_rep_cost is None
                                else dict(pre_prune_state_viterbi_rep_cost)
                            ),
                            state_min_nonzero_steps=(
                                None
                                if pre_prune_state_min_nonzero_steps is None
                                else dict(pre_prune_state_min_nonzero_steps)
                            ),
                            next_column_index=int(processed_columns),
                        )
                else:
                    checkpoint_resume_state = _freeze_resume_state(
                        state_log_mass=(
                            dict(state_log_mass)
                            if kept_state_log_mass is None
                            else dict(kept_state_log_mass)
                        ),
                        state_viterbi=dict(state_viterbi),
                        state_viterbi_rep_cost=(
                            None
                            if state_viterbi_rep_cost is None
                            else dict(state_viterbi_rep_cost)
                        ),
                        state_min_nonzero_steps=(
                            None
                            if state_min_nonzero_steps is None
                            else dict(state_min_nonzero_steps)
                        ),
                        next_column_index=int(processed_columns),
                    )
        guidance_snapshots.append(
            _summarize_guidance_snapshot(
                state_log_mass=dict(primary_state_log_mass),
                processed_columns=int(processed_columns),
                total_columns=int(len(columns)),
                boundary_column_index=int(boundary_column_index),
                active_mask=int(active_mask),
                num_detectors=int(num_detectors),
                num_observables=int(num_observables),
                primary_source=str(primary_source),
                kept_state_log_mass=(
                    dict(state_log_mass)
                    if kept_state_log_mass is None
                    else dict(kept_state_log_mass)
                ),
                pre_prune_state_log_mass=(
                    None
                    if pre_prune_state_log_mass is None
                    else dict(pre_prune_state_log_mass)
                ),
                processed_column_identity_mask=(
                    0
                    if column_identity_masks_by_count is None
                    else int(column_identity_masks_by_count[int(processed_columns)])
                ),
                forward_checkpoint=checkpoint_summary,
                forward_checkpoint_source=str(forward_checkpoint_source_key),
                checkpoint_resume_state=checkpoint_resume_state,
            )
        )

