                    logical_rerank_pass_count=int(logical_rerank_pass_count),
                    tail_checkpoint_window_columns=int(tail_checkpoint_window_columns),
                    tail_checkpoint_count=int(len(tail_checkpoint_summaries)),
                    tail_checkpoint_min_top1_posterior=float(tail_checkpoint_min_top1_posterior),
                    tail_checkpoint_min_log_posterior_gap=float(tail_checkpoint_min_log_posterior_gap),
