def evaluate_progressive_family(
    *,
    columns: list[ProgressiveColumn],
    exact_joint: np.ndarray,
    num_detectors: int,
    num_observables: int = 1,
    beam_size: int | None = None,
    delayed_pruning_gap_threshold: float = 0.0,
    delayed_pruning_factor: int = 1,
    pruning_replay_checkpoint_stride: int = 0,
    pruning_replay_horizon: int = 0,
    lookahead_depth: int = 0,
    score_mode: str = "prefix",
    lookahead_shortlist_size: int = 0,
    tail_exact_columns: int = 0,
    superstep_mode: str = "none",
    superstep_path_budget: int = 250000,
    superstep_state_budget: int = 4096,
    superstep_transition_budget: int = 0,
    detector_bucket_pruning: bool = False,
    detector_bucket_max_logicals: int = 4,
    logical_rerank_columns: int = 0,
    logical_rerank_shortlist_size: int = 0,
    logical_rerank_min_classes: int = 0,
    logical_rerank_state_budget: int = 1024,
    logical_rerank_transition_budget: int = 100000,
    logical_rerank_checkpoint_stride: int = 0,
    logical_rerank_max_passes: int = 1,
    logical_rerank_mode: str = "exact_tail",
    pruned_prefix_rescue_window_columns: int = 0,
    pruned_prefix_rescue_seed_limit: int = 0,
    pruned_prefix_rescue_state_cap: int = 0,
    clamp_assignments: dict[int, int] | None = None,
    progress_label: str | None = None,
    progress_every_syndromes: int = 0,
    collect_decisions: bool = True,
    debug_pruning_engine: str = "optimized",
    collect_debug_metrics: bool = False,
    debug_shadow_score_modes: tuple[str, ...] | list[str] | None = None,
    final_logical_select_mode: str = "log_mass",
    final_logical_select_rep_cost_weight: float = 0.0,
    final_logical_select_max_log_mass_gap: float = float("inf"),
) -> dict[str, object]:
    logical_state_count = 1 << int(num_observables)
    final_logical_select_mode_key = _normalize_final_logical_select_mode(final_logical_select_mode)
    frontier = build_frontier_layout(columns, num_detectors=int(num_detectors))
    syndrome_count = 1 << int(num_detectors)
    normalized_clamps = _normalize_clamp_assignments(columns, clamp_assignments)

    if beam_size is None and not bool(collect_decisions) and not normalized_clamps:
        exact_summary = exact._decision_summary(np.asarray(exact_joint, dtype=np.float64))
        return {
            "fer": float(exact_summary["fer"]),
            "fail_total": float(exact_summary["fer"]),
            "logical_fail": float(exact_summary["fer"]),
            "syndrome_fail": 0.0,
            "exception_fail": 0.0,
            "success_probability": float(exact_summary["success_probability"]),
            "mean_states": 0.0,
            "mean_transition_evals": 0.0,
            "mean_lookahead_transition_evals": 0.0,
            "mean_total_transition_evals": 0.0,
            "mean_pruned_states": 0.0,
            "max_states_seen": int(1 << (int(frontier.max_active_detectors) + int(num_observables))),
            "frontier_max_active_detectors": int(frontier.max_active_detectors),
            "frontier_active_width_profile": list(frontier.active_width_profile),
            "beam_size": None,
            "delayed_pruning_gap_threshold": float(delayed_pruning_gap_threshold),
            "delayed_pruning_factor": int(delayed_pruning_factor),
            "delayed_pruning_trigger_count": 0,
            "delayed_pruning_active_prune_count": 0,
            "delayed_pruning_peak_beam_size": 0,
            "pruning_replay_checkpoint_stride": int(pruning_replay_checkpoint_stride),
            "pruning_replay_horizon": int(pruning_replay_horizon),
            "pruning_replay_attempt_count": 0,
            "pruning_replay_applied_count": 0,
            "pruning_replay_replaced_state_count": 0,
            "mean_cumulative_pruned_prefix_rescued_mass": 0.0,
            "mean_cumulative_discarded_prefix_mass": 0.0,
            "mean_max_discarded_prefix_fraction": 0.0,
            "mean_mean_discarded_prefix_fraction": 0.0,
            "max_discarded_prefix_mass_seen": 0.0,
            "max_discarded_prefix_fraction_seen": 0.0,
            "lookahead_depth": int(lookahead_depth),
            "score_mode": str(score_mode),
            "superstep_mode": str(superstep_mode),
            "superstep_path_budget": int(superstep_path_budget),
            "superstep_state_budget": int(superstep_state_budget),
            "superstep_transition_budget": int(superstep_transition_budget),
            "detector_bucket_pruning": bool(detector_bucket_pruning),
            "detector_bucket_max_logicals": int(detector_bucket_max_logicals),
            "lookahead_shortlist_size": int(lookahead_shortlist_size),
            "tail_exact_columns": int(tail_exact_columns),
            "logical_rerank_columns": int(logical_rerank_columns),
            "logical_rerank_shortlist_size": int(logical_rerank_shortlist_size),
            "logical_rerank_min_classes": int(logical_rerank_min_classes),
            "logical_rerank_state_budget": int(logical_rerank_state_budget),
            "logical_rerank_transition_budget": int(logical_rerank_transition_budget),
            "logical_rerank_checkpoint_stride": int(logical_rerank_checkpoint_stride),
            "logical_rerank_max_passes": int(logical_rerank_max_passes),
            "logical_rerank_mode": str(logical_rerank_mode),
            "pruned_prefix_rescue_window_columns": int(pruned_prefix_rescue_window_columns),
            "pruned_prefix_rescue_seed_limit": int(pruned_prefix_rescue_seed_limit),
            "pruned_prefix_rescue_state_cap": int(pruned_prefix_rescue_state_cap),
            "final_logical_select_mode": str(final_logical_select_mode_key),
            "final_logical_select_rep_cost_weight": float(final_logical_select_rep_cost_weight),
            "final_logical_select_max_log_mass_gap": float(final_logical_select_max_log_mass_gap),
            "logical_fail_missing_terminal": 0.0,
            "logical_fail_present_but_not_selected": 0.0,
            "clamp_count": 0,
            "debug_pruning_engine": str(debug_pruning_engine),
        }

    fail_total = 0.0
    logical_fail = 0.0
    logical_fail_missing_terminal = 0.0
    logical_fail_present_but_not_selected = 0.0
    syndrome_fail = 0.0
    success_probability = 0.0
    mean_states = 0.0
    mean_transitions = 0.0
    mean_lookahead_transitions = 0.0
    mean_pruned_states = 0.0
    mean_cumulative_pruned_prefix_rescued_mass = 0.0
    mean_cumulative_discarded_prefix_mass = 0.0
    mean_max_discarded_prefix_fraction = 0.0
    mean_mean_discarded_prefix_fraction = 0.0
    max_discarded_prefix_mass_seen = 0.0
    max_discarded_prefix_fraction_seen = 0.0
    max_states_seen = 0
    decisions: list[dict[str, object]] = []

    for syndrome in range(int(syndrome_count)):
        if int(progress_every_syndromes) > 0 and (
            int(syndrome) == 0
            or ((int(syndrome) + 1) % int(progress_every_syndromes) == 0)
            or (int(syndrome) + 1 == int(syndrome_count))
        ):
            if progress_label is not None:
                print(
                    f"[progressive] {str(progress_label)} syndrome {int(syndrome) + 1}/{int(syndrome_count)}",
                    flush=True,
                )
        result = decode_progressive(
            columns,
            target_syndrome=int(syndrome),
            num_detectors=int(num_detectors),
            num_observables=int(num_observables),
            beam_size=beam_size,
            delayed_pruning_gap_threshold=float(delayed_pruning_gap_threshold),
            delayed_pruning_factor=int(delayed_pruning_factor),
            pruning_replay_checkpoint_stride=int(pruning_replay_checkpoint_stride),
            pruning_replay_horizon=int(pruning_replay_horizon),
            lookahead_depth=int(lookahead_depth),
            score_mode=str(score_mode),
            lookahead_shortlist_size=int(lookahead_shortlist_size),
            tail_exact_columns=int(tail_exact_columns),
            superstep_mode=str(superstep_mode),
            superstep_path_budget=int(superstep_path_budget),
            superstep_state_budget=int(superstep_state_budget),
            superstep_transition_budget=int(superstep_transition_budget),
            detector_bucket_pruning=bool(detector_bucket_pruning),
            detector_bucket_max_logicals=int(detector_bucket_max_logicals),
            logical_rerank_columns=int(logical_rerank_columns),
            logical_rerank_shortlist_size=int(logical_rerank_shortlist_size),
            logical_rerank_min_classes=int(logical_rerank_min_classes),
            logical_rerank_state_budget=int(logical_rerank_state_budget),
            logical_rerank_transition_budget=int(logical_rerank_transition_budget),
            logical_rerank_checkpoint_stride=int(logical_rerank_checkpoint_stride),
            logical_rerank_max_passes=int(logical_rerank_max_passes),
            logical_rerank_mode=str(logical_rerank_mode),
            pruned_prefix_rescue_window_columns=int(pruned_prefix_rescue_window_columns),
            pruned_prefix_rescue_seed_limit=int(pruned_prefix_rescue_seed_limit),
            pruned_prefix_rescue_state_cap=int(pruned_prefix_rescue_state_cap),
            clamp_assignments=normalized_clamps,
            layout=frontier,
            track_best_path=bool(collect_decisions),
            debug_pruning_engine=str(debug_pruning_engine),
            collect_debug_metrics=bool(collect_debug_metrics),
            debug_shadow_score_modes=debug_shadow_score_modes,
            final_logical_select_mode=str(final_logical_select_mode_key),
            final_logical_select_rep_cost_weight=float(final_logical_select_rep_cost_weight),
            final_logical_select_max_log_mass_gap=float(final_logical_select_max_log_mass_gap),
        )
        diagnostics = summarize_progressive_beam_diagnostics(result)
        syndrome_mass = float(np.sum(exact_joint[int(syndrome), :]))
        logical_row = np.asarray(exact_joint[int(syndrome), :], dtype=np.float64).reshape(-1)
        if logical_row.shape[0] != int(logical_state_count):
            raise ValueError("exact_joint logical axis does not match num_observables")
        exact_map_logical_hat = int(np.argmax(logical_row))
        terminal_logical_masks = {
            int(summary.logical_mask)
            for summary in tuple(result.terminal_logical_class_summaries)
        }
        exact_map_logical_hat_retained_terminal = bool(
            str(result.status) == "ok" and int(exact_map_logical_hat) in terminal_logical_masks
        )
        if str(result.status) != "ok":
            exact_map_logical_hat_failure_mode = "syndrome_fail"
        elif int(result.logical_hat) == int(exact_map_logical_hat):
            exact_map_logical_hat_failure_mode = "selected"
        elif bool(exact_map_logical_hat_retained_terminal):
            exact_map_logical_hat_failure_mode = "present_but_not_selected"
        else:
            exact_map_logical_hat_failure_mode = "missing_terminal"

        mean_states += float(np.mean(np.asarray(result.state_count_by_column, dtype=np.float64))) * syndrome_mass
        mean_transitions += float(np.sum(np.asarray(result.expanded_transition_count_by_column, dtype=np.float64))) * syndrome_mass
        mean_lookahead_transitions += float(np.sum(np.asarray(result.lookahead_transition_count_by_column, dtype=np.float64))) * syndrome_mass
        mean_pruned_states += float(np.sum(np.asarray(result.pruned_state_count_by_column, dtype=np.float64))) * syndrome_mass
        mean_cumulative_pruned_prefix_rescued_mass += float(result.cumulative_pruned_prefix_rescued_mass) * syndrome_mass
        mean_cumulative_discarded_prefix_mass += float(result.cumulative_discarded_prefix_mass) * syndrome_mass
        mean_max_discarded_prefix_fraction += float(diagnostics.max_discarded_prefix_fraction) * syndrome_mass
        mean_mean_discarded_prefix_fraction += float(diagnostics.mean_discarded_prefix_fraction) * syndrome_mass
        max_discarded_prefix_mass_seen = max(
            float(max_discarded_prefix_mass_seen),
            float(diagnostics.max_discarded_prefix_mass),
        )
        max_discarded_prefix_fraction_seen = max(
            float(max_discarded_prefix_fraction_seen),
            float(diagnostics.max_discarded_prefix_fraction),
        )
        max_states_seen = max(int(max_states_seen), int(result.max_state_count))

        if str(result.status) != "ok":
            syndrome_fail += syndrome_mass
            fail_total += syndrome_mass
            success_mass = 0.0
            logical_fail_mass = 0.0
            logical_fail_missing_terminal_mass = 0.0
            logical_fail_present_but_not_selected_mass = 0.0
        else:
            success_mass = float(logical_row[int(result.logical_hat)])
            logical_fail_mass = float(np.sum(logical_row) - float(success_mass))
            logical_fail_missing_terminal_mass = float(
                sum(
                    float(logical_row[int(logical_mask)])
                    for logical_mask in range(int(logical_state_count))
                    if int(logical_mask) != int(result.logical_hat)
                    and int(logical_mask) not in terminal_logical_masks
                )
            )
            logical_fail_present_but_not_selected_mass = float(
                sum(
                    float(logical_row[int(logical_mask)])
                    for logical_mask in terminal_logical_masks
                    if int(logical_mask) != int(result.logical_hat)
                )
            )
            logical_fail += logical_fail_mass
            logical_fail_missing_terminal += logical_fail_missing_terminal_mass
            logical_fail_present_but_not_selected += logical_fail_present_but_not_selected_mass
            fail_total += logical_fail_mass
            success_probability += success_mass

        if bool(collect_decisions):
            decisions.append(
                {
                    "syndrome": int(syndrome),
                    "status": str(result.status),
                    "logical_hat": int(result.logical_hat),
                    "exact_map_logical_hat": int(exact_map_logical_hat),
                    "exact_map_logical_hat_retained_terminal": bool(exact_map_logical_hat_retained_terminal),
                    "exact_map_logical_hat_failure_mode": str(exact_map_logical_hat_failure_mode),
                    "success_mass": float(success_mass),
                    "logical_fail_mass": float(logical_fail_mass),
                    "logical_fail_missing_terminal_mass": float(logical_fail_missing_terminal_mass),
                    "logical_fail_present_but_not_selected_mass": float(
                        logical_fail_present_but_not_selected_mass
                    ),
                    "syndrome_fail_mass": float(syndrome_mass if str(result.status) != "ok" else 0.0),
                    "max_states": int(result.max_state_count),
                    "delayed_pruning_trigger_count": int(result.delayed_pruning_trigger_count),
                    "delayed_pruning_active_prune_count": int(result.delayed_pruning_active_prune_count),
                    "delayed_pruning_peak_beam_size": int(result.delayed_pruning_peak_beam_size),
                    "pruning_replay_attempt_count": int(result.pruning_replay_attempt_count),
                    "pruning_replay_applied_count": int(result.pruning_replay_applied_count),
                    "pruning_replay_replaced_state_count": int(result.pruning_replay_replaced_state_count),
                    "pruning_replay_replayed_column_count": int(result.pruning_replay_replayed_column_count),
                    "pruning_replay_extra_transition_evals": int(result.pruning_replay_extra_transition_evals),
                    "mean_states": float(np.mean(np.asarray(result.state_count_by_column, dtype=np.float64))),
                    "transition_evals": int(np.sum(np.asarray(result.expanded_transition_count_by_column, dtype=np.int64))),
                    "lookahead_transition_evals": int(np.sum(np.asarray(result.lookahead_transition_count_by_column, dtype=np.int64))),
                    "score_mode": str(result.score_mode),
                    "superstep_mode": str(result.superstep_mode),
                    "superstep_path_budget": int(result.superstep_path_budget),
                    "superstep_state_budget": int(result.superstep_state_budget),
                    "superstep_transition_budget": int(result.superstep_transition_budget),
                    "detector_bucket_pruning": bool(result.detector_bucket_pruning),
                    "detector_bucket_max_logicals": int(result.detector_bucket_max_logicals),
                    "lookahead_shortlist_size": int(result.lookahead_shortlist_size),
                    "tail_exact_columns": int(result.tail_exact_columns),
                    "logical_rerank_columns": int(result.logical_rerank_columns),
                    "logical_rerank_shortlist_size": int(result.logical_rerank_shortlist_size),
                    "logical_rerank_min_classes": int(result.logical_rerank_min_classes),
                    "logical_rerank_state_budget": int(result.logical_rerank_state_budget),
                    "logical_rerank_transition_budget": int(result.logical_rerank_transition_budget),
                    "logical_rerank_checkpoint_stride": int(result.logical_rerank_checkpoint_stride),
                    "logical_rerank_max_passes": int(result.logical_rerank_max_passes),
                    "logical_rerank_mode": str(result.logical_rerank_mode),
                    "logical_rerank_pass_count": int(result.logical_rerank_pass_count),
                    "pruned_prefix_rescue_window_columns": int(result.pruned_prefix_rescue_window_columns),
                    "pruned_prefix_rescue_seed_limit": int(result.pruned_prefix_rescue_seed_limit),
                    "pruned_prefix_rescue_state_cap": int(result.pruned_prefix_rescue_state_cap),
                    "pruned_prefix_rescue_seeded_state_count": int(result.pruned_prefix_rescue_seeded_state_count),
                    "pruned_prefix_rescue_absorbed_state_count": int(result.pruned_prefix_rescue_absorbed_state_count),
                    "cumulative_pruned_prefix_rescued_mass": float(result.cumulative_pruned_prefix_rescued_mass),
                    "cumulative_discarded_prefix_mass": float(result.cumulative_discarded_prefix_mass),
                    "max_discarded_prefix_mass": float(diagnostics.max_discarded_prefix_mass),
                    "mean_discarded_prefix_mass": float(diagnostics.mean_discarded_prefix_mass),
                    "max_discarded_prefix_fraction": float(diagnostics.max_discarded_prefix_fraction),
                    "mean_discarded_prefix_fraction": float(diagnostics.mean_discarded_prefix_fraction),
                    "final_logical_select_mode": str(result.final_logical_select_mode),
                    "final_logical_select_rep_cost_weight": float(result.final_logical_select_rep_cost_weight),
                    "final_logical_select_max_log_mass_gap": float(
                        result.final_logical_select_max_log_mass_gap
                    ),
                    "final_logical_select_gate_triggered": bool(result.final_logical_select_gate_triggered),
                    "terminal_top_log_mass_gap": float(result.terminal_top_log_mass_gap),
                    "terminal_logical_class_summaries": tuple(
                        (
                            int(summary.logical_mask),
                            float(summary.log_mass),
                            float(summary.best_viterbi),
                            float(summary.representative_cost),
                        )
                        for summary in tuple(result.terminal_logical_class_summaries)
                    ),
                }
            )

    out = {
        "fer": float(fail_total),
        "fail_total": float(fail_total),
        "logical_fail": float(logical_fail),
        "logical_fail_missing_terminal": float(logical_fail_missing_terminal),
        "logical_fail_present_but_not_selected": float(logical_fail_present_but_not_selected),
        "syndrome_fail": float(syndrome_fail),
        "exception_fail": 0.0,
        "success_probability": float(success_probability),
        "mean_states": float(mean_states),
        "mean_transition_evals": float(mean_transitions),
        "mean_lookahead_transition_evals": float(mean_lookahead_transitions),
        "mean_total_transition_evals": float(mean_transitions + mean_lookahead_transitions),
        "mean_pruned_states": float(mean_pruned_states),
        "max_states_seen": int(max_states_seen),
        "frontier_max_active_detectors": int(frontier.max_active_detectors),
        "frontier_active_width_profile": list(frontier.active_width_profile),
        "beam_size": None if beam_size is None else int(beam_size),
        "delayed_pruning_gap_threshold": float(delayed_pruning_gap_threshold),
        "delayed_pruning_factor": int(delayed_pruning_factor),
        "delayed_pruning_trigger_count": float(
            np.mean([float(decision.get("delayed_pruning_trigger_count", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "delayed_pruning_active_prune_count": float(
            np.mean([float(decision.get("delayed_pruning_active_prune_count", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "delayed_pruning_peak_beam_size": int(
            max((int(decision.get("delayed_pruning_peak_beam_size", 0)) for decision in decisions), default=0)
        )
        if bool(collect_decisions)
        else 0,
        "pruning_replay_checkpoint_stride": int(pruning_replay_checkpoint_stride),
        "pruning_replay_horizon": int(pruning_replay_horizon),
        "pruning_replay_attempt_count": float(
            np.mean([float(decision.get("pruning_replay_attempt_count", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "pruning_replay_applied_count": float(
            np.mean([float(decision.get("pruning_replay_applied_count", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "pruning_replay_replaced_state_count": float(
            np.mean([float(decision.get("pruning_replay_replaced_state_count", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "pruning_replay_replayed_column_count": float(
            np.mean([float(decision.get("pruning_replay_replayed_column_count", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "pruning_replay_extra_transition_evals": float(
            np.mean([float(decision.get("pruning_replay_extra_transition_evals", 0)) for decision in decisions])
        )
        if bool(collect_decisions) and decisions
        else 0.0,
        "mean_cumulative_pruned_prefix_rescued_mass": float(mean_cumulative_pruned_prefix_rescued_mass),
        "mean_cumulative_discarded_prefix_mass": float(mean_cumulative_discarded_prefix_mass),
        "mean_max_discarded_prefix_fraction": float(mean_max_discarded_prefix_fraction),
        "mean_mean_discarded_prefix_fraction": float(mean_mean_discarded_prefix_fraction),
        "max_discarded_prefix_mass_seen": float(max_discarded_prefix_mass_seen),
        "max_discarded_prefix_fraction_seen": float(max_discarded_prefix_fraction_seen),
        "lookahead_depth": int(lookahead_depth),
        "score_mode": str(score_mode),
        "superstep_mode": str(superstep_mode),
        "superstep_path_budget": int(superstep_path_budget),
        "superstep_state_budget": int(superstep_state_budget),
        "superstep_transition_budget": int(superstep_transition_budget),
        "detector_bucket_pruning": bool(detector_bucket_pruning),
        "detector_bucket_max_logicals": int(detector_bucket_max_logicals),
        "lookahead_shortlist_size": int(lookahead_shortlist_size),
        "tail_exact_columns": int(tail_exact_columns),
        "logical_rerank_columns": int(logical_rerank_columns),
        "logical_rerank_shortlist_size": int(logical_rerank_shortlist_size),
        "logical_rerank_min_classes": int(logical_rerank_min_classes),
        "logical_rerank_state_budget": int(logical_rerank_state_budget),
        "logical_rerank_transition_budget": int(logical_rerank_transition_budget),
        "logical_rerank_checkpoint_stride": int(logical_rerank_checkpoint_stride),
        "logical_rerank_max_passes": int(logical_rerank_max_passes),
        "logical_rerank_mode": str(logical_rerank_mode),
        "pruned_prefix_rescue_window_columns": int(pruned_prefix_rescue_window_columns),
        "pruned_prefix_rescue_seed_limit": int(pruned_prefix_rescue_seed_limit),
        "pruned_prefix_rescue_state_cap": int(pruned_prefix_rescue_state_cap),
        "final_logical_select_mode": str(final_logical_select_mode_key),
        "final_logical_select_rep_cost_weight": float(final_logical_select_rep_cost_weight),
        "final_logical_select_max_log_mass_gap": float(final_logical_select_max_log_mass_gap),
        "clamp_count": int(len(normalized_clamps)),
        "debug_pruning_engine": str(debug_pruning_engine),
    }
    if bool(collect_decisions):
        out["decisions"] = decisions
    return out
